#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    long long min_val = k + 1; // Initialize with a value larger than any possible a_i
    int min_idx = -1;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long total_spells = 0;

    // We always use the pile with the minimum value as the source (a_i).
    // This pile (a[min_idx]) never changes.
    // We copy its value to all other piles.
    // For each other pile a[j] (where j != min_idx), we can add a[min_idx] to it
    // as many times as possible without exceeding k.
    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue; // Skip the source pile itself
        }
        // For each other pile a[i], calculate how many times min_val can be added.
        // Current value is a[i]. Max allowed is k.
        // We need a[i] + count * min_val <= k
        // count * min_val <= k - a[i]
        // count <= (k - a[i]) / min_val
        // Since count must be an integer, it's floor((k - a[i]) / min_val)
        total_spells += (k - a[i]) / min_val;
    }

    std::cout << total_spells << std::endl;
}

