    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reverse of a permutation has the same fingerprint.
    // If p is not a palindrome, then reverse(p) is a different permutation.
    // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
    // For example, [1,2,1] is a palindrome, but it's not a permutation.
    // A permutation cannot be a palindrome unless n=1 (which is not allowed, n>=2).
    // For n >= 2, if p_i = p_{n-1-i}, then p_1 = p_n.
    // If p_1 = p_n, then since all elements must be distinct, this is only possible if n=1.
    // But n >= 2. So p_1 != p_n.
    // This means p is never equal to reverse(p).
    // Thus, reverse(p) is always a different permutation with the same fingerprint.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

