            // Can be 1 (1 press) or 2-1 (2 presses) or 5-2-2 (3 presses)
            // Optimal is 1 press (+1 or -1)
            ans += 1;
        } else if (diff == 2) {
            // Can be 2 (1 press) or 1+1 (2 presses)
            // Optimal is 1 press (+2 or -2)
            ans += 1;
        } else if (diff == 3) {
            // Can be 1+1+1 (3 presses) or 2+1 (2 presses) or 5-2 (2 presses)
            // Optimal is 2 presses (e.g., +2, +1 or +5, -2)
            ans += 2;
        } else if (diff == 4) {
            // Can be 1+1+1+1 (4 presses) or 2+2 (2 presses) or 5-1 (2 presses)
