#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long initial_a1 = a[0];
    long long added_to_a1 = 0;

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i; // 0-indexed pile_idx, corresponds to (i+1)-th pile
        long long haybales_in_pile = a[i];
        long long days_to_reach_a1 = pile_idx; // 0-indexed distance is pile_idx

        if (days_to_reach_a1 <= d) {
            // We can move haybales from this pile to pile 0
            long long max_haybales_from_this_pile = haybales_in_pile;
            long long haybales_to_move = std::min(max_haybales_from_this_pile, d / days_to_reach_a1);

            added_to_a1 += haybales_to_move;
            d -= haybales_to_move * days_to_reach_a1;
        }
    }

    std::cout << initial_a1 + added_to_a1 << std::endl;
}

