#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, starting from the second to last element
    // a[n-1] can never be a bad price because there are no days after it.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price, it means
            // a[i] <= min_suffix_price.
            // This a[i] could potentially be the new minimum for elements
            // to its left.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

