#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    int max_val_in_matrix = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] > max_val_in_matrix) {
                max_val_in_matrix = a[i][j];
            }
        }
    }

    std::vector<int> p(n);
    if (max_val_in_matrix == n) {
        // Case 1: n is present in the matrix a.
        // This means there is some p_k = n.
        // For such k, max_{j!=k} a[k][j] = n-1.
        // And p_k = n.
        // For all other i, p_i = max_{j!=i} a[i][j].
        for (int i = 0; i < n; ++i) {
            int current_max_for_row = 0;
            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                if (a[i][j] > current_max_for_row) {
                    current_max_for_row = a[i][j];
                }
            }
            p[i] = current_max_for_row;
        }
    } else {
        // Case 2: n is NOT present in the matrix a.
        // This implies that n is the largest element in the permutation,
        // and it must be assigned to some p_k.
        // For this p_k = n, max_{j!=k} a[k][j] = n-1.
        // For all other i, p_i = max_{j!=i} a[i][j].
        // So, exactly one p_k will be n, and all others will be max_{j!=i} a[i][j].
        // The value n is not present in the matrix, so it must be the value of one p_i.
        // The maximum value found in the matrix is n-1.
        // This means that one of the p_i must be n, and all other p_j must be <= n-1.
        // For any i, p_i = max_{j!=i} a[i][j] if p_i is not n.
        // If p_i is n, then max_{j!=i} a[i][j] = n-1.
        // So, we can assign p_i = max_{j!=i} a[i][j] for all i.
        // Then, find the index k where p[k] is the maximum among these values.
        // This p[k] should be n-1. We then change it to n.

        int max_val_among_row_maxes = 0;
        int max_idx = -1;

        for (int i = 0; i < n; ++i) {
            int current_max_for_row = 0;
            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                if (a[i][j] > current_max_for_row) {
                    current_max_for_row = a[i][j];
                }
            }
            p[i] = current_max_for_row;
            if (p[i] > max_val_among_row_maxes) {
                max_val_among_row_maxes = p[i];
                max_idx = i;
            }
        }
        // The element at max_idx must be n.
        // All other elements are correctly determined as max_{j!=i} a[i][j].
        // The value at p[max_idx] would be n-1 (the largest value in the matrix).
        // We need to change it to n.
        p[max_idx] = n;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_pos is -1, it means the frog is at cell 0.
                             // If last_R_pos is i, it means the frog is at cell i.
                             // The next 'R' or the target n+1 must be reachable from here.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at index i.
                // The cell is i+1.
                // The distance from the previous 'R' (or 0) to this 'R' is (i+1) - (last_R_pos + 1).
                // This simplifies to i - last_R_pos.
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' to n+1.
        // The last 'R' was at index last_R_pos. The cell is last_R_pos + 1.
        // The target is n+1.
        // The distance is (n+1) - (last_R_pos + 1) = n - last_R_pos.
        max_gap = std::max(max_gap, n - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

