int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top part (from apex to cut x_i) should be i * (total_area / n)
        // Total area = (1/2) * base * height = (1/2) * 1 * h = h/2
        // Area of top part = i * (h / (2n)) = (i * h) / (2n)
        // Also, area of top part = (1/2) * base_at_x_i * x_i
        // By similar triangles, base_at_x_i / 1 = x_i / h  => base_at_x_i = x_i / h
        // So, area of top part = (1/2) * (x_i / h) * x_i = x_i^2 / (2h)
        // Equating the two expressions for area:
        // x_i^2 / (2h) = (i * h) / (2n)
        // x_i^2 = (i * h^2) / n
        // x_i = sqrt((i * h^2) / n)
        // x_i = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

