int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The numbers from 1 to k+1 will be used to generate k distinct differences.
                       // The remaining numbers from k+2 to n will be appended in increasing order.

    // Generate the first k+1 elements to produce k distinct differences
    // This sequence alternates between smallest available and largest available
    // from the range [1, k+1].
    // Example: k=2, range [1,3]. Sequence: 1, 3, 2. Differences: |1-3|=2, |3-2|=1.
    // Example: k=3, range [1,4]. Sequence: 1, 4, 2, 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // Append the remaining numbers in increasing order
    // These numbers are from k+2 to n.
    // Appending them in increasing order ensures that the differences generated
    // will be 1. Since 1 is already among the k distinct differences generated
    // by the first part (unless k=0, which is not allowed), this doesn't add
    // new distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

