    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int current_balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                current_balance++;
                open_needed--;
            }
        } else { // c == ')'
            if (close_needed > 0 && current_balance > 0) {
                result += ')';
                current_balance--;
                close_needed--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

