    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m;
        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // The last digits of m, 2m, 3m, ... form a cycle of length 10.
        // Calculate the sum of last digits for one full cycle (10 terms).
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining terms after full cycles
        long long remaining_terms = count % 10;
        for (long long i = 1; i <= remaining_terms; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This means a[i] <= a[i+1] <= ... <= a[n-1].
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // After this loop, a[i...n-1] is non-decreasing.
    // If i=0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This means a[j] >= a[j+1] >= ... >= a[i-1].
    // We start from i-1 because we need to consider elements to the left of the non-decreasing suffix.
    int j = i; // j starts at i, meaning the non-increasing part could be empty.
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // After this loop, a[j...i-1] is non-increasing.
    // If j=0, then a[0...i-1] is non-increasing.

    // The prefix to remove has length `j`.
    std::cout << j << std::endl;
}

