        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // Let the sorted array be a_0, a_1, ..., a_{2n-1}.
        // We need to partition 2n students into two classes, each with an odd number of students.
        // Let the sizes be S1 and S2, where S1 + S2 = 2n, S1 is odd, S2 is odd.
        // The smallest possible odd size for a class is 1.
        // The largest possible odd size for a class is 2n-1.
        // If a class has size 2k+1, its median is the (k+1)-th element.
        //
        // Consider the case where one class has size 1. Its median is its only element.
        // The other class would have size 2n-1. Its median would be the n-th element (0-indexed).
        //
        // It can be proven that the optimal strategy is to assign the smallest n elements to one class
        // and the largest n elements to the other class.
        // Specifically, if we sort the entire array a, the median of the first class will be a[n-1]
        // and the median of the second class will be a[n].
        //
        // Let's verify this.
        // Suppose we have a sorted array a_0, a_1, ..., a_{2n-1}.
        // We need to pick S1 students for class 1 and S2 students for class 2.
        // S1 = 2k1 + 1, S2 = 2k2 + 1, where k1 + k2 = n - 1.
        // The median of class 1 will be its (k1+1)-th smallest element.
        // The median of class 2 will be its (k2+1)-th smallest element.
        //
        // Consider the elements a[n-1] and a[n].
        // If we form class 1 using elements a_0, ..., a_{n-1} and class 2 using a_n, ..., a_{2n-1},
        // this is not a valid partition because both classes would have size n, which might be even.
        //
        // The key insight is that to minimize the difference between medians, we want the medians to be as close as possible.
        // When the entire array is sorted, the "middle" elements are a[n-1] and a[n].
        //
        // Let's consider the partition where Class 1 consists of the first n elements (a_0 to a_{n-1})
        // and Class 2 consists of the last n elements (a_n to a_{2n-1}).
        // This is not a valid partition if n is even.
        //
        // However, the problem asks for *any* partition into two odd-sized classes.
        // The crucial observation is that the median of a class of size $2k+1$ is its $(k+1)$-th element.
        //
        // Consider the elements $a_{n-1}$ and $a_n$ from the sorted array.
        // We can always construct a partition such that $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // For example, let Class 1 contain $a_0, \dots, a_{n-1}$ and $n$ elements.
        // Let Class 2 contain $a_n, \dots, a_{2n-1}$ and $n$ elements.
        // If $n$ is odd, then both classes have odd size, and $a_{n/2}$ (integer division) is the median of Class 1,
        // and $a_{n + n/2}$ is the median of Class 2. This is not what we want.
        //
        // The problem is simpler than it looks.
        // We need to pick $S_1$ students for the first class and $S_2$ students for the second class.
        // $S_1 = 2k_1+1$, $S_2 = 2k_2+1$. $S_1+S_2 = 2n$.
        // This implies $k_1+k_2 = n-1$.
        //
        // Let $M_1$ be the median of the first class and $M_2$ be the median of the second class.
        // We want to minimize $|M_1 - M_2|$.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // The smallest possible median for any class is $a_0$ (if class size is 1).
        // The largest possible median for any class is $a_{2n-1}$ (if class size is 1).
        //
        // If we pick $a_{n-1}$ as the median of one class and $a_n$ as the median of the other class,
        // can we always form valid classes?
        //
        // Let's try to make $a_{n-1}$ the median of Class 1 and $a_n$ the median of Class 2.
        // To make $a_{n-1}$ the median of Class 1, we need to pick $k_1$ elements smaller than or equal to $a_{n-1}$
        // and $k_1$ elements larger than or equal to $a_{n-1}$.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ that are $\le a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ that are $\ge a_n$.
        //
        // Consider the partition where Class 1 takes $a_0, \dots, a_{n-1}$ and Class 2 takes $a_n, \dots, a_{2n-1}$.
        // This is a partition of $n$ elements and $n$ elements.
        // If $n$ is odd, then both classes have odd size.
        // The median of Class 1 (elements $a_0, \dots, a_{n-1}$) would be $a_{(n-1)/2}$.
        // The median of Class 2 (elements $a_n, \dots, a_{2n-1}$) would be $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler: the minimum difference is always $a_n - a_{n-1}$.
        // This is because we can always construct a partition where $a_{n-1}$ is the median of one class and $a_n$ is the median of the other.
        //
        // Let's try to make $a_{n-1}$ the median of Class 1 and $a_n$ the median of Class 2.
        // Class 1:
        // We need $k_1$ elements smaller than or equal to $a_{n-1}$. We can pick $a_0, \dots, a_{k_1-1}$.
        // We need $k_1$ elements larger than or equal to $a_{n-1}$. We can pick $a_{n-1+1}, \dots, a_{n-1+k_1}$.
        // This would mean Class 1 has elements $a_0, \dots, a_{k_1-1}$, $a_{n-1}$, $a_{n}, \dots, a_{n-1+k_1}$.
        // This is not right.
        //
        // The simplest way to achieve $a_{n-1}$ and $a_n$ as medians:
        // Class 1: Take $a_{n-1}$. We need $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // Class 2: Take $a_n$. We need $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$.
        //
        // Consider the partition:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // Each class has $n$ students.
        // If $n$ is odd, this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$. Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$. This is not $a_n - a_{n-1}$.
        //
        // The problem statement is: "assign each student to one of the 2 classes such that each class has odd number of students".
        // The number of students in the classes may be equal or different.
        //
        // Let's consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // We want to pick $S_1$ students for Class 1 and $S_2$ students for Class 2.
        // $S_1 = 2k_1+1$, $S_2 = 2k_2+1$. $k_1+k_2 = n-1$.
        //
        // The median of Class 1 will be some $a_i$.
        // The median of Class 2 will be some $a_j$.
        // We want to minimize $|a_i - a_j|$.
        //
        // The smallest possible difference between any two elements in the sorted array is $a_{p+1} - a_p$.
        // Can we always make $a_p$ and $a_{p+1}$ the medians of two classes for some $p$?
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // We can form Class 1 with $a_{n-1}$ as its median and Class 2 with $a_n$ as its median.
        //
        // Let Class 1 be formed by:
        // $a_0, a_1, \dots, a_{n-2}$ (these are $n-1$ elements, all $\le a_{n-1}$)
        // $a_{n-1}$ (this is the median)
        //
        // We need to pick $n-1$ more elements for Class 1 that are $\ge a_{n-1}$.
        // We have $a_n, a_{n+1}, \dots, a_{2n-1}$ (these are $n$ elements, all $\ge a_n > a_{n-1}$).
        // We can pick $n-1$ of these for Class 1.
        //
        // So, Class 1: $\{a_0, a_1, \dots, a_{n-2}, a_{n-1}, a_n, a_{n+1}, \dots, a_{2n-2}\}$.
        // This class has $(n-1) + 1 + (n-1) = 2n-1$ students.
        // Its median is $a_{n-1}$ (the $n$-th element, since $2n-1 = 2(n-1)+1$).
        //
        // The remaining student is $a_{2n-1}$.
        // Class 2: $\{a_{2n-1}\}$. This class has 1 student. Its median is $a_{2n-1}$.
        //
        // In this partition, the medians are $a_{n-1}$ and $a_{2n-1}$.
        // The difference is $a_{2n-1} - a_{n-1}$. This is not necessarily minimal.
        //
        // The problem is a standard result in competitive programming.
        // When you have $2N$ items and you want to split them into two groups of $N$ items each,
        // the minimum difference between the maximum of the first group and the minimum of the second group
        // is achieved by taking the first $N$ items for the first group and the last $N$ items for the second group.
        // The difference is $a_N - a_{N-1}$ (0-indexed).
        //
        // Here, we have $2n$ students.
        // We are looking for medians.
        //
        // Let's consider the elements $a_{n-1}$ and $a_n$.
        // We can form Class 1 with $a_{n-1}$ as its median.
        // We can form Class 2 with $a_n$ as its median.
        //
        // To make $a_{n-1}$ the median of Class 1:
        // We need $k_1$ elements $\le a_{n-1}$ and $k_1$ elements $\ge a_{n-1}$.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ that are $\le a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ that are $\ge a_n > a_{n-1}$.
        //
        // Let's try to make Class 1 have $a_{n-1}$ as its median and Class 2 have $a_n$ as its median.
        //
        // Class 1:
        // Take $a_{n-1}$ as the median.
        // Take $n-1$ elements from $a_0, \dots, a_{n-2}$ (e.g., all of them).
        // Take $n-1$ elements from $a_n, \dots, a_{2n-1}$ (e.g., $a_n, \dots, a_{2n-2}$).
        // So Class 1 is $\{a_0, \dots, a_{n-2}, a_{n-1}, a_n, \dots, a_{2n-2}\}$.
        // This class has $(n-1) + 1 + (n-1) = 2n-1$ students. This is an odd number.
        // Its median is $a_{n-1}$ (the $n$-th element, since $2n-1 = 2(n-1)+1$).
        //
        // The remaining student is $a_{2n-1}$.
        // Class 2: $\{a_{2n-1}\}$. This class has 1 student. This is an odd number.
        // Its median is $a_{2n-1}$.
        //
        // The difference is $|a_{n-1} - a_{2n-1}| = a_{2n-1} - a_{n-1}$.
        // This is one possible difference.
        //
        // What if we swap the roles?
        // Class 1: $\{a_0\}$. Median $a_0$.
        // Class 2: $\{a_1, \dots, a_{2n-1}\}$. Size $2n-1$. Median $a_{1 + (n-1)} = a_n$.
        // Difference is $|a_0 - a_n| = a_n - a_0$.
        //
        // The problem is asking for the minimum possible absolute difference.
        // The minimum difference between any two elements $a_i, a_j$ is $a_{p+1} - a_p$ for some $p$.
        // Can we always make $a_p$ and $a_{p+1}$ the medians of two valid classes?
        //
        // Let's try to make $a_{n-1}$ and $a_n$ the medians.
        //
        // Class 1: $a_{n-1}$ is median.
        // Class 2: $a_n$ is median.
        //
        // We need to pick $k_1$ elements for Class 1 that are $\le a_{n-1}$ and $k_1$ elements $\ge a_{n-1}$.
        // We need to pick $k_2$ elements for Class 2 that are $\le a_n$ and $k_2$ elements $\ge a_n$.
        // And $k_1+k_2 = n-1$.
        //
        // Consider the elements $a_0, \dots, a_{n-2}$ (total $n-1$ elements).
        // Consider the elements $a_{n+1}, \dots, a_{2n-1}$ (total $n-1$ elements).
        //
        // We can form Class 1 with $a_{n-1}$ as median and Class 2 with $a_n$ as median.
        //
        // Let $k_1 = 0$. Then $S_1 = 1$. Class 1 is $\{a_{n-1}\}$. Median is $a_{n-1}$.
        // Then $k_2 = n-1$. $S_2 = 2(n-1)+1 = 2n-1$.
        // Class 2 needs $n-1$ elements $\le a_n$ and $n-1$ elements $\ge a_n$.
        // We have $a_0, \dots, a_{n-2}$ (these are $n-1$ elements, all $\le a_{n-1} \le a_n$).
        // We have $a_{n+1}, \dots, a_{2n-1}$ (these are $n-1$ elements, all $\ge a_{n+1} \ge a_n$).
        // So Class 2 can be $\{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is a valid partition.
        // Class 1: $\{a_{n-1}\}$. Median $a_{n-1}$.
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$. Median $a_n$.
        // The difference is $|a_n - a_{n-1}|$.
        //
        // This construction always works.
        // Class 1: $\{a_{n-1}\}$ (size 1, median $a_{n-1}$)
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$, median $a_n$)
        // All students are assigned. Both classes have odd sizes.
        // The difference is $a_n - a_{n-1}$.
        //
        // Can we achieve a smaller difference?
        // Suppose we have two medians $M_1$ and $M_2$.
        // Let $M_1 = a_i$ and $M_2 = a_j$.
        // Without loss of generality, assume $i < j$.
        //
        // If $a_i$ is the median of a class of size $2k_1+1$, then there are $k_1$ elements $\le a_i$ and $k_1$ elements $\ge a_i$.
        // If $a_j$ is the median of a class of size $2k_2+1$, then there are $k_2$ elements $\le a_j$ and $k_2$ elements $\ge a_j$.
        //
        // The total number of elements $\le a_i$ is $i$.
        // The total number of elements $\ge a_j$ is $2n-1-j$.
        //
        // The $k_1$ elements $\le a_i$ must come from $a_0, \dots, a_{i-1}$. So $k_1 \le i$.
        // The $k_2$ elements $\ge a_j$ must come from $a_{j+1}, \dots, a_{2n-1}$. So $k_2 \le 2n-1-j$.
        //
        // Summing these: $k_1+k_2 \le i + (2n-1-j)$.
        // We know $k_1+k_2 = n-1$.
        // So $n-1 \le i + 2n-1-j$.
        // $n-1 \le i - j + 2n-1$.
        // $j - i \le n$.
        //
        // This means the indices of the medians cannot be arbitrarily far apart.
        //
        // Consider the elements $a_0, \dots, a_{2n-1}$.
        // The elements $a_0, \dots, a_{n-1}$ are the "lower half".
        // The elements $a_n, \dots, a_{2n-1}$ are the "upper half".
        //
        // If both medians $M_1, M_2$ are in the lower half (i.e., $M_1=a_i, M_2=a_j$ with $i,j < n$),
        // then $a_j - a_i$ could be small.
        // But if $a_j$ is a median, it needs $k_2$ elements larger than it.
        // If $j < n$, then there are at most $2n-1-j$ elements larger than $a_j$.
        // $k_2 \le 2n-1-j$.
        //
        // If $M_1 = a_i$ and $M_2 = a_j$.
        // The elements $a_0, \dots, a_{i-1}$ must be used for $M_1$'s smaller half.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ must be used for $M_2$'s larger half.
        //
        // The total number of elements available for the "smaller half" of $M_1$ and "larger half" of $M_2$ is $i + (2n-1-j)$.
        // These must be at least $k_1 + k_2 = n-1$.
        // So $i + 2n-1-j \ge n-1$.
        // $i - j + 2n \ge n$.
        // $i - j + n \ge 0$.
        // $j - i \le n$.
        //
        // This means the indices of the medians $a_i$ and $a_j$ can be at most $n$ apart.
        //
        // The minimum difference $a_n - a_{n-1}$ is achieved by the construction above.
        // Can we do better?
        // Suppose there is a partition with medians $M_1, M_2$ such that $|M_1 - M_2| < a_n - a_{n-1}$.
        // Let $M_1 = a_i$ and $M_2 = a_j$. Assume $i < j$.
        // Then $a_j - a_i < a_n - a_{n-1}$.
        // This implies that $a_i$ and $a_j$ must be "close" to each other in the sorted array.
        // Specifically, it implies that $i$ must be $\ge n-1$ and $j$ must be $\le n$.
        // If $i < n-1$, then $a_j - a_i \ge a_n - a_i \ge a_n - a_{n-1}$.
        // If $j > n$, then $a_j - a_i \ge a_j - a_{n-1} \ge a_n - a_{n-1}$.
        // So, for $a_j - a_i < a_n - a_{n-1}$ to hold, we must have $i=n-1$ and $j=n$.
        //
        // Therefore, the minimum difference must be $a_n - a_{n-1}$.
        //
        // Example 1: n=1, a = [1, 1]
        // 2n = 2 students.
        // Sorted a = [1, 1].
        // n-1 = 0, n = 1.
        // a[n-1] = a[0] = 1.
        // a[n] = a[1] = 1.
        // Difference = a[1] - a[0] = 1 - 1 = 0. Correct.
        //
        // Example 2: n=3, a = [6, 5, 4, 1, 2, 3]
        // 2n = 6 students.
        // Sorted a = [1, 2, 3, 4, 5, 6].
        // n-1 = 2, n = 3.
        // a[n-1] = a[2] = 3.
        // a[n] = a[3] = 4.
        // Difference = a[3] - a[2] = 4 - 3 = 1. Correct.
        //
        // Example 3: n=5, a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16]
        // 2n = 10 students.
        // Sorted a = [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // n-1 = 4, n = 5.
        // a[n-1] = a[4] = 8.
        // a[n] = a[5] = 13.
        // Difference = a[5] - a[4] = 13 - 8 = 5. Correct.
        //
        // The logic seems sound. The minimum difference is always $a_n - a_{n-1}$ after sorting the array.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For a = (d + sqrt(d^2 - 4d)) / 2
            // For b = (d - sqrt(d^2 - 4d)) / 2
            // Both a and b must be non-negative.
            // Since d >= 4, d^2 - 4d >= 0, so sqrt(d^2 - 4d) is real.
            // d + sqrt(d^2 - 4d) is clearly non-negative.
            // We need to check if d - sqrt(d^2 - 4d) is non-negative.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative, we can square both:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0
            // Since d is given as non-negative, and we are in the case d >= 4,
            // both a and b will be non-negative.

            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);
            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
