    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for elements to be placed (the 'b' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for original elements (the 'a' array elements)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, we can advance j.
        // If a[j] is not greater than a[i], we need a larger element, so we increment j.
        // If a[j] is greater than a[i], we found a match. We increment both i and j, and increment count.
        // The outer loop implicitly handles incrementing i.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // If we found an element a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'b' array for the next match
        } else {
            // If j reaches n, it means all remaining elements in 'a' (from a[i] onwards)
            // cannot be beaten by any available element.
            // We can break because further increments of i won't find a match either.
            break;
        }
    }

    std::cout << count << std::endl;

