// Function to check if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        return A == 1;
    }

    // Case 2: More than one toy
    // The final product must be negative and <= -1.
    // This requires an odd number of negative factors.
    // The magnitude must be >= 1.

    // Number of negative toys: A + B
    long long neg_count = A + B;

    // If neg_count is even, the final product will be positive.
    // So, Box 1 is impossible.
    if (neg_count % 2 == 0) {
        return false;
    }

    // If neg_count is odd, the final product will be negative.
    // Now we need to ensure the magnitude can be >= 1.

    // If there are any toys in Box 1 or Box 4, we can potentially make the magnitude large.
    // If A > 0 or D > 0, we can always make the magnitude >= 1.
    // We just need to ensure we can combine them in a way that results in an odd number of negatives.
    if (A > 0 || D > 0) {
        return true;
    }

    // If A == 0 and D == 0, all initial toys are in Box 2 or Box 3.
    // All initial toys have magnitude < 1.
    // The product of any number of such toys will always have magnitude < 1.
    // So, it's impossible to get a value <= -1.
    return false;
}

// Function to check if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        return B == 1;
    }

    // Case 2: More than one toy
    // The final product must be negative and between -1 and 0.
    // This requires an odd number of negative factors.
    // The magnitude must be < 1.

    // Number of negative toys: A + B
    long long neg_count = A + B;

    // If neg_count is even, the final product will be positive.
    // So, Box 2 is impossible.
    if (neg_count % 2 == 0) {
        return false;
    }

    // If neg_count is odd, the final product will be negative.
    // Now we need to ensure the magnitude can be < 1.

    // If there are any toys in Box 2 or Box 3, we can potentially make the magnitude small.
    // If B > 0 or C > 0, we can always make the magnitude < 1.
    // We just need to ensure we can combine them in a way that results in an odd number of negatives.
    if (B > 0 || C > 0) {
        return true;
    }

    // If B == 0 and C == 0, all initial toys are in Box 1 or Box 4.
    // All initial toys have magnitude >= 1.
    // The product of any number of such toys (if total_toys > 1) will always have magnitude >= 1.
    // So, it's impossible to get a value between -1 and 0.
    return false;
}

// Function to check if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        return C == 1;
    }

    // Case 2: More than one toy
    // The final product must be positive and between 0 and 1.
    // This requires an even number of negative factors.
    // The magnitude must be < 1.

    // Number of negative toys: A + B
    long long neg_count = A + B;

    // If neg_count is odd, the final product will be negative.
    // So, Box 3 is impossible.
    if (neg_count % 2 != 0) {
        return false;
    }

    // If neg_count is even, the final product will be positive.
    // Now we need to ensure the magnitude can be < 1.

    // If there are any toys in Box 2 or Box 3, we can potentially make the magnitude small.
    // If B > 0 or C > 0, we can always make the magnitude < 1.
    // We just need to ensure we can combine them in a way that results in an even number of negatives.
    if (B > 0 || C > 0) {
        return true;
    }

    // If B == 0 and C == 0, all initial toys are in Box 1 or Box 4.
    // All initial toys have magnitude >= 1.
    // The product of any number of such toys (if total_toys > 1) will always have magnitude >= 1.
    // So, it's impossible to get a value between 0 and 1.
    return false;
}

// Function to check if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false;

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        return D == 1;
    }

    // Case 2: More than one toy
    // The final product must be positive and >= 1.
    // This requires an even number of negative factors.
    // The magnitude must be >= 1.

    // Number of negative toys: A + B
    long long neg_count = A + B;

    // If neg_count is odd, the final product will be negative.
    // So, Box 4 is impossible.
    if (neg_count % 2 != 0) {
        return false;
    }

    // If neg_count is even, the final product will be positive.
    // Now we need to ensure the magnitude can be >= 1.

    // If there are any toys in Box 1 or Box 4, we can potentially make the magnitude large.
    // If A > 0 or D > 0, we can always make the magnitude >= 1.
    // We just need to ensure we can combine them in a way that results in an even number of negatives.
    if (A > 0 || D > 0) {
        return true;
    }

    // If A == 0 and D == 0, all initial toys are in Box 2 or Box 3.
    // All initial toys have magnitude < 1.
    // The product of any number of such toys will always have magnitude < 1.
    // So, it's impossible to get a value >= 1.
    return false;
}

