#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_max_height: max height achievable for a peak at index i
    // if the left part is strictly increasing.
    // a_0' >= 0, a_1' >= 1, ..., a_i' >= i
    // So, a_j' >= j for j <= i.
    // We can achieve a_j' = j if a_j >= j.
    // The actual value a_j' can be anything from j to a_j.
    // The maximum value a_i' can take is a_i.
    // The minimum value a_i' must take is i.
    // So, a_i' must be at least i.
    // Also, a_i' must be at least a_{i-1}' + 1.
    // Let L[i] be the maximum possible value for a_i' such that a_0' < ... < a_i'.
    // L[0] = a[0]
    // L[i] = min(a[i], L[i-1] + 1)
    // This is not quite right. We need to ensure a_j' >= j.
    // Let's define L[i] as the maximum value we can assign to a_i
    // such that a_0' < a_1' < ... < a_i' and a_j' >= j for all j <= i.
    // L[0] = a[0] (must be >= 0)
    // L[i] = min(a[i], L[i-1] + 1)
    // This ensures a_j' >= a_{j-1}' + 1.
    // We also need a_j' >= j.
    // So, L[i] = min(a[i], L[i-1] + 1) if L[i-1] + 1 >= i.
    // If L[i-1] + 1 < i, then it's impossible to make a_i' >= i while maintaining a_i' >= a_{i-1}' + 1.
    // This is equivalent to saying that if a_j < j for any j, then it's impossible to make a_j' >= j.
    // So, we need a_j >= j for all j <= i.
    // If a_j < j for any j, then L[j] should be -1 (impossible).
    // Let's define L[i] as the maximum value a_i can take while satisfying a_0' < ... < a_i' and a_j' >= j.
    // L[0] = a[0] >= 0. If a[0] < 0, impossible.
    // L[i] = min(a[i], L[i-1] + 1) if L[i-1] is not -1 and a[i] >= i.
    // If a[i] < i, then L[i] = -1.
    // If L[i-1] is -1, then L[i] = -1.
    // This is equivalent to:
    // L[i] = min(a[i], L[i-1] + 1) if a[i] >= i and L[i-1] != -1.
    // Otherwise L[i] = -1.
    // A simpler way:
    // Let L[i] be the maximum value a_i can take such that a_0' < ... < a_i'.
    // L[0] = a[0].
    // L[i] = min(a[i], L[i-1] + 1).
    // Then, for a peak at k, we need L[k] >= k.
    // This is because a_0' must be at least 0, a_1' at least 1, ..., a_k' at least k.
    // If L[k] < k, then it's impossible to satisfy a_k' >= k.

    std::vector<long long> L(n);
    L[0] = a[0];
    for (int i = 1; i < n; ++i) {
        if (L[i-1] == -1) { // If previous element couldn't satisfy conditions
            L[i] = -1;
        } else {
            L[i] = std::min(a[i], L[i-1] + 1);
        }
    }

    // Calculate suffix_max_height: max height achievable for a peak at index i
    // if the right part is strictly decreasing.
    // a_n-1' >= 0, a_n-2' >= 1, ..., a_i' >= n-1-i
    // So, a_j' >= n-1-j for j >= i.
    // Let R[i] be the maximum possible value for a_i' such that a_i' > a_{i+1}' > ... > a_{n-1}'.
    // R[n-1] = a[n-1].
    // R[i] = min(a[i], R[i+1] + 1).
    // Similar to L, we need R[i] >= n-1-i.
    // R[i] = min(a[i], R[i+1] + 1) if R[i+1] is not -1 and a[i] >= n-1-i.
    // Otherwise R[i] = -1.

    std::vector<long long> R(n);
    R[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        if (R[i+1] == -1) { // If next element couldn't satisfy conditions
            R[i] = -1;
        } else {
            R[i] = std::min(a[i], R[i+1] + 1);
        }
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        // For a peak at index k, we need:
        // 1. The left part a_0' < ... < a_k' is strictly increasing.
        //    This means L[k] must be valid (not -1).
        // 2. The right part a_k' > ... > a_{n-1}' is strictly decreasing.
        //    This means R[k] must be valid (not -1).
        // 3. The peak value a_k' must be at least k (from left part requirement).
        // 4. The peak value a_k' must be at least n-1-k (from right part requirement).
        //    So, a_k' >= max(k, n-1-k).
        // 5. The value a_k' must be achievable from a[k], i.e., a_k' <= a[k].
        //
        // Combining L and R:
        // L[k] represents the maximum value a_k can take while satisfying the left part.
        // R[k] represents the maximum value a_k can take while satisfying the right part.
        // For a peak at k, we need to find a value a_k' such that:
        // a_k' <= L[k] (if L[k] != -1)
        // a_k' <= R[k] (if R[k] != -1)
        // a_k' >= k
        // a_k' >= n-1-k
        //
        // So, we need to check if min(L[k], R[k]) >= max(k, n-1-k).
        // If L[k] or R[k] is -1, then min(L[k], R[k]) will effectively be -1,
        // making the condition false, which is correct.

        if (L[k] != -1 && R[k] != -1) {
            long long max_achievable_at_k = std::min(L[k], R[k]);
            long long min_required_at_k = std::max((long long)k, (long long)(n - 1 - k));
            if (max_achievable_at_k >= min_required_at_k) {
                possible = true;
                break;
            }
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // The optimal strategy is to pair the largest A_i with the largest B_i,
    // the second largest A_i with the second largest B_i, and so on.
    // This means if A is sorted ascending, and B is sorted ascending,
    // we should pair A[i] with B[i].
    // However, the problem asks for A_i' >= B_j for all i, j.
    // The function F(n, k) = (n+1) / (k+1).
    // We want to maximize sum F(A'_i, B_i) = sum (A'_i + 1) / (B_i + 1).
    // This is a rearrangement inequality problem.
    // To maximize sum (X_i / Y_i), if X_i are sorted ascending, Y_i should be sorted ascending.
    // If X_i are sorted ascending, Y_i should be sorted descending to maximize sum (X_i * Y_i).
    // Here we have (A'_i + 1) and (B_i + 1).
    // Let X_i = A'_i + 1 and Y_i = B_i + 1. We want to maximize sum X_i / Y_i.
    // This is maximized when X_i and Y_i are sorted in the same order.
    // So, if we sort A' + 1 in ascending order, we should sort B + 1 in ascending order.
    // This means A' should be sorted ascending, and B should be sorted ascending.
    // So, the i-th smallest A value should be paired with the i-th smallest B value.

    // Create the result array A'
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest A value (a_elements[i].value) should be paired
        // with the i-th smallest B value (b_elements[i].value).
        // The original index of this B value is b_elements[i].original_index.
        // So, result_a_prime[b_elements[i].original_index] should be a_elements[i].value.
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
