#include <iostream>
#include <algorithm>
#include <map>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            // Chanek's turn
            if (n == 1) {
                chanek_coins += 1;
                n -= 1;
            } else if (n == 2) {
                chanek_coins += 2; // Take N/2 = 1, then N=1, opponent takes 1. Chanek gets 1. Total 1+1=2.
                                   // Take 1, N=1. Opponent takes 1. Chanek gets 1.
                                   // Taking N/2 is better.
                n -= 2;
            } else if (n == 3) {
                chanek_coins += 1; // Take 1. N=2. Opponent takes 2. Chanek gets 1.
                                   // No N/2 option.
                n -= 1;
            } else if (n % 2 == 1) {
                // N is odd. Must take 1.
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1. Opponent plays optimally.
                // If opponent takes N-1/2, then N-1 is odd.
                // If N-1 is odd, opponent takes 1.
                // This path is complex. Let's analyze the optimal strategy.

                // If N is even, we have two choices: take 1 or take N/2.
                // Consider taking N/2:
                // Chanek gets N/2. Remaining coins: N/2.
                // Now it's opponent's turn with N/2 coins.
                // If N/2 is odd, opponent must take 1. Then N/2-1 coins left.
                // If N/2 is even, opponent can take 1 or N/4.

                // The key insight for even N:
                // If N is even, and N is not a power of 2:
                // N = 2^k * M, where M is odd and M > 1.
                // If we take N/2, we get 2^(k-1) * M.
                // The opponent faces 2^(k-1) * M.
                // If we take 1, we get 1. The opponent faces N-1 (odd).

                // Let's consider the case where N is even.
                // If N is a power of 2 (N = 2^k):
                // Chanek takes N/2. N becomes N/2.
                // Opponent takes (N/2)/2. N becomes N/4.
                // This continues until N=1.
                // Chanek gets N/2 + N/8 + N/32 + ...
                // Opponent gets N/4 + N/16 + N/64 + ...
                // Total for Chanek: N * (1/2 + 1/8 + 1/32 + ...) = N * ( (1/2) / (1 - 1/4) ) = N * (1/2) / (3/4) = N * (2/3)
                // Total for Opponent: N * (1/4 + 1/16 + 1/64 + ...) = N * ( (1/4) / (1 - 1/4) ) = N * (1/4) / (3/4) = N * (1/3)
                // So if N is a power of 2, Chanek takes N/2.

                // If N is even but not a power of 2:
                // N = 2^k * M, where M is odd and M > 1.
                // Option 1: Take N/2.
                // Chanek gets N/2. Remaining N/2 = 2^(k-1) * M.
                // Opponent faces N/2.
                // Option 2: Take 1.
                // Chanek gets 1. Remaining N-1 (odd).
                // Opponent faces N-1. Opponent must take 1.
                // Then Chanek faces N-2 (even).

                // The optimal strategy for an even N that is not a power of 2:
                // Chanek should take 1.
                // Why? If Chanek takes N/2, the opponent faces N/2 = 2^(k-1) * M.
                // If k=1, N = 2 * M. Chanek takes M. Opponent faces M (odd). Opponent takes 1.
                // If Chanek takes 1, opponent faces 2M-1 (odd). Opponent takes 1. Chanek faces 2M-2.
                // This seems to be the core of the problem.

                // Let's test the hypothesis:
                // If N is even and N is a power of 2 (N=2^k), take N/2.
                // If N is even and N is NOT a power of 2, take 1.
                // If N is odd, take 1.

                // Check if N is a power of 2
                bool is_power_of_2 = (n > 0) && ((n & (n - 1)) == 0);

                if (is_power_of_2) {
                    chanek_coins += n / 2;
                    n /= 2;
                } else {
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else {
            // Opponent's turn
            if (n == 1) {
                opponent_coins += 1;
                n -= 1;
            } else if (n == 2) {
                opponent_coins += 2;
                n -= 2;
            } else if (n == 3) {
                opponent_coins += 1;
                n -= 1;
            } else if (n % 2 == 1) {
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                bool is_power_of_2 = (n > 0) && ((n & (n - 1)) == 0);
                if (is_power_of_2) {
                    opponent_coins += n / 2;
                    n /= 2;
                } else {
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

