#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // Case 1: Array is already good.
    // current_sum = 2 * current_xor
    // current_sum - 2 * current_xor = 0
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << "\n\n";
        return;
    }

    // Case 2: Append one element.
    // Let the appended element be x.
    // New sum: current_sum + x
    // New XOR: current_xor ^ x
    // We need: current_sum + x = 2 * (current_xor ^ x)
    // This equation is generally hard to solve for x directly with bitwise operations.
    // However, the problem guarantees a solution with at most 3 elements.
    // The strategy below uses 2 or 3 elements.

    // Case 3: Append two elements.
    // Let the appended elements be x and y.
    // New sum: current_sum + x + y
    // New XOR: current_xor ^ x ^ y
    // We need: current_sum + x + y = 2 * (current_xor ^ x ^ y)
    // A common strategy for competitive programming problems involving XOR and sum
    // is to try to make the XOR sum a specific value, often by adding 0 or a value
    // that cancels out the current XOR.
    //
    // Let's try to make the final XOR sum equal to current_xor.
    // This means we need to append elements x, y such that x ^ y = 0.
    // The simplest way to achieve this is x = y.
    // If we append x and x, then the new XOR sum is current_xor ^ x ^ x = current_xor.
    // The new sum is current_sum + x + x = current_sum + 2x.
    // The condition becomes: current_sum + 2x = 2 * current_xor.
    // 2x = 2 * current_xor - current_sum
    // x = current_xor - current_sum / 2
    //
    // This requires (2 * current_xor - current_sum) to be non-negative and even.
    // If current_sum is odd, then 2 * current_xor - current_sum is odd, so x cannot be an integer.
    // If current_sum is even, then 2 * current_xor - current_sum is even.
    // Let's check the parity of current_sum and current_xor.
    // We know that S - X is even.
    // current_sum - current_xor is even.
    // This means current_sum and current_xor have the same parity.
    //
    // We need current_sum + 2x = 2 * current_xor.
    // This means current_sum must be even.
    // If current_sum is odd, this strategy won't work with two identical elements.
    //
    // Let's try a different strategy that always works with at most 3 elements.
    //
    // We want to find $b_1, \dots, b_s$ such that $S_0 + \sum b_i = 2 \cdot (X_0 \oplus \bigoplus b_i)$.
    //
    // Consider appending two elements: $X_0$ and $S_0 + X_0$.
    // Let $b_1 = X_0$.
    // Let $b_2 = S_0 + X_0$.
    //
    // New sum: $S' = S_0 + b_1 + b_2 = S_0 + X_0 + (S_0 + X_0) = 2S_0 + 2X_0$.
    // New XOR: $X' = X_0 \oplus b_1 \oplus b_2 = X_0 \oplus X_0 \oplus (S_0 + X_0) = 0 \oplus (S_0 + X_0) = S_0 + X_0$.
    //
    // We need $S' = 2X'$.
    // Is $2S_0 + 2X_0 = 2 \cdot (S_0 + X_0)$?
    // Yes, this is always true!
    //
    // So, we can always append two elements: $X_0$ and $S_0 + X_0$.
    // These elements are non-negative since $a_i \ge 0$, so $S_0 \ge 0$ and $X_0 \ge 0$.
    // The maximum value for $a_i$ is $10^9$.
    // $N$ up to $10^5$.
    // $S_0$ can be up to $10^5 \cdot 10^9 = 10^{14}$.
    // $X_0$ can be up to $2^{30}-1$ (approx $10^9$).
    // $S_0 + X_0$ can be up to $10^{14} + 10^9$, which fits in a long long.
    // The problem states $b_i \le 10^{18}$, so $S_0 + X_0$ is well within limits.

    // This strategy always works and uses 2 elements.
    // Since the problem allows up to 3 elements and doesn't require minimizing,
    // this is a valid solution.

    std::cout << 2 << "\n";
    std::cout << current_xor << " " << current_sum + current_xor << "\n";
}

