    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its pattern string
// e.g., 241 -> "011" (2 is even, 4 is even, 1 is odd, but problem says 0 for even, 1 for odd)
// So 241 -> "001" (2%2=0, 4%2=0, 1%2=1)
// The problem statement says "0 stands for the even digits, while 1 stands for the odd."
// So 241: 1 (odd) -> 1, 4 (even) -> 0, 2 (even) -> 0. Result "001".
// The pattern is always 18 characters long, padded with '0's from the left.
std::string get_pattern_from_num(long long n) {
    std::string s = "";
    if (n == 0) {
        s = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                s += '0';
            } else { // Odd digit
                s += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 characters long
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we should normalize both to a fixed length, say 18, by padding with '0's.
    // Since we build the string from right to left, we need to reverse it and then pad.
    std::reverse(s.begin(), s.end());
    while (s.length() < 18) {
        s = '0' + s;
    }
    return s;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each pattern string
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string p = get_pattern_from_num(a);
            pattern_counts[p]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string p = get_pattern_from_num(a);
            pattern_counts[p]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 characters long
            while (s.length() < 18) {
                s = '0' + s;
            }
            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

