#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items are taken from the right side
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;
        long long left_items_weight = prefix_sum[i];
        long long right_items_weight = prefix_sum[n] - prefix_sum[i];

        current_energy += left_items_weight * l;
        current_energy += right_items_weight * r;

        int num_left = i;
        int num_right = n - i;

        if (num_left > num_right) {
            // More items taken from left.
            // The last item taken must have been from the left.
            // The difference is num_left - num_right.
            // If num_left - num_right = 1, no extra penalty.
            // If num_left - num_right > 1, then (num_left - num_right - 1) times
            // we took an item from the left when the previous one was also from the left.
            current_energy += (num_left - num_right - 1) * Ql;
        } else if (num_right > num_left) {
            // More items taken from right.
            // The last item taken must have been from the right.
            // The difference is num_right - num_left.
            // If num_right - num_left = 1, no extra penalty.
            // If num_right - num_left > 1, then (num_right - num_left - 1) times
            // we took an item from the right when the previous one was also from the right.
            current_energy += (num_right - num_left - 1) * Qr;
        }
        // If num_left == num_right, no extra penalty from this rule.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

