int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 0 means cannot move left (x-1).
            // If robot is at (x,y) and cannot move left, it cannot reach any point (X,Y) where X < x.
            // So, X must be >= x. This means min_x = max(min_x, x).
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f2 = 0 means cannot move up (y+1).
            // If robot is at (x,y) and cannot move up, it cannot reach any point (X,Y) where Y > y.
            // So, Y must be <= y. This means max_y = min(max_y, y).
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }

            // f3 = 0 means cannot move right (x+1).
            // If robot is at (x,y) and cannot move right, it cannot reach any point (X,Y) where X > x.
            // So, X must be <= x. This means max_x = min(max_x, x).
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4 = 0 means cannot move down (y-1).
            // If robot is at (x,y) and cannot move down, it cannot reach any point (X,Y) where Y < y.
            // So, Y must be >= y. This means min_y = max(min_y, y).
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

