void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;
    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int k = 0; k <= 9; ++k) {
        std::string t(n, ' ');
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_k = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < k) {
                t[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > k) {
                t[i] = '2';
                s2_digits.push_back(d[i]);
            }
        }

        // Check if s1_digits is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if s2_digits is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Now assign digits equal to k
        // First, assign all d[i] == k to color 2, then to color 1
        // This ensures that all d[i] == k assigned to color 1 appear before those assigned to color 2
        // in the final sequence.
        // The split point for digits equal to k is determined by the last digit of s1_digits.
        // All d[i] == k that are colored 1 must be >= last_s1_digit (if s1_digits is not empty).
        // All d[i] == k that are colored 2 must be <= first_s2_digit (if s2_digits is not empty).

        // Find the first occurrence of k that we want to color 2
        // All k's before this index will be colored 1, all k's from this index onwards will be colored 2.
        int split_idx_for_k = -1; // Index in original string d_str
        for (int i = 0; i < n; ++i) {
            if (d[i] == k) {
                // If s1_digits is empty, we can color this k as 1.
                // If s1_digits is not empty, this k must be >= s1_digits.back() to be colored 1.
                // Since d[i] == k, this condition is k >= s1_digits.back().
                // If this condition is violated, we must color this k as 2.
                if (!s1_digits.empty() && k < s1_digits.back()) {
                    split_idx_for_k = i;
                    break;
                }
                // Otherwise, we can color it 1.
                // We continue searching for a k that must be colored 2.
            }
        }

        // If no such k was found, all k's can be colored 1.
        // But we need to ensure that if we color a k as 1, it doesn't violate s1_digits order.
        // And if we color a k as 2, it doesn't violate s2_digits order.
        // The strategy is: color all k's that appear before the first k that MUST be colored 2 as 1.
        // Color all k's that appear from the first k that MUST be colored 2 as 2.
        // This is equivalent to finding the "pivot" k.
        // All k's before pivot are 1, all k's at/after pivot are 2.
        // The pivot is the first k such that if it were colored 1, it would violate s1_digits.
        // Or, if no such k exists, then all k's can be colored 1.
        // Or, if all k's must be colored 2, then the pivot is the first k.

        // Let's try a simpler approach for digits equal to k:
        // Iterate through d[i] == k.
        // If d[i] == k, try to assign it to color 1.
        // If it violates s1_digits non-decreasing property, then it must be color 2.
        // Once we assign a k to color 2, all subsequent k's must also be color 2.
        // This is because if a later k was color 1, it would appear before the current k (which is color 2)
        // in the final sequence, but both are equal to k, so it would be fine.
        // However, the problem states "if you write in a row from left to right all the digits painted in the color 1,
        // and then after them all the digits painted in the color 2".
        // This means relative order within color 1 is preserved, and relative order within color 2 is preserved.
        // So, if we have d_i = k and d_j = k with i < j.
        // If d_i is color 1, d_j can be color 1 or 2.
        // If d_i is color 2, d_j must be color 2. (Because if d_j is color 1, it would appear before d_i in the final sequence, but d_i appeared before d_j in original sequence, which is a contradiction for relative order).
        // This implies that all digits equal to k that are colored 1 must appear before all digits equal to k that are colored 2 in the original sequence.
        // So there must be an index `p` such that d_i = k is colored 1 for i < p, and d_i = k is colored 2 for i >= p.

        int last_s1_val = s1_digits.empty() ? -1 : s1_digits.back();
        int first_s2_val = s2_digits.empty() ? 10 : s2_digits.front();

        std::vector<int> temp_s1_k;
        std::vector<int> temp_s2_k;

        int first_k_idx = -1; // Index of the first 'k' in the original string
        int last_k_idx = -1;  // Index of the last 'k' in the original string

        for(int i=0; i<n; ++i) {
            if (d[i] == k) {
                if (first_k_idx == -1) first_k_idx = i;
                last_k_idx = i;
            }
        }

        // Try all possible split points for digits equal to k
        // The split point `p` means d[i]=k for i < p are color 1, d[i]=k for i >= p are color 2.
        // If no k exists, first_k_idx remains -1.
        // If all k's are color 1, p = n+1.
        // If all k's are color 2, p = first_k_idx.
        // The loop for `p` should iterate through all possible positions where the split for `k` can occur.
        // This means `p` can be any index `i` where `d[i] == k`, or `n` (all `k`s are color 1).
        // Or, more simply, `p` can be any index from `0` to `n`.
        // If `p` is `i`, then `d[i]` and all subsequent `k`s are color 2.
        // All `k`s before `i` are color 1.

        // Let's try to find the optimal split point for k.
        // All d[i] < k are color 1.
        // All d[i] > k are color 2.
        // For d[i] == k:
        // We want to find an index `split_k_pos` (0 to n) such that:
        // - For all `i < split_k_pos` where `d[i] == k`, `t[i] = '1'`.
        // - For all `i >= split_k_pos` where `d[i] == k`, `t[i] = '2'`.
        // This ensures relative order for `k`s.

        // We need to find the smallest `split_k_pos` such that `k`s colored '1' maintain non-decreasing order with `s1_digits`,
        // and `k`s colored '2' maintain non-decreasing order with `s2_digits`.
        // And `last_s1_digit_final <= first_s2_digit_final`.

        // Let's try to determine the split point for k.
        // All d[i] == k before some index `idx_k_split` are colored 1.
        // All d[i] == k at or after `idx_k_split` are colored 2.
        // `idx_k_split` can range from 0 to n.
        // If `idx_k_split = 0`, all `k`s are color 2.
        // If `idx_k_split = n`, all `k`s are color 1.

        // The smallest possible value for `idx_k_split` is 0.
        // The largest possible value for `idx_k_split` is n.

        int current_s1_max = s1_digits.empty() ? -1 : s1_digits.back();
        int current_s2_min = s2_digits.empty() ? 10 : s2_digits.front();

        int best_split_k_pos = -1;

        // Iterate through all possible split points for k.
        // `i` represents the index in the original string `d`.
        // All `d[j] == k` for `j < i` are colored 1.
        // All `d[j] == k` for `j >= i` are colored 2.
        // This means `i` is the first index where a `k` digit is colored 2.
        // If `i=0`, all `k`s are color 2. If `i=n`, all `k`s are color 1.
        for (int split_k_pos = 0; split_k_pos <= n; ++split_k_pos) {
            std::vector<int> temp_s1_digits = s1_digits;
            std::vector<int> temp_s2_digits = s2_digits;
            std::string current_t = t;
            bool current_split_k_possible = true;

            for (int i = 0; i < n; ++i) {
                if (d[i] == k) {
                    if (i < split_k_pos) { // Color 1
                        current_t[i] = '1';
                        temp_s1_digits.push_back(d[i]);
                    } else { // Color 2
                        current_t[i] = '2';
                        temp_s2_digits.push_back(d[i]);
                    }
                }
            }

            // Check s1_digits non-decreasing
            for (size_t i = 0; i + 1 < temp_s1_digits.size(); ++i) {
                if (temp_s1_digits[i] > temp_s1_digits[i+1]) {
                    current_split_k_possible = false;
                    break;
                }
            }
            if (!current_split_k_possible) continue;

            // Check s2_digits non-decreasing
            for (size_t i = 0; i + 1 < temp_s2_digits.size(); ++i) {
                if (temp_s2_digits[i] > temp_s2_digits[i+1]) {
                    current_split_k_possible = false;
                    break;
                }
            }
            if (!current_split_k_possible) continue;

            // Check last_s1 <= first_s2
            if (!temp_s1_digits.empty() && !temp_s2_digits.empty()) {
                if (temp_s1_digits.back() > temp_s2_digits.front()) {
                    current_split_k_possible = false;
                }
            }
            if (!current_split_k_possible) continue;

            // If we reach here, this coloring is valid.
            std::cout << current_t << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

