// Function to get prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // This means x must not be divisible by q.
        // Let q = q_1^a_1 * q_2^a_2 * ... * q_k^a_k be the prime factorization of q.
        // For x to not be divisible by q, there must be at least one prime factor q_j
        // such that the power of q_j in x is less than the power of q_j in q.

        // We iterate through each prime factor q_j of q.
        // For each q_j, we try to construct a candidate x by dividing p by q_j
        // until it's no longer divisible by q_j, or until it's no longer divisible by q.
        // More precisely, we want to find the smallest power of q_j, say q_j^b_j,
        // such that p / q_j^b_j is not divisible by q.
        // To maximize x, we want to divide p by the smallest possible factor that makes it not divisible by q.
        // This means we should divide p by q_j until the resulting number is no longer divisible by q.
        // The resulting number will be p / (q_j^k) where k is the smallest integer such that (p / q_j^k) % q != 0.
        // We do this for each distinct prime factor q_j of q and take the maximum among these candidates.

        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);
        long long max_x = 0;

        for (const auto& factor_pair : q_factors) {
            long long prime_factor = factor_pair.first;
            // int exponent_in_q = factor_pair.second; // Not directly needed, we just need the prime factor itself

            long long current_p = p;
            // Divide current_p by prime_factor until current_p is no longer divisible by q
            // or until current_p is no longer divisible by prime_factor.
            while (current_p % prime_factor == 0) {
                if ((current_p / prime_factor) % q != 0) {
                    // If dividing by prime_factor one more time makes it not divisible by q,
                    // then current_p / prime_factor is a candidate.
                    max_x = std::max(max_x, current_p / prime_factor);
                    break; // We found the largest candidate for this prime_factor
                }
                current_p /= prime_factor;
            }
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

