int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n <= abs_m for simpler logic
        if (abs_n > abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k < abs_m (cannot reach target)
        if (k < abs_m) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= abs_m
        // We can always reach (abs_n, abs_m) in abs_m moves using abs_m diagonal moves
        // to reach (abs_m, abs_m) and then abs_m - abs_n cardinal moves to reach (abs_n, abs_m).
        // This is not quite right.
        // The minimum number of moves to reach (abs_n, abs_m) is abs_m.
        // This can be achieved by abs_n diagonal moves and abs_m - abs_n cardinal moves.
        // So, we use abs_n diagonal moves to reach (abs_n, abs_n).
        // Then we use abs_m - abs_n cardinal moves to reach (abs_n, abs_m).
        // Total moves so far: abs_n + (abs_m - abs_n) = abs_m.
        // Number of diagonal moves so far: abs_n.
        // Remaining moves: k - abs_m.

        long long remaining_moves = k - abs_m;
        long long current_diagonal_moves = abs_n;

        if (remaining_moves % 2 == 0) {
            // If remaining_moves is even, we can use them all as pairs of (diagonal, anti-diagonal)
            // or (cardinal, anti-cardinal) moves, which don't change parity of coordinates.
            // Each pair of moves can be (1,1) then (-1,-1) or (1,0) then (-1,0) etc.
            // Each such pair can be converted to two diagonal moves (e.g., (1,1) then (-1,-1))
            // or two cardinal moves (e.g., (1,0) then (-1,0)).
            // The key is that we can always add 2 moves without changing the final position.
            // If we add 2 moves, we can make them both diagonal (e.g., (1,1) then (-1,-1)).
            // So, we can convert all remaining_moves into diagonal moves.
