            } else if (op_char == '|') {
                bit_val[j][0] |= x_j;
                bit_val[j][1] |= x_j;
            } else { // op_char == '^'
                bit_val[j][0] ^= x_j;
                bit_val[j][1] ^= x_j;
            }
        }
    }

    // Now, bit_val[j][0] is the final state of bit j if input bit x_j was 0.
    // And bit_val[j][1] is the final state of bit j if input bit x_j was 1.

    // We need to find A_AND, A_OR, A_XOR such that:
    // ( ( (x & A_AND) | A_OR) ^ A_XOR ) for all x from 0 to 1023
    // is equivalent to the original program.

    // For each bit j:
    // Let f_j(0) = bit_val[j][0]
    // Let f_j(1) = bit_val[j][1]

    // We want to find a_and_j, a_or_j, a_xor_j such that:
    // ( ( (x_j & a_and_j) | a_or_j) ^ a_xor_j ) == f_j(x_j)

    // Let's determine the values for A_AND, A_OR, A_XOR bit by bit.
    int A_AND = 1023; // Initialize to all 1s (no effect on AND initially)
    int A_OR = 0;     // Initialize to all 0s (no effect on OR initially)
    int A_XOR = 0;    // Initialize to all 0s (no effect on XOR initially)

    for (int j = 0; j < 10; ++j) {
        int f_j_0 = bit_val[j][0];
        int f_j_1 = bit_val[j][1];

        // Case 1: f_j(0) = 0, f_j(1) = 0
        // This means the j-th output bit is always 0, regardless of input x_j.
        // To achieve this:
        // ( (0 & a_and_j) | a_or_j) ^ a_xor_j = 0  => (0 | a_or_j) ^ a_xor_j = 0 => a_or_j ^ a_xor_j = 0
        // ( (1 & a_and_j) | a_or_j) ^ a_xor_j = 0  => (a_and_j | a_or_j) ^ a_xor_j = 0
        // From a_or_j ^ a_xor_j = 0, we get a_or_j = a_xor_j.
        // Substitute into second: (a_and_j | a_or_j) ^ a_or_j = 0.
        // This implies a_and_j | a_or_j = a_or_j. This is true if a_and_j is 0.
        // So, a_and_j = 0, a_or_j = 0, a_xor_j = 0.
        // This means we need to force the bit to 0.
        // We can do this by setting a_and_j = 0.
        // A_AND &= ~(1 << j); // Set j-th bit of A_AND to 0
        // A_OR |= 0;
        // A_XOR |= 0;
        // This is equivalent to: A_AND &= ~(1 << j);

        // Case 2: f_j(0) = 0, f_j(1) = 1
        // This means the j-th output bit is x_j.
        // To achieve this:
        // ( (0 & a_and_j) | a_or_j) ^ a_xor_j = 0  => a_or_j ^ a_xor_j = 0
        // ( (1 & a_and_j) | a_or_j) ^ a_xor_j = 1  => (a_and_j | a_or_j) ^ a_xor_j = 1
        // From a_or_j ^ a_xor_j = 0, we get a_or_j = a_xor_j.
        // Substitute into second: (a_and_j | a_or_j) ^ a_or_j = 1.
        // This implies a_and_j | a_or_j = 1 ^ a_or_j.
        // If a_or_j = 0, then a_and_j | 0 = 1, so a_and_j = 1.
        //   Then a_or_j = 0, a_xor_j = 0, a_and_j = 1.
        //   This means: x_j & 1 | 0 ^ 0 = x_j. This works.
        // If a_or_j = 1, then a_and_j | 1 = 0. This is impossible.
        // So, a_and_j = 1, a_or_j = 0, a_xor_j = 0.
        // This means: A_AND |= (1 << j); A_OR |= 0; A_XOR |= 0;
        // This is equivalent to: A_AND |= (1 << j);

        // Case 3: f_j(0) = 1, f_j(1) = 0
        // This means the j-th output bit is 1 - x_j (NOT x_j).
        // To achieve this:
        // ( (0 & a_and_j) | a_or_j) ^ a_xor_j = 1  => a_or_j ^ a_xor_j = 1
        // ( (1 & a_and_j) | a_or_j) ^ a_xor_j = 0  => (a_and_j | a_or_j) ^ a_xor_j = 0
        // From a_or_j ^ a_xor_j = 1, we get a_xor_j = 1 - a_or_j.
        // Substitute into second: (a_and_j | a_or_j) ^ (1 - a_or_j) = 0.
        // If a_or_j = 0, then (a_and_j | 0) ^ 1 = 0 => a_and_j ^ 1 = 0 => a_and_j = 1.
        //   Then a_or_j = 0, a_xor_j = 1, a_and_j = 1.
        //   This means: x_j & 1 | 0 ^ 1 = x_j ^ 1. This works.
        // If a_or_j = 1, then (a_and_j | 1) ^ 0 = 0 => 1 ^ 0 = 0 => 1 = 0. Impossible.
        // So, a_and_j = 1, a_or_j = 0, a_xor_j = 1.
        // This means: A_AND |= (1 << j); A_OR |= 0; A_XOR |= (1 << j);
        // This is equivalent to: A_AND |= (1 << j); A_XOR |= (1 << j);

        // Case 4: f_j(0) = 1, f_j(1) = 1
        // This means the j-th output bit is always 1, regardless of input x_j.
        // To achieve this:
        // ( (0 & a_and_j) | a_or_j) ^ a_xor_j = 1  => a_or_j ^ a_xor_j = 1
        // ( (1 & a_and_j) | a_or_j) ^ a_xor_j = 1  => (a_and_j | a_or_j) ^ a_xor_j = 1
        // From a_or_j ^ a_xor_j = 1, we get a_xor_j = 1 - a_or_j.
        // Substitute into second: (a_and_j | a_or_j) ^ (1 - a_or_j) = 1.
        // If a_or_j = 0, then (a_and_j | 0) ^ 1 = 1 => a_and_j ^ 1 = 1 => a_and_j = 0.
        //   Then a_or_j = 0, a_xor_j = 1, a_and_j = 0.
        //   This means: x_j & 0 | 0 ^ 1 = 0 ^ 1 = 1. This works.
        // If a_or_j = 1, then (a_and_j | 1) ^ 0 = 1 => 1 ^ 0 = 1 => 1 = 1. This works.
        //   Then a_or_j = 1, a_xor_j = 0, a_and_j can be anything (0 or 1).
        //   Let's pick a_and_j = 1 (no change to A_AND).
        //   This means: x_j & 1 | 1 ^ 0 = 1. This works.
        // So, we have two options:
        //   1) a_and_j = 0, a_or_j = 0, a_xor_j = 1
        //   2) a_and_j = 1, a_or_j = 1, a_xor_j = 0
        // We prefer the second option because it uses OR to set the bit to 1, which is simpler.
        // A_AND |= (1 << j); A_OR |= (1 << j); A_XOR |= 0;
        // This is equivalent to: A_OR |= (1 << j);

        if (f_j_0 == 0 && f_j_1 == 0) { // Output bit is always 0
            A_AND &= ~(1 << j); // Force bit to 0 using AND
        } else if (f_j_0 == 0 && f_j_1 == 1) { // Output bit is x_j
            // A_AND already has 1 at this bit, A_OR and A_XOR have 0. No change needed.
        } else if (f_j_0 == 1 && f_j_1 == 0) { // Output bit is 1 - x_j
            A_XOR |= (1 << j); // Flip bit using XOR
        } else { // f_j_0 == 1 && f_j_1 == 1, Output bit is always 1
            A_OR |= (1 << j); // Force bit to 1 using OR
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_AND != 1023) { // If A_AND is not all 1s, we need an AND operation
        result_ops.push_back({'&', A_AND});
    }
    if (A_OR != 0) { // If A_OR is not all 0s, we need an OR operation
        result_ops.push_back({'|', A_OR});
    }
    if (A_XOR != 0) { // If A_XOR is not all 0s, we need an XOR operation
        result_ops.push_back({'^', A_XOR});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

long long solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Max length for which 2^L-1 <= N_max (2e5) is L=17 (2^17-1 = 131071, 2^18-1 = 262143)
    // So, we only need to check substrings up to length 18 (or 19 to be safe, 20 is definitely enough)
    // Let's use a constant MAX_CHECK_LEN, say 20.
    // For substrings longer than MAX_CHECK_LEN, the value f(s_l...s_r) will be much larger than r-l+1
    // unless there are many leading zeros.
    // The maximum value of r-l+1 is N_max = 2e5.
    // The maximum value of f(s_l...s_r) that we care about is N_max.
    // If a substring has length L, its value is at most 2^L-1.
    // If L > 18, then 2^L-1 > 2^18-1 > 2e5.
    // So if L > 18, for f(s_l...s_r) to be <= 2e5, it must have many leading zeros.
    // The first '1' must appear at an index such that the remaining part has length at most 18.
    // Example: s_l...s_r. If s_k is the first '1', then r-k+1 <= 18.
    // This means k >= r-17.
    // So, for a fixed r, we only need to check l such that r-l+1 <= 18, or l >= r-17.
    // And for l such that s_l = '1', we check l up to r.
    // The maximum length of a substring whose value can be equal to its length is around 18.
    // For example, if length is 18, max value is 2^18-1 = 262143.
    // If length is 19, max value is 2^19-1 = 524287.
    // So if r-l+1 > 18, then f(s_l...s_r) must be small, meaning it must have many leading zeros.
    // Specifically, if s_l...s_r is good, then r-l+1 = f(s_l...s_r).
    // Since r-l+1 <= N_max = 2e5, f(s_l...s_r) must be <= 2e5.
    // This implies that the effective length of the binary number (from the first '1' to s_r)
    // must be at most 18.
    // Let k be the index of the first '1' in s_l...s_r.
    // Then r-k+1 <= 18.
    // This means k >= r-17.
    // So for each r, we only need to check l from max(0, r-17) up to r.
    // This is a window of size at most 18.
    // This covers all cases where s_l = '1'.

    // For cases where s_l = '0', we need to count how many leading zeros there are.
    // Let's iterate through all possible right endpoints `r`.
    // For each `r`, we iterate `l` backwards from `r` down to `max(0, r - 1 - 18)`.
    // The `r - 1 - 18` is because if `s_l` is '0', we need to find the first '1' at `s_k`.
    // The length of `s_k...s_r` is `r-k+1`. This must be at most 18.
    // So `k >= r-17`.
    // The length of `s_l...s_r` is `r-l+1`.
    // The value `f(s_l...s_r)` is `f(s_k...s_r)`.
    // So we need `r-l+1 = f(s_k...s_r)`.
    // The maximum value of `f(s_k...s_r)` is `2^18-1` (if `r-k+1=18`).
    // So `r-l+1` can be at most `2^18-1`.
    // This means `l >= r - (2^18-1) + 1`.
    // Since `2^18-1` is about `2.6e5`, this means `l` can be very far to the left.
    // This is the tricky part.

    // Let's fix the right endpoint `r`.
    // We want to find `l` such that `r - l + 1 = f(s_l \dots s_r)`.
    // The value `f(s_l \dots s_r)` is determined by the first '1' from the left.
    // Let `k` be the index of the first '1' in `s_l \dots s_r`.
    // If no '1' exists, `f(s_l \dots s_r) = 0`. Then `r - l + 1 = 0`, which is impossible.
    // So there must be at least one '1'.
    // The value `f(s_l \dots s_r)` is `f(s_k \dots s_r)`.
    // The length of `s_k \dots s_r` is `len_suffix = r - k + 1`.
    // The value `val_suffix = f(s_k \dots s_r)`.
    // We need `r - l + 1 = val_suffix`.
    // This means `l = r + 1 - val_suffix`.
    // Also, `l` must be less than or equal to `k` (since `s_l \dots s_k \dots s_r`).
    // And `s_l \dots s_{k-1}` must all be '0's.

    // Iterate `r` from `0` to `n-1`.
    // For each `r`, we will iterate `k` (index of first '1') backwards from `r` down to `max(0, r - 18)`.
    // This ensures `r - k + 1 <= 19`. (19 is safe, 18 is enough for 2e5)
    // Let's use `MAX_VAL_LEN = 19`. So `r - k + 1 <= MAX_VAL_LEN`.
    // This means `k >= r - MAX_VAL_LEN + 1`.
    // So `k` goes from `r` down to `max(0, r - MAX_VAL_LEN + 1)`.
    // Inside this loop, we calculate `val_suffix = f(s_k \dots s_r)`.
    // If `s[k]` is '0', we skip this `k` because `k` must be the index of the first '1'.
    // If `s[k]` is '1':
    //   Calculate `val_suffix`.
    //   If `val_suffix` is too large (e.g., `val_suffix > n`), we can stop for this `r` and `k` range.
    //   The maximum possible length `r-l+1` is `n`. So `val_suffix` cannot exceed `n`.
    //   If `val_suffix > n`, then `r-l+1` cannot be `val_suffix`.
    //   If `val_suffix <= n`:
    //     Calculate the required `l`: `l_req = r + 1 - val_suffix`.
    //     We need to check if this `l_req` is a valid starting index.
    //     1. `0 <= l_req <= k`.
    //     2. All characters `s[l_req \dots k-1]` must be '0'.
    //     If both conditions hold, then `s_{l_req \dots r}` is a good substring.
    //     The number of leading zeros is `k - l_req`.
    //     We need to count how many `l_req` values satisfy this.
    //     This is equivalent to counting how many `l_req` values exist such that `0 <= l_req <= k`
    //     and `s[l_req \dots k-1]` are all '0's.
    //     This is simply `k - (first_zero_block_start_index_before_k)`.
    //     Let `prev_zero_block_start[k]` be the index `p` such that `s[p \dots k-1]` are all '0's
    //     and `s[p-1]` is '1' (or `p=0`).
    //     Then any `l_req` in `[prev_zero_block_start[k], k]` would work.
    //     So, if `l_req` is in this range, we count it.
    //     The number of valid `l_req` values is `k - std::max(l_req, prev_zero_block_start[k]) + 1`.
    //     No, this is simpler: `l_req` must be `r+1-val_suffix`.
    //     We need `l_req <= k`.
    //     And `s[l_req \dots k-1]` must be all '0's.
    //     Let `last_one[k]` be the index of the last '1' before `k`. If no '1' before `k`, it's -1.
    //     Then `s[last_one[k]+1 \dots k-1]` are all '0's.
    //     So `l_req` must be in `[last_one[k]+1, k]`.
    //     If `l_req` is in this range, and `l_req >= 0`, then it's a good substring.

    // Precompute `last_one` array: `last_one[i]` is the index of the last '1' before or at `i-1`.
    // `last_one[0] = -1`.
    // For `i > 0`, `last_one[i] = (s[i-1] == '1' ? i-1 : last_one[i-1])`.
    std::vector<int> last_one(n + 1);
    last_one[0] = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            last_one[i + 1] = i;
        } else {
            last_one[i + 1] = last_one[i];
        }
    }

    const int MAX_VAL_LEN = 19; // Max length of the '1'-suffixed part. 2^18-1 is 262143. 2^19-1 is 524287.
                                // N_max is 2e5. So 18 bits are enough. Let's use 19 for safety.

    for (int r = 0; r < n; ++r) {
        long long current_val = 0;
        for (int k = r; k >= 0 && r - k + 1 <= MAX_VAL_LEN; --k) {
            // k is the potential start of the '1'-suffixed part s_k...s_r
            if (s[k] == '1') {
                current_val += (1LL << (r - k));
            }

            // If current_val exceeds n, then r-l+1 cannot be current_val.
            // We can break early for this r, as current_val will only increase for smaller k.
            if (current_val > n) {
                break; 
            }

            // If s[k] is '0', this k cannot be the start of the '1'-suffixed part.
            // The value `current_val` is `f(s_k \dots s_r)`.
            // If `s[k]` is '0', then `f(s_k \dots s_r)` is actually `f(s_{k'} \dots s_r)` where `k'` is the first '1' after `k`.
            // But we are iterating `k` backwards, so `current_val` is correctly `f(s_k \dots s_r)`
            // where `s_k` is the first '1' in `s_k \dots s_r`.
            // So we only consider `k` where `s[k] == '1'`.
            if (s[k] == '1') {
                // We found a potential `k` (first '1' in `s_l \dots s_r`).
                // The value is `current_val`.
                // The required length is `current_val`.
                // So `r - l + 1 = current_val`.
                // This means `l = r + 1 - current_val`.
                int l_req = r + 1 - static_cast<int>(current_val);

                // Check conditions for `l_req`:
                // 1. `0 <= l_req <= k`.
                // 2. All characters `s[l_req \dots k-1]` must be '0'.
                // Condition 2 is equivalent to `last_one[k] < l_req`.
                // `last_one[k]` is the index of the last '1' in `s[0 \dots k-1]`.
                // If `l_req` is greater than `last_one[k]`, it means all characters `s[last_one[k]+1 \dots k-1]` are '0's.
                // So `l_req` must be in the range `[last_one[k]+1, k]`.
                if (l_req >= 0 && l_req <= k && l_req > last_one[k]) {
                    good_substrings_count++;
                }
            }
        }
    }

    return good_substrings_count;
}

