#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left part (jars 1 to n)
    // diff_left[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // This is for removing k jars from the left.
    // The remaining jars are a[k...n-1] for the left segment.
    // The balance for the remaining left segment (a[k...n-1]) is
    // (total 1s in a[0...n-1] - total 2s in a[0...n-1]) - (diff_left[k])
    // No, this is not correct.
    // Let's define diff_left[k] as the balance of the first k jars (a[0]...a[k-1]).
    // So diff_left[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1]).
    // This is the balance of jars *removed* from the left.
    // The balance of jars *remaining* on the left side (a[k...n-1]) is
    // (total_left_balance) - diff_left[k].
    // total_left_balance = (count of 1s in a[0...n-1]) - (count of 2s in a[0...n-1]).

    std::vector<int> diff_left(n + 1, 0); // diff_left[k] = balance of first k jars (a[0]...a[k-1])
    for (int i = 0; i < n; ++i) {
        diff_left[i + 1] = diff_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right part (jars n+1 to 2n)
    // diff_right[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // This is for removing k jars from the right.
    // The remaining jars are a[n...2n-k-1] for the right segment.
    // The balance for the remaining right segment (a[n...2n-k-1]) is
    // (total_right_balance) - diff_right[k].
    // total_right_balance = (count of 1s in a[n...2n-1]) - (count of 2s in a[n...2n-1]).

    std::vector<int> diff_right(n + 1, 0); // diff_right[k] = balance of last k jars (a[2n-k]...a[2n-1])
    for (int i = 0; i < n; ++i) {
        diff_right[i + 1] = diff_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the right (j)
    // for a given balance of the remaining right segment.
    // The balance of the remaining right segment (a[n...2n-j-1]) is
    // (total_right_balance) - diff_right[j].
    // Let total_right_balance = diff_right[n].
    // So, balance of remaining right segment = diff_right[n] - diff_right[j].
    std::map<int, int> min_j_for_right_balance;

    for (int j = 0; j <= n; ++j) {
        int current_right_balance = diff_right[n] - diff_right[j];
        if (min_j_for_right_balance.find(current_right_balance) == min_j_for_right_balance.end()) {
            min_j_for_right_balance[current_right_balance] = j;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through all possible numbers of jars removed from the left (i)
    for (int i = 0; i <= n; ++i) {
        // Balance of the remaining left segment (a[i...n-1])
        // This is (total_left_balance) - diff_left[i].
        // Let total_left_balance = diff_left[n].
        // So, balance of remaining left segment = diff_left[n] - diff_left[i].
        int current_left_balance = diff_left[n] - diff_left[i];

        // We need the total balance of remaining jars to be 0.
        // (balance of remaining left segment) + (balance of remaining right segment) = 0
        // So, (balance of remaining right segment) must be -current_left_balance.
        int target_right_balance = -current_left_balance;

        if (min_j_for_right_balance.count(target_right_balance)) {
            int j = min_j_for_right_balance[target_right_balance];
            min_removed_jars = std::min(min_removed_jars, i + j);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

