    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive 0s ending at i, or 1s ending at i
    // L[i] is 0 if a[i] is different from a[i-1]
    // L[i] is L[i-1] + 1 if a[i] is same as a[i-1]
    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // Calculate R[i]: length of consecutive 0s starting at i, or 1s starting at i
    // R[i] is 0 if a[i] is different from a[i+1]
    // R[i] is R[i+1] + 1 if a[i] is same as a[i+1]
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == a[i + 1]) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Looking for 010 patterns
            if (i > 0 && a[i - 1] == 1 && i < n - 1 && a[i + 1] == 1) {
                // This is a 0 in a 1...1 0 1...1 pattern
                // The 0 will flip to 1 if it's surrounded by 1s for k steps
                // The number of steps for this 0 to flip is min(L[i-1], R[i+1]) + 1
                max_k = std::max(max_k, std::min(L[i - 1], R[i + 1]) + 1);
            }
        } else { // Looking for 101 patterns
            if (i > 0 && a[i - 1] == 0 && i < n - 1 && a[i + 1] == 0) {
                // This is a 1 in a 0...0 1 0...0 pattern
                // The 1 will flip to 0 if it's surrounded by 0s for k steps
                // The number of steps for this 1 to flip is min(L[i-1], R[i+1]) + 1
                max_k = std::max(max_k, std::min(L[i - 1], R[i + 1]) + 1);
            }
        }
    }

    // If max_k is 0, the sequence is already stable.
    // If max_k is odd, it means there's an unstable pattern that will never fully resolve.
    // For example, 01010. max_k = 2.
    // 01010 -> 00100 -> 00000. Stable.
    // For example, 0110. max_k = 1.
    // 0110 -> 0110. Stable.
    // For example, 010. max_k = 1.
    // 010 -> 000. Stable.
    // The problem states "if it ever becomes stable".
    // The condition for stability is that all 010 and 101 patterns are resolved.
    // A 010 pattern (0 surrounded by 1s) becomes 000 if the 1s are "eaten" by 0s.
    // A 101 pattern (1 surrounded by 0s) becomes 111 if the 0s are "eaten" by 1s.
    // The critical observation is that a 0 surrounded by 1s (or 1 surrounded by 0s)
    // will flip if the "reach" of the surrounding same-valued elements is equal.
    // E.g., 1110111. The 0 is surrounded by 1s. L[i-1]=2, R[i+1]=2. min(2,2)+1 = 3.
    // After 3 steps, the 0 becomes 1.
    // 1110111 -> 1111111
    // If the lengths are unequal, e.g., 110111. L[i-1]=1, R[i+1]=2. min(1,2)+1 = 2.
    // After 2 steps, the 0 becomes 1.
    // 110111 -> 111111
    // The problem is when max_k is odd.
    // Consider 01010.
    // i=1: a[1]=1. L[0]=0, R[2]=0. min(0,0)+1 = 1.
    // i=3: a[3]=1. L[2]=0, R[4]=0. min(0,0)+1 = 1.
    // max_k = 1.
    // 01010 -> 00100.
    // For 00100:
    // i=2: a[2]=1. L[1]=1, R[3]=1. min(1,1)+1 = 2.
    // max_k = 2.
    // 00100 -> 00000.
    // The max_k calculated here is the maximum number of steps for *any single element* to flip.
    // The actual number of steps to stability is max_k / 2 (integer division) if max_k is even,
    // and (max_k + 1) / 2 if max_k is odd.
    // This is because each step, the "boundary" moves by one.
    // E.g., 1110111. max_k = 3. Steps = (3+1)/2 = 2.
    // 1110111 -> 1111111 (after 2 steps)
    // 1110111 -> 110111 -> 111111
    // This is incorrect. The max_k is the number of steps for the *middle* element to flip.
    // The number of steps for the sequence to stabilize is `ceil(max_k / 2.0)`.
    // This is `(max_k + 1) / 2` using integer division.

    int steps = (max_k + 1) / 2;

    // Construct the final stable sequence
    std::vector<int> final_a = a;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // If original was 0
            // Check if it's part of a 1...1 0 1...1 pattern that flips to 1
            if (i > 0 && a[i - 1] == 1 && i < n - 1 && a[i + 1] == 1) {
                if (std::min(L[i - 1], R[i + 1]) >= steps) {
                    final_a[i] = 1;
                }
            }
        } else { // If original was 1
            // Check if it's part of a 0...0 1 0...0 pattern that flips to 0
            if (i > 0 && a[i - 1] == 0 && i < n - 1 && a[i + 1] == 0) {
                if (std::min(L[i - 1], R[i + 1]) >= steps) {
                    final_a[i] = 0;
                }
            }
        }
    }

    std::cout << steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y and a_i values to prevent overflow
// x can be int as it's an index up to N, but intermediate x values can be large
// so it's safer to use long long for x as well during calculations.
// However, the problem states x <= 0 or x > n for termination, so x itself
// doesn't need to be stored as long long if we only care about its value relative to n.
// Let's use long long for x in the simulation to be safe, as a_x can be 10^9.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1); // a[0] unused, a[1] will be set for each run
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp[i] stores a pair: {final_x, final_y} if starting at x=i and performing one full cycle (step 2 then step 3)
    // and then terminating or jumping to another state.
    // Specifically, dp[i].first is the x value after one cycle, and dp[i].second is the y value added in that cycle.
    // We use -1 for x to indicate termination.
    std::vector<std::pair<long long, long long>> dp(n + 1);
    std::vector<bool> visited(n + 1, false); // For cycle detection during DP calculation

    // Calculate DP values for a_i where i >= 2
    // For i = 2 to n, a[i] is fixed.
    // The logic for dp[i] is:
    // Start at (x=i, y=0)
    // Step 2: x_new = i + a[i], y_new = a[i]
    // Step 3: x_final = x_new - a[x_new], y_final = y_new + a[x_new]
    // If x_new <= 0 or x_new > n, then the program terminates after step 2.
    // In this case, dp[i] should reflect this termination.
    // The problem states "If, after any step, x <= 0 or x > n, the program immediately terminates."
    // So, if x_new (after step 2) is out of bounds, the program terminates.
    // The final y would be a[i]. The final x is x_new.
    // If x_final (after step 3) is out of bounds, the program terminates.
    // The final y would be a[i] + a[x_new]. The final x is x_final.
    // Otherwise, it continues from (x_final, y_final).

    // We need to compute dp[i] for i from 2 to n.
    // dp[i] will store the total y accumulated and the final x reached if we start at x=i,
    // perform one step 2 and one step 3, and then continue from the new x.
    // This is a bit tricky because a[x_new] depends on x_new.
    // Let's define dp[i] as {final_x, total_y_added} if we start at x=i and perform one full (step 2, step 3) cycle.
    // If it terminates within this cycle, final_x will be 0 or >n, and total_y_added will be the y accumulated.

    // The problem structure suggests that for a given x, the next x is x + a_x, then x + a_x - a_{x+a_x}.
    // This is a fixed sequence for x >= 2.
    // We can precompute the results for starting positions x = 2 to n.
    // Let `res[i]` be the pair `{final_x, total_y}` if we start at `x=i` and run the program until termination.
    // `res[i].first` will be the final `x` (0 or >n), `res[i].second` will be the total `y`.
    // If it never terminates, `res[i].first` could be a special value like -1.

    // We can use dynamic programming with memoization.
    // `memo[i]` stores `{final_x, total_y}` for starting `x=i`.
    // `final_x` will be the `x` value that caused termination (0 or >n).
    // `total_y` will be the `y` value accumulated.
    // If `memo[i]` is already computed, return it.
    // If we detect a cycle, it means non-termination.

    std::vector<std::pair<long long, long long>> memo(n + 1, {0, 0}); // {final_x, total_y}
    std::vector<bool> in_stack(n + 1, false); // For cycle detection

    auto solve = [&](auto self, int start_x) -> std::pair<long long, long long> {
        if (start_x <= 0 || start_x > n) {
            return {start_x, 0}; // Base case: already terminated
        }
        if (memo[start_x].first != 0 || memo[start_x].second != 0) { // Already computed
            return memo[start_x];
        }
        if (in_stack[start_x]) { // Cycle detected, non-termination
            return {-1, -1}; // Special value for non-termination
        }

        in_stack[start_x] = true;

        long long current_a_val = a[start_x];

        // Step 2: x = start_x + current_a_val, y = current_a_val
        long long x_after_step2 = start_x + current_a_val;
        long long y_after_step2 = current_a_val;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            in_stack[start_x] = false;
            return memo[start_x] = {x_after_step2, y_after_step2};
        }

        // Step 3: x = x_after_step2 - a[x_after_step2], y = y_after_step2 + a[x_after_step2]
        long long a_val_for_step3 = a[x_after_step2];
        long long x_after_step3 = x_after_step2 - a_val_for_step3;
        long long y_after_step3 = y_after_step2 + a_val_for_step3;

        // Now, recursively call for the next state
        std::pair<long long, long long> next_state_result = self(self, x_after_step3);

        in_stack[start_x] = false;

        if (next_state_result.first == -1) { // Non-termination from next state
            return memo[start_x] = {-1, -1};
        } else {
            return memo[start_x] = {next_state_result.first, y_after_step3 + next_state_result.second};
        }
    };

    // Precompute for a_i where i >= 2
    for (int i = 2; i <= n; ++i) {
        if (memo[i].first == 0 && memo[i].second == 0) { // Only compute if not already done
            solve(solve, i);
        }
    }

    // Now, for each query (a_1 = 1 to n-1)
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for this run

        // Simulate the first step for a_1
        long long current_a_val = a[1];

        // Step 2: x = 1 + current_a_val, y = current_a_val
        long long x_after_step2 = 1 + current_a_val;
        long long y_after_step2 = current_a_val;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            std::cout << y_after_step2 << "\n";
            continue;
        }

        // Step 3: x = x_after_step2 - a[x_after_step2], y = y_after_step2 + a[x_after_step2]
        long long a_val_for_step3 = a[x_after_step2];
        long long x_after_step3 = x_after_step2 - a_val_for_step3;
        long long y_after_step3 = y_after_step2 + a_val_for_step3;

        // Now, use the precomputed results for x_after_step3
        std::pair<long long, long long> result_from_dp;
        if (x_after_step3 <= 0 || x_after_step3 > n) {
            result_from_dp = {x_after_step3, 0}; // Terminated
        } else {
            result_from_dp = memo[x_after_step3];
        }

        if (result_from_dp.first == -1) { // Non-termination
            std::cout << -1 << "\n";
        } else {
            std::cout << y_after_step3 + result_from_dp.second << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a_initial(n, LLONG_MAX); // a_initial[j] stores max_j - sum_d_j
                                                  // Initialize with a very large value, as we are taking minimums.

    // Calculate the sum of 'd' values for each index for all type 1 operations
    // that occur *before* any type 2 operation.
    // This is not exactly correct. We need to calculate the sum of 'd' values
    // for each index *at the time of each type 2 operation*.
    // Let's rephrase: a_j = A_0[j] + current_delta[j].
    // So, A_0[j] = a_j - current_delta[j].
    // For a type 2 operation (l, r, m), we have max_{k=l..r} (A_0[k] + current_delta[k]) = m.
    // This implies A_0[k] + current_delta[k] <= m for all k in [l, r].
    // So, A_0[k] <= m - current_delta[k] for all k in [l, r].
    // We want to find the largest possible A_0[k] values.
    // So, A_0[k] = min(previous_upper_bound_for_A_0[k], m - current_delta[k]).
    // Initialize A_0[k] to a very large value (e.g., 10^9) and take minimums.

    std::vector<long long> current_delta(n, 0); // sum of d's applied to each index so far

    // First pass: Determine upper bounds for A_0[j]
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                // A_0[j] + current_delta[j] <= ops[i].val (m_i)
                // A_0[j] <= ops[i].val - current_delta[j]
                a_initial[j] = std::min(a_initial[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If a_initial[j] is still LLONG_MAX, it means no type 2 operation constrained it.
    // We can set it to 0, as it satisfies |a_i| <= 10^9.
    for (int j = 0; j < n; ++j) {
        if (a_initial[j] == LLONG_MAX) {
            a_initial[j] = 0;
        }
    }

    // Second pass: Verify the solution
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, a_initial[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial array elements
    for (int j = 0; j < n; ++j) {
        if (a_initial[j] < -1000000000LL || a_initial[j] > 1000000000LL) {
            // This case should ideally not be reached if the problem constraints
            // and logic are followed, as m_i is up to 5*10^7 and d_i up to 10^4.
            // The maximum possible value for m_i - current_delta[j] would be
            // 5*10^7 - (5000 * -10^4) = 5*10^7 + 5*10^7 = 10^8.
            // The minimum possible value would be
            // -5*10^7 - (5000 * 10^4) = -5*10^7 - 5*10^7 = -10^8.
            // Both are within [-10^9, 10^9].
            // However, it's good practice to check.
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << a_initial[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The smallest possible value for b_1 is 0.
                            // We want to find if there exists a sequence b_i such that
                            // b_i >= prev_val and b_i = (a_i + c_i) % m where 0 <= c_i <= x.

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];
        long long lower_bound_for_b_i = prev_val;

        // Case 1: a_i is already >= prev_val.
        // We can potentially keep a_i as is, or increment it.
        // The smallest possible value for b_i is a_i.
        // If a_i >= lower_bound_for_b_i, then we can set b_i = a_i.
        // This requires c_i = 0, which is <= x.
        // So, we can set prev_val = a_i for the next iteration.
        if (current_a >= lower_bound_for_b_i) {
            // We need to check if we can achieve current_a.
            // This means c_i = 0. This is always possible if x >= 0.
            // We also need to check if we can achieve a value >= lower_bound_for_b_i
            // by incrementing current_a.
            // The values we can achieve are (current_a + 0)%m, (current_a + 1)%m, ..., (current_a + x)%m.
            // If current_a >= lower_bound_for_b_i, then we can choose c_i=0, making b_i=current_a.
            // This is a valid choice. So we update prev_val = current_a.
            // However, we must consider the wrap-around case.
            // If current_a + x < m and current_a + x < lower_bound_for_b_i,
            // then we cannot achieve lower_bound_for_b_i.
            // But this is covered by the condition current_a >= lower_bound_for_b_i.
            // If current_a >= lower_bound_for_b_i, then we can always pick c_i=0,
            // making b_i = current_a. This is a valid choice for b_i.
            // So we set prev_val = current_a.
            // The only exception is if current_a + x < m and current_a + x < lower_bound_for_b_i.
            // This means that even if we increment current_a by up to x, it still doesn't reach lower_bound_for_b_i.
            // This can only happen if current_a < lower_bound_for_b_i, which contradicts the outer if.
            // So if current_a >= lower_bound_for_b_i, we can always set b_i = current_a.
            // The only case where we might need to increment is if current_a + x < m and current_a + x < lower_bound_for_b_i.
            // This is not possible if current_a >= lower_bound_for_b_i.
            // So if current_a >= lower_bound_for_b_i, we can always choose b_i = current_a.
            // The only time we *must* increment is if current_a < lower_bound_for_b_i.
            // If current_a >= lower_bound_for_b_i, we can choose b_i = current_a.
            // This is the smallest possible value for b_i that satisfies b_i >= lower_bound_for_b_i.
            // So we set prev_val = current_a.
            // But wait, what if current_a + x wraps around?
            // Example: m=10, a_i=8, x=3. Possible values: 8, 9, 0, 1.
            // If prev_val=0, and a_i=8. We can choose b_i=8. prev_val becomes 8.
            // If prev_val=9, and a_i=8. We cannot choose b_i=8.
            // We need b_i >= 9.
            // Possible values for b_i are (a_i + c_i) % m for 0 <= c_i <= x.
            // If current_a >= lower_bound_for_b_i:
            //   We can choose c_i = 0, making b_i = current_a. This is valid.
            //   So we can set prev_val = current_a.
            //   However, we must also consider if (current_a + x) % m < lower_bound_for_b_i.
            //   This means that even if we increment current_a by x, it wraps around and becomes too small.
            //   This happens if current_a + x >= m AND (current_a + x) % m < lower_bound_for_b_i.
            //   In this specific case, we cannot achieve lower_bound_for_b_i.
            //   Example: m=10, a_i=8, x=3, prev_val=9.
            //   current_a=8 < prev_val=9. This falls into the else branch.
            //   Example: m=10, a_i=8, x=1, prev_val=8.
            //   current_a=8 >= prev_val=8.
            //   (current_a + x) % m = (8+1)%10 = 9.
            //   Is 9 < prev_val=8? No. So we can set prev_val = current_a = 8.
            //   Example: m=10, a_i=8, x=3, prev_val=8.
            //   current_a=8 >= prev_val=8.
            //   (current_a + x) % m = (8+3)%10 = 1.
            //   Is 1 < prev_val=8? Yes. This means we cannot achieve prev_val=8 by incrementing.
            //   So we must choose b_i = current_a.
            //   This logic is getting complicated. Let's simplify.

            // We need to find the smallest b_i such that b_i >= lower_bound_for_b_i
            // and b_i = (a_i + c_i) % m for some 0 <= c_i <= x.

            // Let's consider the range of values [a_i, (a_i + x) % m] (circularly).
            // If a_i + x < m, the range is [a_i, a_i + x].
            // If a_i + x >= m, the range is [a_i, m-1] U [0, (a_i + x) % m].

            // Case 1: a_i >= lower_bound_for_b_i
            // We can potentially choose b_i = a_i (by c_i=0). This is valid.
            // So the smallest possible b_i is a_i.
            // We need to check if by incrementing a_i, we wrap around and become too small.
            // If (a_i + x) % m < lower_bound_for_b_i, AND a_i + x >= m (meaning it wrapped around),
            // then we cannot achieve lower_bound_for_b_i by incrementing.
            // In this situation, we must choose b_i = a_i.
            // So, if (a_i + x) % m < lower_bound_for_b_i AND (a_i + x) >= m,
            // then we must set prev_val = a_i.
            // Otherwise, we can potentially achieve lower_bound_for_b_i by incrementing.
            // But since a_i >= lower_bound_for_b_i, we can always choose b_i = a_i.
            // So if a_i >= lower_bound_for_b_i, we can always set prev_val = a_i.
            // This is incorrect.
            // Example: m=10, a_i=8, x=3, prev_val=8.
            // a_i=8 >= prev_val=8.
            // (a_i+x)%m = (8+3)%10 = 1.
            // Is 1 < prev_val=8? Yes.
            // This means if we increment a_i, it becomes 9, 0, 1.
            // The values 0, 1 are less than prev_val=8.
            // So we must choose b_i=8. prev_val becomes 8. This is correct.

            // Case 2: a_i < lower_bound_for_b_i
            // We must increment a_i.
            // We need to find c_i such that (a_i + c_i) % m >= lower_bound_for_b_i.
            // The smallest such c_i is `lower_bound_for_b_i - a_i`.
            // If this `c_i` is <= x, then we can achieve `lower_bound_for_b_i`.
            // So we set prev_val = lower_bound_for_b_i.
