    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Max possible operations is m-1 (e.g., change 0 to m-1).
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_cry_volume = children[i].v;
        long long chain_cry_volume = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            children[j].p -= current_cry_volume;
            children[j].p -= chain_cry_volume;

            if (current_cry_volume > 0) {
                current_cry_volume--;
            }

            if (children[j].p < 0) {
                children[j].in_line = false;
                chain_cry_volume += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' can be "passed" by all 'a's
            // currently accumulated to its left (represented by count_a).
            // Each such 'a' will perform an operation with this 'b'.
            // The number of operations is count_a.
            // After this 'b' is processed, it effectively becomes an 'a' for the
            // 'a's further to its left. This new 'a' will then contribute to
            // future operations.
            // So, the number of 'a's that can pass this 'b' doubles.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are waiting to pass 'b's to their right.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., subsequence 1).
    // No pairs will be in different subsequences.
    // f(a_i, a_j) = a_i + a_j for all pairs.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness_all_same = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition_all_same(n, 1); // All in subsequence 1

    // Case 2: One element in one subsequence, rest in another.
    // This is equivalent to having one element in subsequence 1, and n-1 elements in subsequence 2.
    // Or one element in subsequence 2, and n-1 elements in subsequence 1.
    // The choice of which element is alone matters.
    //
    // Let's try putting a[0] (smallest) in subsequence 1, and all others in subsequence 2.
    // Pairs in subsequence 1: None (only a[0] is there).
    // Pairs in subsequence 2: (a[i], a[j]) for i,j in [1, n-1].
    //   min_same = a[1].value + a[2].value
    //   max_same = a[n-2].value + a[n-1].value
    // Pairs in different subsequences: (a[0], a[i]) for i in [1, n-1].
    //   min_diff = a[0].value + a[1].value + h
    //   max_diff = a[0].value + a[n-1].value + h
    //
    // Overall min_f = min(min_same, min_diff)
    // Overall max_f = max(max_same, max_diff)
    //
    // This strategy is optimal if h is large.
    // The minimum possible sum is a[0].value + a[1].value.
    // The maximum possible sum is a[n-2].value + a[n-1].value.
    //
    // If we put a[0] in one group and the rest in another:
    // min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // max_f = max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //
    // The crucial observation is that if we put a[0] in one group and the rest in another,
    // the smallest possible sum is a[0].value + a[1].value (if h is small enough to make a[0]+a[1]+h smaller than a[1]+a[2])
    // or a[1].value + a[2].value (if h is large).
    // The largest possible sum is a[n-2].value + a[n-1].value (if h is small enough to make a[0]+a[n-1]+h smaller than a[n-2]+a[n-1])
    // or a[0].value + a[n-1].value + h (if h is large).
    //
    // Let's consider the specific partition: a[0] in group 1, a[1...n-1] in group 2.
    // min_f_val = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
    // max_f_val = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h);
    // goodness_one_alone = max_f_val - min_f_val;
    //
    // This is not quite right. The problem is that a[0]+a[1]+h could be the minimum, and a[n-2]+a[n-1] could be the maximum.
    // Or a[1]+a[2] could be the minimum, and a[0]+a[n-1]+h could be the maximum.
    //
    // Let's consider the values:
    // V_same_min = a[1].value + a[2].value
    // V_same_max = a[n-2].value + a[n-1].value
    // V_diff_min = a[0].value + a[1].value + h
    // V_diff_max = a[0].value + a[n-1].value + h
    //
    // The overall min_f is min(V_same_min, V_diff_min)
    // The overall max_f is max(V_same_max, V_diff_max)
    //
    // The goodness for this partition is max(V_same_max, V_diff_max) - min(V_same_min, V_diff_min).
    //
    // This partition is optimal when h is large.
    // The condition for this partition to be better than all-same is when
    // (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value) is large.
    //
    // Let's check the specific condition:
    // If a[0].value + a[n-1].value + h - (a[0].value + a[1].value + h) < (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    // This simplifies to a[n-1].value - a[1].value < (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    // This is not a simple condition.
    //
    // The key insight for the "one element alone" case is that if `h` is large enough,
    // then `a_i + a_j + h` will always be greater than `a_k + a_l`.
    // Specifically, if `a[0].value + a[1].value + h > a[n-2].value + a[n-1].value`,
    // then all `f` values from different groups will be larger than all `f` values from same groups.
    // In this scenario, `min_f = a[1].value + a[2].value` (from same group)
    // and `max_f = a[0].value + a[n-1].value + h` (from different groups).
    // Goodness = `(a[0].value + a[n-1].value + h) - (a[1].value + a[2].value)`.
    //
    // Let's compare `goodness_all_same` with `(a[0].value + a[n-1].value + h) - (a[1].value + a[2].value)`.
    // This second value is the goodness if we put `a[0]` in one group and the rest in another,
    // AND `a[0].value + a[1].value + h` is greater than `a[1].value + a[2].value`.
    // This is true if `h > a[2].value - a[0].value`.
    //
    // If `h > a[n-1].value - a[0].value`, then `a[0].value + a[1].value + h` is likely to be the overall maximum.
    // No, `a[0].value + a[n-1].value + h` is the largest `diff` value.
    // `a[n-2].value + a[n-1].value` is the largest `same` value.
    //
    // The condition for the "one element alone" strategy to be optimal is when `h` is large.
    // Specifically, if `a[0].value + a[1].value + h` is greater than `a[n-2].value + a[n-1].value`,
    // then all `f` values from different groups are larger than all `f` values from same groups.
    // In this case, `min_f = a[1].value + a[2].value` (from same group)
    // and `max_f = a[0].value + a[n-1].value + h` (from different groups).
    // Goodness = `(a[0].value + a[n-1].value + h) - (a[1].value + a[2].value)`.
    //
    // This is the "large h" case.
    // Let's call this `goodness_large_h`.
    long long goodness_large_h = (a[0].value + a[n - 1].value + h) - (a[1].value + a[2].value);
    std::vector<int> partition_large_h(n);
    partition_large_h[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_large_h[a[i].original_index] = 2;
    }

    // Compare the two strategies
    long long min_goodness = goodness_all_same;
    std::vector<int> best_partition = partition_all_same;

    if (goodness_large_h < min_goodness) {
        min_goodness = goodness_large_h;
        best_partition = partition_large_h;
    }

    // There's a third case: n=2.
    // If n=2, a[0], a[1].
    // All same: f(a[0], a[1]) = a[0]+a[1]. Goodness = 0.
    // One alone: Not possible.
    //
    // My logic for n=2:
    // goodness_all_same: a[n-2]+a[n-1] - (a[0]+a[1]) = a[0]+a[1] - (a[0]+a[1]) = 0. Correct.
    // goodness_large_h: requires a[1] and a[2]. If n=2, a[2] doesn't exist.
    // This means the `goodness_large_h` calculation is only valid for `n >= 3`.
    // If `n=2`, `goodness_all_same` is always 0, which is the minimum possible.
    // So for `n=2`, the answer is always 0 and all elements in one group.
    if (n == 2) {
        min_goodness = 0;
        best_partition.assign(n, 1);
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

