// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case 1: Check for k=1
    // A single cut divides s into s1 and s2.
    // We can form s' = s2s1.
    // We need s' to be a palindrome and s' != s.
    // Iterate through all possible cut positions (i from 1 to n-1)
    // s1 = s.substr(0, i), s2 = s.substr(i)
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case 2: Check for k=2
    // If k=1 is not possible, we need to check if k=2 is possible.
    // This means we need to cut s into 3 pieces.
    // However, the problem statement implies that if a solution exists,
    // it's either k=1 or k=2.
    // The only case where k=1 is not possible but k=2 is,
    // is when all characters in s are the same (e.g., "aaaaa")
    // or when s is a palindrome of the form "ababa" where 'a' and 'b' are distinct,
    // and all prefixes/suffixes are not palindromes themselves.

    // Let's analyze the structure of s.
    // If all characters in s are the same (e.g., "aaaa", "bbbbb"),
    // then any rearrangement of pieces will result in the same string s.
    // For example, "aaaa" cut into "a"|"aa"|"a" and reordered will still be "aaaa".
    // In this case, it's impossible to form a new string s' != s.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 must be the answer.
    // Why? Consider s = "nolon".
    // n=5.
    // i=1: s1="n", s2="olon". s'="olonn". Not palindrome.
    // i=2: s1="no", s2="lon". s'="lonno". Not palindrome.
    // i=3: s1="nol", s2="on". s'="onnol". Not palindrome.
    // i=4: s1="nolo", s2="n". s'="nnolo". Not palindrome.
    // So k=1 is not possible for "nolon".
    //
    // For "nolon", k=2 is possible: "no" | "l" | "on". Rearrange to "on" | "l" | "no" -> "onlno".
    // "onlno" is a palindrome and "onlno" != "nolon".
    //
    // The problem statement guarantees that s is a palindrome.
    // If s is a palindrome and not all its characters are the same,
    // then it's always possible to find a k=2 solution.
    //
    // Consider the string s. Since it's a palindrome and not all characters are the same,
    // there must be at least two distinct characters.
    // Let's take the first half of the string: s.substr(0, n/2).
    // If this substring is not a palindrome, then we can cut s into
    // s.substr(0, n/2) | s.substr(n/2, 1) | s.substr(n/2 + 1)
    // and rearrange.
    //
    // A simpler argument:
    // If s is a palindrome and not all characters are the same,
    // then s must contain at least two distinct characters.
    // For example, "abacaba".
    // Consider the string s' formed by taking the suffix of length n-1 and putting it at the beginning,
    // and the first character at the end.
    // E.g., s = "abacaba". s' = "bacabaa". This is not necessarily a palindrome.
    //
    // The key insight for k=2 is that if k=1 doesn't work, and not all characters are the same,
    // then we can always achieve a new palindrome with 2 cuts.
    // For example, take s = "abacaba".
    // Cut it into s[0] | s.substr(1, n-2) | s[n-1].
    // Since s is a palindrome, s[0] == s[n-1].
    // Let s_mid = s.substr(1, n-2). This is also a palindrome.
    // So we have A | B | A where A=s[0] and B=s.substr(1, n-2).
    // We can rearrange this to A | B | A, which is s.
    //
    // However, we can also cut s into s.substr(0, n/2) | s.substr(n/2)
    // and try to form a new palindrome.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible",
    // then k=2 is the answer.
    // The "Impossible" case is only when all characters are the same.
    //
    // So, if we reach this point, it means k=1 was not possible, and not all characters are the same.
    // This implies k=2 is the answer.
    // Example: "nolon". k=1 fails. Not all chars same. Output 2.
    // Example: "otto". k=1 works ("toot"). Output 1.
    // Example: "qqqq". All chars same. Output Impossible.
    // Example: "kinnikkinnik". k=1 works ("nikkinnikkin"). Output 1.

    // Based on the problem structure and examples, if k=1 is not found
