#include <vector>
#include <algorithm>
#include <set>

long long N, M;
std::vector<long long> H, P;

// Function to check if all tracks can be covered within time 't'
bool check(long long t) {
    // Create a set of all unique positions that need to be covered.
    // This includes initial head positions and target tracks.
    // We only care about target tracks that are not already covered by initial head positions.
    std::set<long long> required_tracks_set;
    for (long long p_val : P) {
        required_tracks_set.insert(p_val);
    }

    // Remove tracks that are already covered by initial head positions
    for (long long h_val : H) {
        required_tracks_set.erase(h_val);
    }

    if (required_tracks_set.empty()) {
        return true; // All required tracks are already covered
    }

    std::vector<long long> required_tracks(required_tracks_set.begin(), required_tracks_set.end());

    // dp[i][j] = minimum rightmost track covered by first i heads,
    // having covered up to required_tracks[j-1]
    // This DP state is too complex. Let's rethink.

    // We need to cover all `required_tracks` using `N` heads.
    // Each head `H[i]` can cover a range `[H[i] - t, H[i] + t]`.
    // This is a greedy approach.
    // For each head, we try to cover as many required tracks as possible,
    // starting from the leftmost uncovered track.

    int current_head_idx = 0;
    int current_track_idx = 0; // Index into `required_tracks`

    while (current_track_idx < required_tracks.size()) {
        if (current_head_idx >= N) {
            return false; // Ran out of heads but still have tracks to cover
        }

        long long head_pos = H[current_head_idx];
        long long target_track = required_tracks[current_track_idx];

        // If the current head cannot reach the current target track,
        // then this 't' is not enough.
        if (target_track < head_pos - t) {
            return false;
        }

        // The current head can reach `target_track`.
        // We want to find the maximum `rightmost_reach` this head can achieve
        // while covering `target_track`.
        // This head can move to `target_track` and then further right.
        // The total time spent is `max(abs(head_pos - target_track), abs(head_pos - rightmost_point))`.
        // If it moves to `target_track` and then to `x`, the time is `max(target_track - head_pos, x - head_pos)` if `x >= target_track >= head_pos`.
        // Or `max(head_pos - target_track, head_pos - x)` if `x <= target_track <= head_pos`.
        // Or `max(head_pos - target_track, x - head_pos)` if `target_track <= head_pos <= x`.
        // Or `max(target_track - head_pos, head_pos - x)` if `x <= head_pos <= target_track`.

        // The key insight for covering a range [L, R] with a head at H_i in time T:
        // The head must move to some point X. The time taken is |H_i - X|.
        // All points between H_i and X are covered.
        // If we want to cover [L, R], we need to find an X such that [L, R] is a subsegment of [min(H_i, X), max(H_i, X)]
        // AND |H_i - X| <= T.
        // This means X must be at least R, and X must be reachable from H_i in time T.
        // So, X must be in [H_i - T, H_i + T].
        // Thus, the head can cover the range [L, R] if:
        // 1. L <= H_i + T
        // 2. R >= H_i - T
        // 3. The time to cover [L, R] from H_i is <= T.
        //    This means max(abs(H_i - L), abs(H_i - R)) <= T.
        //    No, this is not correct. The head moves to one endpoint, say X.
        //    Then all points between H_i and X are covered.
        //    If we want to cover [L, R], the head must move to some X such that
        //    min(H_i, X) <= L and max(H_i, X) >= R.
        //    And |H_i - X| <= T.

        // Let's consider the current head H[current_head_idx].
        // It must cover `required_tracks[current_track_idx]`.
        // The head can move to `required_tracks[current_track_idx]` and then further right.
        // The time taken to reach `required_tracks[current_track_idx]` is `abs(H[current_head_idx] - required_tracks[current_track_idx])`.
        // If this time is already greater than `t`, then this head cannot cover it.
        // We already checked `target_track < head_pos - t`.
        // Also need to check `target_track > head_pos + t`.
        if (target_track > head_pos + t) {
            return false;
        }

        // This head can cover `target_track`.
        // What is the maximum rightmost point this head can cover?
        // Let `x` be the rightmost point covered by this head.
        // The time taken is `max(abs(head_pos - target_track), abs(head_pos - x))`.
        // This must be `<= t`.
        // So, `abs(head_pos - x) <= t` AND `abs(head_pos - target_track) <= t`.
        // The second part is already checked.
        // From `abs(head_pos - x) <= t`, we know `x` can be at most `head_pos + t`.
        // Also, `x` must be at least `target_track`.
        // So, `x` can be any point in `[target_track, head_pos + t]`.
        // However, the time constraint is `max(abs(head_pos - target_track), abs(head_pos - x)) <= t`.
        // This means `abs(head_pos - x) <= t` AND `abs(head_pos - target_track) <= t`.
        // The rightmost point `x` that can be covered by this head, starting from `head_pos` and covering `target_track`,
        // is `head_pos + t` if `target_track <= head_pos`.
        // If `target_track > head_pos`, then the head must move right to `target_track`.
        // The time spent is `target_track - head_pos`.
        // If `target_track - head_pos > t`, it's impossible (already checked).
        // If `target_track - head_pos <= t`, then the head has `t - (target_track - head_pos)` time remaining
        // to move further right from `target_track`.
        // So, it can reach `target_track + (t - (target_track - head_pos)) = head_pos + t`.
        // This is the maximum rightmost point it can reach.
        // So, the rightmost point covered by this head is `head_pos + t`.

        // This is not quite right. The head can move to `X` and cover `[min(H_i, X), max(H_i, X)]`.
        // We need to cover `required_tracks[current_track_idx]`.
        // Let `L = required_tracks[current_track_idx]`.
        // The head at `H[current_head_idx]` can cover `L` if `abs(H[current_head_idx] - L) <= t`.
        // If it covers `L`, it can also cover points to its right.
        // The maximum rightmost point it can cover is `H[current_head_idx] + t`.
        // This is true if `L` is between `H[current_head_idx] - t` and `H[current_head_idx] + t`.
        // The actual rightmost point it can cover is `H[current_head_idx] + t`.
        // This is the simplest interpretation.
        // The head moves to some point `X` such that `|H_i - X| <= t`.
        // All points in `[min(H_i, X), max(H_i, X)]` are covered.
        // To cover `L = required_tracks[current_track_idx]`, we need `min(H_i, X) <= L <= max(H_i, X)`.
        // And `|H_i - X| <= t`.
        // We want to maximize `max(H_i, X)`. This is achieved when `X = H_i + t`.
        // So the range covered is `[H_i - t, H_i + t]`.
        // This is the standard interpretation for "a head can cover any point in [H_i - T, H_i + T]".
        // Let's use this.

        long long current_head_reach = head_pos + t;

        // Advance `current_track_idx` as long as tracks are within reach of the current head.
        while (current_track_idx < required_tracks.size() && required_tracks[current_track_idx] <= current_head_reach) {
            current_track_idx++;
        }
        current_head_idx++; // Move to the next head
    }

    return true; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N >> M;

    H.resize(N);
    for (int i = 0; i < N; ++i) {
        std::cin >> H[i];
    }

    P.resize(M);
    for (int i = 0; i < M; ++i) {
        std::cin >> P[i];
    }

    long long low = 0;
    // Max possible time: distance from H[0] to P[M-1] or H[N-1] to P[0].
    // A safe upper bound is 2 * 10^10 (max coordinate value).
    // Or, max(abs(H[0] - P[M-1]), abs(H[N-1] - P[0]))
    // A tighter bound: max(P[M-1] - H[0], H[N-1] - P[0]) if P[M-1] > H[0] and H[N-1] > P[0]
    // Max coordinate is 10^10. So max diff is 10^10.
    long long high = 20000000000LL; // 2 * 10^10, a safe upper bound
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

