// Z-algorithm implementation
std::vector<int> calculate_z_function(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    for (int i = 1, l = 0, r = 0; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-values for all suffixes of s
    // z_values[i][j] will store Z-value for string s.substr(i) + '#' + s.substr(j)
    // This is equivalent to Z-value for s.substr(j) in s.substr(i) + '#' + s.substr(j)
    // which is the length of the longest common prefix of s.substr(i) and s.substr(j).
    // Let's call this LCP(i, j).
    // LCP(i, j) = Z_function(s.substr(j) + '#' + s.substr(i))[s.length() + 1]
    // Or, more simply, LCP(i, j) = Z_function(s.substr(i) + '$' + s.substr(j))[L+1]
    // Or, even better, LCP(i, j) = Z_function(s.substr(i) + s)[L+1+j]
    // No, this is not right. LCP(i, j) is the length of the longest common prefix of s[i..L-1] and s[j..L-1].
    // We need LCP(s[i..], s[j..])
    // This can be computed by building a string s[i..L-1] + '#' + s[j..L-1] and running Z-algo.
    // Or, more efficiently, by building s + '#' + s and using Z-algo on that.
    // Z_s_s[k] = LCP(s, s.substr(k))
    // We need LCP(s.substr(i), s.substr(j)).
    // This is Z_s_s[j-i] if j >= i.
    // If j < i, it's Z_s_s[i-j].
    // No, this is not correct. LCP(s.substr(i), s.substr(j)) is the length of the longest common prefix of s[i..] and s[j..].
    // Let's compute LCP(i, j) for all i, j.
    // LCP(i, j) = Z_function(s.substr(i) + '#' + s.substr(j))[s.length() - i + 1]
    // This is too slow. O(L^3).

    // A better way to compute LCP(i, j) for all i, j:
    // For each i, compute Z-function for s.substr(i) + s.
    // Z_values_for_suffix_i[k] = LCP(s.substr(i), s.substr(k))
    // This is Z_function(s.substr(i) + '#' + s)[L-i+1+k]
    // No, this is Z_function(s.substr(i) + '#' + s)[L-i+1+k]
    // Let's use a standard LCP array construction from suffix array, or just compute Z-function for each suffix.
    // For each starting position `start_idx` from 0 to L-1:
    //   Construct `temp_s = s.substr(start_idx) + s.substr(0, start_idx)`
    //   Compute Z-function for `temp_s`.
    //   `z_values_for_shifted_s[start_idx][k]` would be `z[k]` for this `temp_s`.
    // This is also too slow. O(L^2 * L) = O(L^3).

    // The problem asks for LCP(s[k..], s[k'..])
    // This is LCP(s.substr(k), s.substr(k'))
    // We can compute LCP(i, j) for all i, j in O(L^2) using a sparse table or by iterating.
    // LCP(i, j) is the length of the longest common prefix of s[i..] and s[j..].
    // LCP(i, j) = 0 if s[i] != s[j].
    // LCP(i, j) = 1 + LCP(i+1, j+1) if s[i] == s[j].
    // This can be computed in O(L^2) using dynamic programming.
    std::vector<std::vector<int>> lcp(L + 1, std::vector<int>(L + 1, 0));
    for (int i = L - 1; i >= 0; --i) {
        for (int j = L - 1; j >= 0; --j) {
            if (s[i] == s[j]) {
                lcp[i][j] = 1 + lcp[i + 1][j + 1];
            } else {
                lcp[i][j] = 0;
            }
        }
    }

    double total_win_prob = 0.0;

    // Iterate over all possible first characters t[0]
    for (char char_0 = 'a'; char_0 <= 'z'; ++char_0) {
        std::vector<int> possible_k_for_char_0;
        for (int k = 0; k < L; ++k) {
            if (s[k] == char_0) {
                possible_k_for_char_0.push_back(k);
            }
        }

        if (possible_k_for_char_0.empty()) {
            continue; // This char_0 never appears as t[0]
        }

        // If only one k matches char_0, Vasya wins for sure if this char_0 is revealed.
        // But this is not how it works. Vasya doesn't know k. He knows t[0].
        // He needs to choose p to maximize win probability for THIS char_0.
        // The probability of this char_0 being revealed is (count of k where s[k]=char_0) / L.
        // Then, given this char_0, he chooses p.

        double max_win_prob_for_char_0 = 0.0;

        // Iterate over all possible positions p (from 1 to L-1)
        for (int p = 1; p < L; ++p) {
            int num_k_win_for_p = 0; // Number of k values for which Vasya wins with this p

            for (int k_actual : possible_k_for_char_0) {
                char char_p = s[(p + k_actual) % L];

                int num_matches = 0;
                for (int k_candidate : possible_k_for_char_0) {
                    if (s[(p + k_candidate) % L] == char_p) {
                        num_matches++;
                    }
                }

                if (num_matches == 1) {
                    num_k_win_for_p++;
                }
            }
            // Probability of winning given char_0 and chosen p
            // is (number of k_actual that lead to unique determination) / (total number of k_actual for char_0)
            if (!possible_k_for_char_0.empty()) {
                max_win_prob_for_char_0 = std::max(max_win_prob_for_char_0, 
                                                   (double)num_k_win_for_p / possible_k_for_char_0.size());
            }
        }

        // The probability of char_0 being revealed is possible_k_for_char_0.size() / L.
        total_win_prob += max_win_prob_for_char_0 * (possible_k_for_char_0.size() / (double)L);
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob << std::endl;

    return 0;
}

