        long long min_val = a[0];
        long long total_spells = 0;

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0), we want to add min_val to it
            // as many times as possible without exceeding k.
            // The current value of a[i] is a[i].
            // We can add min_val until a[i] + min_val * count > k.
            // So, a[i] + min_val * count <= k
            // min_val * count <= k - a[i]
            // count <= (k - a[i]) / min_val

            if (a[i] >= k) { // If a[i] is already k or more, we can't add anything to it.
                             // The problem states a_i <= k initially, but if k-a[i] is 0,
                             // then (k-a[i])/min_val would be 0.
                             // This check is technically redundant if a[i] <= k, but good for robustness.
                continue;
            }

            long long remaining_capacity = k - a[i];
            long long spells_for_this_pile = remaining_capacity / min_val;
            total_spells += spells_for_this_pile;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[a[i].original_index] = a[i].value;
            y[a[i].original_index] = b[(i + n - 1) % n].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long ans = 0;

        // Greedy approach for denominations 1, 2, 5
        // This works because 1, 2, 5 form a canonical coin system.
        // For example, if diff % 5 is 3, we can use 1+2 or 1+1+1.
        // If diff % 5 is 4, we can use 2+2 or 1+1+1+1.
        // The greedy choice for 5s, then 2s, then 1s is optimal.

        ans += diff / 5;
        diff %= 5;

        if (diff == 0) {
            // No remaining difference
        } else if (diff == 1) {
            // Can be 1 (1 press)
            // Or 5-2-2 (3 presses) - worse
            // Or 5-2-1-1-1 (5 presses) - worse
            // Or 2-1 (2 presses) - worse
            ans += 1;
        } else if (diff == 2) {
            // Can be 2 (1 press)
            // Or 1+1 (2 presses) - worse
            ans += 1;
        } else if (diff == 3) {
            // Can be 1+2 (2 presses)
            // Or 1+1+1 (3 presses) - worse
            // Or 5-2 (2 presses)
            ans += 2;
        } else if (diff == 4) {
            // Can be 2+2 (2 presses)
            // Or 1+1+2 (3 presses) - worse
            // Or 1+1+1+1 (4 presses) - worse
            // Or 5-1 (2 presses)
            ans += 2;
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, n up to 100. Max cost is 99. Max haybales 100. 100*99 = 9900. d can be 100.
                     // The problem statement says d <= 100. So d fits in int.
                     // However, the sum of costs can exceed int if d was larger.
                     // Let's stick to int for d as per constraints.
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Use long long for current_a1 to be safe, though max is 100 + 100*100 = 10100, fits int.

        for (int i = 1; i < n; ++i) { // Iterate through piles from index 1 (pile 2) to n-1 (pile n)
            int pile_idx = i + 1; // 1-based index of the current pile
            int cost_per_haybale = pile_idx - 1; // Days to move one haybale from pile_idx to pile 1

            if (cost_per_haybale == 0) { // This should only happen for pile 1 itself, which we skip.
                                         // But as a safeguard, if somehow cost is 0, it means infinite moves.
                continue;
            }

            // Calculate how many haybales we can move from this pile
            // based on remaining days.
            long long max_haybales_from_this_pile_by_days = d / cost_per_haybale;

            // We can move at most a[i] haybales from this pile.
            long long haybales_to_move = std::min((long long)a[i], max_haybales_from_this_pile_by_days);

            current_a1 += haybales_to_move;
            d -= haybales_to_move * cost_per_haybale;

            if (d <= 0) { // If we run out of days, no more moves are possible
                break;
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    // Simulate the merging process
    // We only care about numbers up to 2048.
    // Numbers larger than 2048 are not useful for forming 2048.
    // If 2048 is already present, we win.
    // Otherwise, we try to form it by combining smaller powers of two.
    // We iterate from the smallest power of two (1) up to 1024.
    // For each power of two, we combine pairs to form the next higher power.
    // For example, two 1s make a 2, two 2s make a 4, etc.
    // The order of combination doesn't matter for the final sum of values,
    // but it matters for the counts of specific powers of two.
    // Combining smaller numbers first is a greedy strategy that works
    // because it maximizes the number of larger powers of two we can form.
    // Any two numbers of value X can be combined into 2X.
    // This means if we have `k` numbers of value `X`, we can form `k/2` numbers of value `2X`.
    // The remaining `k % 2` numbers of value `X` cannot be combined further.

    for (int p = 1; p < 2048; p *= 2) {
        if (counts[p] > 0) {
            // Number of pairs of 'p' that can be combined
            int num_pairs = counts[p] / 2;
            if (num_pairs > 0) {
                // Add the resulting '2p' values to the count of '2p'
                counts[2 * p] += num_pairs;
            }
        }
    }

    if (counts[2048] > 0) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

