#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to minimize the absolute difference between the medians of two classes.
        // Each class must have an odd number of students.
        // Let the sorted skill levels be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the case where class 1 has size 1 and class 2 has size 2n-1.
        // Class 1 median: a_i (any student).
        // Class 2 median: (2n-1) students. If sorted, median is at index (2n-1-1)/2 = n-1.
        //
        // Consider the case where class 1 has size 2k+1 and class 2 has size 2n-(2k+1).
        // The smallest possible median for a class of size 2k+1 is a_k.
        // The largest possible median for a class of size 2k+1 is a_{2n-1-k}.
        //
        // It can be shown that to minimize the difference, we should pick the median of one class
        // to be a_i and the median of the other class to be a_j, such that i and j are "close".
        //
        // The optimal strategy is to assign the first n elements to one class and the last n elements to the other class.
        // More precisely, if we sort all 2n students' skills: a_0, a_1, ..., a_{2n-1}.
        //
        // We can form two classes:
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // This partition is not valid because each class has n students, which might be even.
        // The problem states each class must have an odd number of students.
        //
        // Let's re-evaluate.
        // The key insight for this type of problem is often that the sorted array provides the bounds.
        // If we have a sorted array $a_0, \dots, a_{2n-1}$, and we need to pick $S_1$ students for class 1
        // and $S_2$ students for class 2, where $S_1, S_2$ are odd and $S_1+S_2=2n$.
        //
        // The median of a class of size $2k+1$ is the $(k+1)$-th element.
        //
        // Consider the two "middle" elements in the sorted array: $a_{n-1}$ and $a_n$.
        //
        // If we assign $a_{n-1}$ to one class and $a_n$ to the other class, can we always make them medians?
        //
        // Let's try to make $a_{n-1}$ the median of Class 1 and $a_n$ the median of Class 2.
        //
        // To make $a_{n-1}$ the median of Class 1:
        // Class 1 must have $2k_1+1$ students. $a_{n-1}$ must be the $(k_1+1)$-th element.
        // This means $k_1$ elements must be $\le a_{n-1}$ and $k_1$ elements must be $\ge a_{n-1}$.
        // We have $n-1$ elements $a_0, \dots, a_{n-2}$ that are $\le a_{n-1}$.
        // We have $n$ elements $a_n, \dots, a_{2n-1}$ that are $\ge a_{n-1}$.
        //
        // To make $a_n$ the median of Class 2:
        // Class 2 must have $2k_2+1$ students. $a_n$ must be the $(k_2+1)$-th element.
        // This means $k_2$ elements must be $\le a_n$ and $k_2$ elements must be $\ge a_n$.
        // We have $n$ elements $a_0, \dots, a_{n-1}$ that are $\le a_n$.
        // We have $n-1$ elements $a_{n+1}, \dots, a_{2n-1}$ that are $\ge a_n$.
        //
        // Consider the partition where Class 1 consists of $a_0, \dots, a_{n-1}$ and Class 2 consists of $a_n, \dots, a_{2n-1}$.
        // This is not valid as each class has $n$ students.
        //
        // The problem is simpler than trying to construct the classes.
        // The minimum possible difference is always $a_n - a_{n-1}$.
        //
        // Let's prove this.
        // We need to show that we can always construct two classes, each of odd size,
        // such that one median is $a_{n-1}$ and the other median is $a_n$.
        //
        // Class 1: Take $a_{n-1}$ as its median.
        // We need $k_1$ elements smaller than or equal to $a_{n-1}$ and $k_1$ elements greater than or equal to $a_{n-1}$.
        // We can pick $k_1$ elements from $a_0, \dots, a_{n-2}$ (there are $n-1$ such elements).
        // We can pick $k_1$ elements from $a_n, \dots, a_{2n-1}$ (there are $n$ such elements).
        //
        // Class 2: Take $a_n$ as its median.
        // We need $k_2$ elements smaller than or equal to $a_n$ and $k_2$ elements greater than or equal to $a_n$.
        // We can pick $k_2$ elements from $a_0, \dots, a_{n-1}$ (there are $n$ such elements).
        // We can pick $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ (there are $n-1$ such elements).
        //
        // Let's try to make Class 1 have $a_{n-1}$ as median and Class 2 have $a_n$ as median.
        //
        // Consider the partition:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // This is not valid if $n$ is even.
        //
        // If $n$ is odd:
        // Class 1 has $n$ students. Median is $a_{(n-1)/2}$.
        // Class 2 has $n$ students. Median is $a_{n + (n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler: the minimum difference is always $a_n - a_{n-1}$.
        // This is because $a_{n-1}$ is the largest possible median for a class of size $2k+1$ that uses only elements from $a_0, \dots, a_{n-1+k}$.
        // And $a_n$ is the smallest possible median for a class of size $2k+1$ that uses only elements from $a_{n-k}, \dots, a_{2n-1}$.
        //
        // More formally:
        // Let $M_1$ be the median of Class 1 and $M_2$ be the median of Class 2.
        // Let $S_1$ be the set of students in Class 1, $S_2$ for Class 2.
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$.
        //
        // $M_1$ must be one of the $a_i$'s. $M_2$ must be one of the $a_j$'s.
        //
        // Consider the $n$-th element $a_{n-1}$ (0-indexed) and $(n+1)$-th element $a_n$.
        //
        // We can always form Class 1 with $a_{n-1}$ as its median and Class 2 with $a_n$ as its median.
        //
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$ and $n$ students from $\{a_n, \dots, a_{2n-1}\}$
        // This is not how it works.
        //
        // The crucial observation is that if we sort all $2n$ students, $a_0, \dots, a_{2n-1}$,
        // then any median of any class must be one of these $a_i$.
        //
        // Let $M_A$ be the median of class A and $M_B$ be the median of class B.
        // Suppose $M_A < M_B$.
        //
        // For $M_A$ to be the median of class A (size $2k_A+1$), there must be at least $k_A$ elements in class A that are $\le M_A$
        // and at least $k_A$ elements in class A that are $\ge M_A$.
        //
        // For $M_B$ to be the median of class B (size $2k_B+1$), there must be at least $k_B$ elements in class B that are $\le M_B$
        // and at least $k_B$ elements in class B that are $\ge M_B$.
        //
        // Total students $2n = (2k_A+1) + (2k_B+1) = 2(k_A+k_B+1)$. So $n = k_A+k_B+1$.
        //
        // The total number of students less than or equal to $M_A$ is at most $n-1$ (if $M_A = a_{n-1}$).
        // The total number of students greater than or equal to $M_B$ is at most $n-1$ (if $M_B = a_n$).
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // It is always possible to construct two classes such that one median is $a_{n-1}$ and the other is $a_n$.
        //
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$ and $n$ students from $\{a_n, \dots, a_{2n-1}\}$
        // This is not how it works.
        //
        // The simplest way to achieve this is to make Class 1 consist of $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // The minimum difference is $a_n - a_{n-1}$.
        //
        // Example 1: n=1, a = [1, 1]. Sorted: [1, 1]. n-1=0, n=1. a[0]=1, a[1]=1. Diff = 1-1=0. Correct.
        // Example 2: n=3, a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6]. n-1=2, n=3. a[2]=3, a[3]=4. Diff = 4-3=1. Correct.
        // Example 3: n=5, a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16]. Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // n-1=4, n=5. a[4]=8, a[5]=13. Diff = 13-8=5. Correct.
        //
        // The logic is that $a_{n-1}$ is the largest possible median for a class that is "left-leaning" (i.e., mostly uses smaller elements),
        // and $a_n$ is the smallest possible median for a class that is "right-leaning" (i.e., mostly uses larger elements).
        //
        // To achieve $a_{n-1}$ as median for Class 1:
        // We need $k_1$ elements $\le a_{n-1}$ and $k_1$ elements $\ge a_{n-1}$.
        // We can pick $k_1$ elements from $a_0, \dots, a_{n-2}$ (there are $n-1$ available).
        // We can pick $k_1$ elements from $a_n, \dots, a_{2n-1}$ (there are $n$ available).
        //
        // To achieve $a_n$ as median for Class 2:
        // We need $k_2$ elements $\le a_n$ and $k_2$ elements $\ge a_n$.
        // We can pick $k_2$ elements from $a_0, \dots, a_{n-1}$ (there are $n$ available).
        // We can pick $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$ (there are $n-1$ available).
        //
        // We need to ensure that the chosen elements for Class 1 and Class 2 are disjoint and cover all $2n$ students.
        //
        // Let's try to construct a valid partition for $a_{n-1}$ and $a_n$ as medians.
        //
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // This partition has $n$ students in each class.
        // If $n$ is odd, then this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$. Median of Class 2 is $a_{n+(n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler. The minimum difference is always $a_n - a_{n-1}$.
        // This is a known property for problems involving medians and partitions.
        // The two medians must "cross" the middle of the sorted array.
        // One median must be $\le a_{n-1}$ and the other must be $\ge a_n$.
        //
        // Proof sketch:
        // Let $M_1$ and $M_2$ be the medians of the two classes. Assume $M_1 \le M_2$.
        // Let Class 1 have $2k_1+1$ students and Class 2 have $2k_2+1$ students.
        // $k_1+k_2+1 = n$.
        //
        // For $M_1$ to be the median of Class 1, there must be at least $k_1$ students in Class 1 with skill $\le M_1$
        // and at least $k_1$ students in Class 1 with skill $\ge M_1$.
        //
        // For $M_2$ to be the median of Class 2, there must be at least $k_2$ students in Class 2 with skill $\le M_2$
        // and at least $k_2$ students in Class 2 with skill $\ge M_2$.
        //
        // Consider the $n$ smallest students $a_0, \dots, a_{n-1}$.
        // Consider the $n$ largest students $a_n, \dots, a_{2n-1}$.
        //
        // The total number of students with skill $\le M_1$ is at least $k_1+k_2$ (if $M_1 \le M_2$).
        // This is not quite right.
        //
        // The total number of students with skill $\le M_1$ is at least $k_1$.
        // The total number of students with skill $\ge M_2$ is at least $k_2$.
        //
        // If $M_1$ is $a_i$ and $M_2$ is $a_j$.
        // $i \le n-1$ and $j \ge n$.
        //
        // Suppose $M_1 > a_{n-1}$. Then $M_1 \ge a_n$.
        // Suppose $M_2 < a_n$. Then $M_2 \le a_{n-1}$.
        //
        // If $M_1 \ge a_n$ and $M_2 \le a_{n-1}$, then $M_1 \ge M_2$.
        //
        // The minimum difference is achieved when $M_1 = a_{n-1}$ and $M_2 = a_n$.
        //
        // We need to show that such a partition is always possible.
        //
        // Let Class 1 be $\{a_0, \dots, a_{n-1}\}$ and Class 2 be $\{a_n, \dots, a_{2n-1}\}$.
        // This is not valid if $n$ is even.
        //
        // Let's try to make Class 1 have $a_{n-1}$ as median and Class 2 have $a_n$ as median.
        //
        // Class 1: $a_{n-1}$ is the median. It needs $k_1$ elements $\le a_{n-1}$ and $k_1$ elements $\ge a_{n-1}$.
        // We can pick $k_1$ elements from $\{a_0, \dots, a_{n-2}\}$ and $k_1$ elements from $\{a_n, \dots, a_{2n-1}\}$.
        //
        // Class 2: $a_n$ is the median. It needs $k_2$ elements $\le a_n$ and $k_2$ elements $\ge a_n$.
        // We can pick $k_2$ elements from $\{a_0, \dots, a_{n-1}\}$ and $k_2$ elements from $\{a_{n+1}, \dots, a_{2n-1}\}$.
        //
        // Let's try to construct a specific partition.
        //
        // Class A: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class B: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // Each class has $n$ students. If $n$ is odd, this is a valid partition.
        // Median of Class A is $a_{(n-1)/2}$. Median of Class B is $a_{n+(n-1)/2}$.
        // The difference is $a_{n+(n-1)/2} - a_{(n-1)/2}$. This is not $a_n - a_{n-1}$.
        //
        // The problem is simpler. The minimum difference is always $a_n - a_{n-1}$.
        // This is a standard result for this type of problem.
        // The two medians must "straddle" the middle of the sorted array.
        // One median must be $a_i$ where $i < n$, and the other must be $a_j$ where $j \ge n$.
        // To minimize $a_j - a_i$, we pick $i=n-1$ and $j=n$.
        //
        // Why can we always achieve this?
        // Let Class 1 be $\{a_0, a_1, \dots, a_{n-1}\}$ and Class 2 be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is not a valid partition if $n$ is even.
        //
        // Consider the partition:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        //
        // The problem statement implies that we can choose the sizes of the classes.
        // Let $S_1 = 1$ and $S_2 = 2n-1$. Both are odd.
        // Class 1: $\{a_{n-1}\}$. Median is $a_{n-1}$.
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // This class has $2n-1$ students. Its median is the $(n)$-th element.
        // The elements are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // Sorted, these are $a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}$.
        // The $n$-th element (0-indexed) is $a_n$.
        // So, we can form Class 1 = $\{a_{n-1}\}$ (median $a_{n-1}$) and Class 2 = $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (median $a_n$).
        // The difference is $|a_n - a_{n-1}|$.
        // This construction is always valid.
        //
        // Therefore, the minimum possible absolute difference is $a_n - a_{n-1}$.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

