#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        // If n is 2, and a[i][j] is 1, then p[i] could be 1 or 2.
        // If p[i] is 1, then max_val_in_row would be 1.
        // If p[i] is 2, then max_val_in_row would be 1.
        // The problem guarantees a solution exists.
        // If max_val_in_row is n-1, it means p[i] must be n.
        // If max_val_in_row is less than n-1, it means p[i] must be max_val_in_row.
        // This logic is based on the observation that if p[i] is not n, then there must be some p[j] > p[i].
        // In that case, min(p[i], p[j]) = p[i]. So max_val_in_row would be p[i].
        // If p[i] is n, then for all j, min(p[i], p[j]) = p[j].
        // So max_val_in_row would be max(p[j] for j != i), which is n-1.
        // So, if max_val_in_row == n-1, then p[i] = n.
        // Otherwise, p[i] = max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n == 0) { // Edge case: no days
            std::cout << 0 << "\n";
            continue;
        }

        // min_suffix_price will store the minimum price encountered
        // from the current position to the end of the array.
        // Initialize with the last element's price, as it's the minimum
        // for the suffix starting at n-1 (which is just a[n-1]).
        // The last day's price can never be bad, as there are no later days.
        int min_suffix_price = a[n - 1];
        int bad_prices_count = 0;

        // Iterate from the second to last day down to the first day.
        // For each day i, we compare a[i] with min_suffix_price,
        // which holds the minimum of a[i+1], ..., a[n-1].
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price,
                // it means a[i] is either equal to or less than
                // the current minimum in the suffix.
                // So, a[i] itself becomes the new minimum for the
                // suffix starting at i.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

