        int last_R_idx = -1; // Represents the position of the last 'R' or the starting point 0.
                             // Initialized to -1 to correctly calculate gap from 0 to first 'R' or n+1.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_gap = std::max(max_gap, i - last_R_idx);
                last_R_idx = i;
            }
        }
        // After iterating through the string, calculate the gap from the last 'R' to n+1.
        // If no 'R' was found, last_R_idx remains -1, and this calculates gap from 0 to n+1.
        max_gap = std::max(max_gap, (int)s.length() - last_R_idx);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for n=1 staircase
        long long n_val = 1;        // n for the current staircase
        while (x >= current_cost) {
            count++;
            x -= current_cost;
            n_val = n_val * 2 + 1; // Next n for a nice staircase (1, 3, 7, 15, ...)
            // Calculate cost for the next staircase with n_val stairs
            // Cost = n_val * (n_val + 1) / 2
            // This can be written as (n_val * n_val + n_val) / 2
            // Or, more simply, current_cost = 2 * current_cost + (n_val+1)/2
            // Let C(n) be the cost for n stairs.
            // C(n) = n(n+1)/2
            // C(2n+1) = (2n+1)(2n+2)/2 = (2n+1)(n+1) = 2n^2 + 3n + 1
            // C(n) = n^2/2 + n/2
            // C(2n+1) = 2n^2 + 3n + 1
            // The difference is C(2n+1) - C(n) = 3/2 n^2 + 5/2 n + 1
            // This is not simple.
            // Let's use the formula for current_cost directly.
            // The sequence of n values is 1, 3, 7, 15, ... which is 2^k - 1.
            // The sequence of costs is C(1)=1, C(3)=6, C(7)=28, C(15)=120, ...
            // Let's observe the pattern of costs:
            // C(1) = 1
            // C(3) = 6 = 2*C(1) + 4
            // C(7) = 28 = 2*C(3) + 16
            // C(15) = 120 = 2*C(7) + 64
            // The added term is 4, 16, 64, ... which is (2^k)^2.
            // For n_k = 2^k - 1, the cost is C(n_k).
            // C(n_{k+1}) = C(2n_k + 1) = 2 * C(n_k) + (n_k + 1)^2
            // Since n_k + 1 = 2^k, (n_k + 1)^2 = (2^k)^2 = 2^(2k) = 4^k.
            // So, current_cost_new = 2 * current_cost_old + (n_val_old + 1)^2
            // where n_val_old is the previous n_val.
            // Let's use n_val for the current n (e.g., 1, then 3, then 7).
            // When n_val is 1, current_cost is 1.
            // Next n_val will be 3. The previous n_val was 1.
            // So, current_cost = 2 * 1 + (1+1)^2 = 2 + 4 = 6. Correct.
            // Next n_val will be 7. The previous n_val was 3.
            // So, current_cost = 2 * 6 + (3+1)^2 = 12 + 16 = 28. Correct.
            current_cost = 2 * current_cost + (n_val / 2 + 1) * (n_val / 2 + 1);
        }
        std::cout << count << "\n";
    }
    return 0;
}

