int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The number of teams k must satisfy:
        // 1. k <= c (at least k coders needed)
        // 2. k <= m (at least k mathematicians needed)
        // 3. 3 * k <= c + m + x (total students needed)
        // So, k <= min(c, m, (c + m + x) / 3)
        // This minimum is the upper bound for k.
        // We can always form k teams if this condition holds.
        // For each team, we use 1 coder, 1 mathematician, and 1 other student.
        // The 'other student' can be a coder, mathematician, or non-specialized.
        // If we have k teams, we use k coders and k mathematicians.
        // The remaining students are (c - k) coders, (m - k) mathematicians, and x non-specialized.
        // The total number of remaining students is (c - k) + (m - k) + x.
        // Each team needs 3 members. We've already assigned 2 (1 coder, 1 mathematician).
        // So, each team needs 1 more member. We need k more members in total.
        // The total available 'other' students are (c - k) + (m - k) + x.
        // We need to check if k <= (c - k) + (m - k) + x.
        // This simplifies to 3k <= c + m + x.
        // So, the conditions k <= c, k <= m, and k <= (c + m + x) / 3 are sufficient.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

