    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top part (triangle from apex to i-th cut)
        // should be i times the area of one piece.
        // Total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n.
        // Area of top i pieces = i * (h/2) / n = (i * h) / (2n).
        //
        // For a triangle with height x and base b_x, similar to the main triangle:
        // b_x / x = 1 / h  => b_x = x / h
        // Area_x = (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).
        //
        // We want Area_x = (i * h) / (2n).
        // So, x^2 / (2h) = (i * h) / (2n).
        // x^2 = (i * h^2) / n.
        // x = sqrt((i * h^2) / n) = h * sqrt(i / n).

        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
