#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The strategy is to reverse the permutation.
    // Let p' be the reversed permutation of p.
    // p'_i = p_{n-i+1}
    // The adjacent sums for p are: p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n
    // The adjacent sums for p' are: p'_1+p'_2, p'_2+p'_3, ..., p'_{n-1}+p'_n
    // which are: p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1
    // These are exactly the same set of sums, just in reverse order.
    // Sorting them will yield the same fingerprint.
    //
    // We need to ensure p' != p.
    // If p is a palindrome (p_i = p_{n-i+1} for all i), then p' would be equal to p.
    // However, a permutation of length n consists of distinct integers from 1 to n.
    // For p to be a palindrome, p_1 must be p_n, p_2 must be p_{n-1}, etc.
    // This is only possible if n=1 (which is not allowed, n>=2) or if the elements are not distinct.
    // For example, if n=2, p=[1,2], p'=[2,1]. p!=p'.
    // If n=3, p=[1,2,3], p'=[3,2,1]. p!=p'.
    // If n=4, p=[1,2,3,4], p'=[4,3,2,1]. p!=p'.
    //
    // A permutation cannot be a palindrome unless n=1.
    // For n >= 2, p_1 and p_n must be distinct (since 1 and n are distinct, and p is a permutation of 1..n).
    // If p_1 = p_n, then p is not a permutation.
    // Thus, p_1 != p_n for any permutation of length n >= 2.
    // Since p'_1 = p_n and p_1 != p_n, it implies p'_1 != p_1.
    // Therefore, p' is always different from p for n >= 2.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

