#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used for the k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is achieved by alternating between left and right pointers
    // The sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // Differences: k, k-1, k-2, ..., 1
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // For the remaining n - (k+1) elements, just append them in increasing order
    // starting from the next available number.
    // This ensures that the differences generated by these elements are small (1)
    // and do not introduce new distinct differences if k < n-1.
    // The numbers used so far are 1, ..., left-1 and right+1, ..., k+1.
    // The next available number is 'left' (which is now (k+1)/2 + 1 or similar).
    // The numbers from k+2 to n have not been used yet.
    // We can simply append them in increasing order.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

