#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    int p = n - 1;
    while (p > 0 && a[p - 1] <= a[p]) {
        p--;
    }

    // Find the rightmost index `q` such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // If p is 0, then the whole array is non-decreasing, so q would be 0.
    // If p is 1, then a[0] <= a[1]...a[n-1] is non-decreasing.
    // If p is n-1, then a[n-1] is the start of the non-decreasing suffix.
    // The segment a[q...p-1] is the "valley" part.
    int q = p;
    while (q > 0 && a[q - 1] >= a[q]) {
        q--;
    }

    std::cout << q << std::endl;
}

