#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For a to be real, d^2 - 4d >= 0
            // d(d - 4) >= 0
            // Since d >= 0, this implies d - 4 >= 0, so d >= 4.
            // If d = 0, it's a special case handled above.
            // If d >= 4, then d^2 - 4d is non-negative.

            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);

            // Solutions for 'a' are (d +/- sqrt_discriminant) / 2
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = d - a1; // b = d - a

            // We need a, b to be non-negative.
            // Since d >= 4, d is positive.
            // sqrt_discriminant = sqrt(d(d-4)).
            // If d >= 4, then d-4 >= 0, so sqrt_discriminant >= 0.
            // Thus, d + sqrt_discriminant >= d > 0, so a1 > 0.
            // For b1 = d - a1 = d - (d + sqrt_discriminant) / 2 = (2d - d - sqrt_discriminant) / 2 = (d - sqrt_discriminant) / 2.
            // We need d - sqrt_discriminant >= 0, which means d >= sqrt_discriminant.
            // Squaring both sides (both are non-negative): d^2 >= d^2 - 4d.
            // This simplifies to 0 >= -4d, or 4d >= 0, which is true for d >= 0.
            // So, both a1 and b1 are guaranteed to be non-negative when d >= 4.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

