int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for elements to be placed (the 'b' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for original positions (the 'a' array elements)
        // We are trying to find an element a[j] from the sorted array
        // to place at a position originally occupied by a[i] (also from sorted array)
        // such that a[j] > a[i].
        // Since both arrays are sorted, we can use a two-pointer approach.
        // If a[j] > a[i], we found a valid pair. Increment count and advance both pointers.
        // If a[j] <= a[i], a[j] is too small for a[i]. We need a larger element for a[i],
        // so we advance j to consider the next larger element from the pool.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // If we found an element a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'b' pool
        } else {
            // If j reaches n, it means all remaining elements in the 'b' pool
            // are less than or equal to a[i] (or we ran out of elements).
            // No more matches can be made for current a[i] or subsequent a[k] (k > i).
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(A.begin(), A.end(), compareElementA);

    // Sort B in ascending order
    std::sort(B.begin(), B.end(), compareElementB);

    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means A_i' should be sorted in the same order as B_i.
    // Since we want to output A' in the original order of B,
    // we need to map the sorted A values back to the original indices of B.

    // Create the result array A_prime, initialized with dummy values
    std::vector<long long> A_prime(m);

    // A is sorted ascending. B is sorted ascending.
    // To maximize sum F(A'_i, B_i), we need to pair largest A with largest B, etc.
    // This means A'_i should be sorted in the same order as B_i.
    // So, if B_j is the k-th smallest B value, then A'_j should be the k-th smallest A value.
    // A[i].value is the (i+1)-th smallest A value.
    // B[i].original_index is the original index of the (i+1)-th smallest B value.
    // So, A_prime[B[i].original_index] should be A[i].value.
    for (int i = 0; i < m; ++i) {
        A_prime[B[i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

