// Function to determine if a box can be the special box
// based on the final sign and magnitude properties.
// `final_sign_is_neg`: true if the final product can be negative.
// `final_mag_is_ge1`: true if the final product's magnitude can be >= 1.
// `final_mag_is_lt1`: true if the final product's magnitude can be < 1.
bool check_box(bool final_sign_is_neg, bool final_mag_is_ge1, bool final_mag_is_lt1, int box_idx) {
    if (box_idx == 0) { // Box 1: (-inf, -1] (negative, magnitude >= 1)
        return final_sign_is_neg && final_mag_is_ge1;
    } else if (box_idx == 1) { // Box 2: (-1, 0) (negative, magnitude < 1)
        return final_sign_is_neg && final_mag_is_lt1;
    } else if (box_idx == 2) { // Box 3: (0, 1) (positive, magnitude < 1)
        return (!final_sign_is_neg) && final_mag_is_lt1;
    } else { // Box 4: [1, inf) (positive, magnitude >= 1)
        return (!final_sign_is_neg) && final_mag_is_ge1;
    }
}

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    // If only one toy, that toy is the super toy.
    if (total_toys == 1) {
        std::cout << (A > 0 ? "Ya" : "Tidak") << " "
                  << (B > 0 ? "Ya" : "Tidak") << " "
                  << (C > 0 ? "Ya" : "Tidak") << " "
                  << (D > 0 ? "Ya" : "Tidak") << std::endl;
        return;
    }

    // Determine possible final sign
    // The final sign depends on the parity of negative numbers multiplied.
    // A and B contain negative numbers.
    // If A+B is odd, the final product can be negative.
    // If A+B is even, the final product can be positive.
    // If A+B is 0, the final product must be positive.
    bool final_sign_can_be_neg = ((A + B) % 2 == 1);
    bool final_sign_can_be_pos = ((A + B) % 2 == 0) || (A + B == 0 && (C > 0 || D > 0)); // If no negatives, must be positive.

    // Determine possible final magnitude properties
    bool final_mag_can_be_ge1 = false; // Can the final product have magnitude >= 1?
    bool final_mag_can_be_lt1 = false; // Can the final product have magnitude < 1?

    // Case 1: There is at least one toy with magnitude >= 1 (from Box 1 or Box 4).
    // If there are toys in Box 1 or Box 4, we can potentially make the final product magnitude >= 1.
    // We can also potentially make it < 1 by multiplying with many Box 2/3 toys.
    if (A > 0 || D > 0) {
        final_mag_can_be_ge1 = true;
        final_mag_can_be_lt1 = true; // We can always make it < 1 by multiplying with enough numbers from (-1, 1)
                                      // unless all other toys are also >= 1.
                                      // But we can always pick a very small number from (-1,1) for B or C.
                                      // If B+C > 0, we can definitely make it < 1.
                                      // If B+C == 0, then all toys are from A or D.
                                      // If A+D > 1, we can pick one toy from A/D, and another from A/D.
                                      // If we have A=1, D=0, B=0, C=0, then final is A. Mag >= 1.
                                      // If we have A=0, D=1, B=0, C=0, then final is D. Mag >= 1.
                                      // If A+D > 0 and B+C > 0, then we can make it < 1.
                                      // If A+D > 0 and B+C == 0:
                                      //   If A+D == 1, then final_mag_can_be_ge1 is true, final_mag_can_be_lt1 is false.
                                      //   If A+D > 1, then we can pick values like 2 and 0.1 (from A/D and B/C) to make it < 1.
                                      //   But if B+C == 0, we only have A and D. All magnitudes are >= 1.
                                      //   So if B+C == 0 and A+D > 0, then final_mag_can_be_ge1 is true, final_mag_can_be_lt1 is false.
                                      // This logic is tricky. Let's simplify.
                                      // If there's at least one toy with magnitude >= 1 (A or D),
                                      // and at least one toy with magnitude < 1 (B or C),
                                      // then we can achieve both >= 1 and < 1.
                                      // Example: 2 * 0.1 = 0.2 (<1)
                                      // Example: 2 * 0.6 = 1.2 (>=1)
                                      // So if (A+D > 0) and (B+C > 0), then both final_mag_can_be_ge1 and final_mag_can_be_lt1 are true.
                                      // If (A+D > 0) and (B+C == 0):
                                      //   All toys have magnitude >= 1. The product of numbers >= 1 is always >= 1.
                                      //   So final_mag_can_be_ge1 is true, final_mag_can_be_lt1 is false.
    } else { // Case 2: All toys have magnitude < 1 (only from Box 2 or Box 3).
        // The product of numbers with magnitude < 1 is always < 1.
        final_mag_can_be_ge1 = false;
        final_mag_can_be_lt1 = true;
    }

    // Refined logic for magnitude:
    // If all toys are from B and C (i.e., A=0, D=0):
    //   Product of numbers with magnitude < 1 is always < 1.
    //   So, final_mag_can_be_ge1 = false, final_mag_can_be_lt1 = true.
    if (A == 0 && D == 0) {
        final_mag_can_be_ge1 = false;
        final_mag_can_be_lt1 = true;
    }
    // If all toys are from A and D (i.e., B=0, C=0):
    //   Product of numbers with magnitude >= 1 is always >= 1.
    //   So, final_mag_can_be_ge1 = true, final_mag_can_be_lt1 = false.
    else if (B == 0 && C == 0) {
        final_mag_can_be_ge1 = true;
        final_mag_can_be_lt1 = false;
    }
    // If there are toys from both (A or D) AND (B or C):
    //   We can achieve both magnitude >= 1 and magnitude < 1.
    //   Example: Pick a large number (e.g., 10 from D) and a small number (e.g., 0.1 from C).
    //   If we multiply 10 * 0.1 = 1. This is >= 1.
    //   If we multiply 10 * 0.01 = 0.1. This is < 1.
    //   So, final_mag_can_be_ge1 = true, final_mag_can_be_lt1 = true.
    else { // (A > 0 || D > 0) && (B > 0 || C > 0)
        final_mag_can_be_ge1 = true;
        final_mag_can_be_lt1 = true;
    }

    std::string results[4];

    // Box 1: (-inf, -1] (negative, magnitude >= 1)
    results[0] = (final_sign_can_be_neg && final_mag_can_be_ge1) ? "Ya" : "Tidak";

    // Box 2: (-1, 0) (negative, magnitude < 1)
    results[1] = (final_sign_can_be_neg && final_mag_can_be_lt1) ? "Ya" : "Tidak";

    // Box 3: (0, 1) (positive, magnitude < 1)
    results[2] = (final_sign_can_be_pos && final_mag_can_be_lt1) ? "Ya" : "Tidak";

    // Box 4: [1, inf) (positive, magnitude >= 1)
    results[3] = (final_sign_can_be_pos && final_mag_can_be_ge1) ? "Ya" : "Tidak";

    std::cout << results[0] << " " << results[1] << " " << results[2] << " " << results[3] << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a prefix of length `len` is a permutation
bool is_permutation_prefix(int len, const std::vector<int>& a, const std::vector<int>& max_prefix_val, const std::vector<int>& min_prefix_val) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_prefix_val[len - 1] != len) return false;
    return true;
}

// Function to check if a suffix of length `len` is a permutation
bool is_permutation_suffix(int len, const std::vector<int>& a, const std::vector<int>& max_suffix_val, const std::vector<int>& min_suffix_val) {
    if (len == 0) return false; // Permutation length must be non-zero
    if (max_suffix_val[a.size() - len] != len) return false;
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max value in prefixes
    std::vector<int> max_prefix_val(n);
    max_prefix_val[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix_val[i] = std::max(max_prefix_val[i - 1], a[i]);
    }

    // Precompute max value in suffixes
    std::vector<int> max_suffix_val(n);
    max_suffix_val[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix_val[i] = std::max(max_suffix_val[i + 1], a[i]);
    }

    // Check for unique elements in prefixes
    std::vector<bool> is_prefix_unique(n + 1, false); // is_prefix_unique[k] means first k elements are unique
    std::vector<bool> seen(n + 1, false); // Using n+1 for 1-based indexing up to n
    bool current_unique = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || seen[a[i]]) { // a[i] > n is impossible given constraints a_i <= n-1
            current_unique = false;
        }
        seen[a[i]] = true;
        is_prefix_unique[i + 1] = current_unique;
    }

    // Check for unique elements in suffixes
    std::vector<bool> is_suffix_unique(n + 1, false); // is_suffix_unique[k] means last k elements are unique
    std::fill(seen.begin(), seen.end(), false);
    current_unique = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || seen[a[i]]) { // a[i] > n is impossible given constraints a_i <= n-1
            current_unique = false;
        }
        seen[a[i]] = true;
        is_suffix_unique[n - i] = current_unique;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 can range from 1 to n-1.
    // If l1 = n, p1 would need to contain n, but a_i <= n-1.
    // If l1 = 0, p1 would be empty, not a permutation.
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if first l1 elements form a permutation of length l1
        bool p1_is_perm = is_prefix_unique[l1] && is_permutation_prefix(l1, a, max_prefix_val, max_prefix_val); // min_prefix_val not needed for max_val check

        // Check if last l2 elements form a permutation of length l2
        bool p2_is_perm = is_suffix_unique[l2] && is_permutation_suffix(l2, a, max_suffix_val, max_suffix_val); // min_suffix_val not needed for max_val check

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops
    // prefix_min_ops[i] stores the minimum value a[i] can take
    // such that a[0] < a[1] < ... < a[i] is possible.
    // Specifically, a[i] must be at least i.
    // And a[i] must be at least a[i-1] + 1.
    // So, a[i] must be at least max(i, a[i-1] + 1).
    // Since we can decrease a[i], we need a[i] (original) >= max(i, a[i-1] + 1).
    // Let's define `left_reach[i]` as the minimum value `a[i]` must be
    // to satisfy `a_0 < a_1 < ... < a_i` where `a_0` is 0.
    // `a_0` must be at least 0.
    // `a_1` must be at least 1.
    // `a_i` must be at least `i`.
    // So, `left_reach[i]` is `i`.
    // We need `a[i]` (original) >= `left_reach[i]`.
    // This is equivalent to `a[i] >= i`.
    // Let's compute `left_possible[i]` which is true if `a[0] < a[1] < ... < a[i]` can be formed
    // with `a[j]` being `j` for `j <= i`.
    // This is `a[j] >= j` for all `j <= i`.
    std::vector<bool> left_possible(n);
    left_possible[0] = (a[0] >= 0); // a[0] must be >= 0
    for (int i = 1; i < n; ++i) {
        left_possible[i] = left_possible[i-1] && (a[i] >= i);
    }

    // Calculate suffix_min_ops
    // suffix_min_ops[i] stores the minimum value a[i] can take
    // such that a[i] > a[i+1] > ... > a[n-1] is possible.
    // Specifically, a[n-1] must be at least 0.
    // a[n-2] must be at least 1.
    // a[i] must be at least n-1-i.
    // So, `right_reach[i]` is `n-1-i`.
    // We need `a[i]` (original) >= `right_reach[i]`.
    // This is equivalent to `a[i] >= n-1-i`.
    // Let's compute `right_possible[i]` which is true if `a[i] > a[i+1] > ... > a[n-1]` can be formed
    // with `a[j]` being `n-1-j` for `j >= i`.
    // This is `a[j] >= n-1-j` for all `j >= i`.
    std::vector<bool> right_possible(n);
    right_possible[n-1] = (a[n-1] >= 0); // a[n-1] must be >= 0
    for (int i = n - 2; i >= 0; --i) {
        right_possible[i] = right_possible[i+1] && (a[i] >= (n - 1 - i));
    }

    // Check for each possible peak k
    // For a peak at index k (0-indexed):
    // 1. a[0] < a[1] < ... < a[k]
    // 2. a[k] > a[k+1] > ... > a[n-1]
    //
    // To satisfy condition 1, we need a[i] >= i for i <= k.
    // To satisfy condition 2, we need a[i] >= n-1-i for i >= k.
    //
    // And importantly, a[k] must be strictly greater than a[k-1] (if k>0)
    // AND a[k] must be strictly greater than a[k+1] (if k<n-1).
    //
    // The minimum value for a[k] to satisfy the increasing part up to k is k.
    // The minimum value for a[k] to satisfy the decreasing part from k is n-1-k.
    // So, a[k] must be at least max(k, n-1-k).
    //
    // The conditions `a[i] >= i` for `i <= k` and `a[i] >= n-1-i` for `i >= k`
    // are checked by `left_possible[k]` and `right_possible[k]` respectively.
    //
    // If `left_possible[k]` is true, it means we can make `a[0], ..., a[k]` into `0, 1, ..., k`.
    // If `right_possible[k]` is true, it means we can make `a[k], ..., a[n-1]` into `n-1-k, n-2-k, ..., 0`.
    //
    // If both are true for a given `k`, then we can make the array `0, 1, ..., k, n-2-k, ..., 0`.
    // For example, if `n=6, k=2`: `0, 1, 2, 3, 2, 1, 0`.
    // The values would be `0, 1, 2, n-1-(k+1), n-1-(k+2), ..., 0`.
    // So, `0, 1, ..., k, n-1-(k+1), n-1-(k+2), ..., n-1-(n-1)`.
    //
    // The values would be:
    // `0, 1, ..., k-1, k` (for the increasing part)
    // `k, k-1, ..., 0` (for the decreasing part, relative to k)
    //
    // The actual values we can achieve are:
    // `a_i' = i` for `i <= k`
    // `a_i' = n-1-i` for `i >= k`
    //
    // For this to be a valid sharpened array, we need:
    // `a_0' < a_1' < ... < a_k'`
    // `a_k' > a_{k+1}' > ... > a_{n-1}'`
    //
    // The values `0, 1, ..., k` satisfy the first part.
    // The values `n-1-k, n-1-(k+1), ..., 0` satisfy the second part.
    //
    // The critical point is `a_k`.
    // The increasing part requires `a_k` to be at least `k`.
    // The decreasing part requires `a_k` to be at least `n-1-k`.
    // So, `a_k` must be at least `max(k, n-1-k)`.
    //
    // If we can make `a_i = i` for `i <= k` and `a_i = n-1-i` for `i >= k`,
    // then the array would be `0, 1, ..., k-1, k, n-1-(k+1), n-1-(k+2), ..., 0`.
    //
    // For this to be sharpened, we need `k > n-1-(k+1)` (if `k < n-1`).
    // This simplifies to `k > n-k-2`, or `2k > n-2`.
    //
    // However, the definition of sharpened allows `k=1` (strictly decreasing) or `k=n` (strictly increasing).
    //
    // If `k=0` (0-indexed, so peak is `a_0`):
    // `a_0 > a_1 > ... > a_{n-1}`.
    // This requires `a_0 >= n-1`, `a_1 >= n-2`, ..., `a_{n-1} >= 0`.
    // This is exactly `right_possible[0]`.
    //
    // If `k=n-1` (0-indexed, so peak is `a_{n-1}`):
    // `a_0 < a_1 < ... < a_{n-1}`.
    // This requires `a_0 >= 0`, `a_1 >= 1`, ..., `a_{n-1} >= n-1`.
    // This is exactly `left_possible[n-1]`.
    //
    // For any `k` from `0` to `n-1`:
    // We need `a[i] >= i` for `i <= k` AND `a[i] >= n-1-i` for `i >= k`.
    // This is equivalent to `left_possible[k]` AND `right_possible[k]`.
    // If both are true, then we can form an array where `a_i = i` for `i <= k` and `a_i = n-1-i` for `i >= k`.
    // Let's call this target array `b`.
    // `b = [0, 1, ..., k-1, k, n-1-(k+1), n-1-(k+2), ..., 0]`
    //
    // Is this `b` array sharpened?
    // The increasing part `0, 1, ..., k` is strictly increasing.
    // The decreasing part `k, n-1-(k+1), ..., 0` is strictly decreasing if `k > n-1-(k+1)`.
    //
    // Example: n=3, k=1 (peak at a[1])
    // `left_possible[1]` means `a[0]>=0, a[1]>=1`.
    // `right_possible[1]` means `a[1]>=1, a[2]>=0`.
    // If both are true, we can form `b = [0, 1, 0]`. This is sharpened.
    // Here `k=1`, `n-1-(k+1) = 3-1-(1+1) = 2-2 = 0`.
    // `k > n-1-(k+1)` becomes `1 > 0`, which is true.
    //
    // Example: n=4, k=1 (peak at a[1])
    // `left_possible[1]` means `a[0]>=0, a[1]>=1`.
    // `right_possible[1]` means `a[1]>=2, a[2]>=1, a[3]>=0`.
    // If both are true, we can form `b = [0, 1, 1, 0]`. This is NOT sharpened because `b[1]` is not strictly greater than `b[2]`.
    // Here `k=1`, `n-1-(k+1) = 4-1-(1+1) = 3-2 = 1`.
    // `k > n-1-(k+1)` becomes `1 > 1`, which is false.
    //
    // So, the condition is:
    // For some `k` (0-indexed):
    // 1. `left_possible[k]` is true.
    // 2. `right_possible[k]` is true.
    // 3. If `k > 0` and `k < n-1`, then `k > n-1-(k+1)`.
    //    This simplifies to `k > n-k-2` or `2k > n-2`.
    //    This is equivalent to `k >= (n-1)/2 + 1` if `n` is odd, or `k >= n/2` if `n` is even.
    //    More simply, `k >= floor((n-1)/2) + 1`.
    //    Or, `k >= (n-1)/2 + 1` if `n` is odd, `k >= n/2` if `n` is even.
    //    This is `k >= (n-1)/2 + 1` for `n` odd, `k >= n/2` for `n` even.
    //    This is `k >= (n+1)/2` for `n` odd, `k >= n/2` for `n` even.
    //    This is `k >= ceil(n/2.0)`.
    //    Let's recheck: `k > n-k-2` means `k` must be strictly greater than `n-k-2`.
    //    If `k = n-k-2`, then `2k = n-2`, `k = (n-2)/2`.
    //    So `k` must be at least `(n-2)/2 + 1 = n/2`.
    //    This is for `k` to be strictly greater than `n-1-(k+1)`.
    //    This condition is only relevant if `k` is not an endpoint.
    //    If `k=0`, it's strictly decreasing. `right_possible[0]` is enough.
    //    If `k=n-1`, it's strictly increasing. `left_possible[n-1]` is enough.
    //
    // Let's simplify the condition for `k` to be a valid peak.
    // We need `a_i >= i` for `i <= k`.
    // We need `a_i >= n-1-i` for `i >= k`.
    //
    // If these conditions hold, we can form an array `b` where `b_i = i` for `i <= k` and `b_i = n-1-i` for `i >= k`.
    // This array `b` is `[0, 1, ..., k-1, k, n-1-(k+1), n-1-(k+2), ..., 0]`.
    //
    // This array `b` is sharpened if and only if:
    // `b_0 < b_1 < ... < b_k` (which is `0 < 1 < ... < k`, always true)
    // AND `b_k > b_{k+1} > ... > b_{n-1}`.
    // The second part means `k > n-1-(k+1)` (if `k < n-1`).
    // If `k = n-1`, the second part is vacuously true (no elements after `b_k`).
    // If `k = 0`, the first part is vacuously true (no elements before `b_k`).
    //
    // So, we need to find if there exists a `k` such that:
    // `left_possible[k]` is true AND `right_possible[k]` is true.
    // If such a `k` exists, then we can form the array `b`.
    // The array `b` is `[0, 1, ..., k-1, k, n-k-2, n-k-3, ..., 0]`.
    //
    // This array `b` is always sharpened.
    // The increasing part `0, 1, ..., k` is strictly increasing.
    // The decreasing part `k, n-k-2, ..., 0` is strictly decreasing.
    // The only potential issue is if `k <= n-k-2`.
    // For example, if `n=4, k=1`. `b = [0, 1, 1, 0]`. Here `k=1`, `n-k-2 = 4-1-2 = 1`. `k <= n-k-2` is `1 <= 1`.
    // This is not sharpened.
    //
    // The condition for `b_k > b_{k+1}` is `k > n-1-(k+1)`.
    // This is `k > n-k-2`.
    //
    // So, we need to find a `k` such that:
    // 1. `a[i] >= i` for all `i <= k`. (Checked by `left_possible[k]`)
    // 2. `a[i] >= n-1-i` for all `i >= k`. (Checked by `right_possible[k]`)
    // 3. `k > n-k-2`. (This is the condition for `b_k > b_{k+1}` if `k < n-1`)
    //    If `k = n-1`, condition 3 is not needed.
    //    If `k = 0`, condition 3 is not needed.
    //
    // Let's re-evaluate the conditions for `b` to be sharpened.
    // `b_i = i` for `i <= k`.
    // `b_i = n-1-i` for `i >= k`.
    //
    // If `k=0`: `b = [0, n-2, n-3, ..., 0]`. This is sharpened if `n=1` (peak is 0), or `0 > n-2` (if `n>1`).
    // `0 > n-2` implies `n < 2`. So only `n=1` works.
    // But `k=0` means `a_0` is the peak. The array is `a_0 > a_1 > ... > a_{n-1}`.
    // The values `n-1, n-2, ..., 0` satisfy this.
    // So `right_possible[0]` is sufficient for `k=0`.
    //
    // If `k=n-1`: `b = [0, 1, ..., n-1]`. This is sharpened.
    // So `left_possible[n-1]` is sufficient for `k=n-1`.
    //
    // For `0 < k < n-1`:
    // `b = [0, 1, ..., k-1, k, n-1-(k+1), ..., 0]`.
    // We need `b_k > b_{k+1}`.
    // This means `k > n-1-(k+1)`.
    // `k > n-k-2`.
    // `2k > n-2`.
    // `k > (n-2)/2`.
    //
    // So, we iterate `k` from `0` to `n-1`.
    // If `left_possible[k]` and `right_possible[k]` are both true:
    //   If `k == 0` or `k == n-1`: it's a valid sharpened array. Output "Yes".
    //   If `0 < k < n-1`: check if `k > (n-2)/2`. If true, it's a valid sharpened array. Output "Yes".
    // If we iterate through all `k` and don't find such a `k`, output "No".

    bool found = false;
    for (int k = 0; k < n; ++k) {
        if (left_possible[k] && right_possible[k]) {
            if (k == 0 || k == n - 1) {
                found = true;
                break;
            }
            // For 0 < k < n-1, we need k > n-k-2
            // This is equivalent to k >= (n-2)/2 + 1
            // Or k >= n/2 if n is even, k >= (n-1)/2 + 1 if n is odd.
            // This is equivalent to k >= ceil(n/2.0)
            // Example: n=4, k=1. (n-2)/2 = 1. k > 1 is false.
            // Example: n=3, k=1. (n-2)/2 = 0.5. k > 0.5 is true.
            if (k > (n - 2) / 2) {
                found = true;
                break;
            }
        }
    }

    if (found) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

