#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <map>

char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Determine the most frequent move in the bot's string s
        // Prioritize R, then P, then S for tie-breaking (arbitrary, any tie-break is fine)
        // The problem statement implies that any optimal answer is fine.
        // The order of checking R, P, S here doesn't matter for correctness,
        // as long as we pick *one* of the most frequent.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) { // Note: if counts['P'] == counts['R'], P will be chosen.
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) { // Note: if counts['S'] == counts['R'] or counts['P'], S will be chosen.
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // If all counts are 0 (empty string, not possible by constraints), this would be ' '.
        // For n >= 1, one of R, P, S will have a count >= 1.

        char our_winning_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        current_sum += a[i];
        current_xor ^= a[i];
    }

    // Case 0: Already good
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // Case 1: Append one element
    // We need S' = 2X'
    // (current_sum + b1) = 2 * (current_xor ^ b1)
    // This is generally hard to solve for b1 directly.
    // Let's try to append two elements.

    // Case 2: Append two elements
    // Let's append x and y.
    // (current_sum + x + y) = 2 * (current_xor ^ x ^ y)
    // A common strategy for competitive programming problems like this is to pick specific values for x and y.
    // A simple choice is to make the XOR sum equal to some value, say current_xor.
    // If we append current_xor, the new XOR sum becomes current_xor ^ current_xor = 0.
    // This is not useful because 2 * 0 = 0, but current_sum + current_xor is likely not 0.

    // Let's try to make the final XOR sum X' equal to current_xor.
    // This means we need to append two numbers b1, b2 such that current_xor ^ b1 ^ b2 = current_xor.
    // This implies b1 ^ b2 = 0, so b1 = b2.
    // Let b1 = b2 = X_val.
    // Then the new XOR sum is current_xor ^ X_val ^ X_val = current_xor.
    // The new sum is current_sum + X_val + X_val = current_sum + 2 * X_val.
    // We need current_sum + 2 * X_val = 2 * current_xor.
    // This means 2 * X_val = 2 * current_xor - current_sum.
    // For this to work, (2 * current_xor - current_sum) must be non-negative and even.
    // Let target_sum_diff = 2 * current_xor - current_sum.
    // If target_sum_diff >= 0 and target_sum_diff % 2 == 0, then X_val = target_sum_diff / 2.
    // This X_val could be a valid number to append twice.
    // However, X_val can be very large, up to 10^18.
    // The problem statement says "It can be shown that the solution always exists".
    // And "You don't have to minimize the number of added elements!".
    // This suggests a simpler, perhaps less optimal, construction.

    // A common trick for these problems is to append elements that simplify the XOR sum.
    // Let's append two elements: current_xor and current_sum.
    // No, this is not right.
    // Let's append two elements: current_xor and (current_sum + current_xor).
    // This is also not right.

    // Consider the strategy:
    // 1. Append X_0 (current_xor).
    //    New XOR sum: X_0' = X_0 ^ X_0 = 0.
    //    New sum: S_0' = S_0 + X_0.
    //    Condition: S_0' = 2 * X_0' => S_0 + X_0 = 2 * 0 = 0.
    //    This is only true if S_0 = 0 and X_0 = 0, which is not generally the case.

    // 2. Append X_0 and then some value Y.
    //    New XOR sum: X_0' = X_0 ^ X_0 ^ Y = Y.
    //    New sum: S_0' = S_0 + X_0 + Y.
    //    Condition: S_0 + X_0 + Y = 2 * Y.
    //    S_0 + X_0 = Y.
    //    So, if we append X_0 and (S_0 + X_0), the array becomes good.
    //    Let b1 = current_xor.
    //    Let b2 = current_sum + current_xor.
    //    New sum: S' = current_sum + b1 + b2 = current_sum + current_xor + (current_sum + current_xor) = 2 * current_sum + 2 * current_xor.
    //    New XOR: X' = current_xor ^ b1 ^ b2 = current_xor ^ current_xor ^ (current_sum + current_xor) = current_sum + current_xor.
    //    Check condition: S' = 2 * X'
    //    (2 * current_sum + 2 * current_xor) = 2 * (current_sum + current_xor)
    //    This is always true!
    //    The values b1 and b2 can be large, up to 10^9 + 10^5 * 10^9 ~ 10^14. This fits in long long.
    //    This strategy uses 2 elements.

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << current_sum + current_xor << std::endl;
}

