// Function to convert a number to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string s = "";
    if (n == 0) {
        s = "0"; // Special case for 0, which is even
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                s += '0';
            } else {
                s += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's to make it 18 characters long
    // The problem states "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies that for comparison, both the number's parity string and the query pattern should be effectively 18 digits long.
    // Since we are comparing from right to left, padding the number's parity string with '0's on the right (which corresponds to left in the number)
    // makes sense for a fixed-length representation.
    while (s.length() < 18) {
        s += '0';
    }
    return s;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
