    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's to make it 18 characters long
            // The problem states "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // This means if the pattern is "1", it should be treated as "00...01" (18 digits).
            // Since our stored keys are 18-digit parity strings, we need to pad the query pattern to 18 digits.
            // The padding should be on the left of the pattern string, which corresponds to the higher-order digits.
            // Example: pattern "010" -> "00...0010" (18 digits)
            // The `get_parity_pattern` function generates strings where the rightmost char is the parity of the rightmost digit.
            // So, if the query pattern is "010", it means rightmost digit even, second rightmost odd, third rightmost even.
            // Our stored keys are also in this format.
            // So, we need to pad the query pattern `s` with '0's on the right to match the 18-char length.
            // Example: s = "010" -> "010000000000000000"
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

