int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n-i items are taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // Items taken from right are w[i], ..., w[n-1]
        // The sum of weights for items taken from the right is prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add bonus energy based on counts
        int items_left = i;
        int items_right = n - i;

        if (items_left > items_right) {
            // More items taken from left. The last item could be from left.
            // If items_left - items_right > 1, then there must have been at least one sequence of two consecutive left takes.
            // The number of "extra" left items that might incur Ql penalty is items_left - items_right - 1.
            // This is equivalent to (items_left - items_right - 1) * Ql
            current_energy += std::max(0, items_left - items_right - 1) * Ql;
        } else if (items_right > items_left) {
            // More items taken from right. The last item could be from right.
            // The number of "extra" right items that might incur Qr penalty is items_right - items_left - 1.
            // This is equivalent to (items_right - items_left - 1) * Qr
            current_energy += std::max(0, items_right - items_left - 1) * Qr;
        }
        // If items_left == items_right, no bonus penalty is added.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

