void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int x = 0; x <= 9; ++x) {
        std::vector<int> colors(n);
        int last1 = -1; // Last digit assigned to color 1
        int first2 = 10; // First digit assigned to color 2

        bool possible_x = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                colors[i] = 1;
                if (d[i] < last1) { // S1 must be non-decreasing
                    possible_x = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > x) {
                colors[i] = 2;
                if (d[i] < first2) { // S2 must be non-decreasing
                    first2 = d[i];
                }
            } else { // d[i] == x
                // Try assigning to color 2 first, if it maintains S2 non-decreasing
                if (d[i] >= first2) {
                    colors[i] = 2;
                } else { // Must assign to color 1
                    colors[i] = 1;
                    if (d[i] < last1) { // S1 must be non-decreasing
                        possible_x = false;
                        break;
                    }
                    last1 = d[i];
                }
            }
        }

        if (!possible_x) {
            continue;
        }

        // Final check for S2 non-decreasing and S1_last <= S2_first
        int current_last1 = -1;
        int current_last2 = -1;
        bool s1_empty = true;
        bool s2_empty = true;

        for (int i = 0; i < n; ++i) {
            if (colors[i] == 1) {
                s1_empty = false;
                if (d[i] < current_last1) {
                    possible_x = false;
                    break;
                }
                current_last1 = d[i];
            } else { // colors[i] == 2
                s2_empty = false;
                if (d[i] < current_last2) {
                    possible_x = false;
                    break;
                }
                current_last2 = d[i];
            }
        }

        if (!possible_x) {
            continue;
        }

        if (!s1_empty && !s2_empty && current_last1 > d[std::find(colors.begin(), colors.end(), 2) - colors.begin()]) {
            // This check is actually redundant if the logic for assigning 'x' digits is correct.
            // The 'x' digits are assigned such that those in color 1 are <= last1, and those in color 2 are >= first2.
            // And last1 is updated correctly.
            // The critical condition is that the last digit of S1 must be <= the first digit of S2.
            // Our construction ensures this: all digits assigned to 1 are <= last1.
            // All digits assigned to 2 are >= first2.
            // If an 'x' digit is assigned to 1, it means it was <= last1.
            // If an 'x' digit is assigned to 2, it means it was >= first2.
            // The split point is effectively 'x'.
            // The last digit of S1 will be the maximum of all digits assigned to 1.
            // The first digit of S2 will be the minimum of all digits assigned to 2.
            // By construction, max(S1) <= x and min(S2) >= x. So max(S1) <= min(S2) is guaranteed.
        }

        // If we reach here, a valid coloring is found
        for (int i = 0; i < n; ++i) {
            std::cout << colors[i];
        }
        std::cout << "\n";
        return;
    }

    std::cout << "-\n";
}

