// Function to get prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x is a divisor of p and x is not divisible by q.
        // This means x must be p / (some factor of p) such that p / (some factor of p) is not divisible by q.
        // Or, more directly, x must be p / (some factor of q that is also a factor of p)
        // such that the resulting x is not divisible by q.

        // Let q = q1^a1 * q2^a2 * ... * qk^ak be the prime factorization of q.
        // If p is divisible by q, then p must contain all these prime factors with at least these powers.
        // To make x not divisible by q, we must remove at least one prime factor q_j from p
        // such that the power of q_j in x becomes less than a_j.
        // To maximize x, we should remove the smallest possible factor from p.
        // This means we should divide p by q_j raised to some power.
        // Specifically, for each prime factor q_j of q, we find the maximum power of q_j that divides p.
        // Let p = q_j^b_j * M, where M is not divisible by q_j.
        // We want to find x = p / q_j^k such that x % q != 0.
        // The largest such x will be p / q_j^(b_j - (a_j - 1)) = p / q_j^(b_j - a_j + 1).
        // This is equivalent to p / (q_j * (q_j^(b_j - a_j))).
        // We want to find the maximum x. This means we want to find the minimum divisor d of p such that (p/d) % q != 0.
        // This is equivalent to finding the minimum d such that d is a divisor of p, and p/d is not divisible by q.
        // The largest x will be p / (q_j * (q_j^(count_p_qj - count_q_qj))) for some q_j.
        // We iterate through all prime factors of q.
        // For each prime factor `f` of `q`, we calculate `p_prime_factor_f = p`.
        // We divide `p_prime_factor_f` by `f` until `p_prime_factor_f` is no longer divisible by `q`.
        // The largest `x` will be the maximum of these `p_prime_factor_f` values.

        long long max_x = 0;
        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

        for (const auto& factor_pair : q_factors) {
            long long prime_factor = factor_pair.first;
            // int exponent_in_q = factor_pair.second; // Not directly needed for this approach

            long long current_p = p;
            // Divide current_p by prime_factor until it's no longer divisible by q.
            // This means we are reducing the power of prime_factor in current_p.
            // We want to find the largest current_p that is a divisor of original p
            // and current_p % q != 0.
            // Since original p % q == 0, we must divide p by some factor.
            // To make current_p % q != 0, we must reduce the power of at least one prime_factor of q.
            // To maximize current_p, we should reduce the power of prime_factor by the minimum amount
            // such that current_p is no longer divisible by q.
            // The minimum amount is to divide by prime_factor until current_p is no longer divisible by q.
            // This means we divide p by prime_factor, then by prime_factor again, and so on,
            // until the resulting number is not divisible by q.
            // The first such number will be the largest possible x for this prime_factor.

            while (current_p % q == 0) {
                current_p /= prime_factor;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

