int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r = (b-1) * b * inv(2) mod MOD
    // If b-1 is 0, sum_r is 0.
    long long sum_r_val;
    if (b == 1) {
        sum_r_val = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long inv2 = (MOD + 1) / 2; // Modular inverse of 2 modulo 10^9 + 7
        sum_r_val = (b_minus_1 % MOD * (b % MOD)) % MOD;
        sum_r_val = (sum_r_val * inv2) % MOD;
    }

    // Sum of (k*b + 1) from k=1 to a
    // This is sum_{k=1}^{a} (k*b + 1) = b * sum_{k=1}^{a} k + sum_{k=1}^{a} 1
    // = b * (a * (a+1) / 2) + a
    // This is sum_kb_plus_1 = (b * a * (a+1) * inv(2) + a) mod MOD
    long long sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    long long inv2 = (MOD + 1) / 2; // Modular inverse of 2 modulo 10^9 + 7
    sum_k_val = (sum_k_val * inv2) % MOD; // sum_{k=1}^{a} k

    long long sum_kb_plus_1_val = (b % MOD * sum_k_val) % MOD;
    sum_kb_plus_1_val = (sum_kb_plus_1_val + (a % MOD)) % MOD;

    // Total sum = (sum_r_val * sum_kb_plus_1_val) mod MOD
    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
