#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
        used_in_s.insert(c1);
        used_in_s.insert(c2);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_s.insert(s[0]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find a starting point for the layout: a character with degree 1
    // or any character if all have degree 0 (single char password)
    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (used_in_s.count(c) && adj[c].size() <= 1) {
            start_char = c;
            break;
        }
    }

    // If no character from s has degree <= 1, it means all characters in s have degree 2.
    // This implies a cycle, which is not possible in a single row.
    // Or, if s is empty, or all characters in s have degree 0 (e.g., "abc" -> a-b, b-c, but a and c have degree 1).
    // The only case where all characters in s have degree 2 is if the graph forms a cycle.
    // A single row cannot form a cycle.
    // The only exception is if s has only one character, then start_char might not be found this way.
    // If s has only one character, start_char will be s[0].
    if (start_char == '\0' && !used_in_s.empty()) {
        // This means all characters in used_in_s have degree 2.
        // This implies a cycle, which is impossible for a linear keyboard.
        // Example: "abacaba" -> a-b, b-a, a-c, c-a.
        // a has neighbors b, c. Degree 2.
        // b has neighbor a. Degree 1.
        // c has neighbor a. Degree 1.
        // This logic is flawed. The graph is built from unique adjacencies.
        // For "abacaba":
        // a: {b, c} (degree 2)
        // b: {a} (degree 1)
        // c: {a} (degree 1)
        // Start char would be 'b' or 'c'.
        // If start_char is still '\0' and used_in_s is not empty, it means all characters in used_in_s have degree 2.
        // This forms a path or a cycle. If it's a cycle, it's impossible.
        // If it's a path, there must be two endpoints with degree 1.
        // So, if start_char is '\0' and used_in_s is not empty, it must be a cycle.
        std::cout << "NO\n";
        return;
    }

    if (start_char == '\0' && used_in_s.empty()) { // s was empty or single char not handled
        // If s is empty, it's not possible by constraints (1 <= |s|).
        // If s has one char, e.g., "a", used_in_s will contain 'a'.
        // adj['a'] will be empty, so adj['a'].size() is 0.
        // So 'a' would be picked as start_char.
        // This case should not be reached.
    }

    if (start_char != '\0') { // If we found a starting character from s
        char current = start_char;
        char prev = '\0'; // Sentinel for the previous character

        while (current != '\0' && visited_in_layout.find(current) == visited_in_layout.end()) {
            layout_str += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    // Check if all characters from s are included in the layout_str
    for (char c : used_in_s) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            // This means there's a disconnected component in the graph formed by s,
            // or a cycle that wasn't traversed.
            // If it's a cycle, it's impossible.
            // If it's a disconnected component, it means the graph from s is not a single path.
            // This is fine, as long as each component is a path.
            // However, the problem implies a single path for all characters in s.
            // If we have multiple paths, we can concatenate them.
            // But the current logic only builds one path.
            // The condition `start_char == '\0' && !used_in_s.empty()` already handles cycles.
            // If we reach here, it means there are multiple paths.
            // Example: s = "ab", "cd". This is not possible by problem constraints (single s).
            // So, if we have multiple components, it means the graph from s is not connected.
            // This should not happen if s is a single string.
            // The only way this can happen is if the graph from s has multiple connected components,
            // and we only traversed one.
            // This implies that the graph from s is not a single path.
            // This is fine, as long as each component is a path.
            // But the problem implies that all characters in s must form a single path.
            // If there are multiple components, it means some characters in s are not connected.
            // This is impossible if they are all part of the same password string.
            // The only way this can happen is if the graph from s is not connected.
            // This means that the password string itself implies disconnected components.
            // E.g., "ab" and "cd" are not connected.
            // But the password is one string.
            // So, if we have a character in used_in_s that is not visited, it means
            // the graph formed by s is not a single path.
            // This implies a "NO" case.
            std::cout << "NO\n";
            return;
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

