#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

// Z-algorithm implementation
std::vector<int> calculate_z_function(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    for (int i = 1, l = 0, r = 0; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-values for all suffixes
    // z_values[i][j] stores Z-value for string s[i..L-1] + s[0..i-1] starting at index j
    // This is equivalent to Z-value for s_shifted_by_i starting at index j
    // We need Z-values for s_shifted_by_i + s_shifted_by_i
    // Let S_i = s[i..L-1] + s[0..i-1]
    // We need Z-values for S_i + S_i
    // The Z-array for S_i + S_i will be of length 2L.
    // z_values_for_shifted_doubled[i] stores the Z-array for (s_shifted_by_i + s_shifted_by_i)
    std::vector<std::vector<int>> z_values_for_shifted_doubled(L);
    for (int i = 0; i < L; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        std::string doubled_shifted_s = shifted_s + shifted_s;
        z_values_for_shifted_doubled[i] = calculate_z_function(doubled_shifted_s);
    }

    // Group initial shifts by their first character
    std::map<char, std::vector<int>> shifts_by_first_char;
    for (int k = 0; k < L; ++k) {
        shifts_by_first_char[s[k]].push_back(k);
    }

    double total_win_prob = 0.0;

    for (auto const& [first_char, initial_k_candidates] : shifts_by_first_char) {
        if (initial_k_candidates.empty()) continue;

        // If only one k is possible, Vasya wins for sure for this first_char.
        if (initial_k_candidates.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // For a given first_char, find the best position p to query.
        // Vasya wants to maximize the probability of winning for this first_char.
        // This means finding p that maximizes the number of k's that become unique.

        // For each possible query position p (from 1 to L-1, since p=0 is already known)
        // calculate how many k's become unique.
        int max_unique_count = 0;

        for (int p = 1; p < L; ++p) {
            // Group candidates by t[p]
            std::map<char, std::vector<int>> candidates_by_second_char;
            for (int k_idx : initial_k_candidates) {
                // t[p] = s[(p + k) % L]
                candidates_by_second_char[s[(p + k_idx) % L]].push_back(k_idx);
            }

            int current_unique_count = 0;
            for (auto const& [second_char, final_k_candidates] : candidates_by_second_char) {
                if (final_k_candidates.empty()) continue;

                if (final_k_candidates.size() == 1) {
                    current_unique_count++;
                } else {
                    // Check if any of these k's are actually unique
                    // A k is unique if no other k' in final_k_candidates produces the same string t.
                    // This means for a k, there is no k' in final_k_candidates (k' != k) such that
                    // s_shifted_by_k == s_shifted_by_k'.
                    // This is equivalent to checking if s_shifted_by_k is a periodic string
                    // with period (k' - k) % L.
                    // Or, more generally, if s_shifted_by_k is equal to s_shifted_by_k'
                    // This can be checked using Z-algorithm.
                    // s_shifted_by_k == s_shifted_by_k' if Z[L + (k' - k + L) % L] >= L
                    // for the Z-array of (s_shifted_by_k + s_shifted_by_k).

                    // For each k in final_k_candidates, check if it's unique among them.
                    for (int i = 0; i < final_k_candidates.size(); ++i) {
                        int k_val = final_k_candidates[i];
                        bool is_unique_among_group = true;
                        for (int j = 0; j < final_k_candidates.size(); ++j) {
                            if (i == j) continue;
                            int k_prime_val = final_k_candidates[j];

                            // Check if s_shifted_by_k_val is identical to s_shifted_by_k_prime_val
                            // This means checking if the string starting at k_val is identical to
                            // the string starting at k_prime_val in the original string s,
                            // considering cyclic shifts.
                            // This is equivalent to checking if s_shifted_by_k_val is equal to
                            // s_shifted_by_k_prime_val.
                            // The Z-array for (s_shifted_by_k_val + s_shifted_by_k_val)
                            // has a value at index (k_prime_val - k_val + L) % L
                            // that indicates the length of the common prefix.
                            // If this length is L, then the two shifted strings are identical.

                            int diff_idx = (k_prime_val - k_val + L) % L;
                            if (z_values_for_shifted_doubled[k_val][diff_idx] >= L) {
                                is_unique_among_group = false;
                                break;
                            }
                        }
                        if (is_unique_among_group) {
                            current_unique_count++;
                        }
                    }
                }
            }
            max_unique_count = std::max(max_unique_count, current_unique_count);
        }
        total_win_prob += static_cast<double>(max_unique_count);
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0-9), we track how an initial 0 and an initial 1 would transform.
    // state_0[bit_idx] = final value of bit_idx if initial bit was 0
    // state_1[bit_idx] = final value of bit_idx if initial bit was 1
    std::vector<int> state_0(10);
    std::vector<int> state_1(10);

    // Initialize: if initial bit is 0, it remains 0. If initial bit is 1, it remains 1.
    std::iota(state_1.begin(), state_1.end(), 0); // state_1[i] = 1 (conceptually)
    std::fill(state_0.begin(), state_0.end(), 0); // state_0[i] = 0 (conceptually)

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1; // i-th bit of the constant

            if (op_char == '&') {
                state_0[i] &= bit_val;
                state_1[i] &= bit_val;
            } else if (op_char == '|') {
                state_0[i] |= bit_val;
                state_1[i] |= bit_val;
            } else if (op_char == '^') {
                state_0[i] ^= bit_val;
                state_1[i] ^= bit_val;
            }
        }
    }

    // Now, for each bit i, we know the mapping:
    // If initial bit is 0, it becomes state_0[i].
    // If initial bit is 1, it becomes state_1[i].

    // We want to find A, B, C such that:
    // (x & A | B) ^ C = final_x
    // Or some other combination of at most 3 operations.
    // The problem statement implies at most 5 lines, but the common reduction is to 3.
    // Let's try to find A, B, C for (x & A | B) ^ C.

    // For each bit i:
    // If x_i = 0: (0 & A_i | B_i) ^ C_i = state_0[i]  =>  (0 | B_i) ^ C_i = state_0[i]  =>  B_i ^ C_i = state_0[i]
    // If x_i = 1: (1 & A_i | B_i) ^ C_i = state_1[i]  =>  (A_i | B_i) ^ C_i = state_1[i]

    // Let's determine A, B, C bit by bit.
    int final_A = 0; // Mask for AND
    int final_B = 0; // Mask for OR
    int final_C = 0; // Mask for XOR

    for (int i = 0; i < 10; ++i) {
        int s0 = state_0[i];
        int s1 = state_1[i];

        // Case 1: s0 = 0, s1 = 0
        // Input 0 -> 0, Input 1 -> 0
        // This means the output bit is always 0, regardless of input.
        // (x_i & 0 | 0) ^ 0 = 0
        // So, A_i = 0, B_i = 0, C_i = 0.
        // This is achieved by setting A_i = 0.
        // (x_i & 0) = 0. Then (0 | B_i) ^ C_i must be 0.
        // If B_i=0, C_i=0. If B_i=1, C_i=1.
        // Let's try to make A_i=0, B_i=0, C_i=0.
        // This means final_A has 0 at bit i. final_B has 0 at bit i. final_C has 0 at bit i.

        // Case 2: s0 = 0, s1 = 1
        // Input 0 -> 0, Input 1 -> 1
        // This means the output bit is the same as the input bit.
        // (x_i & 1 | 0) ^ 0 = x_i
        // So, A_i = 1, B_i = 0, C_i = 0.
        // This means final_A has 1 at bit i. final_B has 0 at bit i. final_C has 0 at bit i.

        // Case 3: s0 = 1, s1 = 0
        // Input 0 -> 1, Input 1 -> 0
        // This means the output bit is the inverse of the input bit.
        // (x_i & 1 | 0) ^ 1 = ~x_i
        // So, A_i = 1, B_i = 0, C_i = 1.
        // This means final_A has 1 at bit i. final_B has 0 at bit i. final_C has 1 at bit i.

        // Case 4: s0 = 1, s1 = 1
        // Input 0 -> 1, Input 1 -> 1
        // This means the output bit is always 1, regardless of input.
        // (x_i & 0 | 1) ^ 0 = 1
        // So, A_i = 0, B_i = 1, C_i = 0.
        // This means final_A has 0 at bit i. final_B has 1 at bit i. final_C has 0 at bit i.

        // Let's combine these:
        if (s0 == 0 && s1 == 0) { // Output always 0
            // A_i = 0, B_i = 0, C_i = 0
            // final_A |= (0 << i);
            // final_B |= (0 << i);
            // final_C |= (0 << i);
        } else if (s0 == 0 && s1 == 1) { // Output is x_i
            // A_i = 1, B_i = 0, C_i = 0
            final_A |= (1 << i);
            // final_B |= (0 << i);
            // final_C |= (0 << i);
        } else if (s0 == 1 && s1 == 0) { // Output is ~x_i
            // A_i = 1, B_i = 0, C_i = 1
            final_A |= (1 << i);
            // final_B |= (0 << i);
            final_C |= (1 << i);
        } else { // s0 == 1 && s1 == 1, Output always 1
            // A_i = 0, B_i = 1, C_i = 0
            // final_A |= (0 << i);
            final_B |= (1 << i);
            // final_C |= (0 << i);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_A != 1023) { // If not all bits are 1 for AND, then we need an AND operation
        result_ops.push_back({'&', final_A});
    }
    if (final_B != 0) { // If not all bits are 0 for OR, then we need an OR operation
        result_ops.push_back({'|', final_B});
    }
    if (final_C != 0) { // If not all bits are 0 for XOR, then we need an XOR operation
        result_ops.push_back({'^', final_C});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long N = std::abs(n);
        long long M = std::abs(m);

        // Ensure N <= M for simpler logic
        if (N > M) {
            std::swap(N, M);
        }

        // Case 1: k < M (or k < N)
        // It's impossible to reach (N, M) in k moves if k is less than the
        // maximum coordinate, because each move changes at least one coordinate
        // by at most 1. So, at least M moves are needed to reach M.
        if (k < M) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= M
        // We can always reach (N, M) in k moves if k >= M.
        // The strategy is to make N diagonal moves to reach (N, N),
        // then M-N straight moves to reach (N, M).
        // This uses N + (M-N) = M moves.
        // The remaining k-M moves can be used to toggle between (x,y) and (x+1,y) and back,
        // or (x,y) and (x,y+1) and back, or (x,y) and (x+1,y+1) and back.
        // Each such pair of moves (e.g., (x,y) -> (x+1,y) -> (x,y)) uses 2 moves
        // and results in no net change in position.
        // The parity of the final coordinates (N, M) must match the parity of k.
        // Each move changes the sum of coordinates (x+y) by -2, 0, or 2 for diagonal moves,
        // and by -1 or 1 for straight moves.
        // This means (x+y) changes parity with each move.
        // So, (N+M) must have the same parity as k.
        // If (N+M) and k have different parities, we need to adjust k.
        // We can always adjust k by 2 by making two extra moves that cancel out.
        // For example, move (x,y) -> (x+1,y) -> (x,y). This uses 2 moves.
        // Or (x,y) -> (x+1,y+1) -> (x,y). This uses 2 moves.
        //
        // The maximum number of diagonal moves is k.
        // However, we must reach (N, M).
        // We can make N diagonal moves to reach (N, N).
        // Then M-N straight moves to reach (N, M).
        // Total moves so far: N + (M-N) = M.
        // Remaining moves: k - M.
        // These remaining moves must be used in pairs that cancel out,
        // or in a way that maintains the final position (N, M).
        //
        // If (k - M) is even, we can use all k moves.
        // The maximum diagonal moves would be k.
        // Example: (2,2,3). N=2, M=2, k=3. k-M = 3-2=1 (odd).
        // Max diag moves: k-1 = 2.
        // (0,0)->(1,1)->(2,2). This is 2 moves, 2 diag.
        // We need 3 moves. (0,0)->(1,0)->(1,1)->(2,2). 1 diag.
        // (0,0)->(1,1)->(2,1)->(2,2). 1 diag.
        //
        // If (k - M) is odd, we cannot use all k moves to reach (N, M)
        // if we only use moves that change parity of (x+y) by 1.
        // Each diagonal move changes (x+y) by 0 or +/-2 (even change).
        // Each straight move changes (x+y) by +/-1 (odd change).
        //
        // Let's consider the parity of (N+M) and k.
        // If (N+M) and k have the same parity, then we can reach (N, M) in k moves.
        // The maximum number of diagonal moves is k.
        // This is because we can always make k diagonal moves to reach (k, k) or similar,
        // and then use straight moves to adjust.
        // For example, if N=2, M=2, k=2. (N+M)=4, k=2. Same parity.
        // (0,0)->(1,1)->(2,2). 2 moves, 2 diag. Max diag = k = 2.
        //
        // If (N+M) and k have different parities, then we cannot reach (N, M) in k moves
        // if all moves are diagonal or all moves are straight.
        // We need to make at least one move that changes the parity of (x+y) by 1.
        //
        // The key insight is that each move changes the parity of (x+y).
        // So, (N+M) must have the same parity as k.
        // If (N+M) % 2 != k % 2, it's impossible to reach (N, M) in k moves.
        // However, this is not entirely true.
        // Consider (0,0) -> (1,0) -> (1,1) -> (2,2).
        // N=2, M=2, k=3. (N+M)=4 (even), k=3 (odd). Parity mismatch.
        // But the example output is 1.
        //
        // The parity condition is (N % 2 == M % 2) and (k % 2 == N % 2)
        // OR (N % 2 != M % 2) and (k % 2 != N % 2).
        // This is equivalent to (N % 2 == M % 2) == (k % 2 == N % 2).
        //
        // Let's re-evaluate.
        // We need to reach (N, M).
        // We can make N diagonal moves to reach (N, N).
        // Then M-N straight moves to reach (N, M).
        // This uses M moves.
        // The number of diagonal moves is N.
        // The number of straight moves is M-N.
        // Total moves = M.
        //
        // We have k total moves.
        // If k == M:
        //   If N % 2 == M % 2: (N, M) has same parity for both coordinates.
        //     We can reach (N, M) using N diagonal moves and M-N straight moves.
        //     The number of diagonal moves is N.
        //     Example: (2,2,2). N=2, M=2, k=2. N=2 diag, M-N=0 straight. Total 2 moves. Max diag = 2.
        //     Example: (4,3,3). N=3, M=4, k=3. Impossible.
        //     Example: (4,3,4). N=3, M=4, k=4. (0,0)->(1,1)->(2,2)->(3,3)->(3,4). 3 diag, 1 straight. Total 4 moves. Max diag = 3.
        //
        // If k > M:
        // We have k - M extra moves.
        // Each pair of extra moves can be used to increase the number of diagonal moves by 2,
        // or decrease by 2, or keep it the same.
        //
        // Consider the parity of (N, M) and k.
        // If N and M have different parities (e.g., (2,3)), then (N+M) is odd.
        // If N and M have the same parity (e.g., (2,2)), then (N+M) is even.
        //
        // Each diagonal move changes (x,y) to (x+/-1, y+/-1). Parity of x and y both flip.
        // So, (x%2, y%2) -> ((x+1)%2, (y+1)%2).
        // Each straight move changes (x,y) to (x+/-1, y) or (x, y+/-1). One parity flips, other stays.
        // So, (x%2, y%2) -> ((x+1)%2, y%2) or (x%2, (y+1)%2).
        //
        // Let's analyze the parity of N and M.
        // Case A: N and M have the same parity (N % 2 == M % 2).
        //   This means N-M is even.
        //   We can reach (N, M) using N diagonal moves to (N, N) and M-N straight moves to (N, M).
        //   This uses M moves.
        //   If k == M: Max diagonal moves is N.
        //   If k > M: We have k-M extra moves.
        //     Since N and M have same parity, (N, M) is reachable from (0,0) with an even number of straight moves
        //     after some diagonal moves.
        //     The total number of moves k must also have the same parity as M.
        //     If k % 2 == M % 2 (i.e., k-M is even):
        //       We can use all k moves. The maximum number of diagonal moves is k.
        //       Example: (2,2,4). N=2, M=2, k=4. N%2==M%2. k-M=2 (even). Max diag = 4.
        //       (0,0)->(1,1)->(2,2)->(1,1)->(2,2). 4 moves, 4 diag.
        //     If k % 2 != M % 2 (i.e., k-M is odd):
        //       We cannot use all k moves to make only diagonal moves or only straight moves.
        //       We need to "waste" one move's parity.
        //       The maximum number of diagonal moves is k-2.
        //       Example: (2,2,3). N=2, M=2, k=3. N%2==M%2. k-M=1 (odd). Max diag = k-2 = 1.
        //       (0,0)->(1,0)->(1,1)->(2,2). 1 diag.
