#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, std::numeric_limits<long long>::max()); // b[j] = min(m_i - current_add[j])
    std::vector<long long> current_add(n, 0); // current_add[j] = sum of d_k applied to j

    // First pass: Determine upper bounds for initial array elements
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_add[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_add[j]);
            }
        }
    }

    // Initialize initial array a_0 with the determined upper bounds
    // If b[j] is still max_long_long, it means no type 2 operation constrained it.
    // We can set it to 0, as it will satisfy |a_i| <= 10^9.
    // However, setting it to 0 might not be optimal for satisfying type 2 queries.
    // The problem asks for *any* suitable array.
    // If b[j] is max_long_long, it means a_0[j] can be anything up to 10^9.
    // To satisfy max queries, we want to make values as large as possible.
    // So, we set a_0[j] = b[j]. If b[j] is max_long_long, it means it's unconstrained by type 2 queries.
    // We can set it to 10^9 to maximize its value, but 0 is also fine.
    // Let's stick to b[j] as the initial value. If it's max_long_long, it means it's not constrained by any max query.
    // We can set it to 0, or any value within [-10^9, 10^9].
    // For simplicity, let's use b[j] directly. If it's max_long_long, it will be handled by the check below.
    // The problem states |a_i| <= 10^9.
    // If b[j] is still max_long_long, it means it was never constrained by a type 2 query.
    // In this case, we can set a_0[j] to 0.
    // If b[j] is constrained, it must be <= 5*10^7 - (-5000*10^4) = 5*10^7 + 5*10^7 = 10^8.
    // And >= -5*10^7 - (5000*10^4) = -5*10^7 - 5*10^7 = -10^8.
    // So, b[j] will always be within [-10^8, 10^8] if constrained.
    // If not constrained, we set it to 0.
    for (int j = 0; j < n; ++j) {
        if (b[j] == std::numeric_limits<long long>::max()) {
            b[j] = 0; // Unconstrained initial value, set to 0
        }
    }

    // Second pass: Verify all operations with the constructed initial array
    std::fill(current_add.begin(), current_add.end(), 0); // Reset current_add

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_add[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, b[j] + current_add[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check if initial array elements are within [-10^9, 10^9]
    for (int j = 0; j < n; ++j) {
        if (b[j] < -1000000000LL || b[j] > 1000000000LL) {
            // This case should ideally not be reached if b[j] is constrained
            // to be within [-10^8, 10^8] or set to 0.
            // But as a safeguard:
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        std::cout << b[j] << (j == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

