            //     Else (a_i > current_min_val + x): we must increment a_i.
            //       The target value must be current_min_val + m.
            //       The cost is (current_min_val + m - a_i) % m.
            //       If this cost > x, then it's impossible. Return false.
            //       Else: we can set b_i = current_min_val + m. current_min_val for next becomes current_min_val.
            // This is still not quite right. The `current_min_val` for the next element should be `b_i`.

            // Let's rephrase: we need to find `b_i` such that `b_i >= current_min_val` and `b_i` can be obtained from `a_i` with at most `x` operations.
            // The values `a_i` can become are `(a_i + k) % m` for `0 <= k <= x`.
            // If `a_i + x < m`: the possible values are `[a_i, a_i + x]`.
            // If `a_i + x >= m`: the possible values are `[a_i, m-1]` union `[0, (a_i + x) % m]`.

            // Case 1: `a_i >= current_min_val`.
            // We can potentially keep `a_i` as `b_i`. This costs 0 operations.
            // This is valid. So, we can set `b_i = a_i`.
            // The `current_min_val` for the next element becomes `a_i`.
            // However, we also have the option to increment `a_i` to `current_min_val + m`.
            // This costs `(current_min_val + m - a_i) % m`.
            // If this cost is `<= x`, then we can achieve `current_min_val + m`.
            // If `a_i` is "too large" (i.e., `a_i > current_min_val + x`), then we cannot keep `a_i` as `b_i`
            // because `b_i` would be `a_i`, and `a_i` is too far from `current_min_val` to be incremented to `current_min_val + m`
            // without exceeding `x` operations.
            // No, this is wrong. If `a_i >= current_min_val`, we can always choose `b_i = a_i`.
            // The only constraint is that `b_i` must be reachable from `a_i` with `k <= x` operations.
            // If we choose `b_i = a_i`, `k=0`, which is `<= x`. So this is always possible.
            // So if `a_i >= current_min_val`, we can set `b_i = a_i`.
            // Then `current_min_val` for the next element becomes `a_i`.
            // This is the greedy choice: keep `b_i` as small as possible.
            // But what if `a_i` is very large, e.g., `a_i = m-1`, `current_min_val = 0`, `x = 0`.
            // Then `b_i = m-1`. Next `current_min_val = m-1`.
            // If `a_{i+1} = 0`, then `a_{i+1} < current_min_val`.
            // Cost to change `a_{i+1}` to `current_min_val` is `(m-1 - 0 + m) % m = m-1`.
            // If `x=0`, this is impossible.
            // So, if `a_i >= current_min_val`, we have two options for `b_i`:
            // 1. `b_i = a_i`. This costs 0. Next `current_min_val` becomes `a_i`.
            // 2. `b_i = current_min_val + m`. This costs `(current_min_val + m - a_i) % m`.
            //    This is only possible if `(current_min_val + m - a_i) % m <= x`.
            //    If this is possible, then `b_i = current_min_val + m` is a valid choice.
            //    Next `current_min_val` becomes `current_min_val + m`.
            // We want to make `b_i` as small as possible, but also ensure future elements can be non-decreasing.
            // The greedy strategy is to make `b_i` as small as possible, i.e., `b_i = current_min_val`.
            // This is possible if `current_min_val` can be reached from `a_i` with `k <= x` operations.
            // Cost to change `a_i` to `current_min_val` is `(current_min_val - a_i + m) % m`.
            // If `(current_min_val - a_i + m) % m <= x`, then we can set `b_i = current_min_val`.
            // In this case, `current_min_val` for the next element remains `current_min_val`.
            // Otherwise, we must set `b_i = a_i`.
            // This is only possible if `a_i >= current_min_val`.
            // If `a_i < current_min_val`, then we must increment `a_i`.
            // The smallest value `a_i` can become that is `>= current_min_val` is `current_min_val`.
            // The cost to change `a_i` to `current_min_val` is `(current_min_val - a_i + m) % m`.
            // If this cost is `> x`, then it's impossible. Return false.
            // Otherwise, we set `b_i = current_min_val`.
            // `current_min_val` for the next element remains `current_min_val`.

            // Let's try this logic:
            // For each a_i:
            //   If a_i >= current_min_val:
            //     We have two options for b_i:
            //     1. Keep b_i = a_i. This costs 0. Next current_min_val becomes a_i.
            //     2. Change b_i to current_min_val. This costs (current_min_val - a_i + m) % m.
            //        This is only possible if (current_min_val - a_i + m) % m <= x.
            //        If possible, next current_min_val becomes current_min_val.
            //     We want to choose the option that makes b_i as small as possible,
            //     which is current_min_val.
            //     So, if (current_min_val - a_i + m) % m <= x, we can set b_i = current_min_val.
            //     Else, we must set b_i = a_i.
            //     This is equivalent to:
            //     If a_i + x < current_min_val + m:
            //       This means we cannot reach current_min_val + m from a_i.
            //       The values we can reach are [a_i, (a_i+x)%m] (possibly wrapped around).
            //       If a_i >= current_min_val, we can keep a_i.
            //       If a_i is in [current_min_val, current_min_val + x], we can keep a_i.
            //       If a_i is in [current_min_val + x + 1, m-1], we cannot keep a_i.
            //       We must increment a_i to current_min_val + m.
            //       The cost for this is (current_min_val + m - a_i) % m.
            //       If this cost is > x, then it's impossible.
            //       So, if a_i >= current_min_val:
            //         If a_i <= current_min_val + x: we can set b_i = a_i. current_min_val for next becomes a_i.
            //         Else (a_i > current_min_val + x): we must increment a_i.
            //           The target value must be current_min_val + m.
            //           The cost is (current_min_val + m - a_i) % m.
            //           If this cost > x, then it's impossible. Return false.
            //           Else: we can set b_i = current_min_val + m. current_min_val for next becomes current_min_val.

            // Let's use the simpler logic:
            // We need to find b_i such that b_i >= current_min_val and b_i is reachable from a_i with <= x operations.
            // We want to make b_i as small as possible. The smallest possible b_i is current_min_val.
            // Can we make b_i = current_min_val?
            // This is possible if (current_min_val - a_i + m) % m <= x.
            // If yes, then we set b_i = current_min_val, and current_min_val for the next element remains current_min_val.
            // If no, we cannot make b_i = current_min_val.
            // In this case, we must make b_i > current_min_val.
            // The smallest value b_i can take is a_i (if a_i >= current_min_val).
            // If a_i < current_min_val, and we cannot make b_i = current_min_val, then it's impossible.
            // Because if a_i < current_min_val, and (current_min_val - a_i + m) % m > x,
            // then we cannot reach current_min_val. And any value > current_min_val would cost even more.
            // So, if a_i < current_min_val:
            //   Cost to reach current_min_val is `current_min_val - a_i`.
            //   If `current_min_val - a_i > x`, then it's impossible. Return false.
            //   Else, we can set `b_i = current_min_val`. `current_min_val` for next remains `current_min_val`.
            // If a_i >= current_min_val:
            //   We can set `b_i = a_i`. Cost is 0. `current_min_val` for next becomes `a_i`.
            //   We can also try to set `b_i = current_min_val`. Cost is `(current_min_val - a_i + m) % m`.
            //   If `(current_min_val - a_i + m) % m <= x`, then we can set `b_i = current_min_val`.
            //   This is the better choice because it keeps `b_i` smaller.
            //   So, if `(current_min_val - a_i + m) % m <= x`, then `current_min_val` for next remains `current_min_val`.
            //   Else (meaning `a_i` is "too large" to be wrapped around to `current_min_val` with `x` operations),
            //     we must set `b_i = a_i`. `current_min_val` for next becomes `a_i`.

            // This logic seems correct and greedy.
            // Let's trace with an example: n=5, m=7, a = [0, 6, 1, 3, 2], x=1.
            // current_min_val = 0.
            // i=0, a[0]=0:
            //   a[0] >= current_min_val (0 >= 0).
            //   Cost to change a[0] to current_min_val (0) is (0 - 0 + 7) % 7 = 0.
            //   0 <= x (1). Yes.
            //   So, b[0] = 0. current_min_val remains 0.
            // i=1, a[1]=6:
            //   a[1] >= current_min_val (6 >= 0).
            //   Cost to change a[1] to current_min_val (0) is (0 - 6 + 7) % 7 = 1.
            //   1 <= x (1). Yes.
            //   So, b[1] = 0. current_min_val remains 0.
            // i=2, a[2]=1:
            //   a[2] >= current_min_val (1 >= 0).
            //   Cost to change a[2] to current_min_val (0) is (0 - 1 + 7) % 7 = 6.
            //   6 <= x (1). No.
            //   So, we must set b[2] = a[2] = 1. current_min_val becomes 1.
            // i=3, a[3]=3:
            //   a[3] >= current_min_val (3 >= 1).
            //   Cost to change a[3] to current_min_val (1) is (1 - 3 + 7) % 7 = 5.
            //   5 <= x (1). No.
            //   So, we must set b[3] = a[3] = 3. current_min_val becomes 3.
            // i=4, a[4]=2:
            //   a[4] < current_min_val (2 < 3).
            //   Cost to change a[4] to current_min_val (3) is 3 - 2 = 1.
            //   1 <= x (1). Yes.
            //   So, b[4] = 3. current_min_val remains 3.
            // All elements processed. Return true.
            // This matches the example output. The resulting array is [0, 0, 1, 3, 3].

        long long diff = (current_min_val - val_a_i + m) % m;
        if (diff <= x) {
            // We can make a_i become current_min_val.
            // So, current_min_val for the next element remains current_min_val.
        } else {
            // We cannot make a_i become current_min_val.
            // We must make a_i become something else.
            // The smallest value a_i can become that is >= current_min_val is a_i itself,
            // but only if a_i >= current_min_val.
            // If a_i < current_min_val, and we cannot make it current_min_val,
            // then we cannot make it any value >= current_min_val.
            // So, if a_i < current_min_val, and diff > x, it's impossible.
            // This is covered by the `diff` calculation.
            // If `val_a_i < current_min_val`, then `diff = current_min_val - val_a_i`.
            // If `diff > x`, then we cannot reach `current_min_val`.
            // And we cannot reach any value `> current_min_val` either, because that would cost even more.
            // So, if `val_a_i < current_min_val` and `diff > x`, return false.
            // This is implicitly handled by the `else` branch.
            // If `val_a_i >= current_min_val`, and `diff > x`, it means `val_a_i` is "too large"
            // to be wrapped around to `current_min_val` with `x` operations.
            // In this case, we must keep `val_a_i` as `b_i`.
            // So, `current_min_val` for the next element becomes `val_a_i`.
            current_min_val = val_a_i;
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2: uncomputed, -1: infinite loop
    std::vector<int> dp_x(n + 1, 0);     // 0: uncomputed, -1: infinite loop

    for (int i = 1; i <= n; ++i) {
        // For each starting x_curr, calculate the next state
        // x_curr is the value of x after step 3, or the initial x.
        // The problem states x=1 initially, then step 2, then step 3.
        // So, the "current" x for the recursive step is the x after step 3.
        // Let's define dp_y[k] as the total y accumulated starting from x=k,
        // and dp_x[k] as the final x value starting from x=k.
        // This is for the sequence of operations:
        // x_new = k + a[k]
        // x_final = x_new - a[k] = k
        // y_accumulated = a[k] + a[k] = 2*a[k]
        // So, if we start at x=k, we move to x=k, and y increases by 2*a[k].
        // This is an infinite loop if k is within [1, n].
        // This interpretation is incorrect based on the problem statement.

        // Let's re-read:
        // Initial: x=1, y=0.
        // Loop:
        //   1. Check termination (x <= 0 or x > n).
        //   2. x = x + a[x], y = y + a[x]. (Let's call this x_step2, y_step2)
        //   3. Check termination (x_step2 <= 0 or x_step2 > n).
        //   4. x = x - a[x_step2], y = y + a[x_step2]. (Let's call this x_step3, y_step3)
        //      Note: a[x_step2] is the value of a at the x *before* step 4, which is x_step2.
        //      This is crucial. The problem says "a_x" but it means the value of a at the current x.
        //      So, in step 4, it's a[x_step2].

        // Let's define dp_y[k] as the total y accumulated *after* the first pair of operations
        // (step 2 then step 3) if the program starts with x=k, and then continues from the new x.
        // And dp_x[k] as the final x value *after* the first pair of operations.

        // If we are at x_curr:
        // val_a = a[x_curr]
        // x_next_step2 = x_curr + val_a
        // y_accum_step2 = val_a
        // If x_next_step2 <= 0 or x_next_step2 > n, then this is a terminal state.
        //   The total y is y_accum_step2. The final x is x_next_step2.
        // Else:
        //   x_next_step3 = x_next_step2 - val_a
        //   y_accum_step3 = y_accum_step2 + val_a = 2 * val_a
        //   If x_next_step3 <= 0 or x_next_step3 > n, then this is a terminal state.
        //     The total y is y_accum_step3. The final x is x_next_step3.
        //   Else:
        //     The program continues from x_next_step3 with y_accum_step3 already added.
        //     So, dp_y[x_curr] = y_accum_step3 + dp_y[x_next_step3]
        //     And dp_x[x_curr] = dp_x[x_next_step3]

        // We can compute dp values for x from 1 to n.
        // The values a[x] are positive, so x + a[x] > x and x - a[x] < x.
        // This means the x values will always move away from the current x.
        // Specifically, x_next_step3 = x_curr + a[x_curr] - a[x_curr] = x_curr.
        // This is the key insight. The x value after one full cycle (step 2 then step 3)
        // returns to its original value.
        // So, if x_curr is in [1, n], it will always return to x_curr.
        // This means it's an infinite loop unless one of the intermediate x values
        // (x_curr + a[x_curr] or x_curr + a[x_curr] - a[x_curr]) goes out of bounds.

        // Let's re-evaluate the problem statement carefully:
        // "The program increases both x and y by a value equal to a_x simultaneously."
        // "The program now increases y by a_x while decreasing x by a_x."
        // The "a_x" in the second sentence refers to the *original* a_x from the start of the step 2/3 block.
        // This is the standard interpretation in competitive programming unless specified otherwise.
        // If it meant a[new_x], it would usually say a[x_new] or similar.

        // So, if current x is `curr_x`:
        // 1. `val_a = a[curr_x]`
        // 2. `x_after_step2 = curr_x + val_a`
        // 3. `y_after_step2 = val_a`
        // 4. Check termination for `x_after_step2`.
        // 5. `x_after_step3 = x_after_step2 - val_a` (This is `curr_x + val_a - val_a = curr_x`)
        // 6. `y_after_step3 = y_after_step2 + val_a = 2 * val_a`
        // 7. Check termination for `x_after_step3`.

        // This means if `curr_x` is in `[1, n]`, then `x_after_step3` is also `curr_x`.
        // This implies an infinite loop if both `x_after_step2` and `x_after_step3` stay in `[1, n]`.
        // The only way to terminate is if `x_after_step2` or `x_after_step3` goes out of bounds.

        // Let's define `dp_y[k]` as the total `y` accumulated if the program starts with `x=k`
        // and `dp_x[k]` as the final `x` value.
        // We need to compute this for `k` from `1` to `n`.
        // The problem asks for `a_1 = i` for `i` from `1` to `n-1`.
        // So, for each `i` from `1` to `n-1`, we set `a[1] = i`.
        // Then we run the simulation starting with `x=1, y=0`.

        // Let's use memoization for the results of starting at `x=k`.
        // `memo_y[k]` stores the total `y` if starting at `x=k` and terminating.
        // `memo_x[k]` stores the final `x` if starting at `x=k` and terminating.
        // `visited[k]` tracks states in the current path to detect cycles.

        // Initialize `memo_y` with -2 (uncomputed), `memo_x` with 0 (uncomputed).
        // `visited` with false.
        std::vector<long long> memo_y(n + 1, -2);
        std::vector<int> memo_x(n + 1, 0);
        std::vector<bool> visited(n + 1, false);

        // Function to solve for a given starting x
        // Returns pair<long long, int> {total_y, final_x}
        // If infinite loop, returns {-1, -1}
        auto solve = [&](int start_x, auto& self) -> std::pair<long long, int> {
            if (start_x <= 0 || start_x > n) {
                return {0, start_x}; // Base case: already terminated, 0 additional y
            }
            if (memo_y[start_x] != -2) {
                return {memo_y[start_x], memo_x[start_x]};
            }
            if (visited[start_x]) {
                return {-1, -1}; // Cycle detected
            }

            visited[start_x] = true;

            long long val_a = a[start_x];

            // Step 2: x = x + a[x], y = y + a[x]
            int x_step2 = start_x + val_a;
            long long y_step2_accum = val_a;

            if (x_step2 <= 0 || x_step2 > n) {
                visited[start_x] = false;
                memo_y[start_x] = y_step2_accum;
                memo_x[start_x] = x_step2;
                return {y_step2_accum, x_step2};
            }

            // Step 3: x = x - a[x_step2], y = y + a[x_step2]
            // The problem states "a_x" for the second operation.
            // This means a[x_step2] is used.
            // This is the standard interpretation.
            // If it meant a[start_x], it would be an infinite loop as x returns to start_x.
            // The example clarifies this:
            // For i=3, a = [3, 2, 4, 1]
            // x=1, y=0
            // val_a = a[1] = 3
            // Step 2: x = 1+3=4, y = 0+3=3
            // Check x=4: in bounds.
            // Step 3: val_a_at_x_step2 = a[4] = 1
            // x = 4-1=3, y = 3+1=4
            // Check x=3: in bounds.
            // Now the loop repeats with x=3, y=4.
            // val_a = a[3] = 4
            // Step 2: x = 3+4=7, y = 4+4=8
            // Check x=7: out of bounds (n=4). Terminate.
            // Final y = 8.

            // This confirms that a[x] in step 3 refers to a[x_after_step2].
            long long val_a_at_x_step2 = a[x_step2];
            int x_step3 = x_step2 - val_a_at_x_step2;
            long long y_step3_accum = y_step2_accum + val_a_at_x_step2;

            // Now, the program continues from x_step3 with y_step3_accum already added.
            std::pair<long long, int> res = self(x_step3, self);

            visited[start_x] = false;

            if (res.first == -1) { // Infinite loop detected further down
                memo_y[start_x] = -1;
                memo_x[start_x] = -1;
                return {-1, -1};
            } else {
                memo_y[start_x] = y_step3_accum + res.first;
                memo_x[start_x] = res.second;
                return {memo_y[start_x], memo_x[start_x]};
            }
        };

    }

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for this run

        // Reset memoization and visited for each run
        std::vector<long long> memo_y(n + 1, -2);
        std::vector<int> memo_x(n + 1, 0);
        std::vector<bool> visited(n + 1, false);

        // Start the simulation from x=1, y=0
        // The `solve` function calculates the total y and final x starting from `start_x`.
        // The initial state is x=1, y=0.
        // The first operation is:
        // val_a = a[1]
        // x_step2 = 1 + val_a
        // y_step2_accum = val_a
        // If x_step2 <= 0 or x_step2 > n, then terminate. Total y = val_a.
        // Else:
        //   val_a_at_x_step2 = a[x_step2]
        //   x_step3 = x_step2 - val_a_at_x_step2
        //   y_step3_accum = y_step2_accum + val_a_at_x_step2
        //   Now, we need to call solve for x_step3, and add y_step3_accum to its result.

        long long initial_val_a = a[1];
        int initial_x_step2 = 1 + initial_val_a;
        long long initial_y_step2_accum = initial_val_a;

        if (initial_x_step2 <= 0 || initial_x_step2 > n) {
            std::cout << initial_y_step2_accum << "\n";
        } else {
            long long initial_val_a_at_x_step2 = a[initial_x_step2];
            int initial_x_step3 = initial_x_step2 - initial_val_a_at_x_step2;
            long long initial_y_step3_accum = initial_y_step2_accum + initial_val_a_at_x_step2;

            std::pair<long long, int> res = [&] (int start_x, auto& self) -> std::pair<long long, int> {
                if (start_x <= 0 || start_x > n) {
                    return {0, start_x};
                }
                if (memo_y[start_x] != -2) {
                    return {memo_y[start_x], memo_x[start_x]};
                }
                if (visited[start_x]) {
                    return {-1, -1};
                }

                visited[start_x] = true;

                long long current_val_a = a[start_x];

                int next_x_step2 = start_x + current_val_a;
                long long next_y_step2_accum = current_val_a;

                if (next_x_step2 <= 0 || next_x_step2 > n) {
                    visited[start_x] = false;
                    memo_y[start_x] = next_y_step2_accum;
                    memo_x[start_x] = next_x_step2;
                    return {next_y_step2_accum, next_x_step2};
                }

                long long current_val_a_at_next_x_step2 = a[next_x_step2];
                int next_x_step3 = next_x_step2 - current_val_a_at_next_x_step2;
                long long next_y_step3_accum = next_y_step2_accum + current_val_a_at_next_x_step2;

                std::pair<long long, int> recursive_res = self(next_x_step3, self);

                visited[start_x] = false;

                if (recursive_res.first == -1) {
                    memo_y[start_x] = -1;
                    memo_x[start_x] = -1;
                    return {-1, -1};
                } else {
                    memo_y[start_x] = next_y_step3_accum + recursive_res.first;
                    memo_x[start_x] = recursive_res.second;
                    return {memo_y[start_x], memo_x[start_x]};
                }
            }(initial_x_step3, solve); // Call the lambda with itself

            if (res.first == -1) {
                std::cout << -1 << "\n";
            } else {
                std::cout << initial_y_step3_accum + res.first << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long d_chain_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply d_chain_cry from previous children who left
            if (d_chain_cry > 0) {
                children[j].p -= d_chain_cry;
            }

            // Apply current_v_cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                d_chain_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

