// Function to calculate the number of '1's in a string
int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // The maximum number of '1's we can achieve in string 'a'
    // is its current count plus the number of '0's it has.
    // This is equivalent to its current count plus (length - current count).
    // If the current count of '1's is odd, we can append '1', increasing the count by 1.
    // If the current count of '1's is even, we can append '0', keeping the count the same.
    // After appending '1', the parity becomes even.
    // So, if we have an odd number of '1's, we can append '1' to make it even.
    // If we have an even number of '1's, we can append '0' to keep it even.
    // This means we can always make the number of '1's even if it's odd,
    // and keep it even if it's already even, by appending a character.
    // The only way to increase the number of '1's is if the current parity is odd.
    // So, the maximum number of '1's we can achieve is `ones_a` if `ones_a` is even,
    // or `ones_a + 1` if `ones_a` is odd.
    // This can be concisely written as `ones_a + (ones_a % 2)`.
    int max_ones_a_after_parity_ops = ones_a + (ones_a % 2);

    // Condition 1: The number of '1's in 'b' must not exceed the maximum possible '1's in 'a'
    // after any number of parity operations.
    if (ones_b > max_ones_a_after_parity_ops) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must not be greater than the length of 'a'
    // after any number of parity operations.
    // The maximum length 'a' can reach is effectively infinite, as we can always append.
    // So, this condition is always met if |b| <= |a| + (some large number).
    // However, we are interested in whether 'b' can be a suffix of some 'a''.
    // This means that the length of 'b' must be less than or equal to the length of 'a'
    // after some number of parity operations.
    // The minimum length 'a' can have is 1 (cannot remove from empty string).
    // The maximum length 'a' can have is effectively infinite.
    // The crucial part is that 'b' must be a suffix of some 'a'' derived from 'a'.
    // This implies that the length of 'b' must be less than or equal to the length of 'a'
    // at the point when 'b' is formed as a suffix.
    // If |b| > |a|, we must perform at least |b| - |a| parity operations.
    // Each parity operation adds one character.
    // So, the length of 'a' can always be extended to match or exceed |b|.

    // If both conditions are met, it is possible.
    // The logic is:
    // 1. If `ones_b` is greater than `ones_a + (ones_a % 2)`, it's impossible.
    //    This is because `ones_a + (ones_a % 2)` represents the maximum number of '1's
    //    we can ever have in `a` *at any point* if we only use parity operations to increase '1's.
    //    If `ones_a` is even, `ones_a % 2` is 0, max '1's is `ones_a`.
    //    If `ones_a` is odd, `ones_a % 2` is 1, max '1's is `ones_a + 1`.
    //    Once `ones_a` becomes even (either it was even, or we appended '1' to make it even),
    //    any subsequent parity operation will append '0' (since parity is 0),
    //    and the number of '1's will not increase further.
    // 2. If `ones_b` is less than or equal to `max_ones_a_after_parity_ops`,
    //    we can always achieve `ones_b` '1's.
    //    - If `ones_a` is odd and `ones_b == ones_a + 1`: append '1'.
    //    - If `ones_a` is odd and `ones_b == ones_a`: remove a '0' from `a` (if possible) or append '0' (if `ones_a` becomes even).
    //    - If `ones_a` is even and `ones_b == ones_a`: append '0'.
    //    The key is that we can always adjust the number of '1's to `ones_b`
    //    as long as `ones_b` is not too large.
    //    Once we have the correct number of '1's, we can append '0's until the string is long enough,
    //    and then remove characters from the front until `b` is a suffix.
    //    The only constraint is that the length of `b` must be achievable.
    //    Since we can always append characters, we can always make `a` long enough.
    //    Then, we can remove characters from the front of `a` until `b` is a suffix.
    //    The only way this fails is if `b` is longer than `a` and we can't get enough '1's.
    //    But we've already checked the '1's count.
    //    So, if `ones_b <= max_ones_a_after_parity_ops`, it's always possible.

    std::cout << "YES\n";

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2 || (n % 4 != 0 && n > 2)) { // N = 2, or N is even but not divisible by 4 (e.g., 6, 10, 14, ...)
                    chanek_coins += 1;
                    n -= 1;
                } else { // N is divisible by 4 (e.g., 4, 8, 12, ...)
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2 || (n % 4 != 0 && n > 2)) { // N = 2, or N is even but not divisible by 4
                    n -= 1;
                } else { // N is divisible by 4
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

