            }
        }

        // `max_l_for_r` is the maximum `l` such that `[l, r]` contains a 3-AP.
        // This is `max(x)` over all `x, k` such that `x+2k <= r` and `s_x = s_{x+k} = s_{x+2k}`.
        // Let `max_l_for_r_val` be this value.
        // We can compute `max_l_for_r_val` for current `r` based on `max_l_for_r_val` for `r-1`.
        // `max_l_for_r_val[r] = max(max_l_for_r_val[r-1], max_x_ending_at_r)`.
        // This is the correct recurrence.
        static int max_l_for_r_val = 0; // Stores max_l_for_r for the current r
        max_l_for_r_val = std::max(max_l_for_r_val, max_x_ending_at_r);

        // If `max_l_for_r_val` is 0, it means no 3-AP ends at or before `r`.
        // So for this `r`, no `l` will form a good pair.
        if (max_l_for_r_val > 0) {
            // For current `r`, any `l` from `1` to `max_l_for_r_val` will form a good pair.
            // The number of such `l` values is `max_l_for_r_val`.
            total_good_pairs += max_l_for_r_val;
        }
    }

    std::cout << total_good_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>
#include <map>

using namespace std;

const long long INF = 4e18; // Sufficiently large infinity

struct Segment {
    long long l, r;
    long long cost; // max(r - h, h - l) for some h in [l, r]
    long long h_val; // The h that achieves this cost

    bool operator<(const Segment& other) const {
        if (l != other.l) return l < other.l;
        return r < other.r;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, m;
    cin >> n >> m;

    vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        cin >> h[i];
    }

    vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        cin >> p[i];
    }

    // Filter out p_i that are already covered by h_i
    vector<long long> required_p;
    int h_idx = 0;
    for (long long val_p : p) {
        while (h_idx < n && h[h_idx] < val_p) {
            h_idx++;
        }
        if (h_idx < n && h[h_idx] == val_p) {
            // p_i is already covered by h_i, skip
        } else {
            required_p.push_back(val_p);
        }
    }
    p = required_p;
    m = p.size();

    if (m == 0) {
        cout << 0 << endl;
        return 0;
    }

    // Calculate initial segments for each head
    // For each head h_i, it can cover [h_i - t, h_i + t] in time t.
    // We need to find the minimum t such that all p_j are covered.
    // This is a binary search problem on t.

    long long low = 0, high = 2e10; // Max possible time: max(p_i) - min(h_i) or similar
    long long ans = high;

    while (low <= high) {
        long long t = low + (high - low) / 2;

        // For a given time t, determine if all required tracks p_j can be covered.
        // Each head h_i can cover the range [h_i - t, h_i + t].
        // We need to check if the union of n such ranges covers all p_j.

        vector<pair<long long, long long>> head_ranges;
        for (long long head_pos : h) {
            head_ranges.push_back({head_pos - t, head_pos + t});
        }

        // Merge overlapping head ranges
        sort(head_ranges.begin(), head_ranges.end());
        vector<pair<long long, long long>> merged_ranges;
        if (!head_ranges.empty()) {
            merged_ranges.push_back(head_ranges[0]);
            for (size_t i = 1; i < head_ranges.size(); ++i) {
                if (head_ranges[i].first <= merged_ranges.back().second) {
                    merged_ranges.back().second = max(merged_ranges.back().second, head_ranges[i].second);
                } else {
                    merged_ranges.push_back(head_ranges[i]);
                }
            }
        }

        // Check if all p_j are covered by the merged ranges
        bool all_covered = true;
        int p_idx = 0;
        for (const auto& range : merged_ranges) {
            while (p_idx < m && p[p_idx] < range.first) {
                // p[p_idx] is not covered by current range and is before it
                all_covered = false;
                break;
            }
            if (!all_covered) break;

            while (p_idx < m && p[p_idx] <= range.second) {
                p_idx++;
            }
        }
        if (p_idx < m) { // Some p_j are still not covered
            all_covered = false;
        }

        if (all_covered) {
            ans = t;
            high = t - 1;
        } else {
            low = t + 1;
        }
    }

    cout << ans << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a_min = elements[0].value;
    long long a_max = elements[n - 1].value;
    long long a_second_min = elements[1].value;
    long long a_second_max = elements[n - 2].value;

    // Case 1: All elements in one subsequence (e.g., S1 is empty or S2 is empty)
    // This means all f(a_i, a_j) = a_i + a_j.
    // min_f = a_min + a_second_min
    // max_f = a_max + a_second_max
    // Goodness = (a_max + a_second_max) - (a_min + a_second_min)
    long long goodness1 = (a_max + a_second_max) - (a_min + a_second_min);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // This means there will be values of type a_i + a_j and a_i + a_j + h.
    // min_f will always be a_min + a_second_min (if n >= 2).
    // max_f could be a_max + a_second_max or a_max + a_min + h.
    // The minimum possible max_f is min(a_max + a_second_max, a_max + a_min + h).
    // However, if a_max and a_min are in different sets, then a_max + a_min + h is a candidate for max_f.
    // If a_max and a_min are in the same set, then a_max + a_second_max is a candidate for max_f.
    // The crucial observation is that if we want to minimize max_f - min_f, we want to make the range of values as small as possible.
    // The smallest possible min_f is a_min + a_second_min.
    // The smallest possible max_f is a_max + a_min + h IF a_min and a_max are in different sets.
    // The smallest possible max_f is a_max + a_second_max IF a_min and a_max are in the same set.

    // Consider the partition where a_min is in S1, and all other elements are in S2.
    // Or a_max is in S1, and all other elements are in S2.
    // Or a_min and a_max are in S1, and all others in S2.
    // Or a_min is in S1, a_max is in S2, and others are distributed.

    // Let's analyze the values:
    // min_val_f = a_min + a_second_min
    // max_val_f_same_subsequence = a_max + a_second_max
    // max_val_f_diff_subsequence = a_max + a_min + h

    // If we put a_min in S1 and all other elements in S2:
    // Pairs in S1: None (if n=1, but n>=2)
    // Pairs in S2: (a_second_min, a_third_min), ..., (a_second_max, a_max)
    // Pairs across S1 and S2: (a_min, a_second_min), ..., (a_min, a_max)
    // min_f = a_min + a_second_min + h (from (a_min, a_second_min))
    // max_f = a_max + a_second_max (from S2) OR a_max + a_min + h (from (a_min, a_max))
    // This strategy is not good because a_min + a_second_min + h is likely large.

    // The key insight is that to minimize max_f - min_f, we want to make min_f as large as possible and max_f as small as possible.
    // The smallest possible value for any f is a_min + a_second_min.
    // The largest possible value for any f is a_max + a_second_max + h (if a_max and a_second_max are in different sets)
    // or a_max + a_second_max (if a_max and a_second_max are in same set)
    // or a_max + a_min + h (if a_max and a_min are in different sets)

    // Consider the partition where a_min is in S1, and all other elements are in S2.
    // This means a_min is in S1, and {a_second_min, ..., a_max} are in S2.
    // Values of f:
    // 1. From S2: (a_second_min + a_third_min) ... (a_second_max + a_max)
    //    Min: a_second_min + a_third_min (if n >= 3)
    //    Max: a_max + a_second_max
    // 2. From S1-S2: (a_min + a_second_min + h) ... (a_min + a_max + h)
    //    Min: a_min + a_second_min + h
    //    Max: a_min + a_max + h
    // Overall min_f = min(a_second_min + a_third_min (if n>=3 else infinity), a_min + a_second_min + h)
    // Overall max_f = max(a_max + a_second_max, a_min + a_max + h)
    // This is not the optimal strategy.

    // The optimal strategy for minimizing max_f - min_f usually involves making the range of values as compact as possible.
    // The smallest possible sum is a_min + a_second_min.
    // The largest possible sum is a_max + a_second_max.
    // If we put a_min and a_max in different sets, then a_min + a_max + h will be a value.
    // If we put a_min and a_max in the same set, then a_min + a_max will be a value.

    // Let's consider two main scenarios for the partition:
    // Scenario A: All elements are in the same subsequence.
    //   min_f = a_min + a_second_min
    //   max_f = a_max + a_second_max
    //   Goodness = (a_max + a_second_max) - (a_min + a_second_min)
    //   This is `goodness1` calculated above.

    // Scenario B: Elements are split into two non-empty subsequences.
    //   In this case, there must be at least one pair (x, y) where x is in S1 and y is in S2.
    //   So, values of type `x + y + h` will exist.
    //   The minimum possible value of `f` is `min(a_i + a_j, a_k + a_l + h)`.
    //   This minimum will always be `a_min + a_second_min` (if n >= 2).
    //   The maximum possible value of `f` is `max(a_i + a_j, a_k + a_l + h)`.
    //   This maximum could be `a_max + a_second_max` (if a_max and a_second_max are in the same set)
    //   OR `a_max + a_min + h` (if a_max and a_min are in different sets).

    // Let's consider a specific partition for Scenario B:
    // Put `a_min` in S1. Put `a_max` in S2. Put all other elements in S2.
    // S1 = {a_min}
    // S2 = {a_second_min, ..., a_second_max, a_max}
    //
    // Values of f:
    // 1. Pairs within S2:
    //    Min: a_second_min + elements[2].value (if n >= 3)
    //    Max: a_max + a_second_max
    // 2. Pairs between S1 and S2:
    //    Min: a_min + a_second_min + h
    //    Max: a_min + a_max + h
    //
    // Overall min_f:
    // If n=2, S1={a_min}, S2={a_max}. Only pair is (a_min, a_max). f = a_min + a_max + h. min_f = max_f = a_min + a_max + h. Goodness = 0.
    // If n>=3:
    //   min_f = min(a_second_min + elements[2].value, a_min + a_second_min + h)
    //   This is not necessarily a_min + a_second_min.
    //   This partition strategy is not guaranteed to produce a_min + a_second_min as the minimum.

    // The problem states that `min_f` is the minimum over ALL pairs.
    // So `min_f` will always be `a_min + a_second_min`.
    // The `max_f` will be `max(max_same_subsequence, max_diff_subsequence)`.
    // `max_same_subsequence` is `a_max + a_second_max`.
    // `max_diff_subsequence` is `a_max + a_min + h`.
    // So, `max_f = max(a_max + a_second_max, a_max + a_min + h)`.
    // This is true IF a_min and a_max are in different subsequences.
    // If a_min and a_max are in the same subsequence, then `max_f = a_max + a_second_max`.

    // Let's re-evaluate the possible range of values.
    // The smallest possible sum of two distinct elements is `a_min + a_second_min`.
    // The largest possible sum of two distinct elements is `a_max + a_second_max`.

    // Case 1: All elements in one subsequence (e.g., all 1s).
    //   min_f = a_min + a_second_min
    //   max_f = a_max + a_second_max
    //   Goodness = (a_max + a_second_max) - (a_min + a_second_min)
    //   This is `goodness1`.

    // Case 2: Split into two non-empty subsequences.
    //   This means there is at least one pair (x, y) with x in S1, y in S2.
    //   So, `a_min + a_min_other_subsequence + h` is a candidate for min_f.
    //   And `a_max + a_max_other_subsequence + h` is a candidate for max_f.
    //   Also, `a_min + a_second_min` is always a candidate for min_f (if n >= 2).
    //   And `a_max + a_second_max` is always a candidate for max_f (if n >= 2).

    //   The minimum value of `f` will always be `a_min + a_second_min`.
    //   This is because `a_min + a_second_min` is the smallest possible sum `a_i + a_j`.
    //   Any `a_i + a_j + h` will be greater than or equal to `a_min + a_second_min + h`, which is greater than `a_min + a_second_min` (since h >= 0).
    //   So, `min_f = a_min + a_second_min`.

    //   Now we need to minimize `max_f`.
    //   `max_f` can be:
    //   - `a_max + a_second_max` (if a_max and a_second_max are in the same subsequence)
    //   - `a_max + a_min + h` (if a_max and a_min are in different subsequences)
    //   - `a_max + a_second_max + h` (if a_max and a_second_max are in different subsequences)
    //   The smallest possible `max_f` is `min(a_max + a_second_max, a_max + a_min + h)`.
    //   This is achieved by a partition where `a_min` and `a_max` are in different subsequences.
    //   For example, S1 = {a_min}, S2 = {all others}.
    //   In this partition:
    //     - `a_min` is in S1.
    //     - `a_second_min, ..., a_max` are in S2.
    //     - `a_max` and `a_second_max` are in S2, so `a_max + a_second_max` is a value.
    //     - `a_min` and `a_max` are in different sets, so `a_min + a_max + h` is a value.
    //     - `a_min` and `a_second_min` are in different sets, so `a_min + a_second_min + h` is a value.
    //   The overall `min_f` is `a_min + a_second_min`.
    //   The overall `max_f` is `max(a_max + a_second_max, a_min + a_max + h)`.
    //   Goodness = `max(a_max + a_second_max, a_min + a_max + h) - (a_min + a_second_min)`.

    // Let's call this `goodness2`.
    // `goodness2 = max(a_max + a_second_max, a_min + a_max + h) - (a_min + a_second_min)`.
    // This is the goodness if we ensure `a_min` and `a_max` are in different sets.
    // A simple partition for this is: `a_min` in S1, all others in S2.
    // Or `a_max` in S1, all others in S2.
    // Or `a_min` in S1, `a_max` in S2, and distribute others.

    // The crucial part is that `min_f` is always `a_min + a_second_min`.
    // So we need to minimize `max_f`.
    // `max_f` is determined by the largest sum of two elements in the same set, or the largest sum of two elements in different sets.
    // The largest sum of two elements in the same set is `a_max + a_second_max`.
    // The largest sum of two elements in different sets is `a_max + a_min + h`.
    // So, `max_f` will be at least `min(a_max + a_second_max, a_max + a_min + h)`.
    // This minimum is achieved if we can make `a_max + a_min + h` a value, and `a_max + a_second_max` a value.
    // This happens if `a_min` and `a_max` are in different sets.
    // For example, S1 = {a_min}, S2 = {a_second_min, ..., a_max}.
    // In this partition:
    //   - `a_min + a_second_min` is NOT a value (they are in different sets).
    //   - `a_min + a_second_min + h` IS a value.
    //   - `a_max + a_second_max` IS a value (both in S2).
    //   - `a_max + a_min + h` IS a value (in different sets).
    // So, for this partition:
    //   min_f = min(a_second_min + elements[2].value (if n>=3), a_min + a_second_min + h)
    //   max_f = max(a_max + a_second_max, a_min + a_max + h)

    // This is getting complicated. Let's simplify.
    // The values of f are of two types: `X = a_i + a_j` and `Y = a_i + a_j + h`.
    // The range of `X` values is `[a_min + a_second_min, a_max + a_second_max]`.
    // The range of `Y` values is `[a_min + a_second_min + h, a_max + a_second_max + h]`.

    // If all elements are in one subsequence (e.g., all 1s):
    //   Only `X` values exist.
    //   min_f = a_min + a_second_min
    //   max_f = a_max + a_second_max
    //   Goodness = (a_max + a_second_max) - (a_min + a_second_min)

    // If elements are split into two non-empty subsequences:
    //   Both `X` and `Y` values exist.
    //   min_f = min(min_X, min_Y)
    //   max_f = max(max_X, max_Y)

    //   `min_X` is `a_min + a_second_min`.
    //   `max_X` is `a_max + a_second_max`.
    //   `min_Y` is `a_min + a_second_min + h`.
    //   `max_Y` is `a_max + a_second_max + h`.

    //   So, `min_f = a_min + a_second_min`.
    //   And `max_f = max(max_X, max_Y)`.
    //   This is `max(a_max + a_second_max, a_max + a_second_max + h)`.
    //   Since `h >= 0`, `a_max + a_second_max + h` is always greater than or equal to `a_max + a_second_max`.
    //   So, if both types of values exist, `max_f = a_max + a_second_max + h`.
    //   This would mean `goodness = (a_max + a_second_max + h) - (a_min + a_second_min)`.
    //   This is generally larger than `goodness1` because of the `+h`.

    // This logic is flawed. `max_X` and `max_Y` are not necessarily `a_max + a_second_max` and `a_max + a_second_max + h`.
    // They depend on the specific partition.

    // Let's consider the values `a_min`, `a_second_min`, `a_second_max`, `a_max`.
    // The minimum possible sum is `a_min + a_second_min`.
    // The maximum possible sum is `a_max + a_second_max`.

    // Option 1: All elements in one group.
    //   min_f = a_min + a_second_min
    //   max_f = a_max + a_second_max
    //   Goodness = (a_max + a_second_max) - (a_min + a_second_min)
    //   Partition: all 1s.

    // Option 2: Split into two groups.
    //   This means there is at least one pair (x, y) with x in S1, y in S2.
    //   So, values of type `a_i + a_j + h` will exist.
    //   The minimum value of `f` will be `a_min + a_second_min`. (This is always true, as `a_min + a_second_min + h >= a_min + a_second_min`).
    //   The maximum value of `f` will be `max(max_same_subsequence, max_diff_subsequence)`.
    //   `max_same_subsequence` is `a_max + a_second_max`.
    //   `max_diff_subsequence` is `a_max + a_min + h`.
    //   So, `max_f = max(a_max + a_second_max, a_max + a_min + h)`.
    //   This is the `max_f` if we ensure that `a_min` and `a_max` are in different subsequences.
    //   A partition that achieves this: `a_min` in S1, `a_max` in S2, and all other elements in S2.
    //   S1 = {a_min}
    //   S2 = {a_second_min, ..., a_second_max, a_max}
    //   With this partition:
    //     - `a_min + a_second_min` is NOT a value (they are in different sets).
    //     - `a_min + a_second_min + h` IS a value.
    //     - `a_max + a_second_max` IS a value (both in S2).
    //     - `a_max + a_min + h` IS a value (in different sets).
    //   So, for this partition:
    //     min_f = min(a_second_min + elements[2].value (if n>=3), a_min + a_second_min + h)
    //     max_f = max(a_max + a_second_max, a_min + a_max + h)
    //   This is the crucial part. The `min_f` is not necessarily `a_min + a_second_min` for this specific partition.

    // Let's consider the values `a_min`, `a_max`.
    // If `a_min` and `a_max` are in the same subsequence (say S1):
    //   Then `a_min + a_max` is a value.
    //   `a_min + a_second_min` is a value.
    //   `a_max + a_second_max` is a value.
    //   If S2 is empty, this is Option 1.
    //   If S2 is not empty, then there is some `x` in S1 and `y` in S2.
    //   Then `x + y + h` values exist.
    //   The smallest `x+y+h` is `a_min + a_min_in_S2 + h`.
    //   The largest `x+y+h` is `a_max + a_max_in_S2 + h`.
    //   In this case, `min_f = a_min + a_second_min`.
    //   `max_f = max(a_max + a_second_max, a_max + a_max_in_S2 + h)`.
    //   This `max_f` is at least `a_max + a_second_max + h` (if S2 contains `a_second_max` and S1 contains `a_max`).
    //   This is generally worse than Option 1.

    // The only way to get a better goodness than Option 1 is if `h` is very small,
    // such that `a_max + a_min + h` is smaller than `a_max + a_second_max`.
    // This happens if `a_min + h < a_second_max`.

    // Let's consider the two main candidates for optimal partition:
    // Candidate 1: All elements in one subsequence.
    //   Partition: `1 1 ... 1`
    //   min_f = `a_min + a_second_min`
    //   max_f = `a_max + a_second_max`
    //   Goodness = `(a_max + a_second_max) - (a_min + a_second_min)`

    // Candidate 2: `a_min` in S1, `a_max` in S2, and all other elements in S2.
    //   Partition: `a_min` gets 1, `a_second_min` to `a_max` get 2.
    //   S1 = {a_min}
    //   S2 = {a_second_min, ..., a_max}
    //   Values of f:
    //     - Pairs within S2: `a_i + a_j` for `a_i, a_j` in S2.
    //       Min of these: `a_second_min + elements[2].value` (if n >= 3). If n=2, S2 has only `a_max`, no pairs.
    //       Max of these: `a_max + a_second_max`.
    //     - Pairs between S1 and S2: `a_min + a_j + h` for `a_j` in S2.
    //       Min of these: `a_min + a_second_min + h`.
    //       Max of these: `a_min + a_max + h`.
    //   Overall min_f:
    //     If n=2: S1={a_min}, S2={a_max}. Only pair is (a_min, a_max) across sets. f = a_min + a_max + h. min_f = a_min + a_max + h.
    //     If n>=3: min_f = min(a_second_min + elements[2].value, a_min + a_second_min + h).
    //   Overall max_f:
    //     If n=2: max_f = a_min + a_max + h.
    //     If n>=3: max_f = max(a_max + a_second_max, a_min + a_max + h).

    // Let's analyze n=2 separately.
    // If n=2: elements are a_0, a_1. Sorted: a_min, a_max.
    // Option 1: All in one. S1={a_min, a_max}, S2={}.
    //   f = a_min + a_max. min_f = max_f = a_min + a_max. Goodness = 0. Partition: 1 1.
    // Option 2: Split. S1={a_min}, S2={a_max}.
    //   f = a_min + a_max + h. min_f = max_f = a_min + a_max + h. Goodness = 0. Partition: 1 2.
    // In this case, both give goodness 0. We can pick any. Let's pick 1 1.

    // For n >= 3:
    // Candidate 1: All 1s.
    //   min_f = a_min + a_second_min
    //   max_f = a_max + a_second_max
    //   Goodness1 = (a_max + a_second_max) - (a_min + a_second_min)

    // Candidate 2: `a_min` in S1, all others in S2.
    //   S1 = {elements[0].value}
    //   S2 = {elements[1].value, ..., elements[n-1].value}
    //   min_f = min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //   max_f = max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //   Goodness2 = max_f - min_f

    // Let's compare Goodness1 and Goodness2.
    // Goodness1: (a_max + a_second_max) - (a_min + a_second_min)
    // Goodness2: max(a_max + a_second_max, a_min + a_max + h) - min(a_second_min + elements[2].value, a_min + a_second_min + h)

    // This is the standard approach for this type of problem:
    // The minimum value of `f` is always `a_min + a_second_min`.
    // The maximum value of `f` is `a_max + a_second_max` if all elements are in the same set.
    // The maximum value of `f` is `max(a_max + a_second_max, a_min + a_max + h)` if `a_min` and `a_max` are in different sets.
    // This is because `a_min + a_max + h` is the largest possible `a_i + a_j + h` value.
    // And `a_max + a_second_max` is the largest possible `a_i + a_j` value.

    // So, the minimum goodness is `min(Goodness1, Goodness2_simplified)`.
    // Goodness1 = (a_max + a_second_max) - (a_min + a_second_min)
    // Goodness2_simplified = max(a_max + a_second_max, a_min + a_max + h) - (a_min + a_second_min)
    // This simplification for Goodness2 assumes that `a_min + a_second_min` is always the minimum value of `f` even when split.
    // This is true. If `a_min` and `a_second_min` are in the same set, `a_min + a_second_min` is a value.
    // If `a_min` and `a_second_min` are in different sets, `a_min + a_second_min + h` is a value.
    // Since `h >= 0`, `a_min + a_second_min <= a_min + a_second_min + h`.
    // So, `a_min + a_second_min` is always the minimum possible value of `f`.

    // So, we compare:
    // 1. `(a_max + a_second_max) - (a_min + a_second_min)` (all 1s)
    // 2. `max(a_max + a_second_max, a_min + a_max + h) - (a_min + a_second_min)` (a_min and a_max in different sets)

    // Let `min_val_f = a_min + a_second_min`.
    // Let `max_val_f_same = a_max + a_second_max`.
    // Let `max_val_f_diff = a_min + a_max + h`.

    // Option 1: All in one subsequence.
    //   Goodness = `max_val_f_same - min_val_f`.
    //   Partition: all 1s.

    // Option 2: `a_min` in S1, `a_max` in S2.
    //   This ensures `max_val_f_diff` is a possible value.
    //   We also need `max_val_f_same` to be a possible value.
    //   If `a_max` and `a_second_max` are in S2, then `a_max + a_second_max` is a value.
    //   So, if we put `a_min

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s1 = 0;
    int initial_s2 = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s1++;
        } else {
            initial_s2++;
        }
    }

    int initial_diff = initial_s1 - initial_s2;

    // Calculate prefix sums for differences (1 for strawberry, -1 for blueberry)
    // For jars 1 to n (left side)
    std::vector<int> left_diff_prefix(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_diff_prefix[i + 1] = left_diff_prefix[i] + (a[i] == 1 ? 1 : -1);
    }

    // For jars n+1 to 2n (right side)
    // We want to calculate suffix sums, but it's easier to think of it as
    // prefix sums from right to left.
    // Let right_diff_suffix[k] be the difference for jars 2n-k+1 to 2n.
    // This means we are considering eating k jars from the right.
    std::vector<int> right_diff_suffix(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_diff_suffix[i + 1] = right_diff_suffix[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars eaten from the left to achieve a certain difference
    // map: diff_value -> num_jars_eaten
    std::map<int, int> left_diff_to_jars;
    for (int k = 0; k <= n; ++k) {
        int current_diff = left_diff_prefix[k];
        if (left_diff_to_jars.find(current_diff) == left_diff_to_jars.end()) {
            left_diff_to_jars[current_diff] = k;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars eaten from the right (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int diff_from_right_eaten = right_diff_suffix[k_R];

        // The remaining jars (after eating k_L from left and k_R from right)
        // will have a total difference of initial_diff - diff_from_left_eaten - diff_from_right_eaten.
        // We want this remaining difference to be 0.
        // So, initial_diff - diff_from_left_eaten - diff_from_right_eaten = 0
        // This means diff_from_left_eaten = initial_diff - diff_from_right_eaten
        int target_diff_from_left_eaten = initial_diff - diff_from_right_eaten;

        if (left_diff_to_jars.count(target_diff_from_left_eaten)) {
            int k_L = left_diff_to_jars[target_diff_from_left_eaten];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

