#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The strategy is to reverse the permutation.
    // This works because the set of adjacent sums {p_i + p_{i+1}}
    // is the same as the set of adjacent sums for the reversed permutation {p_{n-i} + p_{n-i-1}}.
    // Specifically, if p' is the reversed permutation, p'_i = p_{n-i+1}.
    // Then p'_i + p'_{i+1} = p_{n-i+1} + p_{n-(i+1)+1} = p_{n-i+1} + p_{n-i}.
    // This is just a reordering of the original sums.
    // For example, if p = [p1, p2, p3, p4], sums are [p1+p2, p2+p3, p3+p4].
    // Reversed p' = [p4, p3, p2, p1], sums are [p4+p3, p3+p2, p2+p1].
    // The set of sums is the same, so the sorted array (fingerprint) will be the same.
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, a permutation of distinct integers from 1 to n cannot be a palindrome
    // unless n=1 (not allowed, n>=2) or n=2 and p=[1,2] or p=[2,1].
    // For n=2, p=[1,2], reversed is [2,1], which is different.
    // For n=2, p=[2,1], reversed is [1,2], which is different.
    // For n > 2, a permutation of 1 to n cannot be a palindrome.
    // If p is a palindrome, p_i = p_{n-i+1} for all i.
    // This would mean p_1 = p_n, p_2 = p_{n-1}, etc.
    // But all elements in a permutation must be distinct.
    // So, p_1 = p_n implies p_1 is not distinct from p_n, which is only possible if n=1.
    // But n >= 2.
    // Therefore, reversing a permutation always yields a different permutation.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

