void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        if (val == 2048) {
            current_sum += 2048 * count;
            break; // If 2048 is present, we can stop.
                   // Even if we have multiple 2048s, one is enough.
                   // And we don't need to combine anything further.
        }

        // Add the contribution of 'val' to the current sum.
        // We can combine 'count' instances of 'val' to form 'count / 2' instances of '2*val'.
        // The remaining 'count % 2' instances of 'val' are added to the sum.
        // This is equivalent to just adding 'val * count' to the sum,
        // as the sum represents the total value we have that can be combined.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

