    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;

    int current_color_for_T_half = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // Always assign to white (c)
        } else if (a[i] > T_half) {
            p[i] = 1; // Always assign to black (d)
        } else { // a[i] == T_half
            if (T_is_even) {
                p[i] = current_color_for_T_half;
                current_color_for_T_half = 1 - current_color_for_T_half; // Alternate color
            } else { // T is odd, so T_half is not an integer, a[i] cannot be T_half
                     // This branch should ideally not be reached if a[i] == T_half
                     // but T is odd. However, if T_half is integer division,
                     // then a[i] == T_half means a[i] < T/2.
                     // The problem states a_i are non-negative integers.
                     // If T is odd, T/2 is not an integer. So a_i cannot be exactly T/2.
                     // For example, if T=7, T_half=3. If a_i=3, then a_i < T/2.
                     // If a_i=4, then a_i > T/2.
                     // So this 'else' branch only executes if T is even.
                p[i] = 0; // Should not happen for T odd
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

