        // This means a_k can modify a_j for any k < j.
        // So, has_pos_one and has_neg_one should track if a 1 or -1 has appeared *anywhere before* the current index.
        // The current implementation correctly updates these flags as we iterate.
        // For a_i, we need to know if there was a 1 or -1 at any a_k where k < i.
        // The flags `has_pos_one` and `has_neg_one` are updated *after* checking `a[i]` vs `b[i]`.
        // This means when checking `a[i]`, the flags reflect elements `a[0]` to `a[i-1]`. This is correct.
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

