#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // This is because all other p[j] (j!=i) must be <= n-1,
        // and if p[i] were n-1, then there would be no value n left for any p[j].
        // But if p[i] is n, then min(p[i], p[j]) = p[j] for all j!=i.
        // So max_val_in_row would be max(p[j] for j!=i), which is n-1.
        // Thus, if max_val_in_row is n-1, p[i] must be n.
        // Otherwise, p[i] is simply max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

