int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents 2^0, 2^1, 2^2, ...
        while (true) {
            long long cost_for_k = k * (k + 1) / 2;
            long long total_cost_for_staircase = cost_for_k + k * (k - 1) / 2; // k*(k+1)/2 + k*(k-1)/2 = k^2

            if (current_cost + total_cost_for_staircase <= x) {
                current_cost += total_cost_for_staircase;
                count++;
                k = k * 2 + 1; // Next k is 2*k_prev + 1
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams, we need 'mid' coders and 'mid' mathematicians at minimum.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and x no-specialization students.
            // These remaining students can fill the third slot in the 'mid' teams.
            // Each team needs 3 members. 'mid' teams need 3 * 'mid' members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' more students to fill the third slot in each team.
            // The available students for the third slot are (c - mid) + (m - mid) + x.
            // If (c - mid) + (m - mid) + x >= mid, then it's possible to form 'mid' teams.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

