int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int target_open = k / 2;
    int target_close = k / 2;

    for (char c : s) {
        if (c == '(') {
            if (open_count < target_open) {
                result += '(';
                open_count++;
            }
        } else { // c == ')'
            if (close_count < target_close && open_count > close_count) {
                result += ')';
                close_count++;
            }
        }
        if (open_count == target_open && close_count == target_close) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate the first k+1 elements to produce k distinct differences
    // The pattern is: left, right, left+1, right-1, left+2, right-2, ...
    // This generates differences: |right-left|, |(left+1)-right|, |(right-1)-(left+1)|, ...
    // which are: k, k-1, k-2, ... , 1
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index: print from left (ascending)
            std::cout << left << " ";
            left++;
        } else { // Odd index: print from right (descending)
            std::cout << right << " ";
            right--;
        }
    }

    // For the remaining n - (k+1) elements, just append them in increasing order.
    // This will generate only difference 1, as the last element printed was either left or right,
    // and the next element will be left or right + 1.
    // Example: if last was left, next is left+1. Diff is 1.
    // Example: if last was right, next is right+1. Diff is 1.
    // In both cases, the sequence continues with consecutive numbers, generating only difference 1.
    // The values of 'left' and 'right' have crossed or met by now.
    // The next available number is max(left, right).
    // Since left was incremented and right decremented, the next number to use is the current 'left' value.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m; // Number of multiples of m up to n

        // Precompute the sum of last digits for one full cycle (10 multiples)
        // The last digits of k*m repeat with a cycle length of 10.
        // E.g., for m=3: 3, 6, 9, 2, 5, 8, 1, 4, 7, 0, then 3, 6, ...
        // The sum of these 10 digits is constant for any m.
        // (m*1)%10, (m*2)%10, ..., (m*10)%10

        long long sum_of_first_ten_last_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_of_first_ten_last_digits += (m * i) % 10;
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_of_first_ten_last_digits;

        // Calculate the sum for the remaining multiples
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (m * i) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

