void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string ans(n, '0');

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we need to expand the segment to include m.
        // The segment must contain all numbers from 1 to m.
        // This means it must contain 1, 2, ..., m-1, and m.
        // The current segment [current_min_idx, current_max_idx] already contains 1, ..., m-1.
        // We need to expand it to include m.
        // The position of m is pos[m].
        // We update current_min_idx and current_max_idx to cover the range [1, m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // satisfies the conditions for m to be beautiful.
        // 1. It contains 1 (guaranteed by initialization and expansion).
        // 2. It contains m (guaranteed by expansion).
        // 3. The length of the segment must be exactly m.
        //    Length = current_max_idx - current_min_idx + 1.
        if (current_max_idx - current_min_idx + 1 == m) {
            ans[m - 1] = '1';
        }
    }

    std::cout << ans << "\n";
}

