void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_ok: prefix_ok[i] is true if a[0...i] can form 0, 1, ..., i
    // i.e., a[j] >= j for all 0 <= j <= i
    std::vector<bool> prefix_ok(n);
    prefix_ok[0] = (a[0] >= 0); // Always true for non-negative a[0]
    for (int i = 1; i < n; ++i) {
        prefix_ok[i] = (a[i] >= i) && prefix_ok[i-1];
    }

    // Calculate suffix_ok: suffix_ok[i] is true if a[i...n-1] can form ..., 2, 1, 0
    // i.e., a[j] >= n-1-j for all i <= j <= n-1
    std::vector<bool> suffix_ok(n);
    suffix_ok[n-1] = (a[n-1] >= 0); // Always true for non-negative a[n-1]
    for (int i = n - 2; i >= 0; --i) {
        suffix_ok[i] = (a[i] >= (n - 1 - i)) && suffix_ok[i+1];
    }

    // Check if there exists a peak k (0-indexed) such that
    // a[0...k] can form 0, 1, ..., k
    // AND a[k...n-1] can form k, k-1, ..., 0
    // This means prefix_ok[k] must be true AND suffix_ok[k] must be true.
    // The condition a[k] >= k and a[k] >= n-1-k is implicitly checked by prefix_ok[k] and suffix_ok[k].
    // We need to find if there is any k such that prefix_ok[k] && suffix_ok[k] is true.
    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (prefix_ok[k] && suffix_ok[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

