int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // First, make the median element equal to s.
    // This is a[median_idx] in the sorted array.
    operations += std::abs(a[median_idx] - s);

    // If a[median_idx] is less than s, we need to increase it.
    // All elements to its left (a[0]...a[median_idx-1]) must be <= s.
    // If any of them are > s, they must be decreased to s.
    // This is not strictly true. They must be <= the new median value.
    // Since we want the median to be exactly s, they must be <= s.
    // Elements to the left of the median (indices 0 to median_idx-1)
    // must be less than or equal to s.
    // If a[median_idx] was originally less than s, and we increased it to s,
    // then any element a[i] for i < median_idx that is greater than s
    // must be decreased to s.
    // This is because if a[i] > s, it would be greater than the median s,
    // which would violate the median property (median_idx elements <= s).
    // So, for i from 0 to median_idx-1, if a[i] > s, we change it to s.
    // The cost is a[i] - s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // If a[median_idx] is greater than s, we need to decrease it.
    // All elements to its right (a[median_idx+1]...a[n-1]) must be >= s.
    // If any of them are < s, they must be increased to s.
    // This is because if a[i] < s, it would be less than the median s,
    // which would violate the median property (median_idx elements >= s).
    // So, for i from median_idx+1 to n-1, if a[i] < s, we change it to s.
    // The cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

