    //     So, if (A+B) is odd and A+D > 0, Box 1 is possible.
    //   What if A+D == 0? Then A=0, D=0. All toys are in B or C.
    //   Product of B and C toys will always be in (-1, 1). So Box 1 is impossible.
    if ((A + B) % 2 == 1 && (A + D > 0)) {
        ans1 = "Ya";
    }

    // Case 2: Final toy in Box 2 (value in (-1, 0))
    // This requires an odd number of negative factors. (A+B) must be odd.
    // The product must have absolute value in (0, 1).
    // This requires that all toys with |val| >= 1 (A+D) are "cancelled out" by toys with |val| < 1 (B+C).
    // This means we need to be able to make the final product's absolute value less than 1.
    // This is possible if there is at least one toy in B or C (B+C > 0).
    // If B+C == 0, then all toys are in A or D. Their product will have |val| >= 1. So Box 2 is impossible.
    // If B+C > 0:
    //   If (A+B) is odd, then it's possible to get a value in (-1, 0).
    //   So, if (A+B) is odd and B+C > 0, Box 2 is possible.
    if ((A + B) % 2 == 1 && (B + C > 0)) {
        ans2 = "Ya";
    }

    // Case 3: Final toy in Box 3 (value in (0, 1))
    // This requires an even number of negative factors. (A+B) must be even.
    // The product must have absolute value in (0, 1).
    // This requires that all toys with |val| >= 1 (A+D) are "cancelled out" by toys with |val| < 1 (B+C).
    // This means we need to be able to make the final product's absolute value less than 1.
    // This is possible if there is at least one toy in B or C (B+C > 0).
    // If B+C == 0, then all toys are in A or D. Their product will have |val| >= 1. So Box 3 is impossible.
    // If B+C > 0:
    //   If (A+B) is even, then it's possible to get a value in (0, 1).
    //   So, if (A+B) is even and B+C > 0, Box 3 is possible.
    if ((A + B) % 2 == 0 && (B + C > 0)) {
        ans3 = "Ya";
    }

    // Case 4: Final toy in Box 4 (value >= 1)
    // This requires an even number of negative factors. (A+B) must be even.
    // The product must have absolute value >= 1.
    // This requires that the number of toys with |val| >= 1 (A+D) is not zero,
    // AND (A+D) - (number of (A+D) toys that are 'cancelled' by B or C toys) >= 1.
    // More simply, if A+D > 0, we can always arrange multiplications to keep the absolute value >= 1.
    // If A+D > 0:
    //   If (A+B) is even, then it's possible to get a value >= 1.
    //   So, if (A+B) is even and A+D > 0, Box 4 is possible.
    //   What if A+D == 0? Then A=0, D=0. All toys are in B or C.
    //   Product of B and C toys will always be in (-1, 1). So Box 4 is impossible.
    if ((A + B) % 2 == 0 && (A + D > 0)) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

