#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareElements);
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    std::vector<long long> result_a(m);

    // Use a map to store counts of B_j values for efficient lookup
    // The key is B_j, the value is the count of how many times it appears
    // in the sorted B array.
    // This map will be used to assign A_i values to B_j values.
    std::map<long long, int> b_counts;
    for (int i = 0; i < m; ++i) {
        b_counts[b_elements[i].value]++;
    }

    // Iterate through sorted A_i values.
    // For each A_i, we want to pair it with the largest possible B_j
    // that is still available.
    // The largest available B_j is the one with the largest value
    // that still has a count > 0 in b_counts.
    // We use a reverse iterator on the map to find the largest B_j.

    // The problem statement guarantees A_i >= B_j for all i, j.
    // This means we don't need to worry about A_i < B_j.

    // The strategy is to pair the smallest A_i with the smallest B_j,
    // the second smallest A_i with the second smallest B_j, and so on.
    // This is because F(n, k) = (n+1)/(k+1).
    // To maximize sum( (A_i + 1) / (B_i + 1) ), we want to pair large A_i with small B_i,
    // and small A_i with large B_i.
    // Specifically, if we sort A in ascending order and B in ascending order,
    // we should pair A_i with B_{m-1-i} (i.e., A_0 with B_{m-1}, A_1 with B_{m-2}, etc.)
    // This is a standard rearrangement inequality application for sum(x_i / y_i) maximization.
    // To maximize sum(x_i / y_i), sort x in ascending order and y in descending order.
    // Here, x_i = A_i + 1 and y_i = B_i + 1.
    // So, sort A_i in ascending order, and B_i in descending order.
    // Then pair A_i with B_i.

    // A_elements is already sorted in ascending order.
    // We need to use B_elements in descending order.
    // The original indices of B_elements are stored in b_elements[i].original_index.
    // We need to assign a_elements[i].value to result_a[b_elements[m-1-i].original_index].

    for (int i = 0; i < m; ++i) {
        // a_elements[i] is the i-th smallest A value.
        // b_elements[m-1-i] is the i-th largest B value.
        // We assign the i-th smallest A value to the original position of the i-th largest B value.
        // This means if B_elements[m-1-i] was originally at index `idx`,
        // then result_a[idx] should be a_elements[i].value.
        result_a[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_good(const std::vector<int>& b) {
    int m = b.size();
    if (m <= 1) {
        return true;
    }

    // Find the peak from the right
    int peak_idx = m - 1;
    while (peak_idx > 0 && b[peak_idx - 1] <= b[peak_idx]) {
        peak_idx--;
    }

    // If peak_idx is 0, the array is already non-decreasing, which is good.
    // If peak_idx is m-1, the array is strictly decreasing from b[0] to b[m-1],
    // or it's just a single element.
    // The elements from b[peak_idx] to b[m-1] form a non-decreasing suffix.

    // Now, from peak_idx, we need to find the point where the elements
    // start decreasing again from the left.
    // This means we are looking for the first element b[i] such that
    // b[i] > b[i+1] for i < peak_idx.
    // The elements b[0]...b[i] must be decreasing.
    // The elements b[i+1]...b[peak_idx] must be non-decreasing.
    // The elements b[peak_idx]...b[m-1] must be non-decreasing.

    // The condition for a good array is that it can be split into
    // a decreasing prefix and a non-decreasing suffix.
    // More precisely, there exists an index `k` such that
    // b[0] >= b[1] >= ... >= b[k] AND b[k] <= b[k+1] <= ... <= b[m-1].
    // This is equivalent to finding the "valley" element.
    // The elements to the left of the valley are decreasing, and to the right are increasing.
    // The example [1, 2, 3, 4, 4, 2, 1] is good.
    // Valley is 1 (last element).
    // [1, 2, 3, 4, 4, 2] is decreasing from right to left.
    // [1] is decreasing from left to right.

    // Let's re-evaluate the good array condition.
    // The elements picked form a non-decreasing sequence c.
    // The elements are picked from ends of b.
    // This means the elements in c are b_i, b_{i+1}, ..., b_j, b_k, ..., b_l
    // where i, j, k, l are indices in the original array.
    // The elements that are picked from the left form a prefix of b.
    // The elements that are picked from the right form a suffix of b.
    // The remaining elements in the middle are never picked. This is wrong.
    // All elements are picked.

    // The elements picked from the left are b_1, b_2, ..., b_L.
    // The elements picked from the right are b_R, b_{R-1}, ..., b_m.
    // The elements b_1, ..., b_L and b_R, ..., b_m must cover all elements.
    // This means L >= R-1.
    // The sequence c is formed by interleaving these two groups.
    // The key insight is that the elements picked from the left form a prefix of the original array,
    // and elements picked from the right form a suffix of the original array.
    // The elements in the middle, if any, are picked last.
    // For example, if we pick b_1, b_m, b_2, b_{m-1}, ...,
    // The elements b_1, b_2, ..., b_k are picked from the left.
    // The elements b_m, b_{m-1}, ..., b_j are picked from the right.
    // The remaining elements are b_{k+1}, ..., b_{j-1}. These must be picked last.
    // This implies that the elements b_{k+1}, ..., b_{j-1} must be non-decreasing.
    // And b_k <= b_{k+1} and b_{j-1} <= b_j.
    // This is not quite right.

    // The correct interpretation:
    // The elements that are picked from the left form a contiguous block b[0...L-1].
    // The elements that are picked from the right form a contiguous block b[R...m-1].
    // All elements must be picked. So L-1 < R.
    // The elements b[0...L-1] are picked in increasing order of index.
    // The elements b[R...m-1] are picked in decreasing order of index.
    // The elements b[L...R-1] are picked last.
    // This means that the elements b[L...R-1] must be non-decreasing.
    // And the elements b[0...L-1] must be non-increasing (when picked from left to right).
    // And the elements b[R...m-1] must be non-increasing (when picked from right to left).
    // This is also not quite right.

    // Let's use the example: b = [1, 2, 3, 4, 4, 2, 1].
    // c = [1, 1, 2, 2, 3, 4, 4]
    // Operations:
    // 1. Take b_1 (value 1). b=[2,3,4,4,2,1], c=[1]
    // 2. Take b_m (value 1). b=[2,3,4,4,2], c=[1,1]
    // 3. Take b_m (value 2). b=[2,3,4,4], c=[1,1,2]
    // 4. Take b_1 (value 2). b=[3,4,4], c=[1,1,2,2]
    // 5. Take b_1 (value 3). b=[4,4], c=[1,1,2,2,3]
    // 6. Take b_m (value 4). b=[4], c=[1,1,2,2,3,4]
    // 7. Take b_1 (value 4). b=[], c=[1,1,2,2,3,4,4]

    // The elements picked from the left are: b[0]=1, b[1]=2, b[2]=3, b[6]=4 (this is wrong, b[6] is not from left)
    // The elements picked from the left are b[0], b[1], b[2].
    // The elements picked from the right are b[6], b[5], b[4], b[3].
    // Original indices:
    // b[0]=1 (1st pick)
    // b[6]=1 (2nd pick)
    // b[5]=2 (3rd pick)
    // b[1]=2 (4th pick)
    // b[2]=3 (5th pick)
    // b[4]=4 (6th pick)
    // b[3]=4 (7th pick)

    // The elements picked from the left are b[0], b[1], b[2].
    // The elements picked from the right are b[3], b[4], b[5], b[6].
    // The elements b[0], b[1], b[2] must be non-decreasing. (1,2,3)
    // The elements b[3], b[4], b[5], b[6] must be non-increasing. (4,4,2,1)
    // This is the condition!
    // An array `b` is good if there exists an index `k` (0 <= k <= m) such that:
    // 1. The prefix `b[0...k-1]` is non-decreasing. (If k=0, empty prefix, non-decreasing).
    // 2. The suffix `b[k...m-1]` is non-increasing. (If k=m, empty suffix, non-increasing).

    // Let's check this condition with the example: b = [1, 2, 3, 4, 4, 2, 1].
    // k=0: prefix [], suffix [1,2,3,4,4,2,1]. Suffix is not non-increasing.
    // k=1: prefix [1], suffix [2,3,4,4,2,1]. Suffix is not non-increasing.
    // k=2: prefix [1,2], suffix [3,4,4,2,1]. Suffix is not non-increasing.
    // k=3: prefix [1,2,3], suffix [4,4,2,1]. Suffix is non-increasing (4>=4>=2>=1). Prefix is non-decreasing (1<=2<=3).
    // So for k=3, the condition holds. Thus, [1,2,3,4,4,2,1] is good.

    // Let's check another example: [4, 5, 2].
    // k=0: prefix [], suffix [4,5,2]. Not non-increasing.
    // k=1: prefix [4], suffix [5,2]. Suffix is non-increasing (5>=2). Prefix is non-decreasing.
    // So for k=1, the condition holds. Thus, [4,5,2] is good.

    // This condition seems correct and matches the examples.
    // The elements from b[0...k-1] are picked from the left.
    // The elements from b[k...m-1] are picked from the right.
    // The elements picked from the left are b[0], b[1], ..., b[k-1].
    // The elements picked from the right are b[m-1], b[m-2], ..., b[k].
    // The final sequence `c` is formed by interleaving these two sequences.
    // The elements b[0], ..., b[k-1] must be non-decreasing.
    // The elements b[k], ..., b[m-1] must be non-increasing.
    // This is because we can always pick the smaller of the two available ends.
    // If we have b[0...k-1] non-decreasing and b[k...m-1] non-increasing:
    // We can pick b[0], then b[1], ..., b[k-1]. This forms a non-decreasing prefix of `c`.
    // Then we pick b[m-1], b[m-2], ..., b[k]. This forms a non-decreasing suffix of `c`.
    // The last element picked from the left is b[k-1].
    // The first element picked from the right is b[m-1].
    // The last element picked from the right is b[k].
    // The sequence of elements picked from the left is (b[0], b[1], ..., b[k-1]).
    // The sequence of elements picked from the right is (b[m-1], b[m-2], ..., b[k]).
    // We need to interleave these to form a non-decreasing sequence.
    // This is possible if and only if the condition holds.
    // The elements b[0], ..., b[k-1] are picked in order.
    // The elements b[m-1], ..., b[k] are picked in order.
    // The final sequence `c` will be `b[0], b[1], ..., b[k-1], b[k], ..., b[m-1]`
    // if we pick all from left then all from right, or vice versa.
    // This is not what the problem states. We can pick from either end.

    // The condition is: there exists an index `k` (0 <= k <= m) such that
    // `b[0] <= b[1] <= ... <= b[k-1]` AND `b[k] >= b[k+1] >= ... >= b[m-1]`.
    // This means the array looks like `/\` (non-decreasing then non-increasing).
    // The peak is at `b[k-1]` or `b[k]`.
    // Example: [1,2,3,4,4,2,1]. Here k=3. Prefix [1,2,3] is non-decreasing. Suffix [4,4,2,1] is non-increasing.
    // This is the correct condition.

    // Algorithm:
    // 1. Find the rightmost index `k` such that `b[k...m-1]` is non-increasing.
    //    This means `b[k] >= b[k+1] >= ... >= b[m-1]`.
    //    Start from `k = m-1`. While `k > 0` and `b[k-1] >= b[k]`, decrement `k`.
    //    After this loop, `k` is the first index of the non-increasing suffix.
    //    If `k=0`, the whole array is non-increasing.
    // 2. Now check if the prefix `b[0...k-1]` is non-decreasing.
    //    Start from `i = 0`. While `i < k-1` and `b[i] <= b[i+1]`, increment `i`.
    //    If `i == k-1`, then the prefix `b[0...k-1]` is non-decreasing.
    //    If `k=0`, the prefix is empty, which is non-decreasing.
    //    So, if `i == k-1` (or `k=0`), the array is good.

    // Let's trace this algorithm for b = [1, 2, 3, 4, 4, 2, 1] (m=7)
    // Step 1: Find k for non-increasing suffix.
    // k = 6 (b[6]=1)
    // k=6, b[5]=2, b[6]=1. b[5] >= b[6] (2>=1). k becomes 5.
    // k=5, b[4]=4, b[5]=2. b[4] >= b[5] (4>=2). k becomes 4.
    // k=4, b[3]=4, b[4]=4. b[3] >= b[4] (4>=4). k becomes 3.
    // k=3, b[2]=3, b[3]=4. b[2] >= b[3] (3>=4) is false. Loop stops.
    // So k = 3. The suffix b[3...6] = [4,4,2,1] is non-increasing.

    // Step 2: Check if prefix b[0...k-1] is non-decreasing.
    // k=3, so prefix is b[0...2] = [1,2,3].
    // i = 0.
    // i=0, b[0]=1, b[1]=2. b[0] <= b[1] (1<=2). i becomes 1.
    // i=1, b[1]=2, b[2]=3. b[1] <= b[2] (2<=3). i becomes 2.
    // i=2. Loop condition `i < k-1` (2 < 2) is false. Loop stops.
    // Check `i == k-1`. `2 == 2`. This is true.
    // So the array is good.

    // Trace for b = [4, 3, 3, 8, 4, 5, 2] (m=7)
    // Step 1: Find k for non-increasing suffix.
    // k = 6 (b[6]=2)
    // k=6, b[5]=5, b[6]=2. b[5] >= b[6] (5>=2). k becomes 5.
    // k=5, b[4]=4, b[5]=5. b[4] >= b[5] (4>=5) is false. Loop stops.
    // So k = 5. The suffix b[5...6] = [5,2] is non-increasing.

    // Step 2: Check if prefix b[0...k-1] is non-decreasing.
    // k=5, so prefix is b[0...4] = [4,3,3,8,4].
    // i = 0.
    // i=0, b[0]=4, b[1]=3. b[0] <= b[1] (4<=3) is false. Loop stops.
    // Check `i == k-1`. `0 == 4` is false.
    // So the array is NOT good.

    // This algorithm seems robust.

    int k = m - 1;
    while (k > 0 && b[k - 1] >= b[k]) {
        k--;
    }
    // Now k is the first index of the non-increasing suffix.
    // The suffix is b[k...m-1].

    // Check if the prefix b[0...k-1] is non-decreasing.
    // If k=0, prefix is empty, which is non-decreasing.
    // If k>0, check b[0] <= b[1] <= ... <= b[k-1].
    int i = 0;
    while (i < k - 1 && b[i] <= b[i + 1]) {
        i++;
    }
    // If i reaches k-1, it means the prefix is non-decreasing.
    return (i == k - 1) || (k == 0);
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // We need to find the smallest `p` such that `a[p...n-1]` is good.
    // This means we iterate `p` from `0` to `n-1`.
    // The remaining array `b` would be `a[p...n-1]`.
    // The length of `b` is `m = n-p`.
    // The elements of `b` are `a[p], a[p+1], ..., a[n-1]`.

    // The `is_good` function takes a vector. We can pass a sub-vector or
    // use iterators. For efficiency, it's better to pass iterators or
    // indices to avoid copying.
    // Let's modify `is_good` to take `begin_idx` and `end_idx`.

    // The problem asks for the shortest prefix to delete.
    // This means we want the smallest `p`.
    // We can iterate `p` from `n-1` down to `0`.
    // The first `p` for which `a[p...n-1]` is good is our answer.
    // The length of the prefix to delete is `p`.

    // Let's find the rightmost peak of the non-increasing suffix.
    // This is the `k` from the `is_good` function.
    // `k` is the first index of the non-increasing suffix `a[k...n-1]`.
    // `a[k] >= a[k+1] >= ... >= a[n-1]`.
    int k_suffix_start = n - 1;
    while (k_suffix_start > 0 && a[k_suffix_start - 1] >= a[k_suffix_start]) {
        k_suffix_start--;
    }
    // Now `a[k_suffix_start ... n-1]` is non-increasing.
    // This `k_suffix_start` is the `k` in the `is_good` function for the full array `a`.

    // Now we need to find the leftmost `p` such that `a[p...k_suffix_start-1]` is non-decreasing.
    // This means `a[p] <= a[p+1] <= ... <= a[k_suffix_start-1]`.
    // We are looking for the smallest `p` such that `a[p...n-1]` is good.
    // This means we are looking for the smallest `p` such that there exists an index `j` (`p <= j <= n`)
    // where `a[p...j-1]` is non-decreasing and `a[j...n-1]` is non-increasing.

    // Let's find the rightmost index `i` such that `a[i] > a[i+1]`.
    // This `i` marks the end of the first decreasing sequence from the right.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // n=7
    // i=5: a[5]=3, a[6]=2. 3 > 2. So i=5.
    // The suffix `a[6]` is non-increasing.
    // The suffix `a[5...6]` is `[3,2]`, which is non-increasing.
    // The suffix `a[4...6]` is `[5,3,2]`, which is non-increasing.
    // The suffix `a[3...6]` is `[4,5,3,2]`, which is NOT non-increasing (4 < 5).
    // So the longest non-increasing suffix starting from the right is `a[4...6] = [5,3,2]`.
    // The starting index of this suffix is `j = 4`.

    // Let's find the rightmost index `j` such that `a[j] > a[j+1]`.
    // This `j` is the last point where the array decreases when scanned from left to right.
    // All elements `a[j+1], ..., a[n-1]` must be non-increasing.
    // So, `a[j+1] >= a[j+2] >= ... >= a[n-1]`.
    // Let `idx1` be the largest index such that `a[idx1] < a[idx1+1]`.
    // If no such `idx1` exists, the array is non-increasing.
    // If `idx1` exists, then `a[idx1+1 ... n-1]` is non-increasing.
    // This `idx1+1` is our `k_suffix_start` from before.
    // Let `k_suffix_start = n-1`.
    // While `k_suffix_start > 0` and `a[k_suffix_start-1] >= a[k_suffix_start]`, decrement `k_suffix_start`.
    // After this, `a[k_suffix_start ... n-1]` is non-increasing.

    // Now we need to find the rightmost index `idx2` such that `a[idx2] > a[idx2+1]` AND `idx2 < k_suffix_start`.
    // This `idx2` is the last "descent" before the non-increasing suffix `a[k_suffix_start ... n-1]`.
    // We need to remove elements up to `idx2`.
    // The elements `a[idx2+1 ... k_suffix_start-1]` must be non-decreasing.
    // So we need to find the largest `p` such that `a[p] > a[p+1]` and `p < k_suffix_start`.
    // The answer will be `p+1`.

    // Example: [1, 3, 1, 4, 5, 3, 2]
    // n=7
    // k_suffix_start:
    // k=6, a[5]=3, a[6]=2. 3>=2. k=5.
    // k=5, a[4]=5, a[5]=3. 5>=3. k=4.
    // k=4, a[3]=4, a[4]=5. 4>=5 is false. Stop.
    // So k_suffix_start = 4. The suffix `a[4...6]` = `[5,3,2]` is non-increasing.

    // Now we need to find the smallest `p` such that `a[p...k_suffix_start-1]` is non-decreasing.
    // This means `a[p] <= a[p+1] <= ... <= a[k_suffix_start-1]`.
    // We are looking for the largest `p_candidate` such that `a[p_candidate] > a[p_candidate+1]` and `p_candidate < k_suffix_start`.
    // The answer will be `p_candidate + 1`.
    // Let `p_candidate = k_suffix_start - 1`.
    // While `p_candidate > 0` and `a[p_candidate-1] <= a[p_candidate]`, decrement `p_candidate`.
    // This `p_candidate` will be the first element of the non-decreasing prefix `a[p_candidate ... k_suffix_start-1]`.
    // The elements to be removed are `a[0 ... p_candidate-1]`.
    // So the length of the prefix to remove is `p_candidate`.

    // Example: [1, 3, 1, 4, 5, 3, 2]
    // k_suffix_start = 4.
    // We need to check `a[0...3]` = `[1,3,1,4]`.
    // p_candidate = k_suffix_start = 4.
    // While `p_candidate > 0` and `a[p_candidate-1] <= a[p_candidate]`:
    // p_candidate=4. a[3]=4, a[4]=5. This is wrong. `p_candidate` should be the start of the prefix.
    // The prefix is `a[p ... k_suffix_start-1]`.
    // We need to find the smallest `p` such that `a[p ... k_suffix_start-1]` is non-decreasing.
    // This means we need to find the largest `i < k_suffix_start-1` such that `a[i] > a[i+1]`.
    // If such `i` exists, then `p = i+1`.
    // If no such `i` exists, then `p = 0`.

    // Let `p_to_remove = 0`.
    // Iterate `i` from `k_suffix_start - 1` down to `0`.
    // If `i > 0` and `a[i-1] > a[i]`, then `p_to_remove = i`. Break.
    // This `p_to_remove` is the length of the prefix to remove.

    // Example: [1, 3, 1, 4, 5, 3, 2]
    // n=7.
    // k_suffix_start = 4. (suffix `a[4...6]` = `[5,3,2]` is non-increasing)
    // We need to check `a[0...3]` = `[1,3,1,4]`.
    // `p_to_remove = 0`.
    // `i` from `k_suffix_start-1` (which is 3) down to `0`.
    // i=3: `a[2]=1, a[3]=4`. `a[2] > a[3]` (1>4) is false.
    // i=2: `a[1]=3, a[2]=1`. `a[1] > a[2]` (3>1) is true.
    // So `p_to_remove = i = 2`. Break.
    // Answer is 2. This matches example.

    // Example: [4, 3, 3, 8, 4, 5, 2]
    // n=7.
    // k_suffix_start:
    // k=6, a[5]=5, a[6]=2. 5>=2. k=5.
    // k=5, a[4]=4, a[5]=5. 4>=5 is false. Stop.
    // k_suffix_start = 5. Suffix `a[5...6]` = `[5,2]` is non-increasing.
    // We need to check `a[0...4]` = `[4,3,3,8,4]`.
    // `p_to_remove = 0`.
    // `i` from `k_suffix_start-1` (which is 4) down to `0`.
    // i=4: `a[3]=8, a[4]=4`. `a[3] > a[4]` (8>4) is true.
    // So `p_to_remove = i = 4`. Break.
    // Answer is 4. This matches example.

    // Example: [1, 2, 3, 4]
    // n=4.
    // k_suffix_start:
    // k=3, a[2]=3, a[3]=4. 3>=4 is false. Stop.
    // k_suffix_start = 3. Suffix `a[3...3]` = `[4]` is non-increasing.
    // We need to check `a[0...2]` = `[1,2,3]`.
    // `p_to_remove = 0`.
    // `i` from `k_suffix_start-1` (which is 2) down to `0`.
    // i=2: `a[1]=2, a[2]=3`. 2>3 is false.
    // i=1: `a[0]=1, a[1]=2`. 1>2 is false.
    // i=0: Loop condition `i > 0` is false.
    // Loop finishes. `p_to_remove` remains 0.
    // Answer is 0. This matches example.

    // This logic seems correct.

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int k_suffix_start = n - 1;
    while (k_suffix_start > 0 && a[k_suffix_start - 1] >= a[k_suffix_start]) {
        k_suffix_start--;
    }

    int p_to_remove = 0;
    // Iterate from `k_suffix_start - 1` down to `1` (index `0` is `a[0]`, `a[i-1]` would be `a[-1]`).
    // We are looking for the first `i` (from right to left) such that `a[i-1] > a[i]`.
    // If such `i` is found, then `a[0...i-1]` must be removed.
    // The remaining prefix `a[i...k_suffix_start-1]` must be non-decreasing.
    // So `p_to_remove` is `i`.
    for (int i = k_suffix_start - 1; i > 0; --i) {
        if (a[i - 1] > a[i]) {
            p_to_remove = i;
            break;
        }
    }

    std::cout << p_to_remove << std::endl;
}

