void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want to find b1, b2, ... such that (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor(b_i))
    // Let S = current_sum, X = current_xor_sum
    // We need S' = 2 * X'
    //
    // Case 1: Array is already good.
    // If current_sum == 2 * current_xor_sum, then we don't need to append any elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // Case 2: Append two elements.
    // Let's try to append two elements, say Y and Z.
    // We want (S + Y + Z) = 2 * (X ^ Y ^ Z).
    // A common strategy for competitive programming problems like this is to pick Y and Z strategically.
    // Consider Y = X.
    // Then the new XOR sum becomes X' = X ^ X ^ Z = Z.
    // The new sum becomes S' = S + X + Z.
    // So we need S + X + Z = 2 * Z.
    // This simplifies to S + X = Z.
    // So, if we append X and (S + X), the condition might be met.
    // Let's check:
    // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum.
    // New sum: S' = current_sum + current_xor_sum + (current_sum + current_xor_sum) = 2 * current_sum + 2 * current_xor_sum.
    // New XOR sum: X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum.
    // Is S' = 2 * X'?
    // (2 * current_sum + 2 * current_xor_sum) == 2 * (current_sum + current_xor_sum)
    // Yes, this is always true.
    // So, appending current_xor_sum and (current_sum + current_xor_sum) always makes the array good.
    // This uses 2 elements. The problem allows up to 3.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

