int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side.
    // 'i' represents the number of items taken from the left.
    // So, 'i' items are w[0]...w[i-1].
    // The remaining 'n-i' items are taken from the right side.
    // These are w[n-1]...w[n-(n-i)].
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // The sum of weights for items taken from the right is
        // total_sum - sum_of_left_items = prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Calculate extra energy based on counts
        int num_left = i;
        int num_right = n - i;

        if (num_left > num_right) {
            // More items taken from left. The last item must have been from left.
            // The difference in counts is num_left - num_right.
            // If num_left = num_right + 1, no extra cost.
            // If num_left = num_right + k (k > 1), then k-1 times we took left consecutively
            // after the right items were exhausted.
            current_energy += (long long)(num_left - num_right - 1) * Ql;
        } else if (num_right > num_left) {
            // More items taken from right. The last item must have been from right.
            // The difference in counts is num_right - num_left.
            // If num_right = num_left + 1, no extra cost.
            // If num_right = num_left + k (k > 1), then k-1 times we took right consecutively
            // after the left items were exhausted.
            current_energy += (long long)(num_right - num_left - 1) * Qr;
        }
        // If num_left == num_right, no extra cost.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

