                //   If it can be color 1 (current_digit >= last1), assign it to color 1.
                //   Else (it must be current_digit < last1, so it cannot be color 1), assign it to color 2 (if possible).

                if (current_digit == pivot_digit) {
                    if (current_digit >= last1) { // Can be color 1
                        colors[i] = '1';
                        last1 = current_digit;
