                        possible = false;
                        break;
                    }
                }
            } else if (can_color1) {
                colors[i] = '1';
                last1 = current_digit;
            } else if (can_color2) {
                colors[i] = '2';
                last2 = current_digit;
            } else {
                possible = false;
                break;
            }
        }

        if (possible) {
            std::cout << colors << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

