#include <iostream>

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;
    sum_r_term = (sum_r_term * modInverse(2)) % MOD;

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // sum_k_term = b * sum_{k=1 to a} k + a
    // sum_k_term = b * (a * (a+1) / 2) + a
    long long sum_k_inner_sum = (a);
    sum_k_inner_sum = (sum_k_inner_sum * (a + 1)) % MOD;
    sum_k_inner_sum = (sum_k_inner_sum * modInverse(2)) % MOD;

    long long sum_k_term = (b * sum_k_inner_sum) % MOD;
    sum_k_term = (sum_k_term + a) % MOD;

    // Total sum = sum_r_term * sum_k_term
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited_in_layout;
    char start_char = '\0';

    // Find a starting character for the layout.
    // It should be a character with only one required neighbor,
    // or any character if all have two neighbors (which means it's a cycle or a long path).
    // Or, if there are no adjacencies (s has length 1), any char can be start.
    if (s.length() == 1) {
        start_char = s[0];
    } else {
        for (const auto& pair : adj) {
            if (pair.second.size() == 1) {
                start_char = pair.first;
                break;
            }
        }
        // If no char has 1 neighbor, it means all chars in adj have 2 neighbors.
        // This implies a cycle or a single long path where all internal nodes have 2 neighbors.
        // In this case, pick any character from adj as a starting point.
        if (start_char == '\0' && !adj.empty()) {
            start_char = adj.begin()->first;
        }
    }

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // To keep track of the direction in the path

        while (visited_in_layout.find(current_char) == visited_in_layout.end()) {
            layout += current_char;
            visited_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;

            if (current_char == '\0') { // End of path
                break;
            }
        }
    }

    // Check if all characters from 's' that had adjacencies are included in the layout.
    // This handles cases where the graph might be disconnected or form multiple paths.
    // If a character from 's' is not in the layout, it means it's part of a separate component
    // that wasn't traversed from the chosen start_char. This should not happen if the graph is a single path.
    // However, if the graph is a cycle, and we started from an arbitrary point, we might end up
    // with a layout that doesn't include all characters if the cycle is not fully traversed.
    // The current logic for `while` loop will traverse a full path or cycle.
    // The only issue would be if `s` implies multiple disconnected paths/cycles, which is fine.
    // But if `s` implies a single path/cycle and we didn't traverse it fully, it's an error.
    // The `visited_in_layout` set should contain all characters that appeared in `s`.
    for (char c : s) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            // This means 's' implies a disconnected graph, or a character in 's'
            // was not part of the path we constructed. This should not happen
            // if the graph is valid (max 2 neighbors).
            // If it's a valid path/cycle, all characters from 's' should be in `adj` and thus traversed.
            // The only way this could happen is if `s` has length 1 and `start_char` was not set.
            // But `start_char` is set for length 1.
            // Or if `s` has multiple components, but we only build one.
            // The problem implies a single connected component for the required adjacencies.
            // If `s` is "ab" and then "cd", these are two separate components.
            // The current logic will build "ab" and then add 'c' and 'd' later.
            // This check is actually not needed if the graph is guaranteed to be connected for chars in `s`.
            // Let's assume the graph formed by `s` is connected.
            // If it's not connected, the problem statement doesn't explicitly forbid it.
            // Example: s = "ab" then s = "cd". This is not possible as s is one string.
            // So all characters in `s` must form a single connected component.
            // Thus, if `start_char` is chosen from `adj`, all characters in `adj` will be traversed.
        }
    }

    // Add remaining characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
