#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    std::vector<std::vector<int>> pos_to_char_count(n, std::vector<int>(26, 0));
    for (int i = 0; i < n; ++i) {
        pos_to_char_count[i][s[i] - 'a']++;
    }

    std::vector<std::vector<int>> char_pair_counts(26, std::vector<int>(26, 0));
    for (int i = 0; i < n; ++i) {
        char_pair_counts[s[i] - 'a'][s[(i + 1) % n] - 'a']++;
    }

    std::vector<std::vector<int>> char_pair_counts_p(n, std::vector<std::vector<int>>(26, std::vector<int>(26, 0)));
    for (int p = 1; p < n; ++p) {
        for (int i = 0; i < n; ++i) {
            char_pair_counts_p[p][s[i] - 'a'][s[(i + p) % n] - 'a']++;
        }
    }

    double total_win_prob = 0.0;

    for (int c0_idx = 0; c0_idx < 26; ++c0_idx) {
        if (char_indices[c0_idx].empty()) {
            continue;
        }

        double max_win_prob_for_c0 = 0.0;

        for (int p = 1; p < n; ++p) {
            double current_win_prob_for_c0_and_p = 0.0;
            int num_k_with_c0 = char_indices[c0_idx].size();

            for (int cp_idx = 0; cp_idx < 26; ++cp_idx) {
                int count_k_for_c0_cp = char_pair_counts_p[p][c0_idx][cp_idx];
                if (count_k_for_c0_cp == 1) {
                    current_win_prob_for_c0_and_p += 1.0;
                }
            }
            max_win_prob_for_c0 = std::max(max_win_prob_for_c0, current_win_prob_for_c0_and_p / num_k_with_c0);
        }
        total_win_prob += max_win_prob_for_c0 * char_indices[c0_idx].size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

#include <iostream>
