int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    if (k * k < n) {
        k++;
    }

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start_idx = i;
        int block_end_idx = std::min(i + k, n);

        for (int j = block_end_idx - 1; j >= block_start_idx; --j) {
            p[j] = current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n and m are non-negative and n >= m for simpler logic
        n = std::abs(n);
        m = std::abs(m);
        if (n < m) {
            std::swap(n, m);
        }

        // Case 1: Not enough moves to reach (n, m)
        // Minimum moves required is n (by making m diagonal moves and n-m axial moves)
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: Parity check
        // The parity of (n + m) must be the same as the parity of k.
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // The parity of (x+y) changes if the move is axial (e.g., (1,0) changes x+y by 1)
        // or if the move is diagonal (e.g., (1,1) changes x+y by 2, (1,-1) changes x+y by 0).
        // More simply, each move changes the parity of (x+y) by 1 if it's an axial move,
        // and by 0 if it's a diagonal move.
        // So, (n+m) and k must have the same parity if all moves were axial.
        // If we make a diagonal move, it changes both x and y by 1 (or -1).
        // The parity of (x+y) changes by 0 or 2, so it remains the same.
        // If we make an axial move, it changes one coordinate by 1 (or -1).
        // The parity of (x+y) changes by 1.
        // So, the parity of (n+m) must be the same as the parity of k.
        // (n+m) % 2 == k % 2
        // This is equivalent to (k - (n + m)) % 2 == 0.
        // Or, (k - n - m) % 2 == 0.
        // Since n and m are non-negative, n+m is the minimum number of moves if only axial moves were allowed.
        // If k has different parity than n+m, we need to adjust.
        // Each "extra" move (beyond n+m) must be a pair of moves that cancel out,
        // e.g., (1,0) then (-1,0), or (1,1) then (-1,-1).
        // A pair of moves like (1,0) and (-1,0) takes 2 moves and changes (x,y) by (0,0).
        // A pair of moves like (1,1) and (-1,-1) takes 2 moves and changes (x,y) by (0,0).
        // In both cases, the total displacement is 0, and 2 moves are used.
        // So, if k and (n+m) have different parities, we need at least one "extra" move.
        // The minimum number of moves to reach (n,m) is n (if n>=m).
        // If k - n is odd, it means we have an odd number of "extra" moves beyond the minimum n diagonal moves.
        // Each "extra" move (beyond the n moves to reach (n,m) using n diagonal moves and 0 axial moves)
        // must be paired up to cancel out.
        // For example, if we are at (n,m) and have 1 move left, we can't end up at (n,m).
        // If we are at (n,m) and have 2 moves left, we can do (1,0) then (-1,0) and end up at (n,m).
        // This means if k - n is odd, we cannot reach (n,m) in exactly k moves.
        // This is because each move changes the parity of (x+y) by 1 if it's axial, and by 0 if it's diagonal.
        // The parity of (x+y) changes by 1 for each axial move.
        // The parity of (x+y) changes by 0 for each diagonal move.
        // So, the parity of (n+m) must be the same as the parity of the number of axial moves.
        // Let D be diagonal moves, A be axial moves. K = D + A.
        // (n+m) % 2 == A % 2.
        // K % 2 == (D+A) % 2.
        // If (k - n) % 2 != 0, it's impossible.
        // This is equivalent to (k % 2) != (n % 2).
        // Let's re-evaluate the parity condition.
        // Consider the parity of (x+y).
        // A diagonal move (dx, dy) where dx, dy are non-zero: (x+dx, y+dy). (x+dx+y+dy) - (x+y) = dx+dy.
        // If dx, dy are both 1 or -1, then dx+dy is 2, -2, or 0. All are even. So parity of (x+y) doesn't change.
        // An axial move (dx, dy) where one is zero: (x+dx, y+dy). (x+dx+y+dy) - (x+y) = dx+dy.
        // If one is 1 or -1 and other is 0, then dx+dy is 1 or -1. Both are odd. So parity of (x+y) changes.
        // So, the parity of (n+m) must be the same as the parity of the number of axial moves.
        // Let `num_axial` be the number of axial moves.
        // We need (n+m) % 2 == num_axial % 2.
        // We have `k` total moves.
        // The maximum number of diagonal moves is `k`.
        // The minimum number of axial moves is 0.
        // If `k` is used for diagonal moves, then `num_axial = 0`.
        // So we need (n+m) % 2 == 0.
        // If `k` is used for diagonal moves, and (n+m) % 2 != 0, then we must use at least one axial move.
        // Each axial move changes the parity of (x+y).
        // So, if (n+m) % 2 != k % 2, it's impossible.
        // Example: (2,2) in 3 moves. n=2, m=2, k=3. n+m=4. k=3. (n+m)%2 = 0, k%2 = 1. Different parities.
        // Output for (2,2,3) is 1. My parity check says impossible. What's wrong?
        // The parity check (n+m)%2 == k%2 is for Manhattan distance.
        // For Chebyshev distance (8-directional moves), the parity check is different.
        // Each move changes x by at most 1, y by at most 1.
        // The parity of x changes if dx is odd. The parity of y changes if dy is odd.
        // A diagonal move (dx, dy) has dx, dy both odd. So x changes parity, y changes parity.
        // An axial move (dx, dy) has one of dx, dy odd and the other zero. So one coordinate changes parity, the other doesn't.
        // Let's consider the parity of (x,y) coordinates.
        // Start at (0,0). After 1 move, we are at (dx, dy).
        // If diagonal: (1,1), (1,-1), (-1,1), (-1,-1). All have (odd, odd) parity.
        // If axial: (1,0), (-1,0), (0,1), (0,-1). All have (odd, even) or (even, odd) parity.
        // After `k` moves, we are at (n,m).
        // If `k` is even:
        //   If all moves are diagonal, (x,y) will be (even, even).
        //   If all moves are axial, (x,y) will be (even, even).
        //   If `k_d` diagonal and `k_a` axial moves, `k_d + k_a = k`.
        //   Final (n,m) parity: (n%2, m%2)
        //   Parity of (n,m) after `k` moves:
        //   (n%2, m%2) = ( (k_d%2 + k_a%2) % 2, (k_d%2 + k_a%2) % 2 ) if all axial moves are (1,0) or (-1,0)
        //   This is getting complicated.
        //
        // Let's use a simpler parity argument:
        // The final position (n,m) must have the same parity as (k,k) if all moves were diagonal.
        // Or, (n,m) must have the same parity as (k,0) or (0,k) if all moves were axial.
        //
        // Consider the parity of `k - n`.
        // If `k - n` is odd, it's impossible.
        // Why? We need to make `n` moves to cover the `n` distance in x (and `m` distance in y).
        // We can make `m` diagonal moves to cover `m` in both x and y.
        // Then we have `n-m` distance left in x, and `k-m` moves left.
        // We need to cover `n-m` in x using `k-m` moves.
        // The remaining `k-m` moves must result in a net displacement of `n-m` in x and `0` in y.
        // Let `k_rem = k-m`. Let `n_rem = n-m`.
        // We need to reach `(n_rem, 0)` in `k_rem` moves.
        // Each move changes `x` by `dx` and `y` by `dy`.
        // `dx` can be -1, 0, 1. `dy` can be -1, 0, 1.
        // If `dx != 0` and `dy != 0`, it's a diagonal move.
        // If `dx == 0` or `dy == 0`, it's an axial move.
        //
        // To reach `(n_rem, 0)` in `k_rem` moves:
        // We need `n_rem` net change in x, `0` net change in y.
        // The `k_rem` moves can be:
        // `p_x` moves of `(1,0)`
        // `m_x` moves of `(-1,0)`
        // `p_y` moves of `(0,1)`
        // `m_y` moves of `(0,-1)`
        // `p_d1` moves of `(1,1)`
        // `m_d1` moves of `(-1,-1)`
        // `p_d2` moves of `(1,-1)`
        // `m_d2` moves of `(-1,1)`
        //
        // Total moves: `k_rem = p_x + m_x + p_y + m_y + p_d1 + m_d1 + p_d2 + m_d2`
        // Net x change: `n_rem = p_x - m_x + p_d1 - m_d1 + p_d2 - m_d2`
        // Net y change: `0 = p_y - m_y + p_d1 - m_d1 - p_d2 + m_d2`
        //
        // From the y-change equation: `p_y - m_y = (p_d2 - m_d2) - (p_d1 - m_d1)`
        //
        // Consider the parity of `k_rem` and `n_rem`.
        // Each move changes the parity of `x` or `y` or both.
        // A move `(dx, dy)` changes `x` by `dx` and `y` by `dy`.
        // The parity of `x` changes if `dx` is odd. The parity of `y` changes if `dy` is odd.
        //
        // Let `k_odd_x` be the number of moves where `dx` is odd.
        // Let `k_odd_y` be the number of moves where `dy` is odd.
        // `n_rem % 2 == k_odd_x % 2`
        // `0 % 2 == k_odd_y % 2`
        //
        // Diagonal moves: `dx, dy` are both odd. So they contribute to both `k_odd_x` and `k_odd_y`.
        // Axial moves: `(1,0), (-1,0)` have `dx` odd, `dy` even. Contribute to `k_odd_x`.
        // Axial moves: `(0,1), (0,-1)` have `dx` even, `dy` odd. Contribute to `k_odd_y`.
        //
        // This is the key:
        // The parity of the final x-coordinate `n` must be the same as the parity of the number of moves that change x-coordinate by an odd amount.
        // The parity of the final y-coordinate `m` must be the same as the parity of the number of moves that change y-coordinate by an odd amount.
        //
        // Let `k_x_odd` be the count of moves where `dx` is odd (i.e., `dx = +/- 1`).
        // Let `k_y_odd` be the count of moves where `dy` is odd (i.e., `dy = +/- 1`).
        // Then `n % 2 == k_x_odd % 2` and `m % 2 == k_y_odd % 2`.
        //
        // Total moves `k`.
        // Each diagonal move contributes to both `k_x_odd` and `k_y_odd`.
        // Each axial move `(dx,0)` contributes to `k_x_odd`.
        // Each axial move `(0,dy)` contributes to `k_y_odd`.
        //
        // The maximum value for `k_x_odd` is `k`. The minimum is `n`.
        // The maximum value for `k_y_odd` is `k`. The minimum is `m`.
        //
        // We need `k_x_odd >= n` and `k_y_odd >= m`.
        // Also, `k_x_odd <= k` and `k_y_odd <= k`.
        //
        // The number of moves that change x by an odd amount (`k_x_odd`) must have the same parity as `n`.
        // The number of moves that change y by an odd amount (`k_y_odd`) must have the same parity as `m`.
        //
        // The total number of moves `k` is `k_x_odd` + `k_y_odd` - `k_diag` (where `k_diag` is number of diagonal moves).
        // This is not quite right.
        //
        // Let's consider the parity of `k - n` and `k - m`.
        // If `k - n` is odd, it means we have an odd number of "extra" moves in the x-direction.
        // An "extra" move in x-direction means a move that changes x by 1, but is not needed for the final displacement.
        // For example, (1,0) then (-1,0) is 2 "extra" moves.
        //
        // The condition is: `(k - n) % 2 == 0` AND `(k - m) % 2 == 0`.
        // This simplifies to `k % 2 == n % 2` AND `k % 2 == m % 2`.
        // So, `n % 2 == m % 2 == k % 2`.
        // If this condition is not met, it's impossible.
        //
