bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        // If all target tracks are covered, return true
        if (p_idx == m) {
            return true;
        }

        long long current_h_pos = h[h_idx];
        long long reach_left = current_h_pos - T;
        long long reach_right = current_h_pos + T;

        // If the current head cannot reach the current target track p[p_idx],
        // it means this head cannot help cover p[p_idx] or any subsequent tracks.
        // Since heads and tracks are sorted, if h[h_idx] cannot reach p[p_idx],
        // then h[h_idx+1] (which is >= h[h_idx]) might be able to.
        // But we need to cover p[p_idx] with *some* head.
        // If p[p_idx] is to the left of what this head can reach, this head can't cover it.
        // We need to find a head that can cover p[p_idx].
        // The greedy strategy is to use the current head h[h_idx] to cover as many
        // *uncovered* tracks as possible, starting from p[p_idx].

        // If p[p_idx] is outside the current head's reach to the right, this head can't cover it.
        // This should not happen if we are processing p_idx correctly.
        // The loop below ensures p[p_idx] is within reach_right.
        // If p[p_idx] is to the left of reach_left, this head cannot cover it.
        // This implies that no previous head could cover it either (because h are sorted).
        // So, if p[p_idx] < reach_left, it's impossible to cover p[p_idx] with this head or any previous head.
        // This is a critical condition for failure.
        if (p[p_idx] < reach_left) {
            // This means p[p_idx] is too far left for current head h[h_idx]
            // and since h is sorted, it was too far left for any h[k] where k < h_idx.
            // So p[p_idx] cannot be covered.
            return false;
        }

        // Greedily cover all tracks p[p_idx], p[p_idx+1], ... that are within reach_right.
        while (p_idx < m && p[p_idx] <= reach_right) {
            p_idx++;
        }
    }

    // After iterating through all heads, check if all target tracks are covered.
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 - 1 + 10^10 - 1 (approx 2*10^10)
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

