    // This is `(a[n-1].value + a[n-2].value + h) - (a[0].value + a[1].value)`.
    // This value is achieved if we have at least one pair in the same subsequence (e.g., a[0], a[1] in S1)
    // AND at least one pair in different subsequences (e.g., a[n-1] in S1, a[n-2] in S2).
    // This is the "mixed" case.
    long long goodness2 = (a[n - 1].value + a[n - 2].value + h) - (a[0].value + a[1].value);
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1; // a[0] in S1
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2; // a[1]...a[n-1] in S2
    }
    // This partition (a[0] in S1, rest in S2) gives:
    // Min f: a[0]+a[1]+h (from a[0] and a[1])
    // Max f: a[n-1]+a[n-2] (from a[n-1] and a[n-2]) OR a[0]+a[n-1]+h (from a[0] and a[n-1])
    // The actual max f for this partition is max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h).
    // The actual min f for this partition is a[0].value + a[1].value + h.
    // So the goodness for this partition is max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) - (a[0].value + a[1].value + h).

    // Let's re-evaluate the goodness for the partition where a[0] is in S1 and a[1...n-1] are in S2.
    // Min_f_val_P2 = a[0].value + a[1].value + h; // Smallest cross-subsequence sum
    // Max_f_val_P2 = a[n-1].value + a[n-2].value; // Largest same-subsequence sum (within S2)
    // If n=2, then S2 only has a[1]. No same-subsequence pairs. Max_f_val_P2 = a[0].value + a[1].value + h.
    // If n > 2, we also need to consider a[0].value + a[n-1].value + h as a potential max.
    // So, if n > 2: Max_f_val_P2 = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);
    // If n = 2: Min_f_val_P2 = a[0].value + a[1].value + h; Max_f_val_P2 = a[0].value + a[1].value + h;
    // Goodness_P2 = Max_f_val_P2 - Min_f_val_P2.

    long long current_min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    if (n == 2) {
        // For n=2, there's only one pair (a[0], a[1]).
        // If they are in the same subsequence: f = a[0]+a[1]. Goodness = 0.
        // If they are in different subsequences: f = a[0]+a[1]+h. Goodness = 0.
        // So for n=2, minimal goodness is always 0.
        // The problem statement says "distinct elements (that is i != j)".
        // If n=2, there is only one pair (a_0, a_1).
        // If a_0, a_1 are in same subseq, f = a_0+a_1. Min=Max=a_0+a_1. Goodness=0.
        // If a_0, a_1 are in different subseq, f = a_0+a_1+h. Min=Max=a_0+a_1+h. Goodness=0.
        // So for n=2, goodness is always 0.
        // The problem asks for minimal goodness. 0 is minimal.
        // We can output partition 1 1 or 1 2.
        // Our current_min_goodness is goodness1, which is (a[1]+a[0]) - (a[0]+a[1]) = 0.
        // So this is correct.
    } else { // n > 2
        long long min_f_P2 = a[0].value + a[1].value + h;
        long long max_f_P2 = std::max(a[n - 1].value + a[n - 2].value, a[0].value + a[n - 1].value + h);
        long long goodness_P2 = max_f_P2 - min_f_P2;

        if (goodness_P2 < current_min_goodness) {
            current_min_goodness = goodness_P2;
            best_partition = partition2;
        }
    }

    std::cout << current_min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

