    // contains at least one 3-AP. If no such `l` exists, we can set `l` to `0`.
    // This means `s[0...i]` does not contain any 3-AP.
    // So, `dp[i]` is the minimum `l` such that `s[l...i]` contains a 3-AP.
    // If `s[0...i]` contains no 3-AP, then `dp[i]` should be `0`.
    // The number of bad substrings ending at `i` is `i - dp[i] + 1`.
    // This is because any substring `s[l'...i]` where `l' >= dp[i]` will not contain a 3-AP.
    // The valid `l'` values are `dp[i], dp[i]+1, ..., i`.
    // The count is `i - dp[i] + 1`.

    // Let's use `min_l_with_3AP[i]` to store the smallest `l` (0-indexed) such that `s[l...i]` contains a 3-AP.
    // If `s[0...i]` contains no 3-AP, `min_l_with_3AP[i]` will be `0`.
    // This means `s[0...i]` is a "bad" string.
    // The number of "bad" substrings ending at `i` is `i - min_l_with_3AP[i] + 1`.
    // This is because if `s[min_l_with_3AP[i]...i]` contains a 3-AP, then `s[min_l_with_3AP[i]-1...i]` also contains it.
    // So, `min_l_with_3AP[i]` is the smallest `l` such that `s[l...i]` contains a 3-AP.
    // Any `l'` such that `l' < min_l_with_3AP[i]` will result in `s[l'...i]` containing a 3-AP.
    // Any `l'` such that `l' >= min_l_with_3AP[i]` will result in `s[l'...i]` NOT containing a 3-AP.
    // So, the number of bad substrings ending at `i` is `i - min_l_with_3AP[i] + 1`.
    // This is the correct interpretation.

    std::vector<int> min_l_with_3AP(n); // Stores the smallest l (0-indexed) such that s[l...i] contains a 3-AP.
                                        // If s[0...i] contains no 3-AP, this value will be 0.

    for (int i = 0; i < n; ++i) {
        // Initialize min_l_with_3AP[i] based on previous value.
        // If s[l...i-1] contains a 3-AP, then s[l...i] also contains it.
        // So, min_l_with_3AP[i] is at least min_l_with_3AP[i-1].
        if (i > 0) {
            min_l_with_3AP[i] = min_l_with_3AP[i-1];
        } else {
            min_l_with_3AP[i] = 0; // For i=0, s[0...0] cannot contain a 3-AP.
        }

        // Check for new 3-APs ending at index i.
        // A 3-AP is (x, x+k, x+2k). If x+2k = i, then we have a new 3-AP.
        // We need to update min_l_with_3AP[i] to max(current_min_l_with_3AP[i], x+1).
        // The smallest l for s[l...i] to contain this 3-AP is x.
        // So, we need to update min_l_with_3AP[i] to max(current_min_l_with_3AP[i], x).
        // No, this is wrong. min_l_with_3AP[i] is the smallest l such that s[l...i] contains a 3-AP.
        // If we find a 3-AP (x, x+k, x+2k=i), then s[x...i] contains a 3-AP.
        // So, the smallest l for s[l...i] to contain a 3-AP could be x.
        // We need to update min_l_with_3AP[i] to min(current_min_l_with_3AP[i], x).
        // But this is not how it works. min_l_with_3AP[i] is the smallest l such that s[l...i] contains a 3-AP.
        // If s[l...i] contains a 3-AP, then s[l-1...i] also contains a 3-AP.
        // So, min_l_with_3AP[i] is the smallest l such that s[l...i] contains a 3-AP.
        // If s[0...i] contains no 3-AP, then min_l_with_3AP[i] = 0.
        // If s[0...i] contains a 3-AP, then min_l_with_3AP[i] > 0.
        // The number of bad substrings ending at i is i - min_l_with_3AP[i] + 1.
        // This is the number of substrings s[l...i] that do NOT contain a 3-AP.
        // These are s[min_l_with_3AP[i]...i], s[min_l_with_3AP[i]+1...i], ..., s[i...i].
        // The count is i - min_l_with_3AP[i] + 1.

        // Let's re-evaluate the definition of `min_l_with_3AP[i]`.
        // `min_l_with_3AP[i]` is the smallest `l` (0-indexed) such that `s[l...i]` contains a 3-AP.
        // If `s[0...i]` contains no 3-AP, then `min_l_with_3AP[i]` is `0`.
        // This means `s[0...i]` is a "bad" string.
        // The number of "bad" substrings ending at `i` is `i - min_l_with_3AP[i] + 1`.
        // This is because any substring `s[l'...i]` where `l' >= min_l_with_3AP[i]` will not contain a 3-AP.
        // The valid `l'` values are `min_l_with_3AP[i], min_l_with_3AP[i]+1, ..., i`.
        // The count is `i - min_l_with_3AP[i] + 1`.

        // Let's use `last_good_start[i]` to denote the smallest `l` such that `s[l...i]` is "good" (contains a 3-AP).
        // If `s[0...i]` is "bad", then `last_good_start[i]` is `0`.
        // The number of "bad" substrings ending at `i` is `i - last_good_start[i] + 1`.
        // This is the correct interpretation.

        // `last_good_start[i]` is the smallest `l` such that `s[l...i]` contains a 3-AP.
        // If `s[0...i]` contains no 3-AP, then `last_good_start[i]` is `0`.
        // The number of bad substrings ending at `i` is `i - last_good_start[i] + 1`.

        // For each `i` from `0` to `n-1`:
        // `last_good_start[i]` is initialized to `last_good_start[i-1]` (or `0` if `i=0`).
        // This means if `s[l...i-1]` contains a 3-AP, then `s[l...i]` also contains it.
        // So, `last_good_start[i]` can't be smaller than `last_good_start[i-1]`.
        // Then, we check for new 3-APs that end at `i`.
        // A 3-AP is `(x, x+k, x+2k)`. If `x+2k = i`, then `s[x...i]` contains a 3-AP.
        // This means `x` is a candidate for `last_good_start[i]`.
        // We need to update `last_good_start[i]` to `max(last_good_start[i], x)`.
        // This is because `last_good_start[i]` should be the smallest `l` such that `s[l...i]` contains a 3-AP.
        // If `s[x...i]` contains a 3-AP, then any `s[l'...i]` with `l' < x` also contains it.
        // So, `last_good_start[i]` should be `x`.
        // This means `last_good_start[i]` should be `min(last_good_start[i], x)`.
        // This is confusing. Let's use the complement.

        // Let `max_l_for_bad_suffix[i]` be the largest `l` such that `s[l...i]` contains NO 3-AP.
        // If `s[0...i]` contains NO 3-AP, then `max_l_for_bad_suffix[i]` is `0`.
        // The number of bad substrings ending at `i` is `i - max_l_for_bad_suffix[i] + 1`.
        // This is because `s[max_l_for_bad_suffix[i]...i]` is bad.
        // `s[max_l_for_bad_suffix[i]+1...i]` is bad.
        // ...
        // `s[i...i]` is bad.
        // The count is `i - max_l_for_bad_suffix[i] + 1`.

        // For each `i` from `0` to `n-1`:
        // `max_l_for_bad_suffix[i]` is initialized to `max_l_for_bad_suffix[i-1]` (or `0` if `i=0`).
        // This means if `s[l...i-1]` is bad, then `s[l...i]` is also bad.
        // So, `max_l_for_bad_suffix[i]` can't be smaller than `max_l_for_bad_suffix[i-1]`.
        // Then, we check for new 3-APs that end at `i`.
        // A 3-AP is `(x, x+k, x+2k)`. If `x+2k = i`, then `s[x...i]` contains a 3-AP.
        // This means `s[x...i]` is a "good" string.
        // So, any `l'` such that `l' <= x` will result in `s[l'...i]` being "good".
        // This means `max_l_for_bad_suffix[i]` cannot be less than `x+1`.
        // So, `max_l_for_bad_suffix[i]` must be updated to `max(max_l_for_bad_suffix[i], x+1)`.
        // This is the correct logic.

        std::vector<int> max_l_for_bad_suffix(n); // Stores the largest l (0-indexed) such that s[l...i] contains NO 3-AP.
                                                  // If s[0...i] contains NO 3-AP, this value will be 0.

        for (int i = 0; i < n; ++i) {
            if (i > 0) {
                max_l_for_bad_suffix[i] = max_l_for_bad_suffix[i-1];
            } else {
                max_l_for_bad_suffix[i] = 0;
            }

            // Check for 3-APs ending at i.
            // (x, x+k, x+2k) where x+2k = i.
            // This means 2k = i-x. So i-x must be even.
            // Also, k = (i-x)/2.
            // x must be >= 0.
            // k must be >= 1. So (i-x)/2 >= 1 => i-x >= 2 => x <= i-2.
            // x+k must be < i. So x + (i-x)/2 < i => (x+i)/2 < i => x+i < 2i => x < i.
            // The condition is 0 <= x < x+k < x+2k = i.
            // This implies x <= i-2.
            // Also, x and i must have the same parity for i-x to be even.

            // Iterate over possible values of k.
            // x+2k = i => x = i-2k.
            // Condition: x >= 0 => i-2k >= 0 => 2k <= i => k <= i/2.
            // Condition: k >= 1.
            // So k ranges from 1 to i/2.
            for (int k = 1; k * 2 <= i; ++k) {
                int x = i - 2 * k;
                if (s[x] == s[x+k] && s[x+k] == s[i]) {
                    // Found a 3-AP (x, x+k, i).
                    // This means s[x...i] is a "good" string.
                    // Any substring s[l'...i] where l' <= x is also "good".
                    // So, max_l_for_bad_suffix[i] cannot be less than x+1.
                    max_l_for_bad_suffix[i] = std::max(max_l_for_bad_suffix[i], x + 1);
                }
            }
            // The number of bad substrings ending at i is (i - max_l_for_bad_suffix[i] + 1).
            // These are s[max_l_for_bad_suffix[i]...i], s[max_l_for_bad_suffix[i]+1...i], ..., s[i...i].
            bad_pairs += (long long)(i - max_l_for_bad_suffix[i] + 1);
        }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        return "0"; // Special case for 0, its pattern is "0"
    }
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern_str += '0';
        } else { // Odd digit
            pattern_str += '1';
        }
        n /= 10;
    }
    // The problem implies padding with 0s from the left for shorter numbers.
    // This means we need to pad the pattern with '0's to the right to match
    // the fixed length of 18 digits.
    // Example: 92 -> "01" (rightmost 2 is even, next 9 is odd).
    // If pattern is "010", 92 matches.
    // This means we need to store "01" and then when querying "010",
    // we effectively compare "010" with "010" (92 padded with 0s from left).
    // The problem statement: "If the pattern is shorter than this integer, it's supplemented with 0-s from the left.
    // Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we should normalize both to a fixed length, say 18.
    // For a number, say 92, it becomes 0...092. Its pattern is 0...0010.
    // For a pattern, say "010", it becomes 0...0010.
    // So, we need to generate a fixed-length pattern for numbers.
    // The maximum number of digits is 18 (for 10^18 - 1).
    // Let's generate a 18-digit pattern.
    std::string fixed_length_pattern = "";
    long long temp_n = n;
    for (int i = 0; i < 18; ++i) {
        if (temp_n > 0) {
            if ((temp_n % 10) % 2 == 0) {
                fixed_length_pattern += '0';
            } else {
                fixed_length_pattern += '1';
            }
            temp_n /= 10;
        } else {
            fixed_length_pattern += '0'; // Pad with '0' for leading zeros
        }
    }
    // The pattern is built from right to left, so the string is reversed.
    // Example: 92 -> 2 (even) -> '0', 9 (odd) -> '1'. String is "01".
    // If we want 18 digits, it's "01" followed by 16 '0's.
    // This is equivalent to reversing the string and then padding.
    // Let's re-evaluate the example: s = 010, 92 matches.
    // 92: ...000000000000000092
    // Parity: ...00000000000000010 (rightmost is 0 for 2, next is 1 for 9)
    // Pattern s = 010: ...000000000000000010
    // They match.
    // So, for a number, we need to generate its 18-digit parity pattern.
    // The string should be built from right to left, but stored in a way that
    // allows direct comparison.
    // If we store "01" for 92, and query "010", they don't match directly.
    // The problem states "parity of the i-th from the right digit".
    // This means the pattern "010" refers to the 1st, 2nd, 3rd digits from the right.
    // For 92, 1st from right is 2 (even), 2nd is 9 (odd), 3rd is 0 (even).
    // So 92's effective pattern for comparison is "010" (for 3 digits).
    // This means we should store a canonical form for each number.
    // A canonical form could be an 18-character string where each char is '0' or '1'.
    // For 92:
    // 1st digit (rightmost): 2 -> '0'
    // 2nd digit: 9 -> '1'
    // 3rd digit: 0 -> '0'
    // ...
    // 18th digit: 0 -> '0'
    // So the canonical pattern for 92 is "000000000000000010" (18 chars).
    // For 0:
    // 1st digit: 0 -> '0'
    // ...
    // 18th digit: 0 -> '0'
    // Canonical pattern for 0 is "000000000000000000".
    // This is what the `fixed_length_pattern` logic above does.
    // The `fixed_length_pattern` is built from right to left, so it's already in the correct order.
    // Example: n=92.
    // i=0: n=92, n%10=2 (even), fixed_length_pattern="0", temp_n=9
    // i=1: n=9, n%10=9 (odd), fixed_length_pattern="01", temp_n=0
    // i=2 to 17: temp_n=0, fixed_length_pattern += '0'.
    // Result: "010000000000000000". This is the pattern for 92.
    // This is correct. The example "010" for 92 means 1st from right is 0, 2nd is 1, 3rd is 0.
    // My generated string "010..." means 1st char is 1st digit from right, 2nd char is 2nd digit from right.
    // So "010..." for 92 means 1st digit is even, 2nd is odd, 3rd is even. This matches.
    return fixed_length_pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int k = 0; k < t; ++k) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern 's' with '0's to the right to make it 18 characters long.
            // This is because the problem states: "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // And "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // This means both the number's pattern and the query pattern should be normalized to the same length.
            // Since numbers can be up to 18 digits, we use 18.
            // Example: query pattern "010". Length 3.
            // Padded to 18: "010000000000000000".
            std::string padded_s = s;
            padded_s.resize(18, '0');
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

