#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <functional> // For std::greater

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // A simple strategy that works for all n >= 2 is to reverse the permutation.
    // Let p' be the reversed permutation of p.
    // p'_i = p_{n-i-1}
    // The adjacent sums for p are (p_0+p_1), (p_1+p_2), ..., (p_{n-2}+p_{n-1}).
    // The adjacent sums for p' are (p'_0+p'_1), (p'_1+p'_2), ..., (p'_{n-2}+p'_{n-1}).
    // Which are (p_{n-1}+p_{n-2}), (p_{n-2}+p_{n-3}), ..., (p_1+p_0).
    // These are exactly the same set of sums, just in reverse order.
    // Since the fingerprint is the sorted array of these sums,
    // F(p) will be equal to F(p').
    // The only case where p' might be equal to p is if p is a palindrome.
    // However, a permutation of distinct integers from 1 to n cannot be a palindrome
    // unless n=1 (which is not allowed, n>=2) or n=2 and p=[1,2] or p=[2,1].
    // For n=2, if p=[1,2], p'=[2,1], which is different.
    // If p=[2,1], p'=[1,2], which is different.
    // For n > 2, a permutation cannot be a palindrome.
    // For example, if p_0 = p_{n-1}, then p_0 and p_{n-1} are the same value,
    // but elements of a permutation must be distinct.
    // So p_0 must be different from p_{n-1}.
    // Thus, p cannot be equal to its reverse p' for n >= 2.
    // Therefore, reversing the permutation always yields a different permutation
    // with the same fingerprint.

    std::reverse(p.begin(), p.end());
    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

