void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long initial_a1 = a[0];
    long long added_to_a1 = 0;

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i + 1; // 1-indexed pile number
        long long cost_per_haybale = pile_idx - 1;

        if (cost_per_haybale > d) {
            // If even one haybale from this pile costs more days than available,
            // we cannot move any haybales from this pile or any further piles.
            break;
        }

        // Calculate how many haybales we can move from this pile
        // given the remaining days.
        long long max_haybales_from_this_pile = d / cost_per_haybale;

        // We can move at most `a[i]` haybales from this pile.
        long long haybales_to_move = std::min(a[i], max_haybales_from_this_pile);

        added_to_a1 += haybales_to_move;
        d -= haybales_to_move * cost_per_haybale;
    }

    std::cout << initial_a1 + added_to_a1 << std::endl;
}

