void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // and '3' for the second digit,
        // and '9' for all subsequent digits.
        // This number will be 2399...9.
        // Let's check its divisibility properties.
        // The digits are 2, 3, 9.
        //
        // Divisibility by 2:
        // The number ends in 9 (for n >= 3) or 3 (for n=2).
        // In both cases, the last digit is odd, so the number is not divisible by 2.
        //
        // Divisibility by 3:
        // The sum of digits is 2 + 3 + (n-2)*9.
        // Sum = 5 + 9n - 18 = 9n - 13.
        // For a number to be divisible by 3, its sum of digits must be divisible by 3.
        // 9n is always divisible by 3.
        // 13 is not divisible by 3 (13 % 3 = 1).
        // So, 9n - 13 is not divisible by 3.
        // Thus, the number is not divisible by 3.
        //
        // Divisibility by 9:
        // For a number to be divisible by 9, its sum of digits must be divisible by 9.
        // Sum = 9n - 13.
        // 9n is always divisible by 9.
        // 13 is not divisible by 9 (13 % 9 = 4).
        // So, 9n - 13 is not divisible by 9.
        // Thus, the number is not divisible by 9.
        //
        // This construction works for all n >= 2.
        // For n=2, the number is 23.
        // 23 % 2 = 1, 23 % 3 = 2. Not divisible by 2 or 3. Valid.
        // For n=3, the number is 239.
        // 239 % 2 = 1, 239 % 3 = 2 (sum=14), 239 % 9 = 5 (sum=14). Not divisible by 2, 3, or 9. Valid.
        // For n > 3, the number is 239...9.
        // Not divisible by 2, 3, or 9. Valid.

        std::cout << '2';
        std::cout << '3';
        for (int i = 0; i < n - 2; ++i) {
            std::cout << '9';
        }
        std::cout << std::endl;
    }
}

