void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // If the strings are already equal, it's possible.
    if (s == t) {
        std::cout << "YES\n";
        return;
    }

    // Check if there is any common character between s and t.
    // We can use a boolean array (or a bitset) for efficiency,
    // as characters are lowercase Latin letters ('a' through 'z').
    std::vector<bool> s_chars(26, false);
    for (char c : s) {
        s_chars[c - 'a'] = true;
    }

    for (char c : t) {
        if (s_chars[c - 'a']) {
            // If a character 'c' exists in both s and t,
            // it means we can potentially make both strings entirely 'c'.
            // For example, if 'c' is in s, we can propagate it throughout s.
            // If 'c' is in t, we can propagate it throughout t.
            // Since we can perform operations on both strings,
            // we can make s entirely 'c' and t entirely 'c', thus making them equal.
            std::cout << "YES\n";
            return;
        }
    }

    // If no common character is found, it's impossible.
    // Because if s and t are to become equal, they must eventually share
    // at least one character that can then be propagated.
    // If they don't share any character initially, they can never share one,
    // as operations only copy existing characters, not create new ones.
    std::cout << "NO\n";
}

