#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i], Need to decrease a[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update has_pos_one and has_neg_one for elements to the left
        // This is crucial: a[i] itself cannot be changed by elements to its right.
        // So, if a[i] is 1 or -1, it contributes to the flags for elements to its left.
        // The flags are only relevant for elements a[k] where k < i.
        // The current a[i] is the one being checked, so its original value is what matters for future operations on a[k] (k<i).
        // But for operations on a[i] itself, we need elements a[k] where k < i.
        // The problem states "choose any pair of indexes (i, j) such that 1 <= i < j <= n".
        // This means a[i] can only be modified by a[k] where k < i.
        // The flags `has_pos_one` and `has_neg_one` should reflect the presence of 1s and -1s among a[0]...a[i-1].
        // Let's re-evaluate the logic.
        // The flags `has_pos_one` and `has_neg_one` should track if there's a 1 or -1 *before* the current index `i`.
        // So, we should update these flags *after* processing `a[i]`.
    }

    // Corrected logic for flags:
    // Iterate from left to right.
    // For each a[i], check if it can be transformed to b[i] using elements a[0]...a[i-1].
    // Then, update flags based on a[i] for subsequent elements a[i+1]...a[n-1].

    has_pos_one = false;
    has_neg_one = false;
    possible = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] < b[i]) { // Need to increase a[i]
                if (!has_pos_one) {
                    possible = false;
                    break;
                }
            } else { // a[i] > b[i], Need to decrease a[i]
                if (!has_neg_one) {
                    possible = false;
                    break;
                }
            }
        }
        // After checking a[i], update flags for elements to its right.
        // The original value of a[i] is what can be added to a[j] for j > i.
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

