void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;
    int half_color_toggle = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // Smaller elements go to white
        } else if (a[i] > T_half) {
            p[i] = 1; // Larger elements go to black
        } else { // a[i] == T_half
            if (T_is_even) {
                // For elements equal to T/2, alternate colors
                p[i] = half_color_toggle;
                half_color_toggle = 1 - half_color_toggle;
            } else {
                // If T is odd, T/2 is not an integer, so a[i] cannot be T/2.
                // This branch should ideally not be reached if a[i] == T_half
                // is only true for integer T_half.
                // However, if T_half is integer division, then a[i] == T_half
                // means a[i] is floor(T/2).
                // But the problem states a_i are non-negative integers.
                // If T is odd, T/2 is not an integer. So a[i] can never be exactly T/2.
                // Thus, this 'else' branch only applies if T is even.
                // For safety, if T is odd and a[i] == T_half (which means a[i] == floor(T/2)),
                // then a[i] + a[j] = T implies a[j] = T - a[i] = T - floor(T/2) = ceil(T/2).
                // Since a[i] != a[j], these elements can always be split.
                // So, if T is odd, elements equal to floor(T/2) can go to color 0.
                p[i] = 0; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

