#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C's stdio and disables synchronization,
    // which can significantly speed up I/O operations.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) { // Loop through each test case
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a std::vector to store prices.
        // It's generally safer and more convenient than raw arrays.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices into the vector
        }

        if (n <= 1) {
            // If there's only one day or no days, no price can be "bad"
            // because there's no "later day".
            std::cout << 0 << "\n";
            continue; // Move to the next test case
        }

        int bad_prices_count = 0;
        // Initialize min_price_so_far with the price of the last day.
        // This variable will store the minimum price encountered
        // from the current position to the end of the array (rightwards).
        int min_price_so_far = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // For each day 'i', we compare its price 'a[i]' with the
        // minimum price found in days 'i+1' through 'n-1'.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_price_so_far) {
                // If the current day's price is greater than the minimum
                // price found later, then this price is "bad".
                bad_prices_count++;
            } else {
                // If the current day's price is not greater than the minimum
                // price found later, it means this price itself is a new
                // minimum (or equal to the current minimum) for the suffix
                // ending at this position. Update min_price_so_far.
                min_price_so_far = a[i];
            }
        }

        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    if (n == 2) {
        // For n=2, the only possible values are 1 and 2.
        // a[0][1] = min(p[0], p[1]).
        // If a[0][1] == 1, then one of p[0], p[1] is 1, and the other is 2.
        // The problem guarantees a solution exists.
        // So, if a[0][1] == 1, then {1, 2} or {2, 1} are valid.
        // We can just output {2, 1} as a canonical choice.
        // This covers the example case.
        p[0] = 2;
        p[1] = 1;
    } else {
        for (int i = 0; i < n; ++i) {
            int max_val_in_row = 0;
            for (int j = 0; j < n; ++j) {
                if (i == j) continue;
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
            p[i] = max_val_in_row;
        }

        // Check if any element in p is n-1. If so, it should be n.
        // This happens if the original permutation contained n, and its corresponding
        // row's maximum was n-1 (the second largest value).
        // If all values in p are less than n, it means n was not assigned.
        // The problem guarantees a solution exists, so exactly one element should be n.
        // If we find that all p[i] are <= n-1, it means the actual 'n' value
        // was assigned to some p[k], and for that k, max(a[k][j] for j!=k) = n-1.
        // In this case, we need to find the p[k] that should be n.
        // This p[k] would be the one that currently holds n-1, and all other values
        // are distinct and smaller.
        // A simpler way: if n is not present in p, then the largest value in p must be n-1.
        // We find the first occurrence of n-1 and change it to n.
        bool n_found = false;
        for (int val : p) {
            if (val == n) {
                n_found = true;
                break;
            }
        }

        if (!n_found) {
            // If n is not found, it means the element that should be n
            // was assigned n-1 because min(n, p_j) = p_j for all p_j < n.
            // So, the maximum value in its row was n-1.
            // We need to find one such element and change its value to n.
            // Since all other values are distinct and smaller, there will be exactly one
            // position that should be n.
            // We can just find the first occurrence of n-1 and change it to n.
            // This is guaranteed to be correct because the problem guarantees a solution.
            for (int i = 0; i < n; ++i) {
                if (p[i] == n - 1) {
                    p[i] = n;
                    break; 
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (inclusive of the first i pieces)
        // should be i times the area of a single piece.
        // Total area of carrot = (1/2) * base * height = (1/2) * 1 * h = h/2.
        // Area of one piece = (h/2) / n = h / (2n).
        // Area of triangle up to i-th cut = i * (h / (2n)).
        // Let x_i be the height of this triangle.
        // By similarity, base_i / x_i = 1 / h, so base_i = x_i / h.
        // Area_i = (1/2) * base_i * x_i = (1/2) * (x_i / h) * x_i = x_i^2 / (2h).
        // So, x_i^2 / (2h) = i * (h / (2n)).
        // x_i^2 = i * (h / (2n)) * (2h) = i * h^2 / n.
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

