int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we use to generate differences 1 to k

    // Generate the first k+1 elements to produce k distinct differences
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index: take from left (small)
            p[i] = left;
            left++;
        } else { // Odd index: take from right (large)
            p[i] = right;
            right--;
        }
    }

    // The remaining elements are simply the unused numbers in increasing order.
    // These will be appended to the permutation.
    // The last number used from the 'left' side was `left-1`.
    // The last number used from the 'right' side was `right+1`.
    // The numbers remaining are `left, left+1, ..., right`.
    // Since `left` and `right` crossed over or met, `left` is now greater than `right`.
    // The numbers `left, left+1, ..., right` are exactly the numbers that were not used
    // in the alternating sequence.
    // For example, if k=2, n=5:
    // p[0]=1, left=2
    // p[1]=3, right=2
    // p[2]=2, left=3
    // Now left=3, right=2. The numbers 1,2,3 have been used.
    // The remaining numbers are 4, 5.
    // The last element generated was p[k].
    // We append the remaining numbers in increasing order.
    // The smallest unused number is `left`.
    // The largest unused number is `n`.
    // So we append `left, left+1, ..., n`.
    // Note that `left` here is the next available number from the 'small' side.
    // The numbers used were `1, 2, ..., left-1` and `right+1, ..., k+1`.
    // The numbers remaining are `left, left+1, ..., right`.
    // But `left` and `right` are now the pointers.
    // The numbers that were not used in the alternating sequence are `k+2, k+3, ..., n`.
    // These are appended in increasing order.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // The numbers are 1-indexed, so p[k+1] should be k+2, etc.
                      // This is equivalent to `p[i] = left; left++;` if `left` was initialized to `k+2`.
    }


    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The number of coders (each team needs at least one coder).
        // 2. The number of mathematicians (each team needs at least one mathematician).
        // 3. The total number of students available (each team needs three students).
        //    For k teams, we need 3k students.
        //    The total students available are c + m + x.
        //    So, 3k <= c + m + x.
        //    This implies k <= (c + m + x) / 3.

        // Combining these, k must be less than or equal to min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.
        // We can binary search for the maximum k that satisfies the conditions.
        // The range for k is [0, 10^8] (since c, m, x <= 10^8, max teams can't exceed 10^8).

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Initial upper bound
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // The remaining students (c - mid) coders, (m - mid) mathematicians, and 'x' non-specialized
            // must be enough to fill the remaining 'mid' spots in the teams.
            // (Each team has 3 members. 1 coder + 1 mathematician = 2 members. 1 spot remaining per team.)

            long long remaining_students_for_third_spot = (c - mid) + (m - mid) + x;

            if (remaining_students_for_third_spot >= mid) {
                // It's possible to form 'mid' teams. Try for more.
                ans = mid;
                low = mid + 1;
            } else {
                // Not enough students for 'mid' teams. Try for fewer.
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k_max = n / m;

        if (k_max == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long m_last_digit = m % 10;

        // Precompute the sum of last digits for one cycle (10 terms)
        // (1*m)%10, (2*m)%10, ..., (10*m)%10
        // This is equivalent to (1*m_last_digit)%10, ..., (10*m_last_digit)%10
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (i * m_last_digit) % 10;
        }

        // Number of full cycles of 10 terms
        long long num_full_cycles = k_max / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining terms after full cycles
        long long remaining_terms = k_max % 10;
        for (long long i = 1; i <= remaining_terms; ++i) {
            total_sum += (i * m_last_digit) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
