#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] = index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, current_min_idx and current_max_idx are already pos[1].
        // The range [pos[1], pos[1]] has length 1, min 1, max 1. So m=1 is beautiful.
        // For m > 1, we need to expand the range to include 'm'.
        // The new element 'm' is at pos[m].
        // We update current_min_idx and current_max_idx to cover the range [1, ..., m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, 2, ..., m.
        // This means its length must be m.
        // The length of the current range is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

