    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'i' such that a[i...n-1] is non-decreasing.
    // This means a[i] <= a[i+1] <= ... <= a[n-1].
    // This is the 'suffix_non_decreasing' part.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // After this loop, a[i...n-1] is non-decreasing.
    // 'i' is the first element of this non-decreasing suffix.

    // Now, find the rightmost index 'j' such that a[j...i-1] is non-increasing.
    // This means a[j] >= a[j+1] >= ... >= a[i-1].
    // This is the 'suffix_non_increasing' part.
    // If i is 0, then the whole array is non-decreasing, so j would be 0.
    // If i is 1, then a[0] is the only element before the non-decreasing suffix,
    // so a[0] is trivially non-increasing.
    int j = i; // Start j from i. If i is 0, j remains 0.
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // After this loop, a[j...i-1] is non-increasing.
    // 'j' is the first element of this non-increasing suffix.

    // The length of the prefix to erase is 'j'.
    std::cout << j << std::endl;
}

