#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate max_left_val[i]: the maximum possible value for a[i]
    // such that a[0] < a[1] < ... < a[i] can be formed.
    // This means a[j] must be at least j for j <= i.
    // And a[j] must be at least a[j-1]+1.
    // So, a[i] must be at least i.
    // And a[i] must be at least a[i-1]+1.
    // The actual value a[i] can take is min(original a[i], max_left_val[i-1]+1).
    // But we are interested in the *minimum* value a[i] must be to satisfy the chain.
    // For a[i] to be part of an increasing sequence starting from 0,
    // a[i] must be at least i.
    // If original a[i] < i, then it's impossible to make a[i] >= i.
    // So, we need a[i] >= i for all i in the increasing part.
    // This is equivalent to checking if a[i] >= i for i from 0 to k-1.
    // The first element a[0] must be at least 0.
    // The second element a[1] must be at least 1.
    // ...
    // The i-th element a[i] must be at least i.
    // If a[i] < i for any i, then it's impossible to make a[i] = i,
    // which is the smallest possible value for a[i] in a strictly increasing sequence
    // starting from 0.
    // So, we find the first index `i` from the left where `a[i] < i`.
    // All elements `a[0]...a[i-1]` can potentially form the increasing part.
    int left_limit = n;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_limit = i;
            break;
        }
    }

    // Calculate max_right_val[i]: the maximum possible value for a[i]
    // such that a[i] > a[i+1] > ... > a[n-1] can be formed.
    // This means a[j] must be at least (n-1)-j for j >= i.
    // So, a[i] must be at least (n-1)-i.
    // If original a[i] < (n-1)-i, then it's impossible to make a[i] >= (n-1)-i.
    // So, we need a[i] >= (n-1)-i for all i in the decreasing part.
    // The last element a[n-1] must be at least 0.
    // The second to last a[n-2] must be at least 1.
    // ...
    // The i-th element a[i] must be at least (n-1)-i.
    // If a[i] < (n-1)-i for any i, then it's impossible to make a[i] = (n-1)-i,
    // which is the smallest possible value for a[i] in a strictly decreasing sequence
    // ending at 0.
    // So, we find the first index `i` from the right where `a[i] < (n-1)-i`.
    // All elements `a[i+1]...a[n-1]` can potentially form the decreasing part.
    int right_limit = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1) - i) {
            right_limit = i;
            break;
        }
    }

    // If there is any k such that 0 <= k < left_limit and right_limit < k,
    // then it's possible.
    // This means we need to find an index k such that:
    // 1. a[0]...a[k-1] can form an increasing sequence (i.e., k <= left_limit)
    // 2. a[k+1]...a[n-1] can form a decreasing sequence (i.e., k >= right_limit)
    // 3. a[k] can be the peak.
    // The conditions `a[i] >= i` for `i < k` and `a[i] >= (n-1)-i` for `i > k`
    // ensure that we can construct the sequences `0, 1, ..., k-1` and `k-1, k-2, ..., 0`
    // (or similar sequences with larger values) up to the peak.
    // The peak `a[k]` itself must be able to be greater than `a[k-1]` and `a[k+1]`.
    // The minimum value for `a[k-1]` is `k-1`.
    // The minimum value for `a[k+1]` is `(n-1)-(k+1)`.
    // So, `a[k]` must be at least `k` and `a[k]` must be at least `(n-1)-k`.
    // This is implicitly covered by the `left_limit` and `right_limit` definitions.
    // If `k < left_limit`, then `a[k] >= k`.
    // If `k > right_limit`, then `a[k] >= (n-1)-k`.
    // So, we just need to check if there's any `k` such that `k < left_limit` AND `k > right_limit`.
    // This is equivalent to checking if `left_limit > right_limit`.
    // If `left_limit > right_limit`, it means there's at least one index `k`
    // that satisfies both conditions. For example, `k = right_limit + 1` would work
    // if `right_limit + 1 < left_limit`.
    // If `left_limit <= right_limit`, then there is no such `k`.

    if (left_limit > right_limit) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Adjust elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int b_ptr = 0; // Pointer for elements to be placed (the 'b' array elements)

    // Iterate through the sorted original array 'a' (representing a_i)
    // and try to find a larger element from 'a' (representing b_j)
    // to place at that position.
    for (int a_ptr = 0; a_ptr < n; ++a_ptr) {
        // We want to find an element a[b_ptr] such that a[b_ptr] > a[a_ptr].
        // Since both arrays are sorted, we can advance b_ptr.
        // If a[b_ptr] is not greater than a[a_ptr], we need a larger element,
        // so we increment b_ptr.
        // We also need to ensure b_ptr is always ahead of or at a_ptr,
        // and that b_ptr doesn't go out of bounds.
        // The condition b_ptr <= a_ptr is implicitly handled by the logic:
        // if a[b_ptr] <= a[a_ptr], we increment b_ptr.
        // If b_ptr starts at 0 and a_ptr starts at 0, and a[0] <= a[0],
        // b_ptr will increment. This is correct because an element cannot be
        // placed at its own position if it's not strictly greater.
        // However, the problem is about finding a permutation.
        // The elements a[a_ptr] and a[b_ptr] are distinct elements from the original multiset.
        // We are effectively trying to match a[a_ptr] with some a[b_ptr] where b_ptr > a_ptr
        // or a[b_ptr] is an element that hasn't been "used" yet.
        // The two-pointer approach works by matching the smallest available 'b' element
        // that is greater than the current 'a' element.
        // 'a_ptr' iterates through the sorted original values.
        // 'b_ptr' iterates through the sorted values that are candidates for the new positions.
        // If a[b_ptr] > a[a_ptr], we found a match. We increment both pointers.
        // If a[b_ptr] <= a[a_ptr], a[b_ptr] cannot be placed at a[a_ptr]'s position to satisfy the condition.
        // So we try the next available 'b' element by incrementing b_ptr.
        // The 'a_ptr' element remains unmatched for now, waiting for a larger 'b' element.

        while (b_ptr < n && a[b_ptr] <= a[a_ptr]) {
            b_ptr++;
        }

        if (b_ptr < n) { // If we found an element a[b_ptr] > a[a_ptr]
            count++;
            b_ptr++; // Move to the next element in 'b' candidates
        } else {
            // No more elements in 'a' (from b_ptr onwards) are greater than a[a_ptr].
            // We can stop early as no further matches are possible for remaining a_ptr.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

