// Function to check if a subarray is a permutation of 1 to len
// This version uses a frequency array and checks max element.
// It's optimized for the specific use case where we know the maximum element
// and can use a boolean array for presence.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return true; // An empty sequence is vacuously a permutation
    if (len > arr.size() - start_idx) return false; // Not enough elements

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

// Optimized check for permutation property for a prefix
// `max_val_prefix[k]` stores the maximum value in `a[0...k-1]`
// `freq_prefix[k]` stores the frequency array for `a[0...k-1]`
// `is_perm_prefix[k]` is true if `a[0...k-1]` is a permutation of `1...k`
void precompute_prefix_permutations(int n, const std::vector<int>& a,
                                    std::vector<bool>& is_perm_prefix,
                                    std::vector<int>& max_val_prefix) {
    is_perm_prefix.assign(n + 1, false);
    max_val_prefix.assign(n + 1, 0);
    std::vector<int> freq(n + 1, 0); // Frequencies for values 1 to n

    int current_max = 0;
    int distinct_count = 0;

    for (int k = 1; k <= n; ++k) {
        int val = a[k - 1];
        if (val > n) { // Value too large for any permutation up to n
            // This path is technically not needed due to problem constraints a_i <= n-1
            // but good for robustness.
            // If val > k, it cannot be a permutation of 1..k.
            // If val > n, it cannot be a permutation of 1..n.
            // Since a_i <= n-1, val will never be n.
            // So if k=n, a[k-1] cannot be n, so it cannot be a permutation of 1..n.
            // This means is_perm_prefix[n] will always be false.
            // This is consistent with the problem constraint a_i <= n-1.
            // A permutation of length n must contain n.
            // So p1 cannot have length n, and p2 cannot have length n.
            // This means l1 < n and l2 < n.
            // So we only care about is_perm_prefix[k] for k < n.
            // And is_perm_suffix[k] for k < n.
        }

        if (freq[val] == 0) {
            distinct_count++;
        }
        freq[val]++;
        if (val > current_max) {
            current_max = val;
        }

        max_val_prefix[k] = current_max;
        if (current_max == k && distinct_count == k) {
            is_perm_prefix[k] = true;
        }
    }
}

// Optimized check for permutation property for a suffix
// `max_val_suffix[k]` stores the maximum value in `a[k...n-1]`
// `is_perm_suffix[k]` is true if `a[k...n-1]` is a permutation of `1...n-k`
void precompute_suffix_permutations(int n, const std::vector<int>& a,
                                    std::vector<bool>& is_perm_suffix,
                                    std::vector<int>& max_val_suffix) {
    is_perm_suffix.assign(n + 1, false); // is_perm_suffix[k] for suffix starting at index k
    max_val_suffix.assign(n + 1, 0);

    std::vector<int> freq(n + 1, 0);
    int current_max = 0;
    int distinct_count = 0;

    for (int k = n - 1; k >= 0; --k) {
        int val = a[k];
        int len = n - k; // Length of suffix a[k...n-1]

        if (val > n) { // Value too large
            // Similar logic as prefix, a_i <= n-1 means is_perm_suffix[0] (for length n) is false.
        }

        if (freq[val] == 0) {
            distinct_count++;
        }
        freq[val]++;
        if (val > current_max) {
            current_max = val;
        }

        max_val_suffix[k] = current_max;
        if (current_max == len && distinct_count == len) {
            is_perm_suffix[k] = true;
        }
    }
}


void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_perm_prefix;
    std::vector<int> max_val_prefix;
    precompute_prefix_permutations(n, a, is_perm_prefix, max_val_prefix);

    std::vector<bool> is_perm_suffix;
    std::vector<int> max_val_suffix;
    precompute_suffix_permutations(n, a, is_perm_suffix, max_val_suffix);

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 is the length of p1, so p1 = a[0...l1-1]
    // l2 is the length of p2, so p2 = a[l1...n-1]
    // l1 + l2 = n
    // Constraints: 1 <= l1, l2 <= n-1 (because a_i <= n-1, so n cannot be present)
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (l2 < 1) continue; // Ensure l2 is at least 1

        // Check if a[0...l1-1] is a permutation of 1...l1
        bool p1_is_perm = is_perm_prefix[l1];

        // Check if a[l1...n-1] is a permutation of 1...l2
        bool p2_is_perm = is_perm_suffix[l1];

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

