#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // We need to append elements b1, b2, ..., bs such that
    // (current_sum + sum(bi)) = 2 * (current_xor ^ xor(bi))

    // Strategy 1: Append two elements
    // Let's try to append two elements, say X and Y.
    // We want (current_sum + X + Y) = 2 * (current_xor ^ X ^ Y)
    // A simple choice for X and Y that often works is X = current_xor and Y = current_sum + current_xor.
    // Let's check this:
    // New sum = current_sum + current_xor + (current_sum + current_xor) = 2 * current_sum + 2 * current_xor
    // New xor = current_xor ^ current_xor ^ (current_sum + current_xor) = 0 ^ (current_sum + current_xor) = current_sum + current_xor
    // Is (2 * current_sum + 2 * current_xor) == 2 * (current_sum + current_xor)?
    // Yes, this is always true.
    // So, we can always append current_xor and (current_sum + current_xor).
    // The problem states that appended elements don't have to be different.
    // The problem also states that solution always exists and we don't have to minimize.
    // This strategy uses 2 elements.

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << (current_sum + current_xor) << std::endl;
}

