#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' can be "passed" by
            // all 'a's to its left. Each 'a' to its left will contribute
            // `count_a` steps when it passes this 'b'.
            // When an 'a' passes a 'b', it becomes 'bb'.
            // The original 'a' is gone, but it effectively creates two 'b's.
            // The 'a's that are further left will then interact with these
            // new 'b's.
            // The key insight is that an 'a' effectively doubles the number
            // of 'b's it needs to pass.
            // So, if we have `count_a` 'a's to the left of the current 'b',
            // these `count_a` 'a's will each perform an operation with this 'b'.
            // The total steps for this 'b' will be `count_a`.
            // After these operations, each of these `count_a` 'a's effectively
            // becomes two 'b's. So, the number of 'a's that are "active"
            // (i.e., `count_a`) doubles for the next 'b' to its left.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are waiting to interact with 'b's to their right.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

