int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_val, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_val, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs with both same x and same y (i.e., identical points)
    // These pairs were counted twice: once in x_counts and once in y_counts.
    // They should only be counted once.
    for (auto const& [point, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    if (n % 2 != 0) { // N is odd
        chanek_coins += 1;
        n -= 1;
        // Now N is even. Opponent's turn.
        // Opponent will try to maximize their coins.
        // If N is 0, game ends.
        // If N is 2, opponent takes 1. Chanek takes 1.
        // If N is 4, opponent takes 2. Chanek takes 1. Opponent takes 1.
        // If N is 6, opponent takes 3. Chanek takes 1. Opponent takes 1. Chanek takes 1.
        // If N is 8, opponent takes 4. Chanek takes 1. Opponent takes 1. Chanek takes 1. Opponent takes 1.
        // This pattern suggests that if N is even, and it's opponent's turn,
        // opponent will take N/2 if N is not a power of 2, or if N is a power of 2 and N > 2.
        // If N is a power of 2, say 2^k, and k > 1, opponent takes N/2 = 2^(k-1).
        // Then Chanek faces 2^(k-1).
        // If N is 2, opponent takes 1. Chanek faces 1. Chanek takes 1.
        // The opponent will always try to take N/2 if N is even and N > 0.
        // If N is 0, game ends.
        // If N is 2, opponent takes 1. Chanek takes 1.
        // If N is 4, opponent takes 2. Chanek takes 1. Opponent takes 1.
        // If N is 6, opponent takes 3. Chanek takes 1. Opponent takes 1. Chanek takes 1.
        // If N is 8, opponent takes 4. Chanek takes 1. Opponent takes 1. Chanek takes 1. Opponent takes 1.
        // The opponent will always take N/2 if N is even and N > 0.
        // This is because taking N/2 leaves N/2 coins for Chanek,
        // while taking 1 coin leaves N-1 coins for Chanek.
        // If N/2 is odd, Chanek takes 1, leaving N/2-1.
        // If N/2 is even, Chanek takes N/4, leaving N/4.
