void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Rule 1: If s[i] is '0', then w[i-x] (if exists) and w[i+x] (if exists) must be '0'.
    // This is the only way to definitively set characters in w to '0'.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if the constructed w can produce s.
    // Rule 2: If s[i] is '1', then at least one of w[i-x] or w[i+x] must be '1'.
    // If we find an s[i] == '1' for which neither w[i-x] nor w[i+x] is '1',
    // then no such w exists.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            bool possible_one = false;
            if (i - x >= 0 && w[i - x] == '1') {
                possible_one = true;
            }
            if (i + x < n && w[i + x] == '1') {
                possible_one = true;
            }

            if (!possible_one) {
                std::cout << -1 << std::endl;
                return;
            }
