#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm> // For std::reverse

// Function to convert a non-negative integer to its parity pattern string
// The pattern is generated from right to left, so the string will be in the correct order
// (e.g., 92 -> "10", 2212 -> "0010")
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    // The pattern is built from right to left, so it's already in the correct order
    // for comparison with query patterns (which are also effectively right-to-left).
    // Example: 92 -> '2' (even) -> '0', '9' (odd) -> '1'. Result "01".
    // But the problem states "i-th from the right digit".
    // If pattern is "010", 92 -> "10".
    // 92: rightmost 2 (even) -> 0. Next 9 (odd) -> 1.
    // So, 92 matches "010" if "10" matches "010".
    // "10" padded with 0s from left: "010". Matches.
    // My current `pattern` string is "01" for 92.
    // If I reverse it, it becomes "10".
    // The problem states "i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern".
    // This means we should compare digit by digit from right to left.
    // If the pattern is "010", and number is 92.
    // Number 92: digits are 9, 2.
    // Pattern "010": digits are 0, 1, 0.
    // Rightmost digit of 92 is 2 (even). Rightmost digit of "010" is 0 (even). Match.
    // Second from right digit of 92 is 9 (odd). Second from right digit of "010" is 1 (odd). Match.
    // Third from right digit of 92 (padded with 0) is 0 (even). Third from right digit of "010" is 0 (even). Match.
    // So 92 matches "010".
    // My `get_parity_pattern` for 92 would produce "01" (2 is 0, 9 is 1).
    // This string "01" represents the parities from right to left.
    // The query pattern `s` is also given as a string, where `s[s.length()-1]` is the rightmost digit's parity.
    // So, if `s` is "010", `s[2]` is '0', `s[1]` is '1', `s[0]` is '0'.
    // My `get_parity_pattern` for 92 is "01".
    // To make them comparable, I need to pad them to length 18 and then compare.
    // The string `pattern` generated by `get_parity_pattern` is already in the correct order for this.
    // For 92, it's "01". For 2212, it's "0010". For 50, it's "01". For 414, it's "010".
    // These are the "normalized" patterns.
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Using a map to store counts of each normalized parity pattern.
    // The key is the normalized pattern string (padded to 18 '0's).
    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+' || type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            // Pad the pattern to length 18 with '0's on the left
            // The problem states "supplemented with 0-s from the left".
            // Since my `get_parity_pattern` builds the string from right to left,
            // the rightmost character of `pattern` corresponds to the rightmost digit of `a`.
            // So, padding with '0's on the left of `pattern` means adding '0's for higher-order digits.
            // Example: 92 -> "01". Padded to 18: "000000000000000001".
            // This is equivalent to padding the number with leading zeros.
            // The pattern string itself is effectively reversed compared to how we usually write numbers.
            // For example, 92 -> "01". If we want to pad it to 18 digits, it becomes "00...001".
            // This is correct for comparison.
            pattern.resize(18, '0'); // Pad with '0's to the right (which are effectively left in terms of digit position)

            if (type == '+') {
                counts[pattern]++;
            } else { // type == '-'
                counts[pattern]--;
            }
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // The query pattern `s` also needs to be normalized.
            // It's given as a string, e.g., "010".
            // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // And "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means both the number's pattern and the query pattern should be treated as if they are 18 digits long,
            // padded with '0's from the left.
            // My `get_parity_pattern` for 92 gives "01".
            // If query is "010".
            // The `s` string is given in the standard reading order.
            // "010" means 0 for 3rd digit, 1 for 2nd, 0 for 1st.
            // To match my `pattern` string format (right-to-left digits), I need to reverse `s`.
            std::reverse(s.begin(), s.end());
            s.resize(18, '0'); // Pad with '0's to the right (which are effectively left in terms of digit position)

            std::cout << counts[s] << "\n";
        }
    }

    return 0;
}

