#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    std::vector<long long> prime_factors_q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    // For each distinct prime factor f of q
    // we try to find the largest divisor of p that is not divisible by q
    // by removing all factors of f from p until it's no longer divisible by q
    for (long long f : prime_factors_q) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= f;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

