#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C stdio and disables synchronization,
    // making input/output operations faster.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int q;
    std::cin >> q; // Read the number of queries

    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k; // Read n, m, k for the current query

        // Ensure n is always less than or equal to m by swapping if necessary.
        // This simplifies logic as we can assume n <= m.
        if (n > m) {
            std::swap(n, m);
        }

        long long ans = -1; // Initialize answer to -1 (impossible)

        // Case 1: n and m have the same parity.
        // This means (n+m) is even and (m-n) is even.
        // The parity of (x+y) must be the same as the parity of k.
        // The parity of (x-y) must be the same as the parity of k.
        // Since (n+m) and (m-n) are both even, this implies k must be even.
        if ((n % 2) == (m % 2)) { // n and m have the same parity
            if ((k % 2) == 0) { // k must also be even
                // If k is even, we can always reach (n,m) in k moves.
                // The maximum number of diagonal moves is k.
                // However, we must make at least m diagonal moves to cover the larger coordinate.
                // The remaining k-m moves must be used to adjust parity or position.
                // Each pair of moves (e.g., (1,0) then (-1,0)) or (1,1) then (-1,-1)
                // can be used to "waste" two moves without changing the final position.
                // If we make m diagonal moves, we reach (m,m) or similar.
                // The remaining k-m moves must be even.
                // If k >= m, we can make m diagonal moves to reach (m,m) (or (m,-m) etc.).
                // The remaining k-m moves can be used to move back and forth.
                // For example, (1,0) then (-1,0) uses 2 moves and changes nothing.
                // (1,1) then (-1,-1) uses 2 moves and changes nothing.
                // Since k and m have the same parity, k-m is even.
                // We can make m diagonal moves to reach (m,m).
                // Then we have k-m moves left. Since k-m is even, we can use (k-m)/2 pairs of
                // (1,0) and (-1,0) moves (or (0,1) and (0,-1) moves) to waste moves.
                // Each such pair is two straight moves.
                // So, we can make m diagonal moves and (k-m) straight moves.
                // Total diagonal moves = m.
                // But we want to maximize diagonal moves.
                // We can make k moves. If k >= m, we can make m diagonal moves to reach (m,m).
                // The remaining k-m moves must be even.
                // We can use (k-m)/2 pairs of (1,1) and (-1,-1) moves.
                // Each such pair consists of 2 diagonal moves.
                // So, we can make m diagonal moves to reach (m,m), and then (k-m) more diagonal moves
                // by moving (1,1) and (-1,-1) repeatedly.
                // Total diagonal moves = m + (k-m) = k.
                // This is possible if k >= m.
                if (k >= m) {
                    ans = k;
                }
            }
        }
        // Case 2: n and m have different parities.
        // This means (n+m) is odd and (m-n) is odd.
        // The parity of (x+y) must be the same as the parity of k.
        // The parity of (x-y) must be the same as the parity of k.
        // Since (n+m) and (m-n) are both odd, this implies k must be odd.
        else { // n and m have different parities
            if ((k % 2) == 1) { // k must also be odd
                // If k is odd, we can always reach (n,m) in k moves.
                // Similar to the even case, we need at least m moves.
                // If k >= m, we can make m diagonal moves to reach (m,m) (or similar).
                // Then we have k-m moves left.
                // Since k and m have different parities, k-m is odd.
                // We can make m diagonal moves to reach (m,m).
                // We have k-m moves left.
                // We need to end up at (n,m).
                // We can make m diagonal moves to reach (m,m).
                // Then we need to reach (n,m) from (m,m) in k-m moves.
                // This means we need to change x-coordinate by n-m and y-coordinate by 0.
                // This requires |n-m| straight moves.
                // The total moves would be m + |n-m| = m + (m-n) = 2m-n.
                // This is not maximizing diagonal moves.

                // Let's reconsider. We need to reach (n,m) in k moves.
                // We can make k-1 moves to reach a point (x',y') such that (x',y') is adjacent to (n,m).
                // Then the last move takes us to (n,m).
                // If k is odd, and n, m have different parities:
                // We can make k-1 moves to reach (n, m-1) or (n-1, m) or (n+1, m) etc.
                // (n, m-1) has coordinates with same parity.
                // (n-1, m) has coordinates with same parity.
                // So, after k-1 moves, we are at a point (x',y') where x' and y' have the same parity.
                // And k-1 is even.
                // From (0,0) to (x',y') in k-1 even moves, where x',y' have same parity.
                // This is possible if k-1 >= max(|x'|, |y'|).
                // The maximum number of diagonal moves for this subproblem is k-1.
                // Then the last move is a straight move to (n,m).
                // So, total diagonal moves = k-1.
                // This is possible if k >= m.
                if (k >= m) {
                    ans = k - 1;
                }
            }
        }

        // The above logic for ans = k or ans = k-1 is correct if k is large enough.
        // Specifically, we need k >= m.
        // If k < m, it's impossible to reach (n,m) because we need at least m moves
        // to cover the larger coordinate distance (even if all moves are diagonal).
        // For example, to reach (0,m), we need at least m moves.
        // To reach (n,m), we need at least m moves.
        // So if k < m, ans remains -1.

        std::cout << ans << "\n"; // Print the result for the current query
    }

    return 0; // Indicate successful execution
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <numeric>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = {};
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u = s[i];
        char v = s[i+1];
        adj[u].insert(v);
        adj[v].insert(u);
    }

    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            std::cout << "NO\n";
            return;
        }
        if (adj[c].size() == 1) {
            start_char = c;
        }
    }

    std::string layout = "";
    std::set<char> visited;

    if (start_char == '\0') { // All characters have 0 or 2 neighbors
        // If all characters have 0 neighbors, it means the password has length 1.
        // Any layout is fine. We can pick 'a' as start.
        // If some characters have 2 neighbors, it means there are cycles or multiple paths.
        // We need to find a character that is part of the password.
        // If s.length() == 1, then s[0] has 0 neighbors.
        // If s.length() > 1, then there must be at least one character with 2 neighbors (or 1 if it's an endpoint).
        // If all characters in adj have 0 or 2 neighbors, and there are characters with 2 neighbors,
        // it means the graph consists of disjoint cycles or paths where all internal nodes have degree 2.
        // For a single row keyboard, we need a single path.
        // If s.length() > 1 and no char has degree 1, it means all connected components are cycles.
        // This is impossible for a linear keyboard layout.
        // The only exception is if the password uses only one character, e.g., "a", then adj['a'] is empty.
        // In this case, start_char would be '\0'. We can pick 'a' as start.
        // If s.length() > 1 and start_char is still '\0', it means all characters involved in the password
        // have degree 2. This forms a cycle, which is not allowed.
        // Example: "abacaba" -> a-b, a-c. a has degree 2, b has degree 1, c has degree 1.
        // This would set start_char to 'b' or 'c'.
        // Example: "abcb" -> a-b, c-b. b has degree 2, a has degree 1, c has degree 1.
        // This would set start_char to 'a' or 'c'.
        // Example: "abac" -> a-b, a-c. a has degree 2, b has degree 1, c has degree 1.
        // This would set start_char to 'b' or 'c'.
        // The only way start_char remains '\0' for s.length() > 1 is if all characters in the password
        // form a cycle. E.g., "abacba" -> a-b, a-c, b-c. All a,b,c have degree 2.
        // This is impossible.
        // So, if s.length() > 1 and start_char is '\0', it's "NO".
        // If s.length() == 1, then s[0] has 0 neighbors. start_char is '\0'. We can pick s[0] as start.
        if (s.length() > 1) {
            std::cout << "NO\n";
            return;
        } else { // s.length() == 1
            start_char = s[0];
        }
    }

    char current = start_char;
    while (current != '\0') {
        if (visited.count(current)) { // Cycle detected or already processed part of a path
            break;
        }
        layout += current;
        visited.insert(current);

        char next_char = '\0';
        for (char neighbor : adj[current]) {
            if (!visited.count(neighbor)) {
                next_char = neighbor;
                break;
            }
        }
        current = next_char;
    }

    if (layout.length() != visited.size()) { // Should not happen if logic is correct
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited.count(c)) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_progression(long long n, long long first_term, long long common_difference, long long mod) {
    if (n <= 0) {
        return 0;
    }
    long long last_term = (first_term + (n - 1) % mod * common_difference % mod) % mod;
    long long sum = (n % mod * (first_term % mod + last_term % mod) % mod) % mod;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9 + 7
    sum = (sum * inv2) % mod;
    return sum;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    long long total_sum = 0;

    // Sum over k from 1 to a
    // Sum over r from 1 to b-1
    // x = r * (k * b + 1)

    // The sum is: sum_{k=1}^{a} sum_{r=1}^{b-1} (r * k * b + r)
    // = sum_{k=1}^{a} (k * b * sum_{r=1}^{b-1} r + sum_{r=1}^{b-1} r)
    // = sum_{k=1}^{a} ((k * b + 1) * sum_{r=1}^{b-1} r)

    // Calculate sum_{r=1}^{b-1} r
    // This is an arithmetic progression: 1, 2, ..., b-1
    // Number of terms = b-1
    // First term = 1, Last term = b-1
    long long sum_r_terms = 0;
    if (b > 1) {
        sum_r_terms = (b - 1);
        sum_r_terms = (sum_r_terms % MOD * (b % MOD)) % MOD;
        long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9 + 7
        sum_r_terms = (sum_r_terms * inv2) % MOD;
    }
    // If b=1, then b-1=0, sum_r_terms is 0, which is correct.

    // Now calculate sum_{k=1}^{a} (k * b + 1)
    // This is sum_{k=1}^{a} (k * b) + sum_{k=1}^{a} 1
    // = b * sum_{k=1}^{a} k + a

    // Calculate sum_{k=1}^{a} k
    // This is an arithmetic progression: 1, 2, ..., a
    // Number of terms = a
    // First term = 1, Last term = a
    long long sum_k_terms = (a % MOD * ((a + 1) % MOD)) % MOD;
    long long inv2 = 500000004; // Modular inverse of 2 modulo 10^9 + 7
    sum_k_terms = (sum_k_terms * inv2) % MOD;

    long long sum_kb_plus_1_terms = (b % MOD * sum_k_terms % MOD + a % MOD) % MOD;

    total_sum = (sum_kb_plus_1_terms * sum_r_terms) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < n; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_val = 0; k_val < n; ++k_val) { // Iterate over all possible true k values
        char c0 = s[k_val]; // The first character Vasya sees, t[0]

        // Find all k' values such that s[k'] == c0
        std::vector<int> possible_k_prime;
        for (int idx : char_indices[c0 - 'a']) {
            possible_k_prime.push_back(idx);
        }

        if (possible_k_prime.size() == 1) {
            // If only one k' matches c0, Vasya already knows k. He wins.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal p.
        // For a fixed c0, Vasya wants to maximize the probability of winning.
        // This means choosing p such that the number of k' values that are uniquely determined
        // by (c0, t[p]) is maximized.
        // t[p] = s[(p + k_val) % n]
        char cp = s[(p_val + k_val) % n]; // This is the character Vasya would see at position p_val

        int max_unique_k_for_c0 = 0;

        // Iterate over all possible choices for p (0 to n-1)
        for (int p_val = 0; p_val < n; ++p_val) {
            std::map<char, std::vector<int>> k_primes_by_cp;
            for (int kp : possible_k_prime) {
                char char_at_p_for_kp = s[(p_val + kp) % n];
                k_primes_by_cp[char_at_p_for_kp].push_back(kp);
            }

            int current_unique_count = 0;
            for (auto const& [char_val, k_list] : k_primes_by_cp) {
                if (k_list.size() == 1) {
                    current_unique_count++;
                }
            }
            max_unique_k_for_c0 = std::max(max_unique_k_for_c0, current_unique_count);
        }

        total_win_prob += static_cast<double>(max_unique_k_for_c0) / possible_k_prime.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / n << std::endl;

    return 0;
}

