        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start = std::max(0, i);
        int block_end = std::min(n, i + k);

        for (int j = block_end - 1; j >= block_start; --j) {
            p[j] = current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

// Function to apply a single operation
int apply_op(int current_val, char op_char, int constant) {
    if (op_char == '&') {
        return current_val & constant;
    } else if (op_char == '|') {
        return current_val | constant;
    } else { // op_char == '^'
        return current_val ^ constant;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Track the effect of the operations on two specific inputs: 0 and 1023 (all 10 bits set)
    int val0 = 0;
    int val1023 = 1023; // 2^10 - 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int constant;
        std::cin >> op_char >> constant;
        val0 = apply_op(val0, op_char, constant);
        val1023 = apply_op(val1023, op_char, constant);
    }

    // Now, we need to find a short sequence of operations that transforms
    // an arbitrary input X into the same output as Petya's program.
    // This means we need to find operations that transform 0 to val0 and 1023 to val1023.

    // Let the new program be X' = (X & C_and) | C_or ^ C_xor
    // Or, more generally, we can think of it bit by bit.
    // For each bit position `b` (from 0 to 9):
    // Let `x_b` be the `b`-th bit of the input `X`.
    // Let `f_b(x_b)` be the `b`-th bit of the output `f(X)`.
    // We know `f_b(0)` (from `val0`) and `f_b(1)` (from `val1023`).
    //
    // Case 1: `f_b(0) = 0`, `f_b(1) = 0`
    //   The `b`-th output bit is always 0, regardless of `x_b`.
    //   This means `C_and` must have `b`-th bit 0.
    //   And `C_or` must have `b`-th bit 0.
    //   And `C_xor` must have `b`-th bit 0.
    //   Effectively, `X & (~(1<<b))` will set this bit to 0.
    //
    // Case 2: `f_b(0) = 0`, `f_b(1) = 1`
    //   The `b`-th output bit is `x_b`.
    //   This means `C_and` must have `b`-th bit 1.
    //   And `C_or` must have `b`-th bit 0.
    //   And `C_xor` must have `b`-th bit 0.
    //   Effectively, `X & (1<<b)` will keep this bit as `x_b`.
    //
    // Case 3: `f_b(0) = 1`, `f_b(1) = 0`
    //   The `b`-th output bit is `~x_b`.
    //   This means `C_and` must have `b`-th bit 1.
    //   And `C_or` must have `b`-th bit 0.
    //   And `C_xor` must have `b`-th bit 1.
    //   Effectively, `X ^ (1<<b)` will flip this bit.
    //
    // Case 4: `f_b(0) = 1`, `f_b(1) = 1`
    //   The `b`-th output bit is always 1, regardless of `x_b`.
    //   This means `C_and` can be 1.
    //   And `C_or` must have `b`-th bit 1.
    //   And `C_xor` must have `b`-th bit 0.
    //   Effectively, `X | (1<<b)` will set this bit to 1.

    // Let's construct the constants for a canonical form: (X & A) | B ^ C
    // This form can represent any bitwise function of X.
    //
    // For each bit `b`:
    // Let `bit0 = (val0 >> b) & 1`
    // Let `bit1 = (val1023 >> b) & 1`
    //
    // If `bit0 == 0` and `bit1 == 0`:
    //   Output bit is always 0. This means `A_b = 0`, `B_b = 0`, `C_b = 0`.
    //   (X & 0) | 0 ^ 0 = 0
    //
    // If `bit0 == 0` and `bit1 == 1`:
    //   Output bit is `x_b`. This means `A_b = 1`, `B_b = 0`, `C_b = 0`.
    //   (X & 1) | 0 ^ 0 = X
    //
    // If `bit0 == 1` and `bit1 == 0`:
    //   Output bit is `~x_b`. This means `A_b = 1`, `B_b = 0`, `C_b = 1`.
    //   (X & 1) | 0 ^ 1 = ~X
    //
    // If `bit0 == 1` and `bit1 == 1`:
    //   Output bit is always 1. This means `A_b = 1`, `B_b = 1`, `C_b = 0`.
    //   (X & 1) | 1 ^ 0 = 1
    //
    // Let's define the constants `A`, `B`, `C` for the form `(X & A) | B ^ C`.
    // `A` will be the mask for bits that depend on `X`.
    // `B` will be the mask for bits that are forced to 1.
    // `C` will be the mask for bits that are flipped.

    int A = 0; // Bits that pass through X
    int B = 0; // Bits that are forced to 1
    int C = 0; // Bits that are flipped (XORed with 1)

    for (int b = 0; b < 10; ++b) {
        int bit0 = (val0 >> b) & 1;
        int bit1 = (val1023 >> b) & 1;

        if (bit0 == 0 && bit1 == 0) {
            // Output bit is 0.
            // A_b = 0, B_b = 0, C_b = 0
            // (X & 0) | 0 ^ 0 = 0
        } else if (bit0 == 0 && bit1 == 1) {
            // Output bit is X_b.
            // A_b = 1, B_b = 0, C_b = 0
            // (X & 1) | 0 ^ 0 = X
            A |= (1 << b);
        } else if (bit0 == 1 && bit1 == 0) {
            // Output bit is ~X_b.
            // A_b = 1, B_b = 0, C_b = 1
            // (X & 1) | 0 ^ 1 = ~X
            A |= (1 << b);
            C |= (1 << b);
        } else { // bit0 == 1 && bit1 == 1
            // Output bit is 1.
            // A_b = 1, B_b = 1, C_b = 0
            // (X & 1) | 1 ^ 0 = 1
            A |= (1 << b);
            B |= (1 << b);
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // The order of operations matters.
    // A common canonical form is (X & A) | B ^ C.
    // This can be implemented as:
    // 1. X & A
    // 2. Result | B
    // 3. Result ^ C

    // If A is 1023 (all bits pass through), then the '& A' operation is redundant.
    // If B is 0, then the '| B' operation is redundant.
    // If C is 0, then the '^ C' operation is redundant.

    if (A != 1023) { // If A is not all ones, we need an AND operation
        result_ops.push_back({'&', A});
    }
    if (B != 0) { // If B is not zero, we need an OR operation
        result_ops.push_back({'|', B});
    }
    if (C != 0) { // If C is not zero, we need an XOR operation
        result_ops.push_back({'^', C});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        long long good_substrings_count = 0;

        // Iterate over all possible starting positions l
        for (int l = 0; l < n; ++l) {
            // If s[l] is '0', we can have very long substrings starting with '0'.
            // The value f(s_l...s_r) will be small.
            // The length r-l+1 can be large.
            // We need to check for small values of f(s_l...s_r).
            // The maximum length for which f(s_l...s_r) can be equal to r-l+1
            // is limited. If f(s_l...s_r) = K, then K must be at most 20 (approx)
            // for K to be equal to r-l+1, because 2^20 is large.
            // Specifically, if len = f(s_l...s_r), then len <= 2^len - 1.
            // For len >= 20, 2^len - 1 is much larger than len.
            // The maximum possible value for f(s_l...s_r) that can be equal to r-l+1
            // is around 20. For example, if len=20, f(s_l...s_r) could be 20.
            // If len=21, f(s_l...s_r) could be 21.
            // The maximum length of a substring we need to check explicitly for
            // f(s_l...s_r) = r-l+1 is about 20 + log2(N) where N is string length.
            // Since N <= 2e5, log2(N) is about 18. So max length is around 38.
            // Let's use a safe upper bound like 60 for the length of the binary string
            // we explicitly convert to decimal.
            // This is because if len > 60, then 2^len - 1 is huge, and f(s_l...s_r)
            // would be at most 2^len - 1.
            // The condition is len = f(s_l...s_r).
            // If s[l] is '1', then f(s_l...s_r) >= 2^(len-1).
            // So we need len >= 2^(len-1). This only holds for len=1.
            // For len=1, f(s_l) = 1. If s[l] = '1', then 1=1, good.
            // For len=2, f(s_l s_{l+1}) >= 2^1 = 2. If s_l='1', s_{l+1}='0', f=2. len=2. Good.
            // If s_l='1', s_{l+1}='1', f=3. len=2. Not good.
            // For len=3, f(s_l s_{l+1} s_{l+2}) >= 2^2 = 4. But len=3. Not good.
            // So if s[l] is '1', only len=1 and len=2 are possible.
            // For len=1, s[l]='1' is good.
            // For len=2, s[l]='1', s[l+1]='0' is good.
            // For len >= 3, if s[l]='1', then f(s_l...s_r) >= 2^(len-1).
            // Since 2^(len-1) > len for len >= 3, no good substrings start with '1' and have length >= 3.
            // So for s[l] = '1', we only need to check len=1 and len=2.

            // If s[l] is '0', then f(s_l...s_r) < 2^(len-1).
            // The value can be small.
            // We need to check for len = f(s_l...s_r).
            // The maximum possible value for f(s_l...s_r) is N.
            // So we need to check substrings of length up to N.
            // However, if len is large, say len > 60, then f(s_l...s_r) can be at most 2^60-1.
            // If len = f(s_l...s_r), then len must be <= 60.
            // So we only need to check substrings of length up to 60.
            // The maximum length of a substring we need to consider is limited.
            // Let's say max_len_check = 20 + log2(N) + some buffer.
            // For N=2e5, log2(N) approx 17.6. So 20+18 = 38. Let's use 60 as a safe upper bound.
            // This means we iterate r from l up to min(n-1, l + 60 - 1).

            long long current_val = 0;
            for (int r = l; r < n; ++r) {
                int len = r - l + 1;

                // Optimization: If s[l] is '1' and len >= 3, break.
                // Because f(1...) >= 2^(len-1), and 2^(len-1) > len for len >= 3.
                if (s[l] == '1' && len >= 3) {
                    break;
                }

                // Optimization: If len is too large, current_val will exceed len.
                // If current_val already exceeds len, and s[r] is '1', then current_val will only grow faster.
                // If current_val already exceeds len, and s[r] is '0', then current_val will double, still exceeding len.
                // So if current_val > len, we can break.
                // This is especially useful for '1' starting substrings.
                // For '0' starting substrings, current_val can be 0 for a long time.
                // The maximum possible value for len is N.
                // The maximum possible value for current_val is also N.
                // If len > 60, then current_val cannot be equal to len.
                // Because if current_val = len, then len must be representable by a 60-bit integer.
                // So we can limit the length of substrings we check explicitly.
                if (len > 60) { // A safe upper bound for len to avoid overflow and unnecessary checks
                    break;
                }

                current_val = (current_val << 1) | (s[r] - '0');

                if (current_val == len) {
                    good_substrings_count++;
                }
            }
        }
        std::cout << good_substrings_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>
