#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Convert jar types to +1 for strawberry, -1 for blueberry
    std::vector<int> b(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        b[i] = (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // P_left[k] = sum of b[0]...b[k-1]
    // P_left[0] = 0
    // P_left[k] = sum of b_i for jars 1 to k
    std::vector<int> p_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        p_left[i + 1] = p_left[i] + b[i];
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // P_right[k] = sum of b[2n-1]...b[2n-k]
    // P_right[0] = 0
    // P_right[k] = sum of b_i for jars 2n-k+1 to 2n
    std::vector<int> p_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        p_right[i + 1] = p_right[i] + b[2 * n - 1 - i];
    }

    // Map to store the minimum number of jars eaten from the left (L)
    // to achieve a certain difference sum (p_left[n] - p_left[L]).
    // Key: difference sum, Value: L
    std::map<int, int> left_diff_to_L;

    // Iterate through possible L values (jars eaten from left: 0 to n)
    // The remaining jars are from index L to 2n-1.
    // The sum of differences for remaining jars is (p_left[n] - p_left[L]) + (p_right[n] - p_right[R]).
    // We want this sum to be 0.
    // So, (p_left[n] - p_left[L]) = -(p_right[n] - p_right[R]).
    // Let current_left_sum = p_left[n] - p_left[L].
    // We need to find R such that -(p_right[n] - p_right[R]) = current_left_sum.
    // This means p_right[n] - p_right[R] = -current_left_sum.
    // Or p_right[R] = p_right[n] + current_left_sum.

    // The sum of differences for jars 1 to n is p_left[n].
    // If we eat L jars from the left, the sum of differences for remaining jars in the left half (jars L+1 to n) is p_left[n] - p_left[L].
    // We want to find the minimum L+R.
    // Let's re-evaluate the sums.
    // The initial total difference is sum(b[0]...b[2n-1]).
    // This is p_left[n] + p_right[n] (if p_right was defined as sum from n+1 to 2n).
    // Let's use a simpler definition:
    // `pref_sum[k]` = sum of `b[0]` through `b[k-1]`. `pref_sum[0] = 0`.
    // `suff_sum[k]` = sum of `b[2n-1]` through `b[2n-k]`. `suff_sum[0] = 0`.

    // The total difference of all 2n jars is `pref_sum[2n]`.
    // If we eat `L` jars from the left (jars `0` to `L-1`) and `R` jars from the right (jars `2n-R` to `2n-1`),
    // the remaining jars are `L` to `2n-R-1`.
    // The sum of differences for remaining jars is `pref_sum[2n-R] - pref_sum[L]`.
    // We want `pref_sum[2n-R] - pref_sum[L] = 0`, so `pref_sum[2n-R] = pref_sum[L]`.
    // We want to minimize `L+R`.

    // Let's use the original definition of p_left and p_right for clarity.
    // p_left[k] = sum of b[0]...b[k-1] (jars 1 to k)
    // p_right[k] = sum of b[2n-1]...b[2n-k] (jars 2n-k+1 to 2n)

    // The total difference of all 2n jars is `p_left[n] + p_right[n]`.
    // If we eat `L` jars from the left (jars 1 to L) and `R` jars from the right (jars 2n-R+1 to 2n),
    // the remaining jars are `L+1` to `2n-R`.
    // The sum of differences for jars `L+1` to `n` is `p_left[n] - p_left[L]`.
    // The sum of differences for jars `n+1` to `2n-R` is `p_right[n] - p_right[R]`.
    // The total sum of differences for remaining jars is `(p_left[n] - p_left[L]) + (p_right[n] - p_right[R])`.
    // We want this to be 0.
    // So, `p_left[n] - p_left[L] = -(p_right[n] - p_right[R])`.
    // Let `target_diff = p_left[n] - p_left[L]`.
    // We need to find `R` such that `p_right[n] - p_right[R] = -target_diff`.
    // This means `p_right[R] = p_right[n] + target_diff`.

    // Store the minimum `L` for each possible `p_left[L]` value.
    // `p_left[L]` is the sum of differences for jars 1 to L.
    // `L` is the number of jars eaten from the left.
    std::map<int, int> diff_to_L;
    for (int L = 0; L <= n; ++L) {
        int current_diff = p_left[L];
        if (diff_to_L.find(current_diff) == diff_to_L.end()) {
            diff_to_L[current_diff] = L;
        } else {
            diff_to_L[current_diff] = std::min(diff_to_L[current_diff], L);
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through possible `R` values (jars eaten from right: 0 to n)
    // `p_right[R]` is the sum of differences for jars 2n-R+1 to 2n.
    // `R` is the number of jars eaten from the right.
    for (int R = 0; R <= n; ++R) {
        int current_diff_right_eaten = p_right[R];
        // The total difference of all jars is `p_left[n] + p_right[n]`.
        // If we eat `L` jars from left and `R` jars from right,
        // the remaining jars have a total difference of `(p_left[n] - p_left[L]) + (p_right[n] - p_right[R])`.
        // We want this to be 0.
        // So, `p_left[n] - p_left[L] = -(p_right[n] - p_right[R])`.
        // `p_left[L] = p_left[n] + (p_right[n] - p_right[R])`.
        // `p_left[L] = (p_left[n] + p_right[n]) - p_right[R]`.

        int target_p_left_L = (p_left[n] + p_right[n]) - current_diff_right_eaten;

        if (diff_to_L.count(target_p_left_L)) {
            int L = diff_to_L[target_p_left_L];
            min_jars_eaten = std::min(min_jars_eaten, L + R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long m;
    std::cin >> n >> m;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Max possible operations is m-1 (e.g., change 0 to m-1)
    long long ans = m - 1; // Initialize with a large enough value

    while (low <= high) {
        long long mid = low + (high - low) / 2; // Current number of operations to check

        bool possible = true;
        long long prev_val = 0; // The minimum possible value for a[i-1] after operations

        for (int i = 0; i < n; ++i) {
            long long current_a = a[i];
            long long target_val; // The value a[i] must be at least

            // Case 1: current_a + mid >= prev_val
            // This means we can potentially make a[i] equal to prev_val or greater
            // by incrementing it at most `mid` times.
            // The smallest value a[i] can take is current_a.
            // The largest value a[i] can take is (current_a + mid) % m.
            // If current_a <= prev_val, we need to increment a[i] to at least prev_val.
            // This requires (prev_val - current_a) increments.
            // If (prev_val - current_a) <= mid, then we can achieve prev_val.
            // So, target_val for a[i] becomes prev_val.
            if (current_a <= prev_val) {
                if (current_a + mid >= prev_val) {
                    target_val = prev_val;
                } else {
                    // Cannot make a[i] >= prev_val even with mid increments.
                    // Example: a[i]=0, prev_val=5, mid=3. (0+3=3 < 5)
                    possible = false;
                    break;
                }
            }
            // Case 2: current_a > prev_val
            // We need a[i] to be at least prev_val.
            // We have two options for a[i]:
            // Option A: a[i] remains current_a. This is valid if current_a >= prev_val.
            // Option B: a[i] becomes (current_a + k) % m for some 1 <= k <= mid.
            // This means a[i] "wraps around".
            // If we don't wrap around, the smallest value a[i] can take is current_a.
            // If we wrap around, the smallest value a[i] can take is 0.
            // The largest value a[i] can take is (current_a + mid) % m.
            else { // current_a > prev_val
                // If current_a + mid < m, then no wrap-around is possible to reach a value smaller than current_a.
                // The smallest value a[i] can take is current_a.
                // Since current_a > prev_val, this is fine.
                // So, target_val for a[i] becomes current_a.
                if (current_a + mid < m) {
                    target_val = current_a;
                } else { // current_a + mid >= m, wrap-around is possible.
                    // This means we can potentially make a[i] smaller than current_a (by wrapping around).
                    // The values a[i] can take are in [current_a, m-1] U [0, (current_a+mid)%m].
                    // We need a[i] to be at least prev_val.
                    // If prev_val is in [0, (current_a+mid)%m], we can choose prev_val.
                    // Otherwise, we must choose current_a (since current_a > prev_val).
                    if (prev_val <= (current_a + mid) % m) {
                        target_val = prev_val;
                    } else {
                        target_val = current_a;
                    }
                }
            }
            prev_val = target_val;
        }

        if (possible) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones_pos;
    std::vector<int> right_zeros_pos;

    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            left_ones_pos.push_back(i);
        } else {
            right_zeros_pos.push_back(i);
        }
    }

    if (left_ones_pos.empty() || right_zeros_pos.empty()) { // All 0s or all 1s
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n), R(n);

    // Calculate L_i: minimum k such that a_k = 1 for k >= i
    int current_one_idx = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_one_idx = i;
        }
        L[i] = current_one_idx;
    }

    // Calculate R_i: maximum k such that a_k = 0 for k <= i
    int current_zero_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            current_zero_idx = i;
        }
        R[i] = current_zero_idx;
    }

    int max_k = 0;
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 1 && a[i+1] == 0) {
            // Find the first 1 at or after i+1 (L[i+1])
            // Find the last 0 at or before i (R[i])
            // If L[i+1] is -1, it means no 1s after i, so this 10 pair is at the end of a 1-block.
            // If R[i] is -1, it means no 0s before i+1, so this 10 pair is at the start of a 0-block.

            // The actual indices for the 1-block and 0-block are i and i+1.
            // We need to find the extent of the 1-block ending at i and 0-block starting at i+1.

            // Find the leftmost 1 in the current 1-block
            int left_boundary_1 = i;
            while (left_boundary_1 > 0 && a[left_boundary_1 - 1] == 1) {
                left_boundary_1--;
            }

            // Find the rightmost 0 in the current 0-block
            int right_boundary_0 = i + 1;
            while (right_boundary_0 < n - 1 && a[right_boundary_0 + 1] == 0) {
                right_boundary_0++;
            }

            int len_1_block = i - left_boundary_1 + 1;
            int len_0_block = right_boundary_0 - (i + 1) + 1;

            max_k = std::max(max_k, std::min(len_1_block, len_0_block));
        }
    }

    std::cout << max_k << "\n";

    std::vector<int> result_a = a;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) { // This is a 1
            // Find the rightmost 0 to its right (R[i])
            // If R[i] is -1, it means no 0s to its right, so it's part of a block of 1s at the end.
            // If R[i] is valid, calculate distance to it.
            if (R[i] != -1) {
                if (R[i] - i < max_k) {
                    result_a[i] = 0;
                }
            }
        } else { // This is a 0
            // Find the leftmost 1 to its left (L[i])
            // If L[i] is -1, it means no 1s to its left, so it's part of a block of 0s at the beginning.
            // If L[i] is valid, calculate distance to it.
            if (L[i] != -1) {
                if (i - L[i] < max_k) {
                    result_a[i] = 1;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <vector>

// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // Calculate parity of string b
    int parity_b = calculate_parity(b);

    // If parity_a is 0, it means string a has an even number of '1's.
    // We can append '0's indefinitely.
    // The maximum number of '1's we can effectively have in a string derived from 'a'
    // without appending '1's is its current count.
    // If parity_a is 1, it means string a has an odd number of '1's.
    // We can append '1' once, then '0's indefinitely.
    // This effectively means we can increase the '1' count by 1 if parity_a is 1.
    // So, the maximum number of '1's we can achieve in a string derived from 'a'
    // (before any truncations) is `ones_in_a` if `parity_a` is 0,
    // and `ones_in_a + 1` if `parity_a` is 1.
    // This is equivalent to `ones_in_a + parity_a`.

    int max_ones_a = 0;
    for (char c : a) {
        if (c == '1') {
            max_ones_a++;
        }
    }
    max_ones_a += parity_a; // This is the maximum number of '1's we can have in a string
                            // that can be formed by 'a' and appending at most one '1' (if parity_a is 1)
                            // and then any number of '0's.

    int ones_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_b++;
        }
    }

    // Condition 1: The number of '1's in b must be less than or equal to the maximum '1's we can generate from a.
    // Condition 2: The length of b must be less than or equal to the maximum length we can generate from a.
    // The maximum length we can generate from a is effectively infinite, as we can always append '0's.
    // However, we only care if we can generate a string of length |b| that has the correct number of '1's.
    // If we can generate `max_ones_a` '1's, and `max_ones_a >= ones_b`, then we can always form a string
    // of length `|b|` with `ones_b` '1's.
    // This is because we can always append '0's to reach the desired length, and '0's don't change the '1' count.
    // The only constraint is that `ones_b` must be achievable.

    if (ones_b <= max_ones_a) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: a_1 in S1, a_2, ..., a_n in S2.
    // min_f:
    //   - a_1 + a_2 + h (a_1 in S1, a_2 in S2)
    //   - a_2 + a_3 (a_2, a_3 in S2)
    //   min_f = min(a_1 + a_2 + h, a_2 + a_3)
    // max_f:
    //   - a_1 + a_n + h (a_1 in S1, a_n in S2)
    //   - a_{n-1} + a_n (a_{n-1}, a_n in S2)
    //   max_f = max(a_1 + a_n + h, a_{n-1} + a_n)
    // goodness = max_f - min_f
    long long min_f2 = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
    long long max_f2 = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 2].value + elements[n - 1].value);
    long long goodness2 = max_f2 - min_f2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Case 3: a_1, ..., a_{n-1} in S1, a_n in S2.
    // min_f:
    //   - a_1 + a_2 (a_1, a_2 in S1)
    //   - a_1 + a_n + h (a_1 in S1, a_n in S2)
    //   min_f = min(a_1 + a_2, a_1 + a_n + h)
    // max_f:
    //   - a_{n-2} + a_{n-1} (a_{n-2}, a_{n-1} in S1)
    //   - a_{n-1} + a_n + h (a_{n-1} in S1, a_n in S2)
    //   max_f = max(a_{n-2} + a_{n-1}, a_{n-1} + a_n + h)
    // goodness = max_f - min_f
    long long min_f3 = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n - 1].value + h);
    long long max_f3 = std::max(elements[n - 3].value + elements[n - 2].value, elements[n - 2].value + elements[n - 1].value + h);
    if (n == 2) { // Special handling for n=2, a_{n-3} and a_{n-2} are not well-defined.
        // Only one pair (a_1, a_2).
        // If a_1 in S1, a_2 in S2: f = a_1 + a_2 + h. min_f = max_f = a_1 + a_2 + h. goodness = 0.
        // This is covered by goodness2.
        // For n=2, Case 3 is identical to Case 2 (just swap S1 and S2 labels).
        // So we can skip Case 3 for n=2 or ensure it's handled correctly.
        // The logic for n=2:
        // min_f3 = min(a_0+a_1, a_0+a_1+h) = a_0+a_1
        // max_f3 = max(a_0+a_1, a_0+a_1+h) = a_0+a_1+h
        // goodness3 = h
        // This is correct.
    }
    long long goodness3 = max_f3 - min_f3;
    std::vector<int> partition3(n);
    for (int i = 0; i < n - 1; ++i) {
        partition3[elements[i].original_index] = 1;
    }
    partition3[elements[n - 1].original_index] = 2;

    long long min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        best_partition = partition2;
    }
    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        best_partition = partition3;
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string coloring(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        int last1 = -1; // Last digit placed in color 1
        int last2 = -1; // Last digit placed in color 2
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < pivot_digit) {
                // Must be color 1
                if (d[i] < last1) {
                    possible_with_pivot = false;
                    break;
                }
                coloring[i] = '1';
                last1 = d[i];
            } else if (d[i] > pivot_digit) {
                // Must be color 2
                if (d[i] < last2) {
                    possible_with_pivot = false;
                    break;
                }
                coloring[i] = '2';
                last2 = d[i];
            } else { // d[i] == pivot_digit
                // Can be color 1 or color 2
                // Prefer color 2 if possible, to keep last1 small
                if (d[i] >= last2) { // Can place in color 2
                    coloring[i] = '2';
                    last2 = d[i];
                } else if (d[i] >= last1) { // Must place in color 1
                    coloring[i] = '1';
                    last1 = d[i];
                } else { // Cannot place in either
                    possible_with_pivot = false;
                    break;
                }
            }
        }

        if (possible_with_pivot) {
            found_solution = true;
            std::cout << coloring << "\n";
            break;
        }
    }

    if (!found_solution) {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i is now being cured

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply current_v_cry reduction
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply total_d_cry_from_leaving reduction
            children[j].p -= total_d_cry_from_leaving;

            // Check for chain reaction
            if (children[j].p < 0) {
                if (children[j].in_line) { // Ensure child hasn't already left in this step
                    children[j].in_line = false;
                    total_d_cry_from_leaving += children[j].d;
                }
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> min_val_for_idx(n, LLONG_MAX); // Stores max_val_for_idx[j] = min(m_k - current_delta_j)

    // Initialize min_val_for_idx based on type 2 operations
    // For each type 2 op (l, r, m), we know that for any j in [l, r],
    // A_j + current_delta_j <= m.
    // This means A_j <= m - current_delta_j.
    // We want to find the tightest upper bound for A_j.
    // So, for each j, A_j <= min(m_k - current_delta_j for all type 2 ops k covering j).
    // We can compute current_delta_j by iterating through operations.

    std::vector<long long> current_delta(n, 0); // current_delta[j] = sum of d's applied to j so far
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_val_for_idx[j] = std::min(min_val_for_idx[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If min_val_for_idx[j] is still LLONG_MAX, it means index j was never constrained by a type 2 operation.
    // We can set its initial value to 0 (or any value within bounds).
    // The problem states |a_i| <= 10^9. 0 is within this bound.
    for (int j = 0; j < n; ++j) {
        if (min_val_for_idx[j] == LLONG_MAX) {
            initial_a[j] = 0;
        } else {
            initial_a[j] = min_val_for_idx[j];
        }
    }

    // Verify the solution
    std::vector<long long> a = initial_a;
    current_delta.assign(n, 0); // Reset current_delta for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y and intermediate sums to prevent overflow
// as a_i can be up to 10^9 and n up to 2*10^5, so y can be n * 10^9 = 2*10^14.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_val[0] is unused, a_val[1] will be set by the loop, a_val[2]...a_val[n-1] are read.
    // The problem statement uses 1-based indexing for a_x, so we'll use a vector of size n+1.
    std::vector<long long> a_val(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_val[i];
    }

    // dp_x[i] stores the final x value if we start at x=i and take one "full step" (x+a[x], then x-a[x])
    // dp_y[i] stores the total y added during that one "full step"
    // dp_x[i] and dp_y[i] are for the state (x, y) after one full step, starting from x=i.
    // The value a[i] is used for the first part of the step.
    std::vector<long long> dp_x(n + 1);
    std::vector<long long> dp_y(n + 1);
    // visited[i] is used to detect cycles during DP calculation.
    // 0: not visited, 1: visiting (in current recursion stack), 2: visited and computed
    std::vector<int> visited(n + 1, 0);

    // Function to compute dp_x[curr_x] and dp_y[curr_x]
    // Returns true if computation finishes (terminates or finds a cycle), false if it's part of a cycle
    bool compute_dp(int curr_x) {
        if (curr_x <= 0 || curr_x > n) { // Base case: terminates
            return true;
        }
        if (visited[curr_x] == 2) { // Already computed
            return true;
        }
        if (visited[curr_x] == 1) { // Cycle detected
            return false;
        }

        visited[curr_x] = 1; // Mark as visiting

        long long val_a_curr_x = a_val[curr_x];

        // Step 1: x_temp = curr_x + val_a_curr_x, y_added_step1 = val_a_curr_x
        long long next_x_after_step1 = curr_x + val_a_curr_x;
        long long y_added_step1 = val_a_curr_x;

        // Check termination after step 1
        if (next_x_after_step1 <= 0 || next_x_after_step1 > n) {
            dp_x[curr_x] = next_x_after_step1;
            dp_y[curr_x] = y_added_step1;
            visited[curr_x] = 2;
            return true;
        }

        // Step 2: y_added_step2 = a_val[next_x_after_step1], x_final = next_x_after_step1 - a_val[next_x_after_step1]
        long long val_a_next_x_after_step1 = a_val[next_x_after_step1];
        long long y_added_step2 = val_a_next_x_after_step1;
        long long final_x_after_one_full_step = next_x_after_step1 - val_a_next_x_after_step1;
        long long total_y_added_in_one_full_step = y_added_step1 + y_added_step2;

        // Now we need to find the result of starting from final_x_after_one_full_step
        // This is where the DP/recursion comes in.
        if (!compute_dp(final_x_after_one_full_step)) { // If the subsequent path leads to a cycle
            // This curr_x is also part of a cycle
            visited[curr_x] = 1; // Keep it as 1 to indicate it's part of a cycle
            return false;
        }

        // If compute_dp(final_x_after_one_full_step) returned true, it means it either terminated
        // or was already computed.
        dp_x[curr_x] = dp_x[final_x_after_one_full_step];
        dp_y[curr_x] = total_y_added_in_one_full_step + dp_y[final_x_after_one_full_step];
        visited[curr_x] = 2; // Mark as computed
        return true;
    }

    // Call compute_dp for all possible starting points (1 to n)
    // This populates dp_x and dp_y for all states.
    for (int i = 1; i <= n; ++i) {
        compute_dp(i);
    }

    // Now, for each i from 1 to n-1, set a_val[1] = i and run the program.
    for (int i = 1; i < n; ++i) {
        a_val[1] = i; // Set a_1 for the current run

        long long current_x = 1;
        long long current_y = 0;

        // First step (x+a[x], y+a[x])
        long long val_a_current_x = a_val[current_x];
        current_x += val_a_current_x;
        current_y += val_a_current_x;

        // Check termination after first step
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now current_x is the starting point for the "full steps" (x+a[x], then x-a[x])
        // We use the precomputed DP values.
        if (visited[current_x] == 1) { // If current_x leads to a cycle
            std::cout << -1 << "\n";
        } else { // If current_x leads to termination
            current_y += dp_y[current_x];
            std::cout << current_y << "\n";
        }
    }

    return 0;
}

