int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k; // k can be up to 10^4, sum of k up to 10^4.
                     // a_i can be up to k.
                     // The number of operations can be (k-a_j)/a_min.
                     // If a_min is 1, and k is 10^4, a_j is 1, then 10^4-1 operations.
                     // Sum of n over test cases is 1000.
                     // Sum of k over test cases is 10^4.
                     // Max operations for one test case: (k-1)/1 * (n-1) ~ 10^4 * 10^3 = 10^7.
                     // This fits in int.
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        int min_idx = -1;

        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_operations = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself
            }
            // For each other pile a[i], we can add min_val to it
            // as many times as possible without exceeding k.
            // Let current_val = a[i]. We want current_val + x * min_val <= k.
            // x * min_val <= k - current_val
            // x <= (k - current_val) / min_val
            // Since x must be an integer, x = floor((k - current_val) / min_val)
            if (min_val > 0) { // To avoid division by zero, though problem constraints say a_i >= 1
                total_operations += (k - a[i]) / min_val;
            }
        }
        std::cout << total_operations << "\n";
    }
    return 0;
}

