            // Can use +2 or -2. One press.
            presses += 1;
        } else if (diff == 3) {
            // Can use +1, +1, +1 (3 presses)
            // Can use +2, +1 (2 presses)
            // Can use +5, -2 (2 presses)
            presses += 2;
        } else if (diff == 4) {
            // Can use +1, +1, +1, +1 (4 presses)
            // Can use +2, +2 (2 presses)
