        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <ranges>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n == 2) {
        // For n=2, the only other permutation is the reverse.
        // p = [p1, p2], F(p) = [p1+p2]
        // p' = [p2, p1], F(p') = [p2+p1]
        // They are always equal.
        std::cout << p[1] << " " << p[0] << std::endl;
        return;
    }

    // For n > 2, reversing the permutation p to get p_rev
    // always yields a permutation with the same fingerprint.
    // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
    // F(p_rev) = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
    // Since addition is commutative, the set of sums is the same.
    // We need to ensure p_rev is different from p.
    // p_rev is different from p unless p is a palindrome.
    // A permutation p is a palindrome if p_i = p_{n-1-i} for all i.
    // For example, [1,2,1] is not a permutation.
    // For a permutation of distinct elements from 1 to n,
    // p_i = p_{n-1-i} implies p_i is unique.
    // If n is odd, the middle element p_{n/2} must be equal to itself.
    // If n is even, there is no middle element.
    // A permutation cannot be a palindrome unless n=1 (which is not allowed here)
    // or if it's a trivial case like [1] or [1,2,1] (not a permutation).
    // For n >= 2, a permutation of distinct elements from 1 to n cannot be a palindrome.
    // Example: [1,2,3] reversed is [3,2,1]. Different.
    // Example: [1,3,2] reversed is [2,3,1]. Different.
    // The only way p_i = p_{n-1-i} for all i is if the set of elements {p_i}
    // is symmetric, but since all elements are distinct, this is impossible
    // unless n=1.
    // For example, if p_1 = p_n, then since p is a permutation, p_1 and p_n must be distinct.
    // This means p_1 != p_n, so p cannot be a palindrome.
    // Therefore, reversing any permutation of length n >= 2 always produces a different permutation.

    // So, simply reverse the given permutation.
    std::ranges::reverse(p);
    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

