        int max_haybales_to_move_from_this_pile = days_remaining / cost_per_haybale;

        int haybales_to_move = std::min(haybales_in_pile, max_haybales_to_move_from_this_pile);

        current_a1 += haybales_to_move;
        days_remaining -= haybales_to_move * cost_per_haybale;

        if (days_remaining <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

