#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The state of has_pos_one and has_neg_one is for elements *before* i.
            // So, if a[i] was 1 or -1, it contributes to the flags for elements j < i.
            // But we are iterating backwards, so the flags should reflect elements 0 to i-1.
            // The flags are updated *after* checking a[i] vs b[i].
            // This means has_pos_one and has_neg_one correctly reflect if there's a 1 or -1
            // at an index k < i.
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. This requires a '1' at some index k < i.
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires a '-1' at some index k < i.
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update flags for the next iteration (i-1).
        // If a[i] was 1 or -1, it contributes to the flags for elements to its right.
        // Since we are iterating backwards, we update the flags *after* checking a[i] vs b[i].
        // This ensures that has_pos_one and has_neg_one correctly reflect the presence of 1s and -1s
        // in the prefix a[0...i-1] when we process index i-1.
        if (a[i] == 1) {
            has_pos_one = true; // This is redundant if we iterate backwards and update after check.
                                // The flags should represent elements *before* current index i.
                                // So, when processing index i, has_pos_one means there's a 1 in a[0...i-1].
                                // This means the flags should be updated *before* the loop or *after* the loop for the next iteration.
                                // Let's re-evaluate the flag logic.
                                //
                                // Correct logic:
                                // When checking a[i], we need to know if there's a 1 or -1 in a[0...i-1].
                                // So, we iterate from left to right.
                                //
                                // Let's restart the loop logic.
        }
    }

    // Re-evaluating the loop direction and flag updates.
    // We need to check from left to right because a[i] can only be modified by a[k] where k < i.
    // The values of a[k] for k < i are fixed and cannot be changed by operations involving indices > k.
    // So, when we consider a[i], its initial value is a[i].
    // To change a[i] to b[i], we need to add some multiple of 1s and -1s from a[0...i-1].
    //
    // For a[0]: It cannot be changed by any operation because there is no k < 0.
    // So, a[0] must be equal to b[0].
    //
    // For a[i] (i > 0):
    // If a[i] < b[i], we need to add (b[i] - a[i]) to a[i]. This requires (b[i] - a[i]) > 0.
    // This means we need to add 1s. So, there must be at least one '1' in a[0...i-1].
    // If a[i] > b[i], we need to add (b[i] - a[i]) to a[i]. This requires (b[i] - a[i]) < 0.
    // This means we need to add -1s. So, there must be at least one '-1' in a[0...i-1].
    // If a[i] == b[i], no operation is strictly necessary for this element.

    has_pos_one = false; // True if there's a 1 in a[0...i-1]
    has_neg_one = false; // True if there's a -1 in a[0...i-1]
    possible = true;

    for (int i = 0; i < n; ++i) {
        if (i == 0) {
            if (a[0] != b[0]) {
                possible = false;
                break;
            }
        } else { // i > 0
            if (a[i] < b[i]) {
                if (!has_pos_one) {
                    possible = false;
                    break;
                }
            } else if (a[i] > b[i]) {
                if (!has_neg_one) {
                    possible = false;
                    break;
                }
            }
            // If a[i] == b[i], no special condition needed from previous elements.
        }

        // Update flags for the next iteration (i+1).
        // These flags will represent elements in a[0...i].
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

