    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, starting from the second to last element
    // (index n-2) down to the first element (index 0).
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            // If the current price is greater than the minimum price found so far
            // to its right, then it's a bad price.
            bad_prices_count++;
        } else {
            // If the current price is not greater than min_suffix_price,
            // it means a[i] <= min_suffix_price.
            // This a[i] could potentially be the new minimum for elements to its left.
            min_suffix_price = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

