void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();

    int max_gap = 0;
    int last_R_pos = 0; // Represents the last position from which a right jump was possible.
                        // Initially, the frog is at 0, and can jump right.
                        // So, the "last R" is effectively at 0.

    for (int i = 0; i < n; ++i) {
        if (s[i] == 'R') {
            // If we encounter an 'R' at index i (which corresponds to cell i+1),
            // it means the frog can jump right from cell i+1.
            // The gap is between the current cell (i+1) and the last cell
            // from which a right jump was possible (last_R_pos).
            // The length of this gap is (i+1) - last_R_pos.
            max_gap = std::max(max_gap, (i + 1) - last_R_pos);
            last_R_pos = i + 1; // Update last_R_pos to the current cell (i+1)
        }
    }

    // After iterating through the string, we need to consider the gap
    // from the last 'R' position to the target cell n+1.
    // The length of this final gap is (n + 1) - last_R_pos.
    max_gap = std::max(max_gap, (n + 1) - last_R_pos);

    std::cout << max_gap << std::endl;
}

