#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) {
                max_val_for_i = std::max(max_val_for_i, a[i][j]);
            }
        }
        p[i] = max_val_for_i;
    }

    // Check if any p[i] is n-1 and no p[j] is n.
    // This happens if the original permutation contained n, but it was always
    // paired with a smaller number, so min(n, p_j) = p_j.
    // In this case, the maximum value observed for any p_i would be n-1.
    // If all p[i] values calculated are less than n, it means the true maximum
    // value 'n' was never the minimum in any pair.
    // This implies that the element corresponding to 'n' in the original permutation
    // would have its p[k] value calculated as max(p_j for j!=k) which would be n-1.
    // So, if all calculated p[i] are <= n-1, then one of them must be n.
    // The problem guarantees a solution exists, and the permutation is 1 to n.
    // If max_val_for_i is n-1 for some i, and no other p[j] is n, then p[i] must be n.
    // This is because the values 1 to n are used. If n is present, it must be
    // assigned to some p[k]. If p[k] = n, then for any j != k, a[k][j] = min(n, p[j]) = p[j].
    // So, max_{j!=k} a[k][j] = max_{j!=k} p[j].
    // If the original permutation was {1, 2, ..., n-1, n}, and n is at index k,
    // then max_{j!=k} p[j] would be n-1.
    // So, p[k] would be calculated as n-1.
    // If we find that all calculated p[i] are <= n-1, it means the true 'n'
    // was never the minimum in any pair. In this case, one of the elements
    // that was calculated as n-1 must actually be n.
    // We can just pick any one of them and set it to n.
    // Since the problem guarantees a solution, and the values are 1 to n,
    // if the maximum value found among all p[i] is n-1, it means one of them
    // must be n. We can just increment one of the n-1 values to n.
    // It doesn't matter which one, as long as it's one of the elements that
    // would have been n-1 if n was present.
    // A simpler way to think about it: the values 1 to n must be present.
    // If after computing max_val_for_i for all i, the maximum value among these
    // computed p[i] is less than n, it means the true 'n' was never the minimum.
    // In this case, one of the computed p[i] values (which would be n-1)
    // must actually be n. We can just find the maximum value among the computed p[i]s
    // and increment it by 1. This will make it n.
    // Example: n=2, p={1,2}. a[0][1]=1, a[1][0]=1.
    // p[0] = max(a[0][1]) = 1.
    // p[1] = max(a[1][0]) = 1.
    // Max of {p[0], p[1]} is 1. Since n=2, we increment one of them to 2.
    // Say p[0]=2, p[1]=1. Output: 2 1. Correct.
    // Example: n=5, p={2,5,4,1,3}.
    // p[0]=max(2,2,1,2)=2 (for p_0=2)
    // p[1]=max(2,4,1,3)=4 (for p_1=5)
    // p[2]=max(2,4,1,3)=4 (for p_2=4)
    // p[3]=max(1,1,1,1)=1 (for p_3=1)
    // p[4]=max(2,3,3,1)=3 (for p_4=3)
    // Max of {2,4,4,1,3} is 4. Since n=5, we increment one of the 4s to 5.
    // Say p[1]=5. Then p={2,5,4,1,3}. Output: 2 5 4 1 3. Correct.

    int max_p_val = 0;
    for (int val : p) {
        max_p_val = std::max(max_p_val, val);
    }

    if (max_p_val < n) {
        // This means the true 'n' was never the minimum in any pair.
        // So, the element corresponding to 'n' in the original permutation
        // would have its p[k] value calculated as max(p_j for j!=k) which would be n-1.
        // We need to find one such element and set it to n.
        // Since max_p_val is n-1, we can just find any element that has this value
        // and increment it.
        for (int i = 0; i < n; ++i) {
            if (p[i] == max_p_val) {
                p[i] = n;
                break; // Only one element needs to be changed
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The total number of students available (c + m + x) / 3
        // 2. The number of coders available, as each team needs at least one coder.
        // 3. The number of mathematicians available, as each team needs at least one mathematician.
        // So, an initial upper bound is min(c, m, (c + m + x) / 3).
        // Let's call this 'low' for binary search.
        // The actual answer can be anywhere from 0 to this initial upper bound.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as a minimum.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and 'x' no-specialization students.
            // These remaining students must fill the remaining 'mid' * 1 slots (3 members per team - 1 coder - 1 mathematician).
            // So, the total number of remaining students must be at least 'mid'.

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                // It's possible to form 'mid' teams. Try for more.
                ans = mid;
                low = mid + 1;
            } else {
                // Not possible to form 'mid' teams. Try for fewer.
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

