int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of (h/2) / n = h / (2n).

    // Consider a cut at distance x from the apex.
    // By similar triangles, if the original triangle has height H and base B,
    // a smaller triangle formed by a cut at distance x from the apex will have
    // height x and base b_x, such that x/b_x = H/B.
    // In our case, H=h, B=1, so x/b_x = h/1 => b_x = x/h.
    // The area of this smaller triangle is (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want to make n-1 cuts. Let the k-th cut (from the apex) be at distance x_k.
    // The area of the triangle formed by the k-th cut and the apex should be k times
    // the area of a single piece.
    // So, x_k^2 / (2h) = k * (h / (2n)).
    // x_k^2 = k * h^2 / n.
    // x_k = sqrt(k * h^2 / n) = h * sqrt(k / n).

    // We need to find x_1, x_2, ..., x_{n-1}.
    for (int k = 1; k < n; ++k) {
        double x_k = h * std::sqrt(static_cast<double>(k) / n);
        std::cout << std::fixed << std::setprecision(12) << x_k << (k == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

