int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        // If l == r, we need to find a divisor of l (excluding 1).
        // The smallest prime factor is always a valid answer.
        // Since l >= 2, l always has a divisor other than 1.
        // If l is prime, l itself is the only divisor > 1.
        // If l is composite, 2 is a possible divisor if l is even.
        // In any case, 2 is a good candidate if l is even.
        // If l is odd, the smallest prime factor is >= 3.
        // However, the problem asks for *any* integer that appears maximum number of times.
        // If l is prime, l is the only answer.
        // If l is composite, any prime factor of l is an answer.
        // The problem statement says "If there are multiple answers, print any of them."
        // For l=r, any divisor of l (other than 1) is equally frequent (1 time).
        // The smallest divisor (other than 1) is the smallest prime factor.
        // For example, if l=r=19, answer is 19. If l=r=20, answer is 2.
        // The simplest is to just return 2 if l is even, otherwise l itself.
        // But the problem implies we should find the one that appears most.
        // If l=r, all divisors appear exactly once. So any divisor is fine.
        // The problem statement implies that 2 is a good default.
        // For l=r=19, 2 is not a divisor.
        // For l=r=20, 2 is a divisor.
