#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;
    int current_balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_needed > 0) {
                result += '(';
                open_needed--;
                current_balance++;
            }
        } else { // c == ')'
            if (close_needed > 0 && current_balance > 0) {
                result += ')';
                close_needed--;
                current_balance--;
            }
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available number and the largest available number
    // from the range [1, k+1].
    // Example: k=4
    // p[0] = 1 (left)
    // p[1] = 5 (right) -> diff = 4
    // p[2] = 2 (left) -> diff = 3
    // p[3] = 4 (right) -> diff = 2
    // p[4] = 3 (left) -> diff = 1
    // The numbers used are 1, 2, 3, 4, 5.
    // The differences are 4, 3, 2, 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smallest available)
            p[i] = left;
            left++;
        } else { // Odd index, take from right (largest available)
            p[i] = right;
            right--;
        }
    }

    // Fill the remaining n - (k+1) elements.
    // These elements should not introduce new distinct differences.
    // The simplest way is to continue with increasing numbers from where we left off.
    // 'left' now holds the next available number after 1, 2, ..., k+1 have been used.
    // For example, if k=4, numbers 1,2,3,4,5 are used. 'left' is 3, 'right' is 3.
    // The next number to use is 6.
    // The numbers used for the first k+1 elements are 1, ..., k+1.
    // So, 'left' will be (k+1)/2 + 1 if k is odd, or k/2 + 1 if k is even.
    // The numbers not yet used are k+2, k+3, ..., n.
    // We can append them in increasing order. This will only generate difference 1.
    // Since 1 is already among the k distinct differences, no new distinct differences are introduced.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This is equivalent to starting from k+2 and incrementing
                      // The numbers used are 1 to k+1 for the first part.
                      // The next number is k+2.
                      // So p[k+1] = k+2, p[k+2] = k+3, ..., p[n-1] = n.
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

