    // If no such `i` exists, the suffix `a[0...n-1]` is non-decreasing.
    int i = n - 2;
    while (i >= 0 && a[i] <= a[i+1]) {
        i--;
    }
    // After this loop, `a[i+1 ... n-1]` is non-decreasing.
    // `i` is now the index of the last element that breaks the non-decreasing suffix.
    // If `i < 0`, the entire array is non-decreasing.

    // Find the rightmost peak of the non-increasing suffix
    // This is the first index `j` from the right such that `a[j] < a[j+1]`
    // If no such `j` exists, the suffix `a[0...n-1]` is non-increasing.
    int j = i; // Start searching from `i` because elements to the right of `i` are already non-decreasing.
               // We are looking for the first element from the right that breaks the non-increasing property.
               // This means we are looking for `a[j] < a[j+1]`
    while (j >= 0 && a[j] >= a[j+1]) {
        j--;
    }
    // After this loop, `a[j+1 ... i+1]` is non-increasing.
    // `j` is now the index of the last element that breaks the non-increasing suffix.
    // If `j < 0`, the entire array is non-increasing.

    // The elements `a[0 ... j]` must be removed.
    // The length of the prefix to remove is `j + 1`.
    std::cout << j + 1 << std::endl;
}

