        }

        long long count = n / m; // Number of multiples of m up to n

        // Calculate the sum of last digits for one cycle (10 multiples)
        // The last digit of k*m is (k*m) % 10.
        // This sequence of last digits repeats every 10 terms.
        // E.g., for m=3: 3, 6, 9, 2, 5, 8, 1, 4, 7, 0, then 3, 6, ...
        long long sum_cycle = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_cycle += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_cycle;

        // Remaining terms after full cycles
        long long remaining_terms = count % 10;
        for (int i = 1; i <= remaining_terms; ++i) {
            total_sum += (static_cast<long long>(i) * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

