void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the subsegment is [1]. This is always possible.
    // The subsegment is p[pos[1]...pos[1]].
    result[0] = '1';

    // Initialize current min_idx and max_idx for the subsegment containing 1
    int min_idx = pos[1];
    int max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Expand the current subsegment [min_idx, max_idx] to include 'm'
        // The number 'm' must be at pos[m].
        // We need to update min_idx and max_idx to cover the range from 1 to m.
        // The new range will be [min(current_min_idx, pos[m]), max(current_max_idx, pos[m])]
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // Check if the current subsegment [min_idx, max_idx] is a permutation of 1...m
        // This means its length must be exactly m.
        // Length = max_idx - min_idx + 1
        if (max_idx - min_idx + 1 == m) {
            result[m - 1] = '1';
        } else {
            result[m - 1] = '0';
        }
    }

    std::cout << result << std::endl;
}

