int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int d_int;
        std::cin >> d_int;
        double d = static_cast<double>(d_int);

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For d >= 4, d^2 - 4d >= 0, so real solutions exist.
            // a = (d + sqrt(d^2 - 4d)) / 2
            // b = (d - sqrt(d^2 - 4d)) / 2
            // Or vice versa.
            // Since a and b are symmetric, we can pick one.
            // Let's pick a = (d + sqrt(d^2 - 4d)) / 2
            // Then b = d - a = d - (d + sqrt(d^2 - 4d)) / 2
            // b = (2d - d - sqrt(d^2 - 4d)) / 2
            // b = (d - sqrt(d^2 - 4d)) / 2

            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);
            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Check non-negativity (already guaranteed for d >= 4)
            // a = (d + sqrt(d^2 - 4d)) / 2. Since d >= 4, d^2 - 4d >= 0, so sqrt is real and non-negative.
            // d is non-negative, so a is non-negative.
            // b = (d - sqrt(d^2 - 4d)) / 2.
            // We need to ensure d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative for d >= 4, we can square both sides:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0. This is true for the given constraints.
            // So, both a and b are non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

