int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int b_ptr = 0; // Pointer for elements we are trying to place (from the sorted array)

    // Iterate through the sorted array 'a' using a_ptr.
    // For each a[a_ptr], we try to find the smallest b[b_ptr] such that b[b_ptr] > a[a_ptr].
    // Since both arrays are sorted, we can use two pointers.
    // a_ptr represents the current element from the original array (sorted) that we want to "beat".
    // b_ptr represents the current element from the available pool (also sorted) that we can use.
    for (int a_ptr = 0; a_ptr < n; ++a_ptr) {
        // While b_ptr is within bounds and the current element a[a_ptr] is not smaller than
        // or equal to the element a[b_ptr] (which means a[b_ptr] is not strictly greater than a[a_ptr]),
        // we advance b_ptr. We are looking for an element a[b_ptr] that is strictly greater.
        while (b_ptr < n && a[b_ptr] <= a[a_ptr]) {
            b_ptr++;
        }
        // If we found such an element (a[b_ptr] > a[a_ptr]), we use it.
        // This means we successfully placed an element from the permutation that is greater.
        // We increment count and advance b_ptr to consider the next available element for future matches.
        if (b_ptr < n) {
            count++;
            b_ptr++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate max_left_val[i] = maximum possible value for a_i'
    // such that a_1' < a_2' < ... < a_i'
    // This means a_i' must be at least i-1.
    // So, a_i' can be at most a_i, and at least i-1.
    // If a_i < i-1, then it's impossible to satisfy the condition for this i.
    // If a_i >= i-1, then a_i' can be any value from i-1 to a_i.
    // We are interested in the maximum possible value for a_i'
    // that allows the prefix to be strictly increasing.
    // max_left_val[i] = min(a[i], max_left_val[i-1] + 1) for i > 0
    // max_left_val[0] = a[0]
    // But we need a_i' >= i-1.
    // So, max_left_val[i] = min(a[i], max_left_val[i-1] + 1) if max_left_val[i-1] + 1 >= i-1
    // This is equivalent to max_left_val[i] = min(a[i], i-1) if we want the smallest possible values.
    // Let's rephrase:
    // For a_1' < a_2' < ... < a_k', we need a_i' >= i-1 for all i in [1, k].
    // This means a[i] must be at least i-1 for all i in [1, k].
    // If a[i] < i-1 for any i in [1, k], then this k is not possible.
    // So, we find the largest `left_reach` such that a[i] >= i for all i in [0, left_reach-1].
    // (using 0-indexed array, so a[i] >= i for a_1...a_{left_reach})
    int left_reach = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_reach++;
        } else {
            break;
        }
    }

    // Similarly, for a_k' > a_{k+1}' > ... > a_n', we need a_i' >= n-i for all i in [k, n].
    // (using 0-indexed array, so a[i] >= n-1-i for a_k...a_n)
    // If a[i] < n-1-i for any i in [k, n], then this k is not possible.
    // So, we find the largest `right_reach` such that a[i] >= n-1-i for all i in [n-right_reach, n-1].
    int right_reach = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_reach++;
        } else {
            break;
        }
    }

    // A peak k (1-indexed) means a_k' is the peak.
    // In 0-indexed, this is a_{k-1}'.
    // For this k-1 to be a valid peak, it must be reachable from the left and from the right.
    // The indices that can be a peak are from 0 to n-1.
    // An index `i` can be a peak if:
    // 1. It's part of the strictly increasing prefix: i < left_reach
    // 2. It's part of the strictly decreasing suffix: n-1-i < right_reach
    //    (or equivalently, i >= n - right_reach)
    // So, we need to find if there exists an index `i` such that `i < left_reach` AND `i >= n - right_reach`.
    // This is equivalent to checking if `left_reach + right_reach > n`.
    // If `left_reach + right_reach > n`, it means there is an overlap of indices that can be part of both increasing and decreasing sequences.
    // Any index `i` in this overlap region can be chosen as `k-1`.
    // For example, if `left_reach = 3` and `n=5`, `right_reach = 3`.
    // Left part can be `a_0, a_1, a_2`.
    // Right part can be `a_2, a_3, a_4`.
    // Index `2` is in both. So `k-1 = 2` is a valid peak.
    // `left_reach + right_reach = 3 + 3 = 6`. `n = 5`. `6 > 5`. Yes.

    if (left_reach + right_reach > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

