#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a prefix a[0...len-1] is a permutation of length len
bool is_prefix_permutation(int len, int n, const std::vector<int>& a, const std::vector<int>& prefix_max, const std::vector<bool>& prefix_distinct) {
    if (len == 0 || len > n) return false;
    return prefix_max[len - 1] == len && prefix_distinct[len - 1];
}

// Function to check if a suffix a[start_idx...n-1] is a permutation of length len
bool is_suffix_permutation(int len, int n, const std::vector<int>& a, const std::vector<int>& suffix_max, const std::vector<bool>& suffix_distinct) {
    if (len == 0 || len > n) return false;
    int start_idx = n - len;
    return suffix_max[start_idx] == len && suffix_distinct[start_idx];
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_distinct(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n
    int current_max_prefix = 0;
    bool current_distinct_prefix = true;

    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) {
            current_distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_prefix = std::max(current_max_prefix, a[i]);
        prefix_max[i] = current_max_prefix;
        prefix_distinct[i] = current_distinct_prefix;
    }

    // Precompute for suffixes
    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_distinct(n);
    std::vector<bool> seen_suffix(n + 1, false); // Max value can be n
    int current_max_suffix = 0;
    bool current_distinct_suffix = true;

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || a[i] <= 0 || seen_suffix[a[i]]) {
            current_distinct_suffix = false;
        }
        seen_suffix[a[i]] = true;
        current_max_suffix = std::max(current_max_suffix, a[i]);
        suffix_max[i] = current_max_suffix;
        suffix_distinct[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_permutation(l1, n, a, prefix_max, prefix_distinct) &&
            is_suffix_permutation(l2, n, a, suffix_max, suffix_distinct)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

