#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        current_sum += a[i];
        current_xor_sum ^= a[i];
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append elements.
        // Let S be current_sum and X be current_xor_sum.
        // We want to find b1, b2, b3 such that (S + b1 + b2 + b3) = 2 * (X ^ b1 ^ b2 ^ b3).
        // We can always achieve this with at most 3 elements.
        // Strategy:
        // 1. Append X.
        //    New sum S' = S + X
        //    New XOR sum X' = X ^ X = 0
        //    Condition: S' = 2 * X'  => S + X = 2 * 0 => S + X = 0.
        //    This is generally not true since S and X are non-negative.
        //    However, if S+X = 0, it means S=0 and X=0.
        //    If S=0 and X=0, then the original array was all zeros, and it was already good.
        //    So, after appending X, the array is usually not good.
        //    But we have simplified the XOR sum to 0.
        //
        // 2. After appending X, the new sum is S_new = S + X, and new XOR sum is X_new = 0.
        //    Now we need to append one more element, say Y, such that
        //    (S_new + Y) = 2 * (X_new ^ Y)
        //    (S + X + Y) = 2 * (0 ^ Y)
        //    (S + X + Y) = 2 * Y
        //    S + X = Y
        //    So, if we append Y = S + X, the condition will be met.
        //
        // This means we can append two elements: X and (S + X).
        // The appended elements are b1 = X, b2 = S + X.
        //
        // Let's verify:
        // Original array: a_1, ..., a_n
        // Original sum: S
        // Original XOR sum: X
        //
        // Append b1 = X:
        // Array: a_1, ..., a_n, X
        // New sum: S_1 = S + X
        // New XOR sum: X_1 = X ^ X = 0
        //
        // Append b2 = S + X:
        // Array: a_1, ..., a_n, X, S + X
        // Final sum: S_final = S_1 + (S + X) = (S + X) + (S + X) = 2 * (S + X)
        // Final XOR sum: X_final = X_1 ^ (S + X) = 0 ^ (S + X) = S + X
        //
        // Check condition: S_final = 2 * X_final
        // 2 * (S + X) = 2 * (S + X)
        // This is always true.
        //
        // So, we can always append two elements: current_xor_sum and (current_sum + current_xor_sum).
        // The problem states we can append at most 3 elements. 2 is <= 3.
        // The values can be large: current_sum can be up to 10^5 * 10^9 = 10^14.
        // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
        // So S + X can be up to 10^14 + 10^9, which fits in long long.
        // The problem states $b_i \le 10^{18}$, which is fine.

        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

