// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        return "000000000000000000"; // Special case for 0, always 18 '0's
    }
    for (int i = 0; i < 18; ++i) {
        if (n == 0) {
            pattern += '0';
        } else {
            pattern += ((n % 10) % 2 == 0 ? '0' : '1');
            n /= 10;
        }
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get MSB first
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;

            // Pad the pattern s with leading zeros to length 18
            std::string padded_s = s;
            if (padded_s.length() < 18) {
                padded_s = std::string(18 - padded_s.length(), '0') + padded_s;
            }

            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

