    // Let 'i' be the count of items taken from the left (0 <= i <= n)
    // Then 'n - i' items are taken from the right side
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right side

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for extra items
        if (i > j) { // More items from left than right
            // The difference is i - j.
            // If i == j + 1, one extra item from left. No penalty.
            // If i == j + 2, two extra items from left. One penalty.
            // The number of "extra" items that incur penalty is (i - j - 1).
            // This is equivalent to max(0, i - (j + 1)).
            current_energy += (long long)(i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // The difference is j - i.
            // If j == i + 1, one extra item from right. No penalty.
            // If j == i + 2, two extra items from right. One penalty.
            // The number of "extra" items that incur penalty is (j - i - 1).
            // This is equivalent to max(0, j - (i + 1)).
            current_energy += (long long)(j - i - 1) * Qr;
        }
        // If i == j, no penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

