int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1 means can move left (x-1). If f1=0, cannot move left.
            // So, if f1=0, the robot must end up at an X >= its current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 1 means can move right (x+1). If f3=0, cannot move right.
            // So, if f3=0, the robot must end up at an X <= its current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 1 means can move down (y-1). If f4=0, cannot move down.
            // So, if f4=0, the robot must end up at a Y >= its current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 1 means can move up (y+1). If f2=0, cannot move up.
            // So, if f2=0, the robot must end up at a Y <= its current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a point exists, one with coordinates
            // not exceeding 10^5 by absolute value exists.
            // Our current bounds can be very large, but any point within [min_x, max_x]
            // and [min_y, max_y] is valid. We can pick min_x and min_y.
            // We need to ensure the output coordinates are within the specified range,
            // but the problem statement implies that if min_x, min_y are valid,
            // they will be within the range or there's a valid point within range.
            // The constraints on x_i, y_i are -10^5 to 10^5.
            // If f1=0, min_x becomes x_i. If f3=0, max_x becomes x_i.
            // So min_x and max_x will be within [-10^5, 10^5] if they are set by any robot.
            // If they are not set, they remain at their initial large values.
            // However, the problem guarantees that if a solution exists, one with coordinates
            // not exceeding 10^5 by absolute value exists. So we can just output min_x, min_y.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

