// Function to find prime factors of a number
std::map<long long, int> prime_factorize(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        while (n % i == 0) {
            factors[i]++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[n]++;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that p % x == 0 and x % q != 0.
        // This means x must be p / (some factor of p/q)
        // Or, more generally, x must be p / k for some k, such that (p/k) % q != 0.
        // We want to maximize p/k, which means minimizing k.
        // The smallest k is 1, which gives x=p, but p % q == 0, so p is not valid.
        // We need to remove some prime factors from p such that the resulting number is no longer divisible by q.

        // Find prime factors of q
        std::map<long long, int> q_factors = prime_factorize(q);

        long long max_x = 1;

        // Iterate through each distinct prime factor f of q
        for (auto const& [f, q_exp] : q_factors) {
            // Calculate the current p_copy to find how many times f divides p
            long long p_copy = p;
            int p_exp = 0;
            while (p_copy > 0 && p_copy % f == 0) {
                p_exp++;
                p_copy /= f;
            }

            // If f is not a factor of p, it's not relevant for reducing p
            // (This case should not happen if p % q == 0, as q_exp > 0 implies f divides q,
            // and if f divides q and q divides p, then f must divide p)
            if (p_exp == 0) continue;

            // We need to reduce the exponent of f in p such that the resulting number is not divisible by q.
            // Specifically, we need to reduce the exponent of f in p to be less than q_exp.
            // The largest such divisor x would be p / (f^(p_exp - (q_exp - 1)))
            // which simplifies to p / (f^(p_exp - q_exp + 1))
            // This is equivalent to p / (f^k) where k is the smallest integer such that
            // (p / (f^k))'s exponent of f is q_exp - 1.
            // So k = p_exp - (q_exp - 1) = p_exp - q_exp + 1.
            // The divisor we are considering is p / (f^(p_exp - q_exp + 1)).
            // This divisor is guaranteed to have f's exponent as q_exp - 1,
            // thus it will not be divisible by q (because its f-exponent is too small).
            // We want to maximize x, so we want to remove the minimum necessary power of f.
            // The minimum power of f to remove is f^(p_exp - q_exp + 1).
            // Let this divisor be current_x = p / (f^(p_exp - q_exp + 1)).
            // We take the maximum of such current_x over all prime factors f of q.

            long long divisor_of_p = 1;
            for (int i = 0; i < p_exp - q_exp + 1; ++i) {
                divisor_of_p *= f;
            }
            max_x = std::max(max_x, p / divisor_of_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
        used_in_s.insert(c1);
        used_in_s.insert(c2);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_s.insert(s[0]);
    }

    bool possible = true;
    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::set<char> visited_for_layout;

    // Find starting points (characters with only one required neighbor)
    // Or any character if all have two neighbors (e.g., a cycle, or a single path)
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars in s have 2 neighbors (a cycle)
    // or it's a single char password.
    // If it's a cycle, we can pick any char from used_in_s as a start.
    // If used_in_s is empty (s.length() == 0, but problem says 1 <= |s|),
    // or if it's a single char password, start_char might still be '\0'.
    if (start_char == '\0' && !used_in_s.empty()) {
        start_char = *used_in_s.begin();
    }

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // Sentinel for the first step

        while (visited_for_layout.find(current_char) == visited_for_layout.end()) {
            layout += current_char;
            visited_for_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
            if (current_char == '\0' && adj[prev_char].size() == 1 && visited_for_layout.size() == used_in_s.size()) {
                // Reached end of a path
                break;
            }
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_for_layout.find(c) == visited_for_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) return 0;
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;

    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    if (term1 % 2 == 0) {
        term1 /= 2;
    } else {
        term2 /= 2;
    }

    return (term1 * term2) % MOD;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_k = sum_{k=1 to a} k
    long long sum_k = sum_arithmetic_series(a);

    // Calculate sum_r = sum_{r=1 to b-1} r
    long long sum_r = sum_arithmetic_series(b - 1);

    // Term 1: sum_{k=1 to a} sum_{r=1 to b-1} (r * k * b)
    // = (sum_{k=1 to a} k) * (sum_{r=1 to b-1} r) * b
    long long term1_val = (sum_k * sum_r) % MOD;
    term1_val = (term1_val * (b % MOD)) % MOD;

    // Term 2: sum_{k=1 to a} sum_{r=1 to b-1} (r)
    // = (sum_{k=1 to a} 1) * (sum_{r=1 to b-1} r)
    // = a * (sum_{r=1 to b-1} r)
    long long term2_val = (a % MOD * sum_r) % MOD;

    long long total_sum = (term1_val + term2_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

