void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    std::vector<int> ans(n);
    bool found_solution = false;

    for (int x = 0; x <= 9; ++x) { // x is the split digit
        std::vector<int> current_ans(n);
        int last1 = -1; // last digit colored 1
        int first2 = 10; // first digit colored 2

        bool possible_for_x = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                current_ans[i] = 1;
                if (d[i] < last1) { // S1 must be non-decreasing
                    possible_for_x = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > x) {
                current_ans[i] = 2;
                if (d[i] < first2) { // S2 must be non-decreasing
                    possible_for_x = false;
                    break;
                }
                first2 = d[i];
            }
        }

        if (!possible_for_x) {
            continue;
        }

        // Now handle digits equal to x
        // Digits equal to x can be colored 1 or 2.
        // If colored 1, they must be >= last1.
        // If colored 2, they must be <= first2.
        // Also, last1 (if exists) must be <= first2 (if exists).
        // The crucial part is that all digits colored 1 must be <= all digits colored 2.
        // So, if a digit d[i] == x is colored 1, it must be <= any d[j] == x colored 2.
        // This means there's a "pivot" point among digits equal to x.
        // All d[i] == x before pivot are 1, all d[i] == x after pivot are 2.
        // Or, more generally, all d[i] == x colored 1 must appear before all d[j] == x colored 2.
        // This is automatically handled by the last1 <= first2 condition.

        // For digits equal to x, we can assign them greedily.
        // Assign 1 if possible, otherwise 2.
        // This means we assign 1 to all d[i] == x as long as d[i] >= last1.
        // Once we assign 2 to a d[i] == x, all subsequent d[j] == x must be 2.
        // This is equivalent to finding the first occurrence of x that we color 2.
        // All x's before that are 1, all x's after that are 2.
        // If no x is colored 2, all x's are 1.
        // If no x is colored 1, all x's are 2.

        // Let's find the first digit equal to x that we *must* color 2.
        // This happens if d[i] == x and d[i] < last1 (which is impossible by construction for d[i] < x)
        // OR if d[i] == x and d[i] > first2 (which is impossible by construction for d[i] > x)
        // The only constraint for d[i] == x is that if it's colored 1, it must be >= last1.
        // If it's colored 2, it must be <= first2.
        // And overall, last1 (from <x or =x) <= first2 (from >x or =x).

        // A simpler approach for digits equal to x:
        // Find the first index `k` such that `d[k] == x` and `d[k]` is colored 2.
        // All `d[i] == x` for `i < k` are colored 1.
        // All `d[i] == x` for `i >= k` are colored 2.
        // If no `d[i] == x` is colored 2, then all `d[i] == x` are colored 1.
        // If no `d[i] == x` is colored 1, then all `d[i] == x` are colored 2.

        // Let's try to find the "split point" for digits equal to x.
        // All d[i] == x before some index `split_idx_for_x` are colored 1.
        // All d[i] == x at or after `split_idx_for_x` are colored 2.
        // If `split_idx_for_x` is `n`, all d[i] == x are colored 1.
        // If `split_idx_for_x` is `0`, all d[i] == x are colored 2.

        // We need to ensure that:
        // 1. S1 is non-decreasing.
        // 2. S2 is non-decreasing.
        // 3. last(S1) <= first(S2).

        // Let's try to assign 1 to all d[i] == x first, then check validity.
        // If it's valid, this is a solution.
        // If not, it means some d[i] == x must be 2.
        // The first d[i] == x that violates S1 non-decreasing must be 2.
        // Or, if last1 (from <x) > x, then all x's must be 2.

        // Let's try to assign colors for d[i] == x.
        // We need to find a `pivot_val` such that all `d[i] == x` before `pivot_val` are 1, and all `d[i] == x` after `pivot_val` are 2.
        // This is not quite right. The relative order of `d[i] == x` matters.
        // The simplest way to handle `d[i] == x` is to assign them greedily.
        // Iterate through `d[i] == x`. If `d[i]` can be 1 (i.e., `d[i] >= last1`), assign 1 and update `last1`.
        // Otherwise, it must be 2. Assign 2 and update `first2`.
        // Once we assign a `d[i] == x` to 2, all subsequent `d[j] == x` must also be 2.
        // This is because if `d[j] == x` (for `j > i`) is assigned 1, then `last1` would be `x`.
        // But `first2` would be `x` (from `d[i]`). So `last1 <= first2` would hold.
        // The problem is that `S2` must be non-decreasing. If `d[i] == x` is 2, then `first2` becomes `x`.
        // If `d[j] == x` (for `j > i`) is 1, then `last1` becomes `x`.
        // This is fine. The only issue is if `d[j] == x` is 1, but `d[j] < last1` (where `last1` is from a previous `d[k] < x`).
        // Or if `d[j] == x` is 2, but `d[j] < first2` (where `first2` is from a previous `d[k] > x`).

        // Let's refine the strategy for digits equal to x.
        // We have `last1_before_x` (from digits < x) and `first2_after_x` (from digits > x).
        // We need to assign colors to `d[i] == x`.
        // All `d[i] == x` that are colored 1 must form a non-decreasing sequence.
        // All `d[i] == x` that are colored 2 must form a non-decreasing sequence.
        // The last `d[i] == x` colored 1 must be `<= x`.
        // The first `d[i] == x` colored 2 must be `>= x`.
        // And `last1_overall <= first2_overall`.

        // The simplest way to handle `d[i] == x` is to find the first `d[i] == x` that we color 2.
        // All `d[j] == x` for `j < i` are colored 1.
        // All `d[j] == x` for `j >= i` are colored 2.
        // This is equivalent to finding a split point `k` for the original string.
        // All `d[i] == x` for `i < k` are 1. All `d[i] == x` for `i >= k` are 2.
        // This is what the example `040425524644` with `x=4` implies.
        // `0` is 1. `4` is 2. `0` is 1. `4` is 2. `2` is 1. `5` is 2. `5` is 2. `2` is 1. `4` is 1. `6` is 2. `4` is 1. `4` is 1.
        // This is not a simple split point for `x`.
        // The example output is `121212211211`.
        // For `x=4`:
        // `d[0]=0` -> `1` (0 < 4) `last1=0`
        // `d[1]=4` -> `2` (4 == 4) `first2=4`
        // `d[2]=0` -> `1` (0 < 4) `last1=0`
        // `d[3]=4` -> `2` (4 == 4) `first2=4`
        // `d[4]=2` -> `1` (2 < 4) `last1=2`
        // `d[5]=5` -> `2` (5 > 4) `first2=5`
        // `d[6]=5` -> `2` (5 > 4) `first2=5`
        // `d[7]=2` -> `1` (2 < 4) `last1=2`
        // `d[8]=4` -> `1` (4 == 4) `last1=4`
        // `d[9]=6` -> `2` (6 > 4) `first2=6`
        // `d[10]=4` -> `1` (4 == 4) `last1=4`
        // `d[11]=4` -> `1` (4 == 4) `last1=4`
        // Final S1: 0022444. Final S2: 44556.
        // This is valid. `last(S1)=4`, `first(S2)=4`. `4 <= 4`.
        // This implies that for `d[i] == x`, we can assign 1 or 2 independently, as long as `S1` and `S2` remain sorted and `last(S1) <= first(S2)`.

        // The strategy for `d[i] == x`:
        // Iterate through `d[i]`.
        // If `d[i] < x`, assign 1. Update `last1`. If `d[i] < last1`, impossible.
        // If `d[i] > x`, assign 2. Update `first2`. If `d[i] < first2`, impossible.
        // If `d[i] == x`:
        //   If `x >= last1` AND `x <= first2`:
        //     We have a choice. To maximize chances of success, we should try to assign 1 as long as possible.
        //     So, if `x >= last1`, assign 1. Update `last1 = x`.
        //     Else (if `x < last1`), we must assign 2. Update `first2 = x`. If `x > first2`, impossible.
        // This greedy choice for `d[i] == x` is:
        // If `d[i] == x`:
        //   If `x >= last1`: assign 1. `last1 = x`.
        //   Else: assign 2. `first2 = x`.
        // This is the strategy used in many solutions. Let's verify it.

        int current_last1 = -1;
        int current_first2 = 10;
        bool current_possible = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < x) {
                if (d[i] < current_last1) {
                    current_possible = false;
                    break;
                }
                current_ans[i] = 1;
                current_last1 = d[i];
            } else if (d[i] > x) {
                if (d[i] < current_first2) {
                    current_possible = false;
                    break;
                }
                current_ans[i] = 2;
                current_first2 = d[i];
            } else { // d[i] == x
                if (x >= current_last1) { // Can be colored 1
                    current_ans[i] = 1;
                    current_last1 = x;
                } else { // Must be colored 2
                    if (x > current_first2) { // Cannot be colored 2 either
                        current_possible = false;
                        break;
                    }
                    current_ans[i] = 2;
                    current_first2 = x;
                }
            }
        }

        if (current_possible) {
            // Final check: last(S1) <= first(S2)
            // This is implicitly handled by current_last1 and current_first2.
            // If current_last1 > current_first2, it means some digit colored 1 was greater than some digit colored 2.
            // This would have been caught by the conditions `d[i] < current_last1` or `d[i] < current_first2`
            // or `x > current_first2` for `d[i] == x`.
            // The only remaining check is if `current_last1` (the largest digit colored 1) is greater than `current_first2` (the smallest digit colored 2).
            // If `current_last1` is still -1 (no digits colored 1), or `current_first2` is still 10 (no digits colored 2), this is fine.
            // Otherwise, `current_last1 <= current_first2` must hold.
            // This is guaranteed by the logic:
            // If `d[i] < x`, `current_last1` is updated.
            // If `d[i] > x`, `current_first2` is updated.
            // If `d[i] == x` and `x >= current_last1`, it's 1. `current_last1` becomes `x`.
            // If `d[i] == x` and `x < current_last1`, it's 2. `current_first2` becomes `x`.
            // In the last case, `x < current_last1` means `x` is smaller than a previous digit colored 1.
            // So `x` must be colored 2. If `x > current_first2`, it's impossible.
            // This means `current_last1` (from a 1) is always `<= x` (if it's a 1) or `<= x` (if it's a 2).
            // And `current_first2` (from a 2) is always `>= x` (if it's a 2) or `>= x` (if it's a 1).
            // The logic ensures that `current_last1 <= x` and `current_first2 >= x` for digits equal to x.
            // And for digits not equal to x, `current_last1 < x` and `current_first2 > x`.
            // So, `current_last1 <= x <= current_first2` is maintained.

            found_solution = true;
            ans = current_ans;
            break;
        }
    }

    if (found_solution) {
        for (int i = 0; i < n; ++i) {
            std::cout << ans[i];
        }
        std::cout << "\n";
    } else {
        std::cout << "-\n";
    }
}

