#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

// Function to compute Z-array for a string
std::vector<int> compute_z_array(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-arrays for all cyclic shifts of s
    // z_arrays[i] stores the Z-array for s[i...L-1] + s[0...i-1]
    std::vector<std::vector<int>> z_arrays(L);
    for (int i = 0; i < L; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        z_arrays[i] = compute_z_array(shifted_s);
    }

    // Group indices k by s[k]
    std::map<char, std::vector<int>> k_by_first_char;
    for (int k = 0; k < L; ++k) {
        k_by_first_char[s[k]].push_back(k);
    }

    double total_win_probability = 0.0;

    for (auto const& [char_0, possible_k_indices] : k_by_first_char) {
        if (possible_k_indices.size() <= 1) {
            total_win_probability += (double)possible_k_indices.size();
            continue;
        }

        // For a fixed char_0, find the best p
        double max_win_prob_for_char_0 = 0.0;

        // Iterate over all possible second positions p (from 1 to L-1)
        for (int p = 1; p < L; ++p) {
            int current_p_wins = 0;

            // Group possible_k_indices by s[(p+k)%L]
            std::map<char, std::vector<int>> k_by_second_char;
            for (int k_idx : possible_k_indices) {
                k_by_second_char[s[(p + k_idx) % L]].push_back(k_idx);
            }

            for (auto const& [char_p, group_k_indices] : k_by_second_char) {
                if (group_k_indices.size() <= 1) {
                    current_p_wins += group_k_indices.size();
                    continue;
                }

                // If multiple k's match (char_0, char_p), check if they are distinguishable
                // A group of k's is distinguishable if for any two k1, k2 in the group,
                // s[k1] == char_0, s[(p+k1)%L] == char_p
                // s[k2] == char_0, s[(p+k2)%L] == char_p
                // AND k1 and k2 are distinguishable by (char_0, char_p)
                // This means that the string s shifted by k1 and s shifted by k2
                // must differ at some position other than 0 or p.
                // If they are identical, Vasya loses.
                // They are identical if s[k1...L-1]s[0...k1-1] == s[k2...L-1]s[0...k2-1]
                // This is equivalent to checking if k1 and k2 are "equivalent" shifts.
                // Two shifts k1 and k2 are equivalent if s[k1...L-1]s[0...k1-1] == s[k2...L-1]s[0...k2-1].
                // This happens if s is periodic and k2-k1 is a multiple of the period.
                // More generally, if s[k1] == s[k2] and s[(p+k1)%L] == s[(p+k2)%L],
                // we need to check if there exists any other j such that s[(j+k1)%L] != s[(j+k2)%L].
                // If for all j, s[(j+k1)%L] == s[(j+k2)%L], then k1 and k2 are indistinguishable.
                // This means the string s shifted by k1 is identical to s shifted by k2.
                // This happens if and only if k1 and k2 are "equivalent" shifts, i.e.,
                // s_shifted_by_k1 == s_shifted_by_k2.
                // This is true if and only if k1 and k2 are congruent modulo the smallest period of s.
                // However, the problem states "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                // This means if there are k1, k2 such that s[k1]=char_0, s[(p+k1)%L]=char_p AND s[k2]=char_0, s[(p+k2)%L]=char_p,
                // AND k1 != k2, then Vasya loses for this (char_0, char_p) combination.
                // This interpretation is simpler and more common in competitive programming.
                // So, if group_k_indices.size() > 1, Vasya loses for this (char_0, char_p) combination.
                // The only exception is if all k in group_k_indices actually correspond to the same *unique* cyclic shift.
                // This happens if s is periodic and all k in group_k_indices are congruent modulo the smallest period of s.
                // But the problem implies k must be uniquely determined, not just the resulting string.
                // "Vasya wants to know the value of k uniquely"
                // So if group_k_indices.size() > 1, Vasya loses.
                // The only way to win is if group_k_indices.size() == 1.

                // Let's re-read carefully: "if there are at least two cyclic shifts of s that fit the information Vasya knowns, Vasya loses."
                // This means if there are k1, k2 (k1 != k2) such that:
                // 1. s[k1] == char_0
                // 2. s[(p+k1)%L] == char_p
                // 3. s[k2] == char_0
                // 4. s[(p+k2)%L] == char_p
                // Then Vasya loses.
                // So, if group_k_indices.size() > 1, Vasya loses for this (char_0, char_p) combination.
                // The only way to win is if group_k_indices.size() == 1.
                // This is the interpretation used in the example "tictictactac".
                // If first is 't', second is 'i', then k could be 0 or 3. Vasya loses.
                // If first is 'i', second is 'c', then k could be 1 or 4. Vasya loses.
                // This implies that if there are multiple k's, Vasya loses.

                // The only case where multiple k's might lead to a win is if they all produce the *same* shifted string.
                // E.g., if s = "aaaa", L=4. If k=0, t="aaaa". If k=1, t="aaaa".
                // If Vasya knows t[0]='a', t[p]='a', and k could be 0 or 1, he loses because he can't distinguish k=0 from k=1.
                // The problem statement "Vasya wants to know the value of k uniquely" confirms this.
                // So, if group_k_indices.size() > 1, Vasya loses.
                // The only way to win is if group_k_indices.size() == 1.

                // This means the logic for `current_p_wins` is correct:
                // if group_k_indices.size() == 1, then Vasya wins for this specific (char_0, char_p) combination.
                // If group_k_indices.size() > 1, Vasya loses.
                // So, `current_p_wins` should just count groups of size 1.
            }
            max_win_prob_for_char_0 = std::max(max_win_prob_for_char_0, (double)current_p_wins);
        }
        total_win_probability += max_win_prob_for_char_0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_probability / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0 to 9), track how it transforms 0 and 1.
    // initial_0[bit_idx] stores the final state of bit_idx if input bit was 0.
    // initial_1[bit_idx] stores the final state of bit_idx if input bit was 1.
    std::vector<int> initial_0(10); // All bits are 0 initially
    std::vector<int> initial_1(10); // Only bit_idx is 1, others are 0

    for (int i = 0; i < 10; ++i) {
        initial_0[i] = 0;
        initial_1[i] = 1;
    }

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int i = 0; i < 10; ++i) {
            int bit_val = (val >> i) & 1;
            if (op_char == '&') {
                initial_0[i] &= bit_val;
                initial_1[i] &= bit_val;
            } else if (op_char == '|') {
                initial_0[i] |= bit_val;
                initial_1[i] |= bit_val;
            } else { // '^'
                initial_0[i] ^= bit_val;
                initial_1[i] ^= bit_val;
            }
        }
    }

    // Now, we have the final state for each bit position.
    // We need to find constants A, B, C such that:
    // (x & A | B) ^ C = final_x
    // for all x from 0 to 1023.

    // Let's determine the effective AND, OR, XOR constants.
    // We need to find A_eff, B_eff, C_eff.
    //
    // For each bit i:
    // Let x_i be the i-th bit of the input.
    // Let y_i be the i-th bit of the output.
    //
    // We know:
    // if x_i = 0, then y_i = initial_0[i]
    // if x_i = 1, then y_i = initial_1[i]
    //
    // We want to find A_i, B_i, C_i such that:
    // (x_i & A_i | B_i) ^ C_i = y_i
    //
    // Case 1: x_i = 0
    // (0 & A_i | B_i) ^ C_i = y_i
    // (0 | B_i) ^ C_i = y_i
    // B_i ^ C_i = initial_0[i]
    //
    // Case 2: x_i = 1
    // (1 & A_i | B_i) ^ C_i = y_i
    // (A_i | B_i) ^ C_i = initial_1[i]

    // Let's try to construct A_eff, B_eff, C_eff.
    //
    // Consider the effect of A_eff, B_eff, C_eff on a bit x_i:
    // If x_i = 0: (0 & A_i | B_i) ^ C_i = B_i ^ C_i
    // If x_i = 1: (1 & A_i | B_i) ^ C_i = (A_i | B_i) ^ C_i
    //
    // We need:
    // B_i ^ C_i = initial_0[i]
    // (A_i | B_i) ^ C_i = initial_1[i]
    //
    // From the first equation, B_i = initial_0[i] ^ C_i. Substitute into the second:
    // (A_i | (initial_0[i] ^ C_i)) ^ C_i = initial_1[i]
    //
    // Let's try to determine A_i, B_i, C_i for each bit.
    //
    // If initial_0[i] == initial_1[i]:
    // This means the output bit y_i is independent of the input bit x_i.
    // So, A_i must be 0.
    // If A_i = 0:
    // (0 | B_i) ^ C_i = initial_0[i]  => B_i ^ C_i = initial_0[i]
    // (0 | B_i) ^ C_i = initial_1[i]  => B_i ^ C_i = initial_1[i]
    // This is consistent. We can choose C_i = 0, then B_i = initial_0[i].
    // So, for this bit: (x_i & 0 | initial_0[i]) ^ 0 = initial_0[i].
    // This means the bit is always initial_0[i], regardless of x_i.
    //
    // If initial_0[i] != initial_1[i]:
    // This means the output bit y_i depends on the input bit x_i.
    // So, A_i must be 1.
    // If A_i = 1:
    // (1 | B_i) ^ C_i = initial_1[i] => 1 ^ C_i = initial_1[i] (since 1 | B_i is always 1)
    // From this, C_i = 1 ^ initial_1[i].
    // Now use B_i ^ C_i = initial_0[i]:
    // B_i = initial_0[i] ^ C_i = initial_0[i] ^ (1 ^ initial_1[i]).
    //
    // So, for each bit i:
    // If initial_0[i] == initial_1[i]:
    //   A_i = 0
    //   B_i = initial_0[i]
    //   C_i = 0
    // Else (initial_0[i] != initial_1[i]):
    //   A_i = 1
    //   C_i = 1 ^ initial_1[i]
    //   B_i = initial_0[i] ^ C_i

    int final_and_const = 0;
    int final_or_const = 0;
    int final_xor_const = 0;

    for (int i = 0; i < 10; ++i) {
        int A_i, B_i, C_i;
        if (initial_0[i] == initial_1[i]) {
            A_i = 0;
            B_i = initial_0[i];
            C_i = 0;
        } else { // initial_0[i] != initial_1[i]
            A_i = 1;
            C_i = 1 ^ initial_1[i];
            B_i = initial_0[i] ^ C_i;
        }
        final_and_const |= (A_i << i);
        final_or_const |= (B_i << i);
        final_xor_const |= (C_i << i);
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total counts
    int total_s = 0;
    int total_b = 0;
    for (int x : a) {
        if (x == 1) {
            total_s++;
        } else {
            total_b++;
        }
    }

    // Prefix sums for the left part (jars 1 to n)
    // diff_L[i] = (count of 1s in a[0...i-1]) - (count of 2s in a[0...i-1])
    // We are interested in jars 1 to n, which are indices 0 to n-1.
    // So, diff_L[i] will be for prefix of length i.
    // diff_L[0] = 0 (empty prefix)
    // diff_L[1] = a[0]==1 ? 1 : -1
    // ...
    // diff_L[n] = (count of 1s in a[0...n-1]) - (count of 2s in a[0...n-1])
    std::vector<int> diff_L(n + 1);
    diff_L[0] = 0;
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Suffix sums for the right part (jars n+1 to 2n)
    // diff_R[i] = (count of 1s in a[2n-1...2n-i]) - (count of 2s in a[2n-1...2n-i])
    // We are interested in jars n+1 to 2n, which are indices n to 2n-1.
    // diff_R[0] = 0 (empty suffix)
    // diff_R[1] = a[2n-1]==1 ? 1 : -1
    // ...
    // diff_R[n] = (count of 1s in a[n...2n-1]) - (count of 2s in a[n...2n-1])
    std::vector<int> diff_R(n + 1);
    diff_R[0] = 0;
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left side
    // to achieve a certain difference.
    // key: difference (S-B), value: number of jars removed from left (k_L)
    std::map<int, int> left_diff_to_kL;
    for (int k_L = 0; k_L <= n; ++k_L) {
        // If k_L jars are removed from the left (jars n, n-1, ..., n-k_L+1),
        // then the remaining left part is jars 1 to n-k_L.
        // The difference for this remaining part is diff_L[n-k_L].
        int current_diff = diff_L[n - k_L];
        if (left_diff_to_kL.find(current_diff) == left_diff_to_kL.end()) {
            left_diff_to_kL[current_diff] = k_L;
        } else {
            left_diff_to_kL[current_diff] = std::min(left_diff_to_kL[current_diff], k_L);
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars removed from the right side (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        // If k_R jars are removed from the right (jars n+1, n+2, ..., n+k_R),
        // then the remaining right part is jars n+k_R+1 to 2n.
        // The difference for this remaining part is diff_R[n-k_R].
        int current_diff_right_remaining = diff_R[n - k_R];

        // The total difference (S-B) for all jars is total_s - total_b.
        // If we remove k_L jars from left and k_R jars from right,
        // the remaining jars are jars 1 to n-k_L and jars n+k_R+1 to 2n.
        // The difference for these remaining jars is
        // (diff_L[n-k_L]) + (diff_R[n-k_R]).
        // We want this total difference to be 0.
        // So, diff_L[n-k_L] + diff_R[n-k_R] = 0.
        // This means diff_L[n-k_L] = -diff_R[n-k_R].

        int target_diff_left_remaining = -current_diff_right_remaining;

        if (left_diff_to_kL.count(target_diff_left_remaining)) {
            int k_L = left_diff_to_kL[target_diff_left_remaining];
            min_removed_jars = std::min(min_removed_jars, k_L + k_R);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_suffix(n + 1); // a_suffix[0] is unused, a_suffix[1] is unused
                                          // a_suffix[i] stores a_i for i >= 2
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_suffix[i];
    }

    std::vector<long long> dp_val(n + 1); // dp_val[i] stores the total y accumulated when starting at x=i and moving to x=i-a[i]
    std::vector<int> dp_next_x(n + 1);    // dp_next_x[i] stores the next x value after starting at x=i and moving to x=i-a[i]

    for (int i = n; i >= 1; --i) {
        long long current_a_i;
        if (i == 1) {
            // This case is handled by the outer loop for each initial_a1
            // We only need dp values for x >= 2
            continue; 
        } else {
            current_a_i = a_suffix[i];
        }

        long long next_x_after_step2 = i - current_a_i;

        if (next_x_after_step2 <= 0) {
            dp_val[i] = current_a_i;
            dp_next_x[i] = 0; // Sentinel for termination
        } else if (next_x_after_step2 > n) {
            dp_val[i] = current_a_i;
            dp_next_x[i] = n + 1; // Sentinel for termination
        } else {
            // The program continues. The next state is (next_x_after_step2, y + current_a_i).
            // From next_x_after_step2, it will first add a[next_x_after_step2] to x and y,
            // then subtract a[next_x_after_step2] from x and add to y.
            // This is exactly what dp_val[next_x_after_step2] and dp_next_x[next_x_after_step2] store.

            // Check for cycle: if next_x_after_step2 is i, it's an infinite loop.
            // This check is implicitly handled by the termination condition of the path traversal.
            // If dp_next_x[next_x_after_step2] is -1, it means it leads to an infinite loop.
            if (dp_next_x[next_x_after_step2] == -1) {
                dp_val[i] = -1;
                dp_next_x[i] = -1;
            } else {
                dp_val[i] = current_a_i + dp_val[next_x_after_step2];
                dp_next_x[i] = dp_next_x[next_x_after_step2];
            }
        }
    }

    for (int initial_a1 = 1; initial_a1 < n; ++initial_a1) {
        long long current_y = initial_a1;
        int current_x = 1 + initial_a1;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
        } else {
            // Now we are at x = current_x, y = current_y.
            // The next step is to apply the (add a[x], sub a[x]) pair.
            // This is exactly what dp_val[current_x] and dp_next_x[current_x] represent.
            if (dp_next_x[current_x] == -1) { // Leads to infinite loop
                std::cout << -1 << "\n";
            } else {
                std::cout << current_y + dp_val[current_x] << "\n";
            }
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (b_1=a_1, b_n=a_n, no middle elements)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n, 0); // L[i] = length of consecutive 0s ending at i
    std::vector<int> R(n, 0); // R[i] = length of consecutive 0s starting at i

    // Calculate L
    if (a[0] == 0) L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // Calculate R
    if (a[n - 1] == 0) R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    std::vector<int> max_dist_to_one(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            max_dist_to_one[i] = 0;
        } else { // a[i] == 0
            int left_one_dist = -1;
            if (i > 0) {
                if (a[i-1] == 1) left_one_dist = 1;
                else if (max_dist_to_one[i-1] != -1) left_one_dist = max_dist_to_one[i-1] + 1;
            }

            int right_one_dist = -1;
            if (i < n-1) {
                if (a[i+1] == 1) right_one_dist = 1;
                // For right_one_dist, we need to look ahead. This is tricky with a single pass.
                // Instead, we can use L and R arrays to find the length of consecutive zeros.
                // The distance to the nearest 1 is (length of zeros) + 1.
                // If a[i] is 0, and it's part of a block of zeros of length K,
                // then the distance to the left 1 is L[i] (if L[i] is not 0, otherwise no left 1)
                // and distance to the right 1 is R[i] (if R[i] is not 0, otherwise no right 1)
                // This is not quite right. L[i] is the length of 0s ending at i.
                // If a[i] is 0, and L[i] = k, it means a[i-k+1...i] are all 0.
                // The nearest 1 to the left of a[i] is at index i-k. Its distance is k.
                // The nearest 1 to the right of a[i] is at index i+R[i]. Its distance is R[i].
                // If there's no 1 to the left, L[i] is the length of 0s from start.
                // If there's no 1 to the right, R[i] is the length of 0s to end.

                // Let's re-evaluate max_dist_to_one[i] for a[i]=0.
                // It's the minimum distance to a 1.
                // If a[i] is 0:
                //   dist_left = (i - (index of nearest 1 to its left))
                //   dist_right = ((index of nearest 1 to its right) - i)
                //   max_dist_to_one[i] = min(dist_left, dist_right)
                // If no 1 to left, dist_left = infinity. If no 1 to right, dist_right = infinity.
                // If all are 0s, max_dist_to_one[i] = infinity.

                // Let's compute dist_to_left_one and dist_to_right_one separately.
                // dist_to_left_one[i]: distance from i to nearest 1 at or before i.
                // dist_to_right_one[i]: distance from i to nearest 1 at or after i.
            }
        }
    }

    std::vector<int> dist_to_left_one(n);
    int last_one_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            last_one_idx = i;
            dist_to_left_one[i] = 0;
        } else {
            if (last_one_idx != -1) {
                dist_to_left_one[i] = i - last_one_idx;
            } else {
                dist_to_left_one[i] = n + 1; // Effectively infinity
            }
        }
    }

    std::vector<int> dist_to_right_one(n);
    last_one_idx = -1; // Re-purpose for right-to-left scan
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            last_one_idx = i;
            dist_to_right_one[i] = 0;
        } else {
            if (last_one_idx != -1) {
                dist_to_right_one[i] = last_one_idx - i;
            } else {
                dist_to_right_one[i] = n + 1; // Effectively infinity
            }
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int min_dist = std::min(dist_to_left_one[i], dist_to_right_one[i]);
            if (min_dist > n) { // All zeros
                max_k = n + 1; // Special value indicating all zeros
                break;
            }
            max_k = std::max(max_k, min_dist);
        }
    }

    if (max_k > n) { // All zeros initially
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << 0 << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // max_k is the maximum minimum distance from any 0 to a 1.
    // This is the number of steps it takes for all 0s to become 1s if they are surrounded by 1s,
    // or for 1s to become 0s if they are surrounded by 0s.
    // The actual number of steps is max_k - 1.
    // If max_k = 0, it means all elements are 1s, or there are no 0s.
    // If max_k = 1, it means all 0s are adjacent to a 1. They will become 0 in 0 steps.
    // If max_k = 2, it means some 0 is 2 away from nearest 1. It will become 0 in 1 step.
    // The number of steps is (max_k - 1).
    // This is the number of steps for the "inner" elements to stabilize.
    // The boundary elements a[0] and a[n-1] never change.

    // The problem asks for the number of steps until the sequence becomes stable.
    // A sequence is stable if b_i = a_i for all i.
    // For i=1 or i=n, b_i = a_i by definition.
    // For i=2...n-1, b_i = median(a_{i-1}, a_i, a_{i+1}).
    // This means a_i is stable if a_i = median(a_{i-1}, a_i, a_{i+1}).
    // This happens if:
    //   a_i = 0 and at least two of (a_{i-1}, a_i, a_{i+1}) are 0.
    //   a_i = 1 and at least two of (a_{i-1}, a_i, a_{i+1}) are 1.
    // This is equivalent to: a_i = a_{i-1} or a_i = a_{i+1}.
    // So, a sequence is stable if for all i in [1, n-2], a_i = a_{i-1} or a_i = a_{i+1}.
    // This means there are no "isolated" 0s or 1s.
    // E.g., 010 is not stable (middle 1 becomes 0). 101 is not stable (middle 0 becomes 1).
    // Stable sequences look like 000...0111...1000...0 or 000...0 or 111...1.
    // Specifically, a stable sequence cannot have 010 or 101 as a subsequence.
    // This means it must be of the form 0...01...1 or 1...10...0 or 0...0 or 1...1.

    // The number of steps is max_k - 1.
    // If max_k = 0, it means all elements are 1s. 0 steps.
    // If max_k = 1, it means all 0s are adjacent to a 1.
    //   Example: 0110. max_k=1.
    //   0110 -> 0110. 0 steps.
    //   Example: 010. max_k=1.
    //   010 -> 000. 1 step.
    // This logic for max_k is for how many steps it takes for a 0 to become a 1 or vice versa.
    // The problem is that max_k is the minimum distance to a 1.
    // If a[i] = 0, and min_dist = k, it means a[i] will become 1 after k-1 steps.
    // If a[i] = 1, and min_dist = k, it means a[i] will become 0 after k-1 steps.
    // This is the number of steps for a cell to flip.
    // The sequence stabilizes when no more cells flip.
    // This happens when all 0s are surrounded by 0s (or boundary) and all 1s by 1s (or boundary).
    // This means all 0s that are "closer" to a 1 than to a 0 will flip to 1.
    // And all 1s that are "closer" to a 0 than to a 1 will flip to 0.

    // The final state of a[i] is determined by whether it's closer to a 0 or a 1.
    // If dist_to_left_one[i] == dist_to_right_one[i], it's ambiguous.
    // In this case, the value of a[i] will flip to 0 if a[i] was 1, or to 1 if a[i] was 0.
    // The rule is: b_i = median(a_{i-1}, a_i, a_{i+1}).
    // If a[i] is 0, it becomes 1 if a_{i-1}=1 and a_{i+1}=1.
    // If a[i] is 1, it becomes 0 if a_{i-1}=0 and a_{i+1}=0.
    // This means 010 -> 000, 101 -> 111.
    // The "spread" of 0s and 1s.
    // A 0 at index `i` will eventually become 1 if `dist_to_left_one[i] < dist_to_right_one[i]`
    // or `dist_to_right_one[i] < dist_to_left_one[i]`.
    // If `dist_to_left_one[i] == dist_to_right_one[i]`, then `a[i]` will become 0.
    // This is because if `a[i]` is 0, and it's equidistant from 1s, it means it's in the middle of a block of 0s.
    // E.g., 10001. `i=2` (middle 0). `dist_to_left_one[2]=2`, `dist_to_right_one[2]=2`.
    // 10001 -> 10001 (no change for middle 0, because neighbors are 0).
    // This is wrong. 10001 -> 10001.
    // The rule is: a[i] becomes 0 if at least two of (a[i-1], a[i], a[i+1]) are 0.
    // a[i] becomes 1 if at least two of (a[i-1], a[i], a[i+1]) are 1.
    // This means a 0 surrounded by 1s (101) becomes 1.
    // A 1 surrounded by 0s (010) becomes 0.
    // This is exactly what the `max_k` logic captures.
    // `max_k` is the maximum `k` such that there exists an `i` where `a[i]` is `X` and its nearest `X` neighbor is `k` away.
    // Or, `max_k` is the maximum `k` such that there exists an `i` where `a[i]` is `X` and its nearest `Y` neighbor is `k` away.
    // The number of steps is `max_k - 1`.
    // If `max_k = 0`, it means all elements are 1s. 0 steps.
    // If `max_k = 1`, it means all 0s are adjacent to a 1, or all 1s are adjacent to a 0.
    //   Example: 0110. max_k=1. Stable. 0 steps.
    //   Example: 010. max_k=1. Not stable. 010 -> 000. 1 step.
    //   Example: 101. max_k=1. Not stable. 101 -> 111. 1 step.
    // So, if max_k = 1, it takes 1 step if there's a 010 or 101 pattern.
    // If max_k = 0, it takes 0 steps.
    // If max_k > 1, it takes max_k - 1 steps.

    // Let's re-evaluate max_k.
    // max_k is the maximum value of `min(dist_to_left_one[i], dist_to_right_one[i])` for all `i` where `a[i] == 0`.
    // This `max_k` is the maximum "distance to a 1" for any 0.
    // Similarly, we need `max_k_prime` for 1s.
    // `max_k_prime` is the maximum value of `min(dist_to_left_zero[i], dist_to_right_zero[i])` for all `i` where `a[i] == 1`.

    std::vector<int> dist_to_left_zero(n);
    last_one_idx = -1; // Re-purpose for last_zero_idx
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            last_one_idx = i;
            dist_to_left_zero[i] = 0;
        } else {
            if (last_one_idx != -1) {
                dist_to_left_zero[i] = i - last_one_idx;
            } else {
                dist_to_left_zero[i] = n + 1;
            }
        }
    }

    std::vector<int> dist_to_right_zero(n);
    last_one_idx = -1; // Re-purpose for last_zero_idx
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            last_one_idx = i;
            dist_to_right_zero[i] = 0;
        } else {
            if (last_one_idx != -1) {
                dist_to_right_zero[i] = last_one_idx - i;
            } else {
                dist_to_right_zero[i] = n + 1;
            }
        }
    }

    int max_k_zeros_to_ones = 0; // Max steps for a 0 to become 1
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int min_dist_to_one = std::min(dist_to_left_one[i], dist_to_right_one[i]);
            if (min_dist_to_one > n) { // All zeros
                max_k_zeros_to_ones = n + 1; // Indicate all zeros
                break;
            }
            max_k_zeros_to_ones = std::max(max_k_zeros_to_ones, min_dist_to_one);
        }
    }

    int max_k_ones_to_zeros = 0; // Max steps for a 1 to become 0
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            int min_dist_to_zero = std::min(dist_to_left_zero[i], dist_to_right_zero[i]);
            if (min_dist_to_zero > n) { // All ones
                max_k_ones_to_zeros = n + 1; // Indicate all ones
                break;
            }
            max_k_ones_to_zeros = std::max(max_k_ones_to_zeros, min_dist_to_zero);
        }
    }

    if (max_k_zeros_to_ones > n && max_k_ones_to_zeros > n) { // All same value
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    int total_steps = 0;
    if (max_k_zeros_to_ones <= n) { // If there are 0s
        total_steps = std::max(total_steps, max_k_zeros_to_ones - 1);
    }
    if (max_k_ones_to_zeros <= n) { // If there are 1s
        total_steps = std::max(total_steps, max_k_ones_to_zeros - 1);
    }

    std::vector<int> final_a(n);
    final_a[0] = a[0];
    final_a[n - 1] = a[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        if (dist_to_left_one[i] == dist_to_right_one[i]) { // Equidistant from 1s
            final_a[i] = 0; // It will become 0 (e.g., 10001 -> 10001, 01110 -> 01110)
        } else if (dist_to_left_one[i] < dist_to_right_one[i]) { // Closer to left 1
            final_a[i] = 1;
        } else { // Closer to right 1
            final_a[i] = 1;
        }
    }

    std::cout << total_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The target value for b_1 must be at least 0.
                            // We want to find the smallest possible b_i for each i.

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: a_i is already >= prev_val.
        // We need b_i >= prev_val.
        // If a_i >= prev_val, we can potentially set b_i = a_i.
        // The increment needed would be 0.
        // If a_i + x >= prev_val, then we can achieve b_i = a_i + k for some k <= x.
        // Specifically, if a_i >= prev_val, we can set b_i = a_i.
        // The increment needed is 0.
        // If a_i < prev_val, we need to increment a_i.
        // The smallest possible b_i is prev_val.
        // To get b_i = prev_val, we need to increment a_i by (prev_val - a_i) mod m.
        // This is (prev_val - a_i + m) % m.
        // Let's call this increment `inc`.
        // If `inc` <= x, then we can achieve b_i = prev_val.
        // If `inc` > x, then we cannot achieve b_i = prev_val.
        // In this case, the smallest b_i we can achieve is (a_i + x) % m.
        // If (a_i + x) % m < prev_val, then it's impossible to satisfy b_i >= prev_val.

        // Let's rephrase: we need to find a b_i such that prev_val <= b_i < m and b_i = (a_i + k) % m for some 0 <= k <= x.
        // If a_i >= prev_val:
        //   We can choose k=0, so b_i = a_i. This satisfies b_i >= prev_val.
        //   The smallest possible b_i is a_i.
        //   However, we also have the option to increment a_i.
        //   If we increment a_i by k, b_i = (a_i + k) % m.
        //   If (a_i + x) % m < prev_val, it means that even with max increment, we wrap around and become smaller than prev_val.
        //   This can only happen if a_i + x >= m.
        //   In this situation, we must ensure that a_i + x (before modulo) is at least prev_val + m.
        //   Or, more simply, if a_i + x < prev_val + m, then we can't reach prev_val.
        //   This is equivalent to saying: if a_i + x < prev_val, then it's impossible.
        //   But we are considering a_i >= prev_val.
        //   So, if a_i >= prev_val, we can always set b_i = a_i. This requires 0 operations.
        //   The only way this fails is if a_i + x wraps around and becomes less than prev_val.
        //   This means (a_i + x) % m < prev_val.
        //   This happens if a_i + x >= m AND (a_i + x) % m < prev_val.
        //   In this specific case, we cannot use a_i as b_i, because we are forced to increment it by at least (m - a_i) to wrap around.
        //   The smallest value we can achieve that is >= prev_val is a_i itself (with 0 increment).
        //   The largest value we can achieve is (a_i + x) % m.
        //   If a_i >= prev_val:
        //     We can set b_i = a_i (increment 0). This is valid.
        //     We can also set b_i = (a_i + k) % m for 0 < k <= x.
        //     If (a_i + x) % m < prev_val, it means that all values (a_i + k) % m for k from 0 to x that are >= prev_val are not possible.
        //     This is the tricky part.
        //     If a_i >= prev_val, we can always choose b_i = a_i. This requires 0 operations.
        //     This is valid as long as a_i is not "too large" such that incrementing it by x makes it wrap around and become smaller than prev_val.
        //     Specifically, if a_i + x >= m AND (a_i + x) % m < prev_val, then we cannot use a_i as b_i.
        //     In this case, we must increment a_i such that it wraps around and becomes >= prev_val.
        //     The smallest such value is prev_val.
        //     The increment needed to reach prev_val from a_i is (prev_val - a_i + m) % m.
        //     If this increment is <= x, then we can set b_i = prev_val.
        //     Otherwise, it's impossible.

        // Let's simplify:
        // We need to find b_i such that prev_val <= b_i < m.
        // And b_i must be reachable from a_i with at most x operations.
        // This means b_i = (a_i + k) % m for some 0 <= k <= x.

        // Option 1: Don't wrap around.
        // We want b_i = a_i + k.
        // This requires a_i + k < m.
        // We need prev_val <= a_i + k.
        // So, k >= prev_val - a_i.
        // Also, k <= x.
        // And k >= 0.
        // So, we need to find k such that max(0, prev_val - a_i) <= k <= x.
        // If such a k exists, we can set b_i = a_i + max(0, prev_val - a_i).
        // This is possible if max(0, prev_val - a_i) <= x.
        // If this is true, we can set b_i = max(a_i, prev_val).
        // And the increment needed is max(0, prev_val - a_i).
        // This is valid if max(a_i, prev_val) < m. (which is always true since prev_val < m and a_i < m)

        // Option 2: Wrap around.
        // We want b_i = (a_i + k) % m.
        // This means a_i + k >= m.
        // We need prev_val <= (a_i + k) % m.
        // The smallest value we can achieve by wrapping around is 0 (if a_i + k = m).
        // The largest value we can achieve by wrapping around is (a_i + x) % m.
        // If we wrap around, the values we can achieve are [0, (a_i + x) % m] and [a_i, m-1].
        // More precisely, the values (a_i + k) % m for 0 <= k <= x are:
        //   a_i, a_i+1, ..., m-1, 0, 1, ..., (a_i+x)%m.
        // We need to pick a b_i from this set such that b_i >= prev_val.

        // Let's consider the value `a_i_plus_x_mod_m = (a_i + x) % m`.
        // And `a_i_plus_x_no_mod = a_i + x`.

        // If `a_i_plus_x_no_mod < m`:
        //   No wrap-around happens.
        //   We need `prev_val <= b_i <= a_i + x`.
        //   If `a_i + x < prev_val`, then it's impossible. Return false.
        //   Otherwise, we can set `b_i = max(a_i, prev_val)`.
        //   `prev_val` for the next iteration becomes `max(a_i, prev_val)`.
        //   This is because `max(a_i, prev_val)` is the smallest possible `b_i` that satisfies `b_i >= prev_val` and `b_i <= a_i + x`.

        // If `a_i_plus_x_no_mod >= m`:
        //   Wrap-around happens.
        //   The values we can achieve are `[a_i, m-1]` and `[0, a_i_plus_x_mod_m]`.
        //   We need to find a `b_i` in these ranges such that `b_i >= prev_val`.
        //   Case A: `prev_val <= a_i_plus_x_mod_m`.
        //     This means `prev_val` is in the wrapped-around part `[0, a_i_plus_x_mod_m]`.
        //     Since we can achieve `prev_val` (by incrementing `a_i` by `(prev_val - a_i + m) % m`, which is <= x),
        //     we can set `b_i = prev_val`.
        //     `prev_val` for the next iteration remains `prev_val`.
        //   Case B: `prev_val > a_i_plus_x_mod_m`.
        //     This means `prev_val` is NOT in the wrapped-around part `[0, a_i_plus_x_mod_m]`.
        //     So, we must find `b_i` in `[a_i, m-1]` such that `b_i >= prev_val`.
        //     This is only possible if `a_i >= prev_val`.
        //     If `a_i < prev_val`, then it's impossible. Return false.
        //     If `a_i >= prev_val`, we can set `b_i = a_i`.
        //     `prev_val` for the next iteration becomes `a_i`.

        // Combining these:
        // Let `target_val = prev_val`.
        // If `a[i] >= target_val`:
        //   We can potentially use `a[i]` as `b_i`. This requires 0 operations.
        //   The only way this fails is if `a[i] + x` wraps around and becomes less than `target_val`.
        //   This means `(a[i] + x) % m < target_val` AND `a[i] + x >= m`.
        //   If this condition is true, we cannot use `a[i]` as `b_i`.
        //   In this case, we must increment `a[i]` such that it wraps around and becomes `target_val` (or greater).
        //   The increment needed to reach `target_val` from `a[i]` is `(target_val - a[i] + m) % m`.
        //   If this increment is `<= x`, then we can set `b_i = target_val`.
        //   Otherwise, it's impossible.
        //   So, if `a[i] >= target_val`:
        //     If `(a[i] + x) % m < target_val` (meaning `a[i] + x` wrapped around and is now too small):
        //       We must increment `a[i]` to reach `target_val` (or higher).
        //       The increment needed is `(target_val - a[i] + m) % m`.
        //       If this increment `> x`, then it's impossible. Return false.
        //       Else, `prev_val` remains `target_val`.
        //     Else (`(a[i] + x) % m >= target_val` or no wrap-around):
        //       We can simply use `a[i]` as `b_i`. `prev_val` becomes `a[i]`.
        // Else (`a[i] < target_val`):
        //   We must increment `a[i]`.
        //   The increment needed to reach `target_val` from `a[i]` is `target_val - a[i]`.
        //   If `target_val - a[i] > x`, then it's impossible. Return false.
        //   Else, `prev_val` remains `target_val`.

        // Let's try this logic:
        // If a[i] >= prev_val:
        //   We can potentially set b_i = a[i]. This requires 0 operations.
        //   This is valid unless incrementing a[i] by x forces it to wrap around and become less than prev_val.
        //   Condition for this: (a[i] + x) % m < prev_val.
        //   If (a[i] + x) % m < prev_val:
        //     This means we *must* increment a[i] such that it wraps around and becomes at least prev_val.
        //     The smallest value we can achieve that is >= prev_val is prev_val itself.
        //     The increment needed to reach prev_val from a[i] is (prev_val - a[i] + m) % m.
        //     If this increment > x, then it's impossible. Return false.
        //     Otherwise, we can set b_i = prev_val. prev_val for next iteration remains prev_val.
        //   Else (a[i] + x does not wrap around to be < prev_val):
        //     We can set b_i = a[i]. prev_val for next iteration becomes a[i].
        // Else (a[i] < prev_val):
        //   We *must* increment a[i].
        //   The increment needed to reach prev_val from a[i] is prev_val - a[i].
        //   If prev_val - a[i] > x, then it's impossible. Return false.
        //   Otherwise, we can set b_i = prev_val. prev_val for next iteration remains prev_val.

        // This logic seems correct and covers all cases.

        if (current_a >= prev_val) {
            // Option 1: Don't increment, keep current_a. This is valid if current_a is not "too large"
            // such that current_a + x wraps around and becomes less than prev_val.
            // If current_a + x < m, no wrap-around, so current_a is fine.
            // If current_a + x >= m, wrap-around occurs.
            //   If (current_a + x) % m < prev_val, then we cannot keep current_a.
            //   We are forced to increment current_a such that it wraps around and becomes at least prev_val.
            //   The smallest such value is prev_val.
            //   The increment needed is (prev_val - current_a + m) % m.
            //   If this increment > x, then it's impossible.
            //   Otherwise, we can achieve prev_val.
            if ((current_a + x) % m < prev_val && (current_a + x) >= m) { // This condition means it wrapped around AND became too small
                // We must increment current_a to reach prev_val.
                // The increment needed is (prev_val - current_a + m) % m.
                // If this increment is > x, then it's impossible.
                // Otherwise, we can achieve prev_val.
                // No change to prev_val for next iteration.
                long long inc_needed = (prev_val - current_a + m) % m;
                if (inc_needed > x) {
                    return false;
                }
                // else, prev_val remains prev_val.
            } else {
                // We can use current_a as b_i.
                prev_val = current_a;
            }
        } else { // current_a < prev_val
            // We must increment current_a to reach at least prev_val.
            // The smallest value we can achieve is prev_val.
            // The increment needed is prev_val - current_a.
            // If this increment is > x, then it's impossible.
            // Otherwise, we can achieve prev_val.
            // No change to prev_val for next iteration.
            long long inc_needed = prev_val - current_a;
            if (inc_needed > x) {
                return false;
            }
            // else, prev_val remains prev_val.
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    long long v, d, p;
    int original_idx;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_line;
    for (int i = 0; i < n; ++i) {
        long long v, d, p;
        std::cin >> v >> d >> p;
        children_line.push_back({v, d, p, i + 1});
    }

    std::vector<int> treated_children_indices;

    while (!children_line.empty()) {
        Child current_child = children_line.front();
        children_line.pop_front();
        treated_children_indices.push_back(current_child.original_idx);

        long long office_cry_volume = current_child.v;
        long long hall_cry_sum = 0; // Sum of d_j from children who left due to chain reaction

        auto it = children_line.begin();
        while (it != children_line.end()) {
            // Apply office cry effect
            if (office_cry_volume > 0) {
                it->p -= office_cry_volume;
                office_cry_volume--;
            }

            // Apply hall cry effect from previous chain reactions
            it->p -= hall_cry_sum;

            if (it->p < 0) {
                hall_cry_sum += it->d; // This child cries in the hall
                it = children_line.erase(it); // Remove child from line
            } else {
                ++it;
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[j] to a very large value (effectively infinity)
    // This represents the upper bound for A_0[j]
    std::vector<long long> initial_a(n, 2000000000LL); // Max possible value for A_0[j] is 10^9,
                                                      // but it can be reduced by d values.
                                                      // A safe upper bound for A_0[j] is 10^9 + 5000 * 10^4 = 1.05 * 10^9.
                                                      // Using 2*10^9 to be safe.

    // Calculate the total delta for each element at the time of each operation
    // delta_prefix_sum[k][j] stores sum of d's applied to A_0[j] up to operation k-1
    // This is not needed explicitly. We can compute current_delta for each element
    // by iterating operations in reverse.

    // Iterate operations in reverse to determine constraints on initial_a
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // Type 1: a_j = a_j + d for l <= j <= r
            // This means that the d value was added to a_j.
            // When we are trying to find initial_a, this d value effectively
            // reduces the upper bound for initial_a[j] by d.
            // If initial_a[j] was constrained to be <= X at this point,
            // then A_0[j] + current_delta[j] <= X.
            // After this operation, current_delta[j] decreases by d.
            // So, A_0[j] + (current_delta[j] - d) <= X - d.
            // This means the constraint on A_0[j] becomes X - d.
            // We need to apply this to the range [l, r].
            // This is a range update operation on initial_a.
            // We can use a difference array or iterate. Given N=5000, iterating is fine.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // Type 2: max(a_j for l <= j <= r) = m
            // This means for all j in [l, r], a_j <= m.
            // So, A_0[j] + current_delta[j] <= m.
            // This implies A_0[j] <= m - current_delta[j].
            // We update initial_a[j] = min(initial_a[j], m - current_delta[j]).
            // This is a range minimum query.
            // We need to apply this to the range [l, r].
            // Again, iterating is fine.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val);
            }
        }
    }

    // Now, initial_a contains the maximum possible values for A_0[j]
    // that satisfy all type 2 constraints when considering the cumulative deltas.
    // We need to verify if this initial_a works.
    // We will use a segment tree or similar structure to efficiently calculate
    // current values and check max constraints.
    // Given N=5000, M=5000, a simple array and iterating for range updates/queries is O(N*M).
    // For verification, we need to simulate operations.
    // A segment tree for range add and range max query would be O(M log N).
    // A difference array for range add and then prefix sums for point query is O(N+M).
    // For range max query, we need a segment tree.

    // Let's use a segment tree for verification.
    // The segment tree will store the current values of the array.
    // Each node will store the maximum value in its range.
    // It will also support range add operations.

    // Segment tree implementation
    std::vector<long long> tree(4 * n);
    std::vector<long long> lazy(4 * n, 0); // Lazy propagation for range add

    auto build = [&](auto self, int node, int start, int end) -> void {
        if (start == end) {
            tree[node] = initial_a[start];
        } else {
            int mid = (start + end) / 2;
            self(self, 2 * node, start, mid);
            self(self, 2 * node + 1, mid + 1, end);
            tree[node] = std::max(tree[2 * node], tree[2 * node + 1]);
        }
    };

    auto push = [&](int node) -> void {
        if (lazy[node] != 0) {
            tree[2 * node] += lazy[node];
            lazy[2 * node] += lazy[node];
            tree[2 * node + 1] += lazy[node];
            lazy[2 * node + 1] += lazy[node];
            lazy[node] = 0;
        }
    };

    auto update_range = [&](auto self, int node, int start, int end, int l, int r, long long val) -> void {
        if (start > end || start > r || end < l) {
            return;
        }
        if (l <= start && end <= r) {
            tree[node] += val;
            lazy[node] += val;
            return;
        }
        push(node);
        int mid = (start + end) / 2;
        self(self, 2 * node, start, mid, l, r, val);
        self(self, 2 * node + 1, mid + 1, end, l, r, val);
        tree[node] = std::max(tree[2 * node], tree[2 * node + 1]);
    };

    auto query_max = [&](auto self, int node, int start, int end, int l, int r) -> long long {
        if (start > end || start > r || end < l) {
            return LLONG_MIN; // Return a very small value for out-of-range queries
        }
        if (l <= start && end <= r) {
            return tree[node];
        }
        push(node);
        int mid = (start + end) / 2;
        long long p1 = self(self, 2 * node, start, mid, l, r);
        long long p2 = self(self, 2 * node + 1, mid + 1, end, l, r);
        return std::max(p1, p2);
    };

    build(build, 1, 0, n - 1);

    // Verify all operations
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            update_range(update_range, 1, 0, n - 1, ops[i].l, ops[i].r, ops[i].val);
        } else { // ops[i].type == 2
            long long current_max = query_max(query_max, 1, 0, n - 1, ops[i].l, ops[i].r);
            if (current_max != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check absolute value constraint for initial_a
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] < -1000000000LL || initial_a[i] > 1000000000LL) {
            // This case should ideally not be hit if the problem constraints are well-defined
            // and our initial_a calculation is correct, as initial_a[j] is derived from m_i values
