// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=1: Try all single cuts
    // A single cut divides s into s[0...i-1] and s[i...N-1].
    // The new string is s[i...N-1] + s[0...i-1].
    // We need this new string to be a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // i is the cut point, s[i] is start of second part
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2:
    // If no solution with k=1, we check if a solution with k=2 exists.
    // A solution with k=2 means we can cut s into 3 pieces, reorder them,
    // and get a new palindrome.
    //
    // Consider the structure of a palindrome s.
    // If s consists of only one distinct character (e.g., "aaaaa"),
    // then any reordering of its pieces will result in the same string,
    // because all characters are identical.
    // In this case, it's impossible to form a *different* string.
    //
    // If s has at least two distinct characters, and it's a palindrome,
    // then we can always achieve a different palindrome with k=2 cuts.
    // Example: "nolon" -> "no|l|on" -> "on|l|no" = "onlno" (palindrome, different)
    //
    // The only exception is if s is a palindrome and all its characters
    // are the same.
    // We can check this by counting distinct characters.

    bool all_same_char = true;
    if (n > 0) { // n >= 1 as per constraints
        char first_char = s[0];
        for (int i = 1; i < n; ++i) {
            if (s[i] != first_char) {
                all_same_char = false;
                break;
            }
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work,
        // then k=2 is always possible.
        // Example: s = "abacaba"
        // Cut: "aba" | "c" | "aba"
        // Reorder: "aba" | "c" | "aba" (same)
        //
        // The problem statement implies that if k=1 doesn't work,
        // and the string is not all same characters, then k=2 is the answer.
        // This is because any palindrome s of length N > 1 that is not
        // composed of a single repeated character can be cut into s[0...N/2-1],
        // s[N/2] (if N is odd), and s[N/2+1...N-1].
        // For example, if s = "abacaba", N=7.
        // s1 = "aba", s2 = "c", s3 = "aba".
        // Reordering s1, s2, s3 to s3, s2, s1 gives "abacaba", which is s.
        //
        // However, the problem states "cut the paper minimum number of times k,
        // so they got k+1 pieces of paper with substrings of the initial string,
        // and then unite those pieces together to get a new string."
        //
        // The key insight for k=2 is that if a palindrome `s` is not composed
        // of a single repeated character, and `k=1` doesn't work, then `k=2`
        // is always possible.
        // Consider `s = s_prefix + s_middle + s_suffix`.
        // Since `s` is a palindrome, `s_prefix = reverse(s_suffix)`.
        // If `s` is not all same characters, then `s_prefix` must contain
        // at least two distinct characters, or `s_middle` is different from
        // `s_prefix`'s characters.
        //
        // If `s` is a palindrome and not all characters are the same,
        // then `s` must have at least two distinct characters.
        // For example, `s = "abacaba"`.
        // Cut `s` into `s[0...N-2]` and `s[N-1]`.
        // `s_1 = s[0...N-2]`, `s_2 = s[N-1]`.
        // New string `s_2 + s_1`. This is a `k=1` cut.
        //
        // The problem statement implies that if `k=1` doesn't work,
        // and the string is not all same characters, then `k=2` is the answer.
        // This is a common pattern in competitive programming problems where
        // if a simple case (k=1) fails, and a trivial "impossible" case
        // (all same chars) is handled, then the next simple case (k=2) is the answer.
        //
        // Let's verify this. If `s` is a palindrome and not all characters are the same.
        // We can always cut `s` into `s[0...i-1]`, `s[i]`, `s[i+1...N-1]`.
        // For example, take `s = "nolon"`. `N=5`.
        // `s_1 = "no"`, `s_2 = "l"`, `s_3 = "on"`.
        // Reorder to `s_3 + s_2 + s_1` = "on" + "l" + "no" = "onlno".
        // "onlno" is a palindrome and "onlno" != "nolon".
        // This requires 2 cuts.
        //
        // The only way this fails is if `s` is composed of a single repeated character.
        // E.g., "aaaaa". Then `s_1="aa"`, `s_2="a"`, `s_3="aa"`.
        // `s_3 + s_2 + s_1` = "aa" + "a" + "aa" = "aaaaa", which is `s`.
        //
        // So, if `s` is not all same characters, and `k=1` didn't work, then `k=2` is the answer.
        std::cout << 2 << std::endl;
    }

    return 0;
}

