#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // All f values are a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 1].value + a[n - 2].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // The optimal strategy for minimizing max_f - min_f is often to put a[0] in one group
    // and a[n-1] in another group, or a[0] and a[n-1] in the same group.
    // Let's consider the partition where a[0] is in S1 and a[n-1] is in S2.
    // The remaining elements can be distributed.
    //
    // The critical observation is that the minimum possible f value is either a[0]+a[1] (if both in same group)
    // or a[0]+a[n-1]+h (if a[0] and a[n-1] are in different groups).
    // The maximum possible f value is either a[n-1]+a[n-2] (if both in same group)
    // or a[n-1]+a[n-2]+h (if a[n-1] and a[n-2] are in different groups, and one is in S1, other in S2)
    // or a[n-1]+a[0]+h (if a[n-1] in S1, a[0] in S2, and S1 has only a[n-1], S2 has only a[0])
    //
    // Let's analyze the four possible configurations for a[0] and a[n-1]:
    // 1. a[0] in S1, a[n-1] in S1. (This is covered by Case 1 if all are in S1)
    //    If S2 is not empty, then min_f could be a[0]+a[1] or a[0]+a_k+h.
    //    max_f could be a[n-1]+a[n-2] or a[n-1]+a_k+h.
    //    This is complex.
    //
    // A simpler approach:
    // The minimum possible sum of two elements is a[0] + a[1].
    // The maximum possible sum of two elements is a[n-1] + a[n-2].
    //
    // The overall minimum f value is `min(a[0]+a[1], a[0]+a[n-1]+h)`
    // The overall maximum f value is `max(a[n-1]+a[n-2], a[n-1]+a[0]+h)`
    //
    // Let's consider two main partition types:
    // Type A: All elements are in the same subsequence (e.g., all 1s).
    //   min_f = a[0].value + a[1].value
    //   max_f = a[n-1].value + a[n-2].value
    //   Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    //   This is `goodness1`.

    // Type B: a[0] is in S1, and a[n-1] is in S2.
    //   To minimize the range, we want to make the values as close as possible.
    //   If a[0] is in S1 and a[n-1] is in S2, then a[0]+a[n-1]+h is a value.
    //   What if we put a[0] in S1, and all other elements a[1], ..., a[n-1] in S2?
    //   S1 = {a[0]}
    //   S2 = {a[1], ..., a[n-1]}
    //   Possible f values:
    //     - From S1: None (only one element)
    //     - From S2: a[i]+a[j] for i,j in [1, n-1]. Min: a[1]+a[2]. Max: a[n-1]+a[n-2].
    //     - Between S1 and S2: a[0]+a[i]+h for i in [1, n-1]. Min: a[0]+a[1]+h. Max: a[0]+a[n-1]+h.
    //   Overall min_f = min(a[1]+a[2], a[0]+a[1]+h)
    //   Overall max_f = max(a[n-1]+a[n-2], a[0]+a[n-1]+h)
    //   Goodness = max_f - min_f
    //   This is a candidate.

    // Let's consider the specific partition: a[0] in S1, a[1]...a[n-1] in S2.
    // This is a specific instance of Type B.
    // min_f_val = min(a[1].value + a[2].value, a[0].value + a[1].value + h) (if n >= 3)
    // If n=2, S2 has only a[1]. No pairs in S2. min_f_val = a[0].value + a[1].value + h.
    // max_f_val = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) (if n >= 3)
    // If n=2, S2 has only a[1]. No pairs in S2. max_f_val = a[0].value + a[1].value + h.

    long long current_min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    // Consider the partition where a[0] is in group 1, and all other elements are in group 2.
    // This is a strong candidate if h is large.
    // S1 = {a[0]}
    // S2 = {a[1], ..., a[n-1]}
    //
    // Values within S2: a[i]+a[j] for i,j in [1, n-1].
    // Min within S2: a[1].value + a[2].value (if n >= 3)
    // Max within S2: a[n-1].value + a[n-2].value (if n >= 3)
    //
    // Values between S1 and S2: a[0].value + a[i].value + h for i in [1, n-1].
    // Min between S1 and S2: a[0].value + a[1].value + h
    // Max between S1 and S2: a[0].value + a[n-1].value + h
    //
    // Overall min_f:
    // If n=2: only a[0]+a[1]+h.
    // If n>=3: min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //
    // Overall max_f:
    // If n=2: only a[0]+a[1]+h.
    // If n>=3: max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)

    long long min_f_val_case2, max_f_val_case2;
    if (n == 2) {
        min_f_val_case2 = a[0].value + a[1].value + h;
        max_f_val_case2 = a[0].value + a[1].value + h;
    } else { // n >= 3
        min_f_val_case2 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        max_f_val_case2 = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);
    }
    long long goodness2 = max_f_val_case2 - min_f_val_case2;

    if (goodness2 < current_min_goodness) {
        current_min_goodness = goodness2;
        best_partition.assign(n, 2); // All in group 2 initially
        best_partition[a[0].original_index] = 1; // a[0] in group 1
    }

    // Consider the partition where a[0] and a[1] are in group 1, and all other elements are in group 2.
    // This is a strong candidate if h is small.
    // S1 = {a[0], a[1]}
    // S2 = {a[2], ..., a[n-1]}
    //
    // Values within S1: a[0].value + a[1].value
    // Values within S2: a[i]+a[j] for i,j in [2, n-1].
    // Min within S2: a[2].value + a[3].value (if n >= 4)
    // Max within S2: a[n-1].value + a[n-2].value (if n >= 4)
    //
    // Values between S1 and S2: a[k]+a[j]+h for k in {0,1}, j in [2, n-1].
    // Min between S1 and S2: a[0].value + a[2].value + h (if n >= 3)
    // Max between S1 and S2: a[1].value + a[n-1].value + h (if n >= 3)
    //
    // Overall min_f:
    // If n=2: only a[0]+a[1].
    // If n=3: min(a[0]+a[1], a[0]+a[2]+h, a[1]+a[2]+h). Note S2 has only a[2].
    // If n>=4: min(a[0]+a[1], a[2]+a[3], a[0]+a[2]+h)
    //
    // Overall max_f:
    // If n=2: only a[0]+a[1].
    // If n=3: max(a[0]+a[1], a[0]+a[2]+h, a[1]+a[2]+h).
    // If n>=4: max(a[n-1]+a[n-2], a[1]+a[n-1]+h)

    long long min_f_val_case3, max_f_val_case3;
    if (n == 2) {
        min_f_val_case3 = a[0].value + a[1].value;
        max_f_val_case3 = a[0].value + a[1].value;
    } else if (n == 3) {
        min_f_val_case3 = std::min({a[0].value + a[1].value, a[0].value + a[2].value + h, a[1].value + a[2].value + h});
        max_f_val_case3 = std::max({a[0].value + a[1].value, a[0].value + a[2].value + h, a[1].value + a[2].value + h});
    } else { // n >= 4
        min_f_val_case3 = std::min({a[0].value + a[1].value, a[2].value + a[3].value, a[0].value + a[2].value + h});
        max_f_val_case3 = std::max({a[n-1].value + a[n-2].value, a[1].value + a[n-1].value + h});
    }
    long long goodness3 = max_f_val_case3 - min_f_val_case3;

    if (goodness3 < current_min_goodness) {
        current_min_goodness = goodness3;
        best_partition.assign(n, 2); // All in group 2 initially
        best_partition[a[0].original_index] = 1; // a[0] in group 1
        best_partition[a[1].original_index] = 1; // a[1] in group 1
    }

    std::cout << current_min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

