            //   This means the interval `[p[p_ptr] - T, p[p_ptr] + T]` must overlap with `[h_i - T, h_i + T]`.
            //   This is equivalent to `max(p[p_ptr] - T, h_i - T) <= min(p[p_ptr] + T, h_i + T)`.
            //   This simplifies to `abs(p[p_ptr] - h_i) <= 2 * T`.

            // So, we need to find an `h_i` such that `p[p_ptr] - 2*T <= h_i <= p[p_ptr] + 2*T`.
            // We iterate `h_ptr` forward until `h[h_ptr] >= p[p_ptr] - 2*T`.
            // If `h_ptr == n`, then no head can cover `p[p_ptr]`, so return false.
            // Now `h[h_ptr]` is a candidate.
            // If `h[h_ptr] > p[p_ptr] + 2*T`, then `h[h_ptr]` is too far right, so no head can cover `p[p_ptr]`. Return false.
            // Otherwise, `h[h_ptr]` can cover `p[p_ptr]`.
            // We use `h[h_ptr]`.
            // This head `h[h_ptr]` can be moved to `x` such that `abs(h[h_ptr] - x) <= T`.
            // To cover `p[p_ptr]` and maximize right reach, we should move `h[h_ptr]` to `x` such that `p[p_ptr]` is in `[x-T, x+T]` and `x+T` is maximized.
            // This means `x` should be as large as possible, subject to `x-T <= p[p_ptr]` and `abs(h[h_ptr] - x) <= T`.
            // So `x = min(h[h_ptr] + T, p[p_ptr] + T)`.
            // The rightmost point covered by this head is `x + T`.
            // Let `covered_until = min(h[h_ptr] + T, p[p_ptr] + T) + T`.
            // Advance `p_ptr` past all points `p[k]` such that `p[k] <= covered_until`.
            // Increment `h_ptr`.

            // This greedy strategy is correct.
            // `h_ptr` is the index of the next head to consider.
            // `p_ptr` is the index of the next point to cover.
            long long current_covered_rightmost = -2e18; // Represents the rightmost point covered by the previous head.
            while (p_ptr < m) {
                // If p[p_ptr] is already covered by the previous head, advance p_ptr.
                if (p[p_ptr] <= current_covered_rightmost) {
                    p_ptr++;
                    continue;
                }

                // We need to cover p[p_ptr]. Use a new head.
                if (h_ptr == n) {
                    return false; // No more heads available.
                }

                // Find the best head h[h_ptr] to cover p[p_ptr] and extend furthest right.
                // The head h[h_ptr] can move to any x in [h[h_ptr]-T, h[h_ptr]+T].
