                // We need p[p_ptr] to be in [x-T, x+T].
                // So, x must be in [p[p_ptr]-T, p[p_ptr]+T].
                // Combining these, x must be in `[max(h[h_ptr]-T, p[p_ptr]-T), min(h[h_ptr]+T, p[p_ptr]+T)]`.
                // For such an x to exist, `max(h[h_ptr]-T, p[p_ptr]-T) <= min(h[h_ptr]+T, p[p_ptr]+T)`.
                // This simplifies to `abs(h[h_ptr] - p[p_ptr]) <= 2*T`.
                // If this condition is not met, `h[h_ptr]` cannot cover `p[p_ptr]`.
                // In this case, we must advance `h_ptr` until we find a head that can cover `p[p_ptr]`.
                // Or, if `h[h_ptr]` is too far to the left (`h[h_ptr] < p[p_ptr] - 2*T`), then it cannot cover `p[p_ptr]`.
                // We must advance `h_ptr`.
                while (h_ptr < n && h[h_ptr] < p[p_ptr] - 2 * T) {
                    h_ptr++;
                }

                if (h_ptr == n) {
                    return false; // No head can cover p[p_ptr].
                }

                // Now, h[h_ptr] >= p[p_ptr] - 2*T.
                // If h[h_ptr] > p[p_ptr] + 2*T, then h[h_ptr] is too far to the right to cover p[p_ptr].
                // Since h is sorted, no subsequent head can cover p[p_ptr] either.
                if (h[h_ptr] > p[p_ptr] + 2 * T) {
                    return false;
                }

                // h[h_ptr] can cover p[p_ptr].
                // We use h[h_ptr].
                // To maximize the rightmost point covered, we should move h[h_ptr] to `x` such that `x+T` is maximized.
                // `x` must be in `[h[h_ptr]-T, h[h_ptr]+T]` and `p[p_ptr]` must be in `[x-T, x+T]`.
                // So `x` must be in `[p[p_ptr]-T, p[p_ptr]+T]`.
                // The largest possible `x` is `min(h[h_ptr]+T, p[p_ptr]+T)`.
                // The rightmost point covered is `min(h[h_ptr]+T, p[p_ptr]+T) + T`.
                current_covered_rightmost = std::min(h[h_ptr] + T, p[p_ptr] + T) + T;

                h_ptr++; // Use this head and move to the next head.
                // p_ptr will advance in the next iteration if p[p_ptr] is covered.
            }
            return true; // All points covered.
        }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible distance between p_i and h_i is 10^10. Max time could be 10^10.
                               // A head at 1 and a point at 10^10. Time is 10^10 - 1.
                               // If h_i is 1 and p_j is 10^10, and T=0, check fails.
                               // If h_i is 1 and p_j is 10^10, and T=10^10-1, check passes.
                               // Max value for p_i or h_i is 10^10.
                               // Max difference is 10^10 - 1.
                               // So T can be up to 10^10.
                               // 2 * 10^10 is a safe upper bound.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

